/* -------------------- DOM helpers -------------------- */
const $ = (id) => document.getElementById(id);

function rafThrottle(fn){
  let raf = 0;
  let lastThis = null;
  let lastArgs = null;
  return function(...args){
    lastThis = this;
    lastArgs = args;
    if (raf) return;
    raf = requestAnimationFrame(() => {
      raf = 0;
      fn.apply(lastThis, lastArgs);
    });
  };
}

let preciseRangeDragState = null;

function syncPreciseRangeVisual(range){
  if (!(range instanceof HTMLInputElement) || range.type !== "range") return;
  const min = Number(range.min || 0);
  const max = Number(range.max || 100);
  const val = Number(range.value || 0);
  const pct = (Number.isFinite(min) && Number.isFinite(max) && Number.isFinite(val) && max > min)
    ? Math.max(0, Math.min(100, ((val - min) / (max - min)) * 100))
    : 0;
  range.style.setProperty("--range-pct", `${pct}%`);
}

function preciseRangeValueFromPointer(range, e){
  const rect = range.getBoundingClientRect();
  const min = Number(range.min || 0);
  const max = Number(range.max || 100);
  if (!rect.width || !Number.isFinite(min) || !Number.isFinite(max) || max <= min) return range.value;

  const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
  let next = min + ((max - min) * ratio);

  const stepRaw = range.getAttribute("step");
  if (stepRaw && stepRaw !== "any"){
    const step = Number(stepRaw);
    if (Number.isFinite(step) && step > 0){
      next = min + Math.round((next - min) / step) * step;
    }
  }

  next = Math.max(min, Math.min(max, next));
  return String(Math.round(next * 1000000) / 1000000);
}

function setPreciseRangeFromPointer(range, e, emitChange = false){
  const next = preciseRangeValueFromPointer(range, e);
  if (range.value !== next){
    range.value = next;
    syncPreciseRangeVisual(range);
    range.dispatchEvent(new Event("input", { bubbles:true }));
  } else {
    syncPreciseRangeVisual(range);
  }
  if (emitChange) range.dispatchEvent(new Event("change", { bubbles:true }));
}

function initPreciseRangeSliders(root = document){
  const scope = root instanceof Element || root instanceof Document || root instanceof DocumentFragment ? root : document;
  if (scope.matches?.('input[type="range"]')) syncPreciseRangeVisual(scope);
  scope.querySelectorAll?.('input[type="range"]').forEach(syncPreciseRangeVisual);
}

function beginPreciseRangeDrag(e){
  if (e.button != null && e.button !== 0) return;
  const range = e.target?.closest?.('input[type="range"]');
  if (!(range instanceof HTMLInputElement) || range.disabled) return;

  preciseRangeDragState = { range, pointerId:e.pointerId };
  try{ range.focus({ preventScroll:true }); }catch{}
  try{ range.setPointerCapture(e.pointerId); }catch{}
  setPreciseRangeFromPointer(range, e);
  e.preventDefault();
}

function handlePreciseRangeMove(e){
  if (!preciseRangeDragState || e.pointerId !== preciseRangeDragState.pointerId) return;
  setPreciseRangeFromPointer(preciseRangeDragState.range, e);
  e.preventDefault();
}

function endPreciseRangeDrag(e){
  if (!preciseRangeDragState || (e.pointerId != null && e.pointerId !== preciseRangeDragState.pointerId)) return;
  const range = preciseRangeDragState.range;
  preciseRangeDragState = null;
  if (range instanceof HTMLInputElement){
    try{ range.releasePointerCapture(e.pointerId); }catch{}
    syncPreciseRangeVisual(range);
    range.dispatchEvent(new Event("change", { bubbles:true }));
  }
}

document.addEventListener("pointerdown", beginPreciseRangeDrag, true);
window.addEventListener("pointermove", handlePreciseRangeMove, { passive:false });
window.addEventListener("pointerup", endPreciseRangeDrag, true);
window.addEventListener("pointercancel", endPreciseRangeDrag, true);
document.addEventListener("input", (e) => {
  if (e.target instanceof HTMLInputElement && e.target.type === "range") syncPreciseRangeVisual(e.target);
}, true);

if (document.readyState === "loading"){
  document.addEventListener("DOMContentLoaded", () => initPreciseRangeSliders(), { once:true });
} else {
  initPreciseRangeSliders();
}

if (typeof MutationObserver !== "undefined"){
  new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      mutation.addedNodes.forEach((node) => initPreciseRangeSliders(node));
    });
  }).observe(document.documentElement, { childList:true, subtree:true });
}

