function showView(name){
  Object.values(views).forEach(v => v.dataset.active = "false");
  views[name].dataset.active = "true";
  hideError("create");
  hideError("login");

  if (name === "chat") document.body.dataset.mode = "chat";
  else delete document.body.dataset.mode;

  // Landing-only educational disguise; revert instantly in chat view.
  try{
    const saved = localStorage.getItem("chatapp_tab_name");
    if (!saved){
      document.title = (name === "chat")
        ? "GradeSort | Grade Sorter, Study Helper"
        : "GradeSort | Grade Sorter, Study Helper";
    }
  }catch{}

  if (name === "home"){
    try{ window.scrollTo(0, 0); }catch{}
  }

  try{ syncSidebarRoomActiveStates(); }catch{}
}

function setError(which, msg){
  const el = which === "create" ? $("create-error") : $("login-error");
  el.textContent = msg;
  el.hidden = false;
}
function hideError(which){
  const el = which === "create" ? $("create-error") : $("login-error");
  el.hidden = true;
  el.textContent = "";
}

function escapeHtml(s){
  return String(s ?? "")
    .replaceAll("&","&amp;")
    .replaceAll("<","&lt;")
    .replaceAll(">","&gt;")
    .replaceAll('"',"&quot;")
    .replaceAll("'","&#039;");
}

function escapeRegExp(s){
  return String(s ?? "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function getRoomMentionUsers(){
  const out = [];
  const codes = new Set();

  try{
    for (const code of roomMembersCache.keys()){
      if (code) codes.add(String(code));
    }
  }catch{}

  const selfCode = String(currentUser?.code || "");
  try{
    if (selfCode && roomMembersCache.has(selfCode)) codes.add(selfCode);
  }catch{}

  for (const code of codes){
    const u = (String(currentUser?.code || "") === code) ? currentUser : liveUserCache.get(code);
    const username = sanitizeUsername(u?.username || "");
    if (!username) continue;
    out.push({
      code,
      username,
      usernameLower: String(u?.usernameLower || username).toLowerCase(),
      displayName: sanitizeUsername(u?.displayName || username) || username,
      displayNameLower: String(u?.displayNameLower || u?.displayName || username).toLowerCase()
    });
  }

  return out;
}

function getRoomMentionTargetByUsername(username){
  const cleaned = sanitizeUsername(username);
  if (!cleaned) return null;
  const lower = cleaned.toLowerCase();

  for (const u of getRoomMentionUsers()){
    if (u.usernameLower === lower) return u;
  }

  return null;
}

function formatTextWithMentions(s){
  const raw = String(s ?? "");
  const re = /(^|\s)@([A-Za-z0-9_]{1,32})\b/g;
  let out = "";
  let last = 0;
  let m;

  while ((m = re.exec(raw))){
    const start = m.index;
    const pre = m[1] || "";
    const username = m[2] || "";
    const mentionStart = start + pre.length;

    out += escapeHtml(raw.slice(last, mentionStart));

    const target = getRoomMentionTargetByUsername(username);
    if (target){
      out += `<button class="mention-link" type="button" data-mention-usercode="${escapeAttr(target.code)}">@${escapeHtml(target.username)}</button>`;
    } else {
      out += escapeHtml(`@${username}`);
    }

    last = re.lastIndex;
  }

  out += escapeHtml(raw.slice(last));
  return out;
}

function replaceDisplayNameMentionsInComposer(input){
  if (!(input instanceof HTMLTextAreaElement || input instanceof HTMLInputElement)) return false;

  const users = getRoomMentionUsers()
    .filter((u) => u.username && u.displayName && u.displayNameLower !== u.usernameLower)
    .sort((a, b) => b.displayName.length - a.displayName.length);

  if (!users.length) return false;

  const original = String(input.value || "");
  let next = original;
  let delta = 0;
  const caret = (typeof input.selectionStart === "number") ? input.selectionStart : original.length;

  for (const u of users){
    const displayName = String(u.displayName || "").trim();
    const username = String(u.username || "").trim();
    if (!displayName || !username) continue;

    const re = new RegExp(`(^|\\s)@(${escapeRegExp(displayName)})(?=$|\\s)`, "gi");
    next = next.replace(re, (match, pre, typed, offset) => {
      const replacement = `${pre}@${username}`;
      if (offset < caret) delta += replacement.length - match.length;
      return replacement;
    });
  }

  if (next === original) return false;

  input.value = next;
  lastMsgInputVal = next;
  const newCaret = Math.max(0, Math.min(next.length, caret + delta));
  try{ input.setSelectionRange(newCaret, newCaret); }catch{}
  if (pingBarEl && !pingBarEl.hidden) closePingBar({ quiet:true });
  return true;
}

function refreshMentionFormattingForRenderedMessages(root = document){
  const scope = (root && typeof root.querySelectorAll === "function") ? root : document;
  scope.querySelectorAll(".bubble-text[data-raw-text]").forEach((el) => {
    el.innerHTML = formatTextWithMentions(el.dataset.rawText || "");
  });
}

// ----- HTML Library + HTML viewer -----
const btnSideGames = $("btn-side-games");

const HTML_LIBRARY_NODE = "htmlLibrary";
const HTML_LIBRARY_META_NODE = "htmlLibraryMeta";
const HTML_LIBRARY_CHUNK_SIZE = 200000;

function getHtmlLibraryChunkIndex(key){
  if (key === "html" || key === "html1") return 1;
  const n = Number(String(key).slice(4));
  if (Number.isFinite(n) && n >= 2) return n;
  return Number.MAX_SAFE_INTEGER;
}
function getHtmlLibraryChunkKeys(item){
  if (!item || typeof item !== "object") return [];
  return Object.keys(item)
    .filter((key) => /^html\d*$/.test(key))
    .sort((a, b) => getHtmlLibraryChunkIndex(a) - getHtmlLibraryChunkIndex(b));
}
function splitHtmlLibraryContent(rawHtml){
  const html = String(rawHtml || "");
  if (!html) return { html:"" };
  if (html.length <= HTML_LIBRARY_CHUNK_SIZE) return { html };

  const out = {};
  let part = 1;
  for (let i = 0; i < html.length; i += HTML_LIBRARY_CHUNK_SIZE){
    const key = part === 1 ? "html" : `html${part}`;
    out[key] = html.slice(i, i + HTML_LIBRARY_CHUNK_SIZE);
    part += 1;
  }
  return out;
}
function joinHtmlLibraryContent(item){
  const keys = getHtmlLibraryChunkKeys(item);
  if (!keys.length) return "";
  return keys.map((key) => String(item[key] || "")).join("");
}
async function joinHtmlLibraryContentAsync(item){
  const keys = getHtmlLibraryChunkKeys(item);
  if (!keys.length) return "";

  const parts = new Array(keys.length);
  for (let i = 0; i < keys.length; i += 1){
    parts[i] = String(item[keys[i]] || "");
    if ((i + 1) % 12 === 0) await new Promise((resolve) => setTimeout(resolve, 0));
  }
  return parts.join("");
}
async function fetchHtmlLibraryChildKeys(code = currentUser?.code){
  if (!code) return [];
  const base = String(firebaseConfig?.databaseURL || "").replace(/\/+$/, "");
  if (!base) return [];
  const path = htmlLibraryPath(code).split("/").map(encodeURIComponent).join("/");
  try{
    const res = await fetch(`${base}/${path}.json?shallow=true`, { cache:"no-store" });
    if (!res.ok) return [];
    const data = await res.json();
    return data && typeof data === "object" ? Object.keys(data) : [];
  }catch{
    return [];
  }
}

