let gamesStageOpen = false;
let gamesStageLoaded = false;
let gamesStageMaximized = false;
let selectedGame = null;
let htmlActivityPresenceRef = null;

let gamesWindowRect = null;
let gamesWindowRectBeforeMaximize = null;
let gamesWindowDragState = null;
let gamesStageClosingPromise = null;
let gamesStageSuppressOverlayCloseUntil = 0;
let parkedHtmlLibraryKey = "";

const GAMES_MIN_WIDTH = 420;
const GAMES_MIN_HEIGHT = 280;
const GAMES_VIEWPORT_MARGIN = 12;

function htmlLibraryPath(code = currentUser?.code){
  return `users/${code}/${HTML_LIBRARY_NODE}`;
}
function htmlLibraryMetaPath(code = currentUser?.code){
  return `users/${code}/${HTML_LIBRARY_META_NODE}`;
}
function sanitizeHtmlLibraryTitle(raw){
  return sanitizeUsername(raw);
}
function makeHtmlLibraryId(){
  return `html_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}
function formatHtmlLibraryDate(ts){
  const n = Number(ts || 0);
  if (!n) return "Saved HTML";
  try{
    return new Date(n).toLocaleString([], { month:"short", day:"numeric", hour:"numeric", minute:"2-digit" });
  }catch{
    return "Saved HTML";
  }
}
function getHtmlLibraryResumeKey(game = selectedGame){
  if (!game?.libraryId) return "";
  return `library:${game.libraryId}`;
}
function isHtmlLibraryPaused(gameOrId = selectedGame){
  const key = typeof gameOrId === "string"
    ? `library:${gameOrId}`
    : getHtmlLibraryResumeKey(gameOrId);
  return !!(key && parkedHtmlLibraryKey === key);
}
function clearGamesFrameResumeMarkers(frame = $("games-frame")){
  if (!frame) return;
  try{ frame.contentWindow?.__gamesStageLifecycle?.clear?.(); }catch{}
  try{
    frame.contentWindow?.document?.querySelectorAll?.("audio").forEach((el) => {
      el.removeAttribute("data-games-resume-on-restore");
    });
  }catch{}
}
function pauseGamesFrameMedia(frame = $("games-frame")){
  if (!frame) return;
  try{ frame.contentWindow?.__gamesStageLifecycle?.pause?.(); }catch{}
  try{
    frame.contentWindow?.document?.querySelectorAll?.("audio").forEach((el) => {
      const shouldResume = !el.paused && !el.ended;
      if (shouldResume) el.setAttribute("data-games-resume-on-restore", "1");
      else el.removeAttribute("data-games-resume-on-restore");
      try{ el.pause?.(); }catch{}
    });
  }catch{}
}
function resumeGamesFrameMedia(frame = $("games-frame")){
  if (!frame) return;
  try{ frame.contentWindow?.__gamesStageLifecycle?.resume?.(); }catch{}
  try{
    frame.contentWindow?.document?.querySelectorAll?.("audio").forEach((el) => {
      if (el.getAttribute("data-games-resume-on-restore") === "1"){
        el.removeAttribute("data-games-resume-on-restore");
        try{ el.play?.(); }catch{}
      }
    });
  }catch{}
}
function forgetParkedGamesFrame(gameOrKey){
  const key = typeof gameOrKey === "string" ? gameOrKey : getHtmlLibraryResumeKey(gameOrKey);
  if (!key) return;

  const frame = $("games-frame");
  const frameKey = frame?.getAttribute("data-games-parked-key") || "";
  if (parkedHtmlLibraryKey !== key && frameKey !== key) return;

  parkedHtmlLibraryKey = "";
  clearGamesFrameResumeMarkers(frame);

  if (!frame) return;

  try{
    frame.removeAttribute("data-games-parked");
    frame.removeAttribute("data-games-parked-key");
    frame.removeAttribute("srcdoc");
    frame.src = "about:blank";
    frame.contentWindow?.stop?.();
    frame.contentWindow?.location?.replace?.("about:blank");
  }catch{}
  try{ frame.remove(); }catch{}
}
function takeParkedGamesFrame(game = selectedGame){
  const key = getHtmlLibraryResumeKey(game);
  const frame = $("games-frame");
  if (!key || parkedHtmlLibraryKey !== key || !frame) return null;

  parkedHtmlLibraryKey = "";
  frame.removeAttribute("data-games-parked");
  frame.removeAttribute("data-games-parked-key");
  resumeGamesFrameMedia(frame);
  return frame;
}
function parkCurrentGamesFrame(){
  const frame = $("games-frame");
  const key = getHtmlLibraryResumeKey(selectedGame);
  if (!frame || !key) return false;

  pauseGamesFrameMedia(frame);
  parkedHtmlLibraryKey = key;
  frame.setAttribute("data-games-parked", "1");
  frame.setAttribute("data-games-parked-key", key);
  return true;
}
function clearOtherParkedGamesFrames(exceptKey = ""){
  if (!parkedHtmlLibraryKey || parkedHtmlLibraryKey === exceptKey) return;
  forgetParkedGamesFrame(parkedHtmlLibraryKey);
}
async function readHtmlLibraryLegacyMeta(id){
  if (!currentUser?.code || !id) return null;

  try{
    const [titleSnap, titleLowerSnap, updatedAtSnap] = await Promise.all([
      db.ref(`${htmlLibraryPath()}/${id}/title`).once("value"),
      db.ref(`${htmlLibraryPath()}/${id}/titleLower`).once("value"),
      db.ref(`${htmlLibraryPath()}/${id}/updatedAt`).once("value")
    ]);

    const title = String(titleSnap.val() || "Untitled HTML");
    return {
      id,
      title,
      titleLower: String(titleLowerSnap.val() || title).toLowerCase(),
      updatedAt: Number(updatedAtSnap.val() || 0)
    };
  }catch{
    return null;
  }
}
async function cacheHtmlLibraryMeta(items){
  if (!currentUser?.code || !Array.isArray(items) || !items.length) return;

  const updates = {};
  items.forEach((item) => {
    if (!item?.id) return;
    updates[`${htmlLibraryMetaPath()}/${item.id}`] = {
      title: String(item.title || "Untitled HTML"),
      titleLower: String(item.titleLower || item.title || "untitled html").toLowerCase(),
      updatedAt: Number(item.updatedAt || 0)
    };
  });

  if (!Object.keys(updates).length) return;
  try{ await db.ref().update(updates); }catch{}
}
async function readHtmlLibrary(){
  if (!currentUser?.code) return [];

  let items = [];
  try{
    const metaSnap = await db.ref(htmlLibraryMetaPath()).once("value");
    const metaRaw = metaSnap.val() || {};
    items = Object.entries(metaRaw).map(([id, item]) => ({
      id,
      title: String(item?.title || "Untitled HTML"),
      titleLower: String(item?.titleLower || item?.title || "untitled html").toLowerCase(),
      updatedAt: Number(item?.updatedAt || 0)
    }));
  }catch{}

  if (!items.length){
    const ids = await fetchHtmlLibraryChildKeys();
    if (ids.length){
      const legacyItems = (await Promise.all(ids.map((id) => readHtmlLibraryLegacyMeta(id)))).filter(Boolean);
      if (legacyItems.length){
        items = legacyItems;
        void cacheHtmlLibraryMeta(legacyItems);
      }
    }
  }

  return items.sort((a, b) => {
    const byTitle = a.titleLower.localeCompare(b.titleLower);
    if (byTitle) return byTitle;
    return String(a.id).localeCompare(String(b.id));
  });
}
async function readHtmlLibraryItem(id){
  if (!currentUser?.code || !id) return null;

  const baseRef = db.ref(`${htmlLibraryPath()}/${id}`);

  try{
    const [titleSnap, titleLowerSnap, updatedAtSnap, chunkCountSnap] = await Promise.all([
      baseRef.child("title").once("value"),
      baseRef.child("titleLower").once("value"),
      baseRef.child("updatedAt").once("value"),
      baseRef.child("htmlChunkCount").once("value")
    ]);

    const title = String(titleSnap.val() || "Untitled HTML");
    const titleLower = String(titleLowerSnap.val() || title).toLowerCase();

    const parts = [];
    const declaredCount = Math.max(0, Number(chunkCountSnap.val() || 0));

    const firstSnap = await baseRef.child("html").once("value");
    let firstVal = firstSnap.val();
    if (firstVal == null){
      const legacyFirst = await baseRef.child("html1").once("value");
      firstVal = legacyFirst.val();
    }
    if (firstVal != null) parts.push(String(firstVal || ""));

    const maxChunks = declaredCount || 10000;
    for (let idx = 2; idx <= maxChunks; idx += 1){
      const snap = await baseRef.child(`html${idx}`).once("value");
      const val = snap.val();
      if (val == null){
        if (declaredCount) parts.push("");
        else break;
      } else {
        parts.push(String(val || ""));
      }
      if (idx % 6 === 0) await new Promise((resolve) => setTimeout(resolve, 0));
    }

    return {
      id,
      title,
      titleLower,
      html: parts.join(""),
      updatedAt: Number(updatedAtSnap.val() || 0)
    };
  }catch{
    return null;
  }
}
async function ensureHtmlLibraryGameLoaded(game = selectedGame){
  if (!game) return null;
  if (game.html != null) return game;
  if (!game.libraryId) return game;
  if (game.__htmlLoadPromise) return game.__htmlLoadPromise;

  game.__htmlLoadPromise = (async () => {
    const item = await readHtmlLibraryItem(game.libraryId);
    if (!item) return null;
    game.label = item.title;
    game.html = item.html;
    return game;
  })();

  try{
    return await game.__htmlLoadPromise;
  } finally {
    delete game.__htmlLoadPromise;
  }
}
async function createHtmlLibraryItem({ title, html = "", file = null, signal = null, onProgress = null } = {}){
  if (!currentUser?.code) return null;
  const id = makeHtmlLibraryId();
  const meta = {
    title,
    titleLower: String(title).toLowerCase(),
    createdAt: firebase.database.ServerValue.TIMESTAMP,
    updatedAt: firebase.database.ServerValue.TIMESTAMP,
    uploadPending: 1,
    uploadProgress: 0
  };

  const itemRef = db.ref(`${htmlLibraryPath()}/${id}`);
  const metaRef = db.ref(`${htmlLibraryMetaPath()}/${id}`);
  const scope = createFirebaseUploadScope({
    type:"html-library",
    place: localStorage.getItem(LS.PLACE) || "home",
    disconnectRefs:[itemRef, metaRef],
    cleanup: async () => {
      try{ await itemRef.remove(); }catch{}
      try{ await metaRef.remove(); }catch{}
    }
  });

  const uploadSignal = signal || scope.signal;

  try{
    await armFirebaseUploadDisconnect(scope);
    await updateRefWithRetry(db.ref(), {
      [`${htmlLibraryPath()}/${id}`]: meta,
      [`${htmlLibraryMetaPath()}/${id}`]: meta
    }, RTDB_CHUNK_UPLOAD_RETRIES, uploadSignal);

    let lastMetaProgressWrite = 0;
    let lastMetaProgressValue = -1;
    const report = (pct) => {
      const n = Math.max(0, Math.min(100, Number(pct) || 0));
      if (typeof onProgress === "function") onProgress(n);
      const now = Date.now();
      if (n < 100 && n - lastMetaProgressValue < 3 && now - lastMetaProgressWrite < 300) return;
      lastMetaProgressValue = n;
      lastMetaProgressWrite = now;
      try{ void metaRef.update({ uploadProgress:n }); }catch{}
    };

    if (file instanceof Blob){
      await writeTextFileChunksToRef(itemRef, "html", file, {
        signal: uploadSignal,
        progressField:"uploadProgress",
        onProgress: report
      });
    } else {
      await writeHtmlStringChunksToRef(itemRef, "html", html, {
        signal: uploadSignal,
        progressField:"uploadProgress",
        onProgress: report
      });
    }

    await db.ref().update({
      [`${htmlLibraryPath()}/${id}/uploadPending`]: null,
      [`${htmlLibraryPath()}/${id}/uploadProgress`]: 100,
      [`${htmlLibraryPath()}/${id}/updatedAt`]: firebase.database.ServerValue.TIMESTAMP,
      [`${htmlLibraryMetaPath()}/${id}/uploadPending`]: null,
      [`${htmlLibraryMetaPath()}/${id}/uploadProgress`]: 100,
      [`${htmlLibraryMetaPath()}/${id}/updatedAt`]: firebase.database.ServerValue.TIMESTAMP
    });

    await finishFirebaseUploadScope(scope);
    return id;
  }catch(e){
    await cleanupFirebaseUploadScope(scope, e?.message || "html upload failed");
    throw e;
  }
}
async function updateHtmlLibraryTitle(id, title){
  const titleLower = String(title).toLowerCase();
  const updatedAt = firebase.database.ServerValue.TIMESTAMP;

  await db.ref().update({
    [`${htmlLibraryPath()}/${id}/title`]: title,
    [`${htmlLibraryPath()}/${id}/titleLower`]: titleLower,
    [`${htmlLibraryPath()}/${id}/updatedAt`]: updatedAt,
    [`${htmlLibraryMetaPath()}/${id}/title`]: title,
    [`${htmlLibraryMetaPath()}/${id}/titleLower`]: titleLower,
    [`${htmlLibraryMetaPath()}/${id}/updatedAt`]: updatedAt
  });
}
async function deleteHtmlLibraryItem(id){
  if (!currentUser?.code || !id) return;
  await db.ref().update({
    [`${htmlLibraryPath()}/${id}`]: null,
    [`${htmlLibraryMetaPath()}/${id}`]: null
  });

  const isDeletedSelectedGame = selectedGame?.libraryId === id;

  forgetParkedGamesFrame(`library:${id}`);

  if (isDeletedSelectedGame){
    selectedGame = null;
    await closeGamesStage({ preserve:false });
  }
}

function getDefaultGamesWindowRect(){
  const vw = Math.max(window.innerWidth || 0, 720);
  const vh = Math.max(window.innerHeight || 0, 480);
  const width = Math.max(GAMES_MIN_WIDTH, Math.min(vw - (GAMES_VIEWPORT_MARGIN * 2), 1120));
  const height = Math.max(GAMES_MIN_HEIGHT, Math.min(vh - (GAMES_VIEWPORT_MARGIN * 2), 720));
  return {
    x: Math.round((vw - width) / 2),
    y: Math.max(GAMES_VIEWPORT_MARGIN, Math.round((vh - height) / 2)),
    width,
    height
  };
}
function getMaximizedGamesWindowRect(){
  return {
    x: GAMES_VIEWPORT_MARGIN,
    y: GAMES_VIEWPORT_MARGIN,
    width: Math.max(GAMES_MIN_WIDTH, window.innerWidth - (GAMES_VIEWPORT_MARGIN * 2)),
    height: Math.max(GAMES_MIN_HEIGHT, window.innerHeight - (GAMES_VIEWPORT_MARGIN * 2))
  };
}
function clampGamesWindowRect(rect){
  const vw = Math.max(window.innerWidth || 0, 720);
  const vh = Math.max(window.innerHeight || 0, 480);
  const width = Math.max(GAMES_MIN_WIDTH, Math.min(Number(rect?.width) || GAMES_MIN_WIDTH, vw - (GAMES_VIEWPORT_MARGIN * 2)));
  const height = Math.max(GAMES_MIN_HEIGHT, Math.min(Number(rect?.height) || GAMES_MIN_HEIGHT, vh - (GAMES_VIEWPORT_MARGIN * 2)));
  const maxX = Math.max(GAMES_VIEWPORT_MARGIN, vw - width - GAMES_VIEWPORT_MARGIN);
  const maxY = Math.max(GAMES_VIEWPORT_MARGIN, vh - height - GAMES_VIEWPORT_MARGIN);
  return {
    x: Math.min(maxX, Math.max(GAMES_VIEWPORT_MARGIN, Number(rect?.x) || GAMES_VIEWPORT_MARGIN)),
    y: Math.min(maxY, Math.max(GAMES_VIEWPORT_MARGIN, Number(rect?.y) || GAMES_VIEWPORT_MARGIN)),
    width,
    height
  };
}
function ensureGamesWindowRect(forceReset = false){
  if (forceReset || !gamesWindowRect) gamesWindowRect = getDefaultGamesWindowRect();
  gamesWindowRect = clampGamesWindowRect(gamesWindowRect);
  return gamesWindowRect;
}
function applyGamesWindowRect(){
  const wrap = $("games-stage-wrap");
  if (!wrap) return;
  const rect = clampGamesWindowRect(gamesWindowRect || getDefaultGamesWindowRect());
  gamesWindowRect = rect;
  wrap.style.left = `${rect.x}px`;
  wrap.style.top = `${rect.y}px`;
  wrap.style.width = `${rect.width}px`;
  wrap.style.height = `${rect.height}px`;
}
function updateGamesWindowChrome(){
  const wrap = $("games-stage-wrap");
  const maxBtn = $("games-stage-maximize");
  if (wrap) wrap.classList.toggle("is-maximized", !!gamesStageMaximized);
  if (maxBtn) maxBtn.setAttribute("aria-label", gamesStageMaximized ? "Restore" : "Maximize");
}
function toggleGamesStageMaximize(){
  if (!gamesStageOpen) return;
  if (gamesStageMaximized){
    gamesStageMaximized = false;
    gamesWindowRect = clampGamesWindowRect(gamesWindowRectBeforeMaximize || getDefaultGamesWindowRect());
  } else {
    gamesWindowRectBeforeMaximize = clampGamesWindowRect(gamesWindowRect || getDefaultGamesWindowRect());
    gamesStageMaximized = true;
    gamesWindowRect = getMaximizedGamesWindowRect();
  }
  applyGamesWindowRect();
  updateGamesWindowChrome();
}
function beginGamesWindowDrag(e){
  if (!gamesStageOpen) return;
  if (e.button !== 0) return;
  if (e.target.closest(".games-stage-winbtn") || e.target.closest(".games-stage-head-actions")) return;

  if (gamesStageMaximized){
    gamesStageMaximized = false;
    gamesWindowRect = clampGamesWindowRect(gamesWindowRectBeforeMaximize || getDefaultGamesWindowRect());
    applyGamesWindowRect();
    updateGamesWindowChrome();
  }

  const rect = clampGamesWindowRect(gamesWindowRect || getDefaultGamesWindowRect());
  gamesStageSuppressOverlayCloseUntil = Date.now() + 500;
  gamesWindowDragState = {
    pointerId: e.pointerId,
    mode: "move",
    startX: e.clientX,
    startY: e.clientY,
    startRect: { ...rect }
  };
  try{ e.currentTarget.setPointerCapture(e.pointerId); }catch{}
  e.preventDefault();
}
function beginGamesWindowResize(e, dir){
  if (!gamesStageOpen) return;
  if (e.button !== 0) return;

  if (gamesStageMaximized){
    gamesStageMaximized = false;
    gamesWindowRect = clampGamesWindowRect(gamesWindowRectBeforeMaximize || getDefaultGamesWindowRect());
    applyGamesWindowRect();
    updateGamesWindowChrome();
  }

  const rect = clampGamesWindowRect(gamesWindowRect || getDefaultGamesWindowRect());
  gamesStageSuppressOverlayCloseUntil = Date.now() + 500;
  gamesWindowDragState = {
    pointerId: e.pointerId,
    mode: "resize",
    dir,
    startX: e.clientX,
    startY: e.clientY,
    startRect: { ...rect }
  };
  try{ e.currentTarget.setPointerCapture(e.pointerId); }catch{}
  e.preventDefault();
}
function handleGamesWindowPointerMove(e){
  if (!gamesWindowDragState || e.pointerId !== gamesWindowDragState.pointerId) return;

  const dx = e.clientX - gamesWindowDragState.startX;
  const dy = e.clientY - gamesWindowDragState.startY;
  const start = gamesWindowDragState.startRect;

  if (gamesWindowDragState.mode === "move"){
    gamesWindowRect = clampGamesWindowRect({
      x: start.x + dx,
      y: start.y + dy,
      width: start.width,
      height: start.height
    });
    applyGamesWindowRect();
    return;
  }

  let next = { x:start.x, y:start.y, width:start.width, height:start.height };
  const dir = gamesWindowDragState.dir || "";

  if (dir.includes("e")) next.width = start.width + dx;
  if (dir.includes("s")) next.height = start.height + dy;
  if (dir.includes("w")){
    next.width = start.width - dx;
    next.x = start.x + dx;
  }
  if (dir.includes("n")){
    next.height = start.height - dy;
    next.y = start.y + dy;
  }

  if (next.width < GAMES_MIN_WIDTH){
    if (dir.includes("w")) next.x -= (GAMES_MIN_WIDTH - next.width);
    next.width = GAMES_MIN_WIDTH;
  }
  if (next.height < GAMES_MIN_HEIGHT){
    if (dir.includes("n")) next.y -= (GAMES_MIN_HEIGHT - next.height);
    next.height = GAMES_MIN_HEIGHT;
  }

  gamesWindowRect = clampGamesWindowRect(next);
  applyGamesWindowRect();
}
function endGamesWindowPointer(e){
  if (!gamesWindowDragState) return;
  if (e && e.pointerId != null && e.pointerId !== gamesWindowDragState.pointerId) return;
  gamesWindowDragState = null;
  gamesStageSuppressOverlayCloseUntil = Date.now() + 200;
}
function bindGamesWindowInteractions(){
  const head = $("games-stage-head");
  if (head && head.dataset.bound !== "1"){
    head.dataset.bound = "1";
    head.addEventListener("pointerdown", beginGamesWindowDrag);
    head.addEventListener("dblclick", (e) => {
      if (e.target.closest(".games-stage-winbtn") || e.target.closest(".games-stage-head-actions")) return;
      toggleGamesStageMaximize();
    });
  }

  document.querySelectorAll("[data-games-resize]").forEach((handle) => {
    if (handle.dataset.bound === "1") return;
    handle.dataset.bound = "1";
    handle.addEventListener("pointerdown", (e) => beginGamesWindowResize(e, handle.dataset.gamesResize));
  });

  if (!window.__gamesStageWindowBound){
    window.__gamesStageWindowBound = true;
    window.addEventListener("pointermove", handleGamesWindowPointerMove);
    window.addEventListener("pointerup", endGamesWindowPointer);
    window.addEventListener("pointercancel", endGamesWindowPointer);
    window.addEventListener("resize", rafThrottle(() => {
      if (!gamesStageOpen) return;
      gamesWindowRect = gamesStageMaximized
        ? getMaximizedGamesWindowRect()
        : clampGamesWindowRect(gamesWindowRect || getDefaultGamesWindowRect());
      applyGamesWindowRect();
    }));
  }
}

async function openUnsavedHtmlFile(file){
  const ok = (file.type === "text/html") || /\.html?$/i.test(file.name || "");
  if (!ok){
    showToast({ title:"Invalid file", body:"Please choose an .html file.", duration:3500 });
    return;
  }
  const html = await file.text();
  await openHtmlStage({
    id: "upload",
    label: `Uploaded: ${file.name || "HTML"}`,
    activityLabel: file.name || "index.html",
    uploadFileName: file.name || "index.html",
    html,
    __upload: true,
    libraryId: null,
  });
}
function getCurrentHtmlActivityPayload(){
  if (!currentUser || !selectedGame || !gamesStageOpen) return null;

  const isLibrary = !!selectedGame.libraryId;
  const rawTitle = isLibrary
    ? String(selectedGame.label || "").trim()
    : String(selectedGame.uploadFileName || selectedGame.activityLabel || selectedGame.label || "").trim();
  const title = rawTitle || (isLibrary ? "Untitled HTML" : "index.html");

  return {
    type: isLibrary ? "library" : "upload",
    title,
    libraryId: isLibrary ? String(selectedGame.libraryId || "") : "",
    fileName: isLibrary ? "" : title,
    updatedAt: firebase.database.ServerValue.TIMESTAMP
  };
}
async function syncMyHtmlActivityPresence(){
  if (!currentUser?.code) return;

  const ref = db.ref(`users/${currentUser.code}/htmlActivity`);
  const payload = getCurrentHtmlActivityPayload();

  if (!payload){
    try{ await ref.onDisconnect().cancel(); }catch{}
    try{ await ref.remove(); }catch{}
    if (htmlActivityPresenceRef === ref) htmlActivityPresenceRef = null;

    currentUser.htmlActivity = null;
    const selfCode = String(currentUser.code || "");
    if (selfCode && liveUserCache.has(selfCode)){
      liveUserCache.set(selfCode, {
        ...(liveUserCache.get(selfCode) || {}),
        htmlActivity: null
      });
    }
    try{ renderOnlineIndicator(); }catch{}
    try{ refreshOpenUserProfileCard(); }catch{}
    return;
  }

  htmlActivityPresenceRef = ref;
  try{ await ref.onDisconnect().remove(); }catch{}
  try{ await ref.set(payload); }catch{}

  currentUser.htmlActivity = { ...payload };
  const selfCode = String(currentUser.code || "");
  if (selfCode){
    liveUserCache.set(selfCode, {
      ...(liveUserCache.get(selfCode) || {}),
      code: selfCode,
      username: currentUser.username || "User",
      usernameLower: String(currentUser.usernameLower || currentUser.username || "user").toLowerCase(),
      displayName: currentUser.displayName || currentUser.username || "User",
      displayNameLower: String(currentUser.displayNameLower || currentUser.displayName || currentUser.username || "user").toLowerCase(),
      bio: String(currentUser.bio || "").slice(0, 400),
      photoDataURL: currentUser.photoDataURL || defaultStickmanDataURL(),
      photoTransform: currentUser.photoTransform || null,
      bannerDataURL: String(currentUser.bannerDataURL || ""),
      bannerTransform: normalizeTransformToRel(currentUser.bannerTransform, 340),
      htmlActivity: { ...payload }
    });
  }

  try{ renderOnlineIndicator(); }catch{}
  try{ refreshOpenUserProfileCard(); }catch{}
}
function openTempHtmlUploadPicker(){
  const input = document.createElement("input");
  input.type = "file";
  input.accept = ".html,.htm,text/html";
  input.style.display = "none";
  document.body.appendChild(input);
  input.addEventListener("change", async () => {
    const file = input.files && input.files[0];
    if (file) await openUnsavedHtmlFile(file);
    try{ input.remove(); }catch{}
  }, { once:true });
  input.click();
}

async function openHtmlStage(game){
  closeModal();

  const nextResumeKey = getHtmlLibraryResumeKey(game);
  const currentResumeKey = getHtmlLibraryResumeKey(selectedGame);
  const isSwitchingGames = !!(gamesStageOpen && currentResumeKey && nextResumeKey && currentResumeKey !== nextResumeKey);

  if (isSwitchingGames){
    await closeGamesStage({ preserve:true });
  } else if (gamesStageOpen){
    destroyGamesFrame({ preserve:true });
  }

  clearOtherParkedGamesFrames(nextResumeKey);
  const shouldResumePaused = isHtmlLibraryPaused(game);

  selectedGame = { ...game, lastProgressSnapshot:null };
  gamesStageOpen = true;
  gamesStageLoaded = shouldResumePaused;
  void syncMyHtmlActivityPresence();
  gamesStageMaximized = false;
  gamesWindowRectBeforeMaximize = null;
  gamesWindowRect = getDefaultGamesWindowRect();

  ensureGamesStage();
  const overlay = $("games-stage-overlay");
  if (overlay) overlay.classList.add("open");

  applyGamesWindowRect();
  updateGamesWindowChrome();
  renderGamesStage();
}

async function openSavedHtmlFromLibrary(id){
  const items = await readHtmlLibrary();
  const item = items.find((x) => x.id === id);
  if (!item) return;

  await openHtmlStage({
    id: `library:${item.id}`,
    label: item.title,
    html: null,
    __upload: true,
    libraryId: item.id
  });

  void ensureHtmlLibraryGameLoaded(selectedGame);
}

let htmlLibraryMenuEl = null;
let htmlLibraryMenuCtx = null;
let htmlLibraryMenuCloseOnEnd = null;
let htmlLibraryMenuCloseSeq = 0;

function htmlLibraryInitials(title){
  const words = String(title || "HTML")
    .trim()
    .split(/\s+/)
    .filter(Boolean);
  const letters = words.length > 1
    ? words.map((word) => word[0]).join("")
    : String(words[0] || "HTML").slice(0, 2);
  return String(letters || "HT").slice(0, 2).toUpperCase();
}
function htmlLibraryCountText(count){
  const n = Number(count || 0);
  return `${n} saved HTML file${n === 1 ? "" : "s"}`;
}
function htmlLibraryListBodyHTML(items, query = ""){
  const hasQuery = !!String(query || "").trim();
  const cards = items.map((item) => {
    const paused = isHtmlLibraryPaused(item.id);
    return `
      <article class="html-library-card${paused ? " is-paused" : ""}" data-html-library-id="${escapeAttr(item.id)}" tabindex="0" aria-label="${escapeAttr(`Open ${item.title}`)}">
        <button class="html-library-card-main" type="button" data-open-html-id="${escapeAttr(item.id)}">
          <span class="html-library-card-mark" aria-hidden="true">${escapeHtml(htmlLibraryInitials(item.title))}</span>
          <span class="html-library-card-title">${escapeHtml(item.title)}</span>
          <span class="html-library-card-open">Open file</span>
          ${paused ? `<span class="html-library-paused-pill">Paused</span>` : ``}
        </button>
      </article>
    `;
  }).join("");

  return `
    <div class="html-library-shell">
      <div class="html-library-grid">
        ${cards || `<div class="html-library-empty">${hasQuery ? "No matching HTML files found." : "No saved HTML files yet. Add one to start the library."}</div>`}
      </div>
    </div>
  `;
}
function htmlLibraryAddBodyHTML(){
  return `
    <div class="html-library-shell html-library-shell-add">
      <div class="html-library-form-card">
        <label class="html-library-label" for="html-library-title-input">Title</label>
        <input class="input" id="html-library-title-input" maxlength="20" placeholder="Title" autocomplete="off" />

        <label class="html-library-label">HTML file</label>
        <div class="html-library-file-drop">
          <button class="btn" id="html-library-file-pick" type="button">Choose File</button>
          <span class="html-library-file-name" id="html-library-file-name">No file selected</span>
        </div>

        <div class="html-library-upload-status" id="html-library-upload-status" hidden>Loading...</div>
        <button class="btn primary html-library-save-wide" id="html-library-save-btn" type="button">Add HTML</button>
      </div>
    </div>
  `;
}
function ensureHtmlLibraryContextMenu(){
  if (htmlLibraryMenuEl) return htmlLibraryMenuEl;

  htmlLibraryMenuEl = document.createElement("div");
  htmlLibraryMenuEl.id = "html-library-menu";
  htmlLibraryMenuEl.className = "msg-menu html-library-menu";
  htmlLibraryMenuEl.hidden = true;
  htmlLibraryMenuEl.innerHTML = `
    <button class="msg-menu-btn" type="button" data-html-library-menu-act="rename">
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none">
          <path d="M5 19h4.3L19.1 9.2a2.1 2.1 0 0 0 0-3L17.8 4.9a2.1 2.1 0 0 0-3 0L5 14.7V19Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M13.6 6.1l4.3 4.3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M4 21h16" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>
      </span>
      <span class="msg-menu-label">Edit Title</span>
    </button>
    <button class="msg-menu-btn" type="button" data-html-library-menu-act="delete">
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none">
          <path d="M5 7h14" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M10 11v6M14 11v6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M8 7l.6 12.1A2 2 0 0 0 10.6 21h2.8a2 2 0 0 0 2-1.9L16 7" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M9.5 7l.5-3h4l.5 3" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
        </svg>
      </span>
      <span class="msg-menu-label">Delete</span>
    </button>
  `;
  document.body.appendChild(htmlLibraryMenuEl);

  htmlLibraryMenuEl.addEventListener("click", async (e) => {
    const btn = e.target.closest("button[data-html-library-menu-act]");
    if (!btn) return;
    const id = htmlLibraryMenuCtx?.id || "";
    const act = btn.getAttribute("data-html-library-menu-act");
    closeHtmlLibraryContextMenu();
    if (!id) return;
    if (act === "rename"){
      await renameHtmlLibraryById(id);
      return;
    }
    if (act === "delete"){
      await deleteHtmlLibraryById(id);
    }
  });

  document.addEventListener("pointerdown", (e) => {
    if (!htmlLibraryMenuEl || htmlLibraryMenuEl.hidden) return;
    if (htmlLibraryMenuEl.contains(e.target)) return;
    closeHtmlLibraryContextMenu();
  }, { capture:true });

  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeHtmlLibraryContextMenu(true);
  }, true);

  window.addEventListener("blur", () => closeHtmlLibraryContextMenu(true));
  window.addEventListener("resize", () => closeHtmlLibraryContextMenu(true));

  return htmlLibraryMenuEl;
}
function positionHtmlLibraryContextMenu(x, y){
  const menu = ensureHtmlLibraryContextMenu();
  if (!menu || menu.hidden) return;

  const vw = Math.max(document.documentElement.clientWidth || 0, window.innerWidth || 0);
  const vh = Math.max(document.documentElement.clientHeight || 0, window.innerHeight || 0);
  const margin = 10;
  const r = menu.getBoundingClientRect();
  let left = Number(x || 0);
  let top = Number(y || 0);

  if (left + r.width > vw - margin) left = vw - r.width - margin;
  if (top + r.height > vh - margin) top = vh - r.height - margin;
  left = Math.max(margin, left);
  top = Math.max(margin, top);

  menu.style.left = `${Math.round(left)}px`;
  menu.style.top = `${Math.round(top)}px`;
}
function openHtmlLibraryContextMenu(id, x, y){
  if (!id) return;
  const menu = ensureHtmlLibraryContextMenu();
  htmlLibraryMenuCtx = { id };

  htmlLibraryMenuCloseSeq += 1;
  if (htmlLibraryMenuCloseOnEnd){
    menu.removeEventListener("animationend", htmlLibraryMenuCloseOnEnd);
    htmlLibraryMenuCloseOnEnd = null;
  }

  menu.hidden = false;
  menu.classList.remove("closing");
  menu.classList.add("open");
  menu.style.left = "10px";
  menu.style.top = "10px";

  requestAnimationFrame(() => positionHtmlLibraryContextMenu(x, y));
}
function closeHtmlLibraryContextMenu(immediate = false){
  const menu = htmlLibraryMenuEl;
  if (!menu || menu.hidden) return;

  htmlLibraryMenuCloseSeq += 1;
  const seq = htmlLibraryMenuCloseSeq;

  if (htmlLibraryMenuCloseOnEnd){
    menu.removeEventListener("animationend", htmlLibraryMenuCloseOnEnd);
    htmlLibraryMenuCloseOnEnd = null;
  }

  if (immediate){
    menu.hidden = true;
    menu.classList.remove("open", "closing");
    htmlLibraryMenuCtx = null;
    return;
  }

  menu.classList.remove("open");
  menu.classList.add("closing");

  htmlLibraryMenuCloseOnEnd = () => {
    if (seq !== htmlLibraryMenuCloseSeq) return;
    htmlLibraryMenuCloseOnEnd = null;
    menu.hidden = true;
    menu.classList.remove("closing");
    htmlLibraryMenuCtx = null;
  };
  menu.addEventListener("animationend", htmlLibraryMenuCloseOnEnd, { once:true });
}
async function renameHtmlLibraryById(id){
  const itemsNow = await readHtmlLibrary();
  const item = itemsNow.find((x) => x.id === id);
  if (!item) return;
  await new Promise((resolve) => setTimeout(resolve, 0));
  const next = prompt("Edit Title", item.title);
  if (next == null) return;
  const cleaned = sanitizeHtmlLibraryTitle(next);
  if (!cleaned){
    showToast({ title:"Invalid title", body:"Use the same rules as usernames.", duration:3500 });
    return;
  }
  await updateHtmlLibraryTitle(id, cleaned);
  if (selectedGame?.libraryId === id){
    selectedGame.label = cleaned;
    void syncMyHtmlActivityPresence();
  }
  showToast({ title:"Title updated", body:`Renamed to ${cleaned}.`, duration:1800 });
  await openHtmlLibraryModal("list");
}
async function deleteHtmlLibraryById(id){
  const itemsNow = await readHtmlLibrary();
  const item = itemsNow.find((x) => x.id === id);
  if (!item) return;
  await new Promise((resolve) => setTimeout(resolve, 0));
  const ok = confirm(`Delete "${item.title}"?`);
  if (!ok) return;
  await deleteHtmlLibraryItem(id);
  showToast({ title:"HTML deleted", body:`${item.title} was removed from your library.`, duration:1800 });
  await openHtmlLibraryModal("list");
}
async function openHtmlLibraryModal(mode = "list"){
  if (!currentUser) return;
  const items = await readHtmlLibrary();

  openModal({
    title: "HTML Library",
    bodyHTML: mode === "add" ? htmlLibraryAddBodyHTML() : htmlLibraryListBodyHTML(items),
    size: "html-library"
  });

  requestAnimationFrame(() => {
    const titleEl = $("modal-title");
    const bodyEl = $("modal-body");

    const bindTempUploadButton = () => {
      const tempBtn = $("html-library-upload-temp-btn");
      if (!tempBtn || tempBtn.dataset.bound === "1") return;
      tempBtn.dataset.bound = "1";
      tempBtn.onclick = () => openTempHtmlUploadPicker();
    };

    if (titleEl){
      titleEl.innerHTML = mode === "add" ? `
        <div class="html-library-titlebar">
          <div class="html-library-title-stack">
            <span class="html-library-title-text">Add HTML</span>
            <span class="html-library-title-sub">Save a file to your library</span>
          </div>
          <div class="html-library-title-actions">
            <button class="html-library-title-action" id="html-library-back-btn" type="button">Library</button>
            <button class="html-library-title-action" id="html-library-upload-temp-btn" type="button">Open Unsaved HTML</button>
          </div>
        </div>
      ` : `
        <div class="html-library-titlebar">
          <div class="html-library-title-stack">
            <span class="html-library-title-text">HTML Library</span>
            <span class="html-library-title-sub">${escapeHtml(htmlLibraryCountText(items.length))}</span>
          </div>
          <div class="html-library-title-actions">
            <input
              class="html-library-search-input"
              id="html-library-search-input"
              type="search"
              placeholder="Search"
              autocomplete="off"
              spellcheck="false"
              aria-label="Search Saved HTML files"
            />
            <button class="html-library-title-action" id="html-library-add-btn" type="button">Add HTML</button>
            <button class="html-library-title-action" id="html-library-upload-temp-btn" type="button">Open Unsaved HTML</button>
          </div>
        </div>
      `;
    }

    bindTempUploadButton();
    $("html-library-back-btn")?.addEventListener("click", () => openHtmlLibraryModal("list"));
    $("html-library-add-btn")?.addEventListener("click", () => openHtmlLibraryModal("add"));

    if (mode === "add"){
      let chosenFile = null;

      const setUploadBusyState = (busy, pct = 0) => {
        const titleInput = $("html-library-title-input");
        const pickBtn = $("html-library-file-pick");
        const saveBtn = $("html-library-save-btn");
        const tempBtn = $("html-library-upload-temp-btn");
        const backBtn = $("html-library-back-btn");
        const closeBtn = $("btn-modal-close");
        const nameEl = $("html-library-file-name");
        const statusEl = $("html-library-upload-status");
        const pctText = formatUploadPercentText(pct);

        if (modalEl){
          if (busy) modalEl.dataset.busy = "1";
          else delete modalEl.dataset.busy;
        }

        if (titleInput) titleInput.disabled = busy;
        if (pickBtn) pickBtn.disabled = busy;
        if (saveBtn){
          saveBtn.disabled = busy;
          saveBtn.textContent = busy ? `Uploading ${pctText}` : "Add HTML";
        }
        if (tempBtn) tempBtn.disabled = busy;
        if (backBtn) backBtn.disabled = busy;
        if (closeBtn) closeBtn.disabled = busy;

        if (nameEl) nameEl.textContent = busy ? `${chosenFile ? chosenFile.name : "HTML"} • ${pctText}` : (chosenFile ? chosenFile.name : "No file selected");
        if (statusEl){
          statusEl.hidden = !busy;
          statusEl.textContent = `Uploading ${pctText}`;
        }
      };

      $("html-library-file-pick")?.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();

        const pickBtn = e.currentTarget;
        if (!pickBtn || pickBtn.dataset.picking === "1") return;
        pickBtn.dataset.picking = "1";

        const input = document.createElement("input");
        input.type = "file";
        input.accept = ".html,.htm,text/html";
        input.style.display = "none";
        document.body.appendChild(input);

        const cleanup = () => {
          delete pickBtn.dataset.picking;
          try{ input.remove(); }catch{}
        };

        input.addEventListener("change", (ev) => {
          chosenFile = ev.target.files && ev.target.files[0] ? ev.target.files[0] : null;
          const nameEl = $("html-library-file-name");
          if (nameEl) nameEl.textContent = chosenFile ? chosenFile.name : "No file selected";
          cleanup();
        }, { once:true });

        setTimeout(() => {
          try{ input.click(); }catch{ cleanup(); }
          setTimeout(() => {
            if (!input.isConnected) return;
            if (!input.files || !input.files.length) cleanup();
          }, 300);
        }, 0);
      });
      $("html-library-save-btn")?.addEventListener("click", async () => {
        const title = sanitizeHtmlLibraryTitle($("html-library-title-input")?.value || "");
        if (!title){
          showToast({ title:"Invalid title", body:"Use the same rules as usernames.", duration:3500 });
          return;
        }
        if (!chosenFile){
          showToast({ title:"Missing file", body:"Choose an .html file first.", duration:3500 });
          return;
        }
        const ok = (chosenFile.type === "text/html") || /\.html?$/i.test(chosenFile.name || "");
        if (!ok){
          showToast({ title:"Invalid file", body:"Please choose an .html file.", duration:3500 });
          return;
        }

        setUploadBusyState(true, 0);
        try{
          await createHtmlLibraryItem({
            title,
            file: chosenFile,
            onProgress: (pct) => setUploadBusyState(true, pct)
          });
          setUploadBusyState(false);
          showToast({ title:"HTML saved", body:`${title} was added to your HTML Library.`, duration:2200 });
          await openHtmlLibraryModal("list");
        }catch(err){
          console.error("html library upload failed:", err);
          setUploadBusyState(false);
          showToast({ title:"Upload failed", body:"Could not save this HTML file. Please try again.", duration:3500 });
        }
      });
      return;
    }

    const renderList = (query = "") => {
      if (!bodyEl) return;
      const q = String(query || "").trim().toLowerCase();
      const filtered = q
        ? items.filter((item) => String(item.titleLower || item.title || "").includes(q))
        : items;

      bodyEl.innerHTML = htmlLibraryListBodyHTML(filtered, q);
    };

    renderList();

    $("html-library-search-input")?.addEventListener("input", (e) => {
      renderList(e.target.value || "");
    });

    bodyEl?.addEventListener("click", async (e) => {
      closeHtmlLibraryContextMenu(true);
      const addBtn = e.target.closest("#html-library-add-btn");
      if (addBtn){
        openHtmlLibraryModal("add");
        return;
      }

      const openBtn = e.target.closest("[data-open-html-id]");
      if (openBtn){
        await openSavedHtmlFromLibrary(openBtn.getAttribute("data-open-html-id"));
      }
    });

    bodyEl?.addEventListener("contextmenu", (e) => {
      const card = e.target.closest(".html-library-card[data-html-library-id]");
      if (!card || !bodyEl.contains(card)) return;
      e.preventDefault();
      e.stopPropagation();
      openHtmlLibraryContextMenu(card.getAttribute("data-html-library-id"), e.clientX, e.clientY);
    });

    bodyEl?.addEventListener("keydown", (e) => {
      if (e.key !== "ContextMenu" && !(e.shiftKey && e.key === "F10")) return;
      const card = e.target.closest(".html-library-card[data-html-library-id]");
      if (!card || !bodyEl.contains(card)) return;
      e.preventDefault();
      const r = card.getBoundingClientRect();
      openHtmlLibraryContextMenu(card.getAttribute("data-html-library-id"), r.left + 18, r.top + 18);
    });
  });
}

function ensureGamesStage(){
  if ($("games-stage-overlay")) return;

  const style = document.createElement("style");
  style.textContent = `
    .games-stage-overlay{
      position:fixed;
      inset:0;
      background:transparent;
      z-index:99999;
      display:none;
      pointer-events:none;
    }
    .games-stage-overlay.open{ display:block; }
    .games-stage-wrap{
      position:fixed;
      left:${GAMES_VIEWPORT_MARGIN}px;
      top:${GAMES_VIEWPORT_MARGIN}px;
      width:960px;
      height:620px;
      display:flex;
      flex-direction:column;
      border-radius:18px;
      overflow:hidden;
      background:#05070d;
      border:1px solid rgba(255,255,255,.14);
      box-shadow:0 28px 90px rgba(0,0,0,.55);
      pointer-events:auto;
      user-select:none;
    }
    .games-stage-wrap.is-maximized{ border-radius:16px; }
    .games-stage-head{
      height:46px;
      display:flex;
      align-items:center;
      justify-content:space-between;
      gap:12px;
      padding:0 12px 0 14px;
      background:linear-gradient(180deg, rgba(28,34,48,.96), rgba(17,22,33,.96));
      border-bottom:1px solid rgba(255,255,255,.08);
      cursor:grab;
      flex:0 0 auto;
    }
    .games-stage-head:active{ cursor:grabbing; }
    .games-stage-head-left{
      display:flex;
      align-items:center;
      gap:12px;
      min-width:0;
    }
    .games-stage-traffic{
      display:flex;
      align-items:center;
      gap:8px;
      flex:0 0 auto;
    }
    .games-stage-winbtn{
      width:12px;
      height:12px;
      border-radius:999px;
      border:0;
      padding:0;
      cursor:pointer;
      box-shadow:inset 0 0 0 1px rgba(0,0,0,.22);
    }
    .games-stage-winbtn.maximize{ background:#62d26f; }
    .games-stage-winbtn.minimize{ background:#f4c84a; }
    .games-stage-winbtn.close{ background:#ff6b6b; }
    .games-stage-title{
      min-width:0;
      color:rgba(255,255,255,.92);
      font-size:13px;
      font-weight:700;
      letter-spacing:.15px;
      white-space:nowrap;
      overflow:hidden;
      text-overflow:ellipsis;
    }
    .games-stage-head-actions{
      display:flex;
      align-items:center;
      gap:8px;
      flex:0 0 auto;
    }
    .games-stage-action{
      appearance:none;
      border:1px solid rgba(255,255,255,.12);
      background:rgba(255,255,255,.05);
      color:rgba(255,255,255,.9);
      height:32px;
      padding:0 12px;
      border-radius:10px;
      cursor:pointer;
      font:inherit;
      font-size:12px;
      font-weight:700;
      letter-spacing:.15px;
    }
    .games-stage-action:hover{
      background:rgba(255,255,255,.085);
      border-color:rgba(255,255,255,.18);
    }
    .games-stage-body{
      position:relative;
      flex:1 1 auto;
      min-height:0;
      background:#000;
      overflow:hidden;
    }
    .games-stage-body.game-mode{ padding:0; }
    .games-stage-splash{
      position:absolute;
      inset:0;
      display:flex;
      align-items:center;
      justify-content:center;
      padding:24px;
      background:linear-gradient(180deg, rgba(8,11,18,.92), rgba(4,6,11,.96));
      color:rgba(255,255,255,.88);
    }
    .games-stage-splash-card{
      width:min(520px, 100%);
      border:1px solid rgba(255,255,255,.09);
      background:rgba(255,255,255,.04);
      border-radius:18px;
      padding:18px 18px 16px;
      box-shadow:0 16px 40px rgba(0,0,0,.25);
    }
    .games-stage-splash-title{
      font-size:16px;
      font-weight:800;
      margin-bottom:6px;
    }
    .games-stage-splash-copy{
      opacity:.8;
      line-height:1.45;
      font-size:13px;
    }
    .games-frame{
      width:100%;
      height:100%;
      border:0;
      background:#000;
      display:block;
    }
    .games-stage-resize{
      position:absolute;
      z-index:4;
      background:transparent;
      pointer-events:auto;
    }
    .games-stage-resize[data-games-resize="n"],
    .games-stage-resize[data-games-resize="s"]{
      left:12px;
      right:12px;
      height:10px;
    }
    .games-stage-resize[data-games-resize="n"]{ top:-5px; cursor:n-resize; }
    .games-stage-resize[data-games-resize="s"]{ bottom:-5px; cursor:s-resize; }
    .games-stage-resize[data-games-resize="e"],
    .games-stage-resize[data-games-resize="w"]{
      top:12px;
      bottom:12px;
      width:10px;
    }
    .games-stage-resize[data-games-resize="e"]{ right:-5px; cursor:e-resize; }
    .games-stage-resize[data-games-resize="w"]{ left:-5px; cursor:w-resize; }
    .games-stage-resize[data-games-resize="ne"],
    .games-stage-resize[data-games-resize="nw"],
    .games-stage-resize[data-games-resize="se"],
    .games-stage-resize[data-games-resize="sw"]{
      width:14px;
      height:14px;
    }
    .games-stage-resize[data-games-resize="ne"]{ top:-7px; right:-7px; cursor:ne-resize; }
    .games-stage-resize[data-games-resize="nw"]{ top:-7px; left:-7px; cursor:nw-resize; }
    .games-stage-resize[data-games-resize="se"]{ right:-7px; bottom:-7px; cursor:se-resize; }
    .games-stage-resize[data-games-resize="sw"]{ left:-7px; bottom:-7px; cursor:sw-resize; }
  `;
  document.head.appendChild(style);

  const overlay = document.createElement("div");
  overlay.id = "games-stage-overlay";
  overlay.className = "games-stage-overlay";
  overlay.innerHTML = `
    <div class="games-stage-wrap" id="games-stage-wrap">
      <div class="games-stage-resize" data-games-resize="n"></div>
      <div class="games-stage-resize" data-games-resize="e"></div>
      <div class="games-stage-resize" data-games-resize="s"></div>
      <div class="games-stage-resize" data-games-resize="w"></div>
      <div class="games-stage-resize" data-games-resize="ne"></div>
      <div class="games-stage-resize" data-games-resize="nw"></div>
      <div class="games-stage-resize" data-games-resize="se"></div>
      <div class="games-stage-resize" data-games-resize="sw"></div>

      <div class="games-stage-head" id="games-stage-head">
        <div class="games-stage-head-left">
          <div class="games-stage-traffic">
            <button class="games-stage-winbtn close" id="games-stage-close" type="button" aria-label="Close"></button>
            <button class="games-stage-winbtn minimize" id="games-stage-minimize" type="button" aria-label="Minimize"></button>
            <button class="games-stage-winbtn maximize" id="games-stage-maximize" type="button" aria-label="Maximize"></button>
          </div>
          <div class="games-stage-title" id="games-stage-title">HTML</div>
        </div>
        <div class="games-stage-head-actions">
          <button class="games-stage-action" id="games-stage-fullscreen" type="button" style="display:none">Fullscreen</button>
          <button class="games-stage-action" id="games-stage-open-tab" type="button">Open in New Tab</button>
          <button class="games-stage-action" id="games-stage-load" type="button">Load</button>
          <button class="games-stage-action" id="games-stage-reload" type="button" style="display:none">Reload</button>
        </div>
      </div>

      <div class="games-stage-body" id="games-stage-body"></div>
    </div>
  `;
  document.body.appendChild(overlay);

  bindGamesWindowInteractions();
  ensureGamesWindowRect(true);
  applyGamesWindowRect();
  updateGamesWindowChrome();

  $("games-stage-close").onclick = () => {
    closeGamesStage({ preserve:false });
  };
  $("games-stage-minimize").onclick = () => {
    closeGamesStage({ preserve:true });
  };
  $("games-stage-maximize").onclick = toggleGamesStageMaximize;
  $("games-stage-fullscreen").onclick = async () => {
    await requestGamesStageFullscreen();
  };

  $("games-stage-load").onclick = async () => {
    if (!selectedGame) return;
    const btn = $("games-stage-load");
    const prev = btn ? btn.textContent : "";
    if (btn){
      btn.disabled = true;
      btn.textContent = "Loading...";
    }
    try{
      const game = await ensureHtmlLibraryGameLoaded(selectedGame);
      if (!game) return;
      gamesStageLoaded = true;
      await renderGamesStage();
      syncGamesStageFullscreenButton();
    } finally {
      if (btn){
        btn.disabled = false;
        btn.textContent = prev || "Load";
      }
    }
  };
  $("games-stage-reload").onclick = async () => {
    if (!selectedGame) return;
    const btn = $("games-stage-reload");
    const prev = btn ? btn.textContent : "";
    if (btn){
      btn.disabled = true;
      btn.textContent = "Loading...";
    }

    const frame = $("games-frame");
    if (frame){
      try{
        revokeGamesFrameBlobURL(frame);
        frame.removeAttribute("srcdoc");
        frame.src = "about:blank";
        frame.contentWindow?.stop?.();
        frame.contentWindow?.location?.replace?.("about:blank");
      }catch{}
      try{ frame.remove(); }catch{}
    }

    forgetParkedGamesFrame(selectedGame);

    const body = $("games-stage-body");
    if (body){
      try{ body.innerHTML = ""; }catch{}
      body.classList.remove("game-mode");
    }

    try{
      const game = await ensureHtmlLibraryGameLoaded(selectedGame);
      if (!game) return;
      gamesStageLoaded = true;
      await renderGamesStage(true);
      syncGamesStageFullscreenButton();
    } finally {
      if (btn){
        btn.disabled = false;
        btn.textContent = prev || "Reload";
      }
    }
  };
  $("games-stage-open-tab").onclick = async () => {
    if (!selectedGame) return;
    const btn = $("games-stage-open-tab");
    const prev = btn ? btn.textContent : "";
    if (btn){
      btn.disabled = true;
      btn.textContent = "Loading...";
    }
    try{
      const game = await ensureHtmlLibraryGameLoaded(selectedGame);
      if (!game) return;
      await openGameInNewTab(game);
    } finally {
      if (btn){
        btn.disabled = false;
        btn.textContent = prev || "Open in Tab";
      }
    }
  };

  document.addEventListener("fullscreenchange", syncGamesStageFullscreenButton);

  overlay.addEventListener("click", (e) => {
    if (e.target !== overlay) return;
    if (gamesWindowDragState) return;
    if (Date.now() < gamesStageSuppressOverlayCloseUntil) return;
    closeGamesStage();
  });
}

function destroyGamesFrame({ preserve = false } = {}){
  const frame = $("games-frame");
  if (frame){
    const parked = preserve && parkCurrentGamesFrame();
    if (parked){
      return;
    }
    try{
      revokeGamesFrameBlobURL(frame);
      frame.removeAttribute("data-games-parked");
      frame.removeAttribute("data-games-parked-key");
      frame.removeAttribute("srcdoc");
      frame.src = "about:blank";
      frame.contentWindow?.stop?.();
      frame.contentWindow?.location?.replace?.("about:blank");
    }catch{}
    try{ frame.remove(); }catch{}
  }
  const body = $("games-stage-body");
  if (body){
    try{ body.innerHTML = ""; }catch{}
    body.classList.remove("game-mode");
  }
}
function syncGamesStageFullscreenButton(){
  const btn = $("games-stage-fullscreen");
  const frame = $("games-frame");
  if (!btn){
    return;
  }

  if (!gamesStageLoaded || !frame){
    btn.style.display = "none";
    btn.textContent = "Fullscreen";
    return;
  }

  btn.style.display = "";
  btn.textContent = document.fullscreenElement === frame ? "Exit Fullscreen" : "Fullscreen";
}
async function requestGamesStageFullscreen(){
  const frame = $("games-frame");
  if (!gamesStageLoaded || !frame) return;

  try{
    if (document.fullscreenElement === frame){
      await document.exitFullscreen?.();
    } else {
      await frame.requestFullscreen?.();
    }
  }catch{}

  syncGamesStageFullscreenButton();
}
async function closeGamesStage({ preserve = false } = {}){
  if (gamesStageClosingPromise) return gamesStageClosingPromise;

  gamesStageSuppressOverlayCloseUntil = Date.now() + 250;

  const overlay = $("games-stage-overlay");
  if (overlay) overlay.classList.remove("open");

  const gameToClose = selectedGame ? { ...selectedGame } : null;

  gamesStageClosingPromise = (async () => {
    if (document.fullscreenElement === $("games-frame")){
      try{ await document.exitFullscreen?.(); }catch{}
    }

    if (preserve){
      destroyGamesFrame({ preserve:true });
    } else {
      forgetParkedGamesFrame(gameToClose);
      destroyGamesFrame();
    }

    gamesStageOpen = false;
    gamesStageLoaded = false;
    gamesStageMaximized = false;
    gamesWindowRect = null;
    gamesWindowRectBeforeMaximize = null;
    selectedGame = null;

    await syncMyHtmlActivityPresence();
    syncGamesStageFullscreenButton();
    syncGamesSidebarButton();
  })();

  try{
    await gamesStageClosingPromise;
  }finally{
    gamesStageClosingPromise = null;
  }
}

async function renderGamesStage(forceReloadFrame = false){
  if (!gamesStageOpen) return;

  const body = $("games-stage-body");
  if (!body) return;

  const btnFullscreen = $("games-stage-fullscreen");
  const btnOpen = $("games-stage-open-tab");
  const btnLoad = $("games-stage-load");
  const btnReload = $("games-stage-reload");
  const title = $("games-stage-title");

  if (!selectedGame){
    closeGamesStage();
    return;
  }

  if (title) title.textContent = selectedGame.label || "HTML";
  if (btnFullscreen) btnFullscreen.style.display = gamesStageLoaded ? "" : "none";
  if (btnOpen) btnOpen.style.display = "";
  if (btnLoad) btnLoad.style.display = gamesStageLoaded ? "none" : "";
  if (btnReload) btnReload.style.display = gamesStageLoaded ? "" : "none";

  ensureGamesWindowRect();
  applyGamesWindowRect();
  updateGamesWindowChrome();

  if (!gamesStageLoaded){
    destroyGamesFrame();
    body.classList.remove("game-mode");
    body.innerHTML = `
      <div class="games-stage-splash">
        <div class="games-stage-splash-card">
          <div class="games-stage-splash-title">${escapeHtml(selectedGame.label || "HTML")}</div>
          <div class="games-stage-splash-copy">Click <b>Load</b> to run this HTML here.</div>        </div>
    `;
    return;
  }

  body.classList.add("game-mode");

  let frame = null;
  if (!forceReloadFrame){
    frame = takeParkedGamesFrame(selectedGame) || $("games-frame");
  }

  if (!frame || forceReloadFrame){
    forgetParkedGamesFrame(selectedGame);
    body.innerHTML = `<iframe class="games-frame" id="games-frame" src="about:blank" sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-pointer-lock allow-popups" allow="fullscreen" allowfullscreen></iframe>`;    frame = $("games-frame");

    await writeHtmlIntoIframeSameOrigin(frame, selectedGame.html);
  }
}

async function openGameInNewTab(game){
  const w = window.open("about:blank", "_blank");
  if (!w) return;

  const loadedGame = await ensureHtmlLibraryGameLoaded(game);
  if (!loadedGame){
    try{ w.close(); }catch{}
    return;
  }

  const html = patchUploadedHtmlToSameOrigin(loadedGame.html || "");
  w.document.open();
  w.document.write(html);
  w.document.close();
}

function escapeAttr(s){
  return String(s)
    .replace(/&/g,"&amp;")
    .replace(/"/g,"&quot;")
    .replace(/</g,"&lt;")
    .replace(/>/g,"&gt;");
}

function serializeStorage(store){
  const out = {};
  try{
    for (let i = 0; i < store.length; i++){
      const k = store.key(i);
      if (k != null) out[k] = store.getItem(k);
    }
  }catch{}
  return out;
}

function injectIntoHead(html, snippet){
  if (/<head[^>]*>/i.test(html)) return html.replace(/<head[^>]*>/i, (m) => m + snippet);
  if (/<html[^>]*>/i.test(html)) return html.replace(/<html[^>]*>/i, (m) => m + "<head>" + snippet + "</head>");
  return "<head>" + snippet + "</head>" + html;
}

function getGamesStageLifecycleScript(){
  return `<script>
(() => {
  if (window.__gamesStageLifecycle) return;

  const nativeRAF = typeof window.requestAnimationFrame === "function"
    ? window.requestAnimationFrame.bind(window)
    : null;
  const nativeCAF = typeof window.cancelAnimationFrame === "function"
    ? window.cancelAnimationFrame.bind(window)
    : null;

  let paused = false;
  let nextRafId = 1;
  const rafCallbacks = new Map();
  const rafNativeIds = new Map();
  const audioContexts = new Set();

  function scheduleRaf(id){
    if (!nativeRAF || !rafCallbacks.has(id)) return;
    const cb = rafCallbacks.get(id);
    const nativeId = nativeRAF((ts) => {
      if (!rafCallbacks.has(id)) return;
      if (paused){
        rafNativeIds.set(id, 0);
        return;
      }
      rafNativeIds.delete(id);
      rafCallbacks.delete(id);
      try{ cb(ts); }catch(err){ setTimeout(() => { throw err; }, 0); }
    });
    rafNativeIds.set(id, nativeId);
  }

  if (nativeRAF && nativeCAF){
    window.requestAnimationFrame = function(cb){
      const id = nextRafId++;
      rafCallbacks.set(id, cb);
      scheduleRaf(id);
      return id;
    };
    window.cancelAnimationFrame = function(id){
      const nativeId = rafNativeIds.get(id);
      if (nativeId) nativeCAF(nativeId);
      rafNativeIds.delete(id);
      rafCallbacks.delete(id);
    };
  }

  function trackAudioContext(ctx){
    if (ctx && typeof ctx === "object") audioContexts.add(ctx);
    return ctx;
  }

  function wrapAudioContext(name){
    const NativeCtor = window[name];
    if (typeof NativeCtor !== "function") return;

    function WrappedAudioContext(...args){
      return trackAudioContext(Reflect.construct(NativeCtor, args, WrappedAudioContext));
    }

    WrappedAudioContext.prototype = NativeCtor.prototype;
    Object.setPrototypeOf(WrappedAudioContext, NativeCtor);
    window[name] = WrappedAudioContext;
  }

  wrapAudioContext("AudioContext");
  wrapAudioContext("webkitAudioContext");

  window.__gamesStageLifecycle = {
    pause(){
      paused = true;
      try{ document.documentElement.dataset.gamesStagePaused = "1"; }catch{}
      audioContexts.forEach((ctx) => {
        try{
          const shouldResume = ctx.state === "running";
          ctx.__gamesStageResumeOnRestore = shouldResume ? "1" : "";
          if (shouldResume) ctx.suspend?.();
        }catch{}
      });
    },
    resume(){
      paused = false;
      try{ delete document.documentElement.dataset.gamesStagePaused; }catch{}
      rafCallbacks.forEach((_, id) => {
        if (!rafNativeIds.get(id)) scheduleRaf(id);
      });
      audioContexts.forEach((ctx) => {
        try{
          if (ctx.__gamesStageResumeOnRestore === "1"){
            ctx.__gamesStageResumeOnRestore = "";
            if (ctx.state !== "closed") ctx.resume?.();
          }
        }catch{}
      });
    },
    clear(){
      paused = false;
      try{ delete document.documentElement.dataset.gamesStagePaused; }catch{}
      if (nativeCAF){
        rafNativeIds.forEach((nativeId) => {
          if (nativeId) nativeCAF(nativeId);
        });
      }
      rafNativeIds.clear();
      rafCallbacks.clear();
      audioContexts.forEach((ctx) => {
        try{ ctx.__gamesStageResumeOnRestore = ""; }catch{}
      });
    }
  };
})();
</script>`;
}

function patchUploadedHtmlToSameOrigin(html){
  const baseHref = location.href.split("#")[0];
  let out = String(html || "");
  const baseTag = /<base\b/i.test(out) ? "" : `<base href="${escapeAttr(baseHref)}">`;

  out = out.replace(
    /(<script\b[^>]*\bsrc\s*=\s*["'])([^"']*build\/three(?:\.min)?\.js)(["'][^>]*>\s*<\/script>)/gi,
    `$1https://unpkg.com/three@0.149.0/build/three.min.js$3`
  );

  // Fast path: for large HTML, avoid heavy regex work that can stall/crash the UI.
  if (out.length > 300000){
    return injectIntoHead(out, baseTag + getGamesStageLifecycleScript());
  }

  out = out.replace(
    /<head\b[^>]*>([\s\S]*?)<\/head>/i,
    (full, headContent) => {
      let nextHead = String(headContent || "");

      // Defer external scripts (cheap regex, avoids catastrophic backtracking).
      nextHead = nextHead.replace(
        /<script\b([^>]*?)\bsrc=(["'][^"']+["'])([^>]*)>\s*<\/script>/gi,
        (m, beforeSrc, srcValue, afterSrc) => {
          const attrs = `${beforeSrc}src=${srcValue}${afterSrc}`;
          if (/\bdefer\b/i.test(attrs)) return m;
          if (/\basync\b/i.test(attrs)) return m;
          if (/\btype\s*=\s*["']module["']/i.test(attrs)) return m;
          return `<script${beforeSrc}src=${srcValue}${afterSrc} defer></script>`;
        }
      );

      // Wrap inline scripts to run after DOMContentLoaded (skip module/ld+json).
      nextHead = nextHead.replace(
        /<script\b([^>]*)>([\s\S]*?)<\/script>/gi,
        (m, attrs, code) => {
          const a = String(attrs || "");
          if (/\bsrc\s*=/i.test(a)) return m;
          if (/\btype\s*=\s*["'](?:module|application\/ld\+json)["']/i.test(a)) return m;
          const c = String(code || "");
          if (!c.trim()) return m;
          return `<script${a}>
document.addEventListener("DOMContentLoaded", () => {
${c}
}, { once:true });
</script>`;
        }
      );

      return full.replace(headContent, nextHead);
    }
  );

  out = injectIntoHead(out, baseTag + getGamesStageLifecycleScript());
  return out;
}

function revokeGamesFrameBlobURL(frame){
  if (!frame) return;
  const url = frame.getAttribute("data-games-blob-url");
  if (url && url.startsWith("blob:")){
    try{ URL.revokeObjectURL(url); }catch{}
  }
  frame.removeAttribute("data-games-blob-url");
}

async function writeHtmlIntoIframeSameOrigin(iframe, html){
  if (!iframe) return;

  revokeGamesFrameBlobURL(iframe);

  const patched = patchUploadedHtmlToSameOrigin(html || "");

  // Let the UI paint "Loading..." before we hand a big document to the iframe.
  await new Promise((resolve) => setTimeout(resolve, 0));

  const useSrcdocDirectly = location.protocol === "file:" || location.origin === "null";

  if (useSrcdocDirectly){
    try{
      iframe.removeAttribute("srcdoc");
      iframe.srcdoc = patched;
      return;
    }catch{}
  }

  try{
    const blob = new Blob([patched], { type:"text/html;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    iframe.setAttribute("data-games-blob-url", url);
    try{ iframe.removeAttribute("srcdoc"); }catch{}
    iframe.src = url;
  }catch{
    try{
      iframe.removeAttribute("srcdoc");
      iframe.srcdoc = patched;
    }catch{
      try{
        const doc = iframe.contentDocument || iframe.contentWindow.document;
        doc.open();
        doc.write(patched);
        doc.close();
      }catch{}
    }
  }
}

