/* -------------------- Stickman default (SVG data URL) -------------------- */
function defaultStickmanDataURL(){
  const svg = `
  <svg xmlns="http://www.w3.org/2000/svg" width="256" height="256" viewBox="0 0 256 256">
    <defs>
      <radialGradient id="g" cx="35%" cy="30%" r="75%">
        <stop offset="0%" stop-color="#ffffff" stop-opacity=".22"/>
        <stop offset="55%" stop-color="#6ea8ff" stop-opacity=".18"/>
        <stop offset="100%" stop-color="#000000" stop-opacity="0"/>
      </radialGradient>
    </defs>
    <rect width="256" height="256" rx="128" fill="#0f1218"/>
    <circle cx="128" cy="128" r="120" fill="url(#g)"/>
    <circle cx="128" cy="88" r="28" fill="none" stroke="#e9eefc" stroke-opacity=".92" stroke-width="10"/>
    <path d="M128 118 L128 180" stroke="#e9eefc" stroke-opacity=".92" stroke-width="10" stroke-linecap="round"/>
    <path d="M88 142 L168 142" stroke="#e9eefc" stroke-opacity=".92" stroke-width="10" stroke-linecap="round"/>
    <path d="M104 210 L128 180 L152 210" fill="none" stroke="#e9eefc" stroke-opacity=".92" stroke-width="10" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
  return "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg.trim());
}

/* -------------------- Rules -------------------- */
function sanitizeUsername(raw){
  let s = (raw ?? "").replace(/\s+/g, " ").trim(); // collapses whitespace runs
  for (const ch of s){
    const code = ch.codePointAt(0);
    if (code < 32 || code > 126) return null; // ASCII printable only
  }
  if (!s) return null;
  if (s.length > 20) return null;
  return s;
}

function getUserDisplayName(user){
  return String(user?.displayName || user?.username || "User");
}

/* Room names are display-preserved, but room keys are case-insensitive. */
function sanitizeRoomName(raw){
  let s = String(raw ?? "").replace(/\s+/g, " ").trim();
  for (const ch of s){
    const code = ch.codePointAt(0);
    if (code < 32 || code > 126) return null;
  }
  if (!s || s.length > 20) return null;
  if (/[.#$\[\]\/]/.test(s)) return null;
  return s;
}
function sanitizeRoomCode(raw){
  const name = sanitizeRoomName(raw);
  return name ? name.toLowerCase() : null;
}
function roomDisplayName(roomId, meta = null){
  const metaName = sanitizeRoomName(meta?.name);
  if (metaName) return metaName;
  const rawId = String(roomId ?? "").trim();
  const idName = sanitizeRoomName(rawId);
  if (idName) return idName;
  return rawId || "Room";
}
function sanitizeRoomPassword(raw){
  let s = String(raw ?? "").replace(/\s+/g, " ").trim();
  for (const ch of s){
    const code = ch.codePointAt(0);
    if (code < 32 || code > 126) return null;
  }
  return s || null;
}
function legacyRoomPasswordHashInput(password, roomId){
  const clean = sanitizeRoomPassword(password);
  if (!clean) return null;
  return `chatapp-room-password-v1:${sanitizeRoomCode(roomId) || ""}:${clean}`;
}
function legacyRoomPasswordHashFallback(input){
  let h = 2166136261;
  const s = String(input || "");
  for (let i = 0; i < s.length; i += 1){
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619) >>> 0;
  }
  return h.toString(16).padStart(8, "0");
}
function legacyFallbackRoomPasswordHash(password, roomId){
  const input = legacyRoomPasswordHashInput(password, roomId);
  return input ? `fallback:${legacyRoomPasswordHashFallback(input)}` : null;
}
async function computeLegacyRoomPasswordHash(password, roomId){
  const input = legacyRoomPasswordHashInput(password, roomId);
  if (!input) return null;
  try{
    if (globalThis.crypto?.subtle && globalThis.TextEncoder){
      const bytes = new TextEncoder().encode(input);
      const digest = await crypto.subtle.digest("SHA-256", bytes);
      return Array.from(new Uint8Array(digest)).map((b) => b.toString(16).padStart(2, "0")).join("");
    }
  }catch{}
  return legacyFallbackRoomPasswordHash(password, roomId);
}
function isPrivateRoomMeta(meta){
  return !!(meta && (meta.private === true || String(meta.password || "").trim() || String(meta.passwordHash || "").trim()));
}
async function verifyLegacyRoomPasswordHash(meta, password, roomId){
  const expectedHash = String(meta?.passwordHash || "").trim();
  if (!expectedHash) return false;
  if (expectedHash.startsWith("fallback:")){
    return expectedHash === legacyFallbackRoomPasswordHash(password, roomId);
  }
  const hash = await computeLegacyRoomPasswordHash(password, roomId);
  return !!hash && hash === expectedHash;
}
async function migrateLegacyRoomPassword(roomId, meta, password){
  const id = sanitizeRoomCode(roomId);
  const clean = sanitizeRoomPassword(password);
  if (!id || !clean || !String(meta?.passwordHash || "").trim()) return;
  const nextMeta = { ...(roomsMetaCache.get(id) || meta || {}), private:true, password:clean, passwordHash:null };
  try{
    await db.ref(`rooms/${id}`).update({ private:true, password:clean, passwordHash:null });
    roomsMetaCache.set(id, nextMeta);
    scheduleRoomsListCacheSave();
    refreshRoomIconSurfaces(id);
  }catch{}
}
async function verifyRoomPassword(meta, password, roomId){
  if (!isPrivateRoomMeta(meta)) return true;
  const clean = sanitizeRoomPassword(password);
  if (!clean) return false;

  const expectedPassword = String(meta?.password || "").trim();
  if (expectedPassword) return expectedPassword === clean;

  const legacyOk = await verifyLegacyRoomPasswordHash(meta, clean, roomId);
  if (legacyOk) await migrateLegacyRoomPassword(roomId, meta, clean);
  return legacyOk;
}
function roomLockIconSVG(){
  return `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M7.5 10V8a4.5 4.5 0 0 1 9 0v2" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
      <rect x="5.5" y="10" width="13" height="10" rx="2.4" stroke="currentColor" stroke-width="2"/>
      <path d="M12 14v2.4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
    </svg>
  `;
}
function privateRoomMarkHTML(meta){
  return isPrivateRoomMeta(meta) ? `<span class="room-lock-mark" aria-label="Private Room" title="Private">${roomLockIconSVG()}</span>` : "";
}

function fnv1aHex(str){
  let h = 0x811c9dc5;
  for (let i=0;i<str.length;i++){
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, "0");
}
async function sha256Hex(text){
  try{
    if (!crypto?.subtle) return fnv1aHex(text);
    const enc = new TextEncoder().encode(text);
    const buf = await crypto.subtle.digest("SHA-256", enc);
    const arr = Array.from(new Uint8Array(buf));
    return arr.map(b => b.toString(16).padStart(2,"0")).join("");
  }catch{
    return fnv1aHex(text);
  }
}

const DISPLAY_NAME_INDEX_NODE = "displayNames";

async function claimDisplayName(displayName, code){
  const cleaned = sanitizeUsername(displayName);
  const ownerCode = String(code || "").trim();
  if (!cleaned || !ownerCode) return { ok:false, reason:"invalid" };

  const displayNameLower = cleaned.toLowerCase();
  const hash = await sha256Hex(displayNameLower);
  const ref = db.ref(`${DISPLAY_NAME_INDEX_NODE}/${hash}`);

  try{
    const snap = await ref.once("value");
    const current = snap.val();

    if (current){
      const currentCode = (typeof current === "string")
        ? current
        : String(current?.code || current?.c || "").trim();

      if (currentCode && currentCode !== ownerCode){
        let stillTaken = false;
        try{
          const ownerSnap = await db.ref(`users/${currentCode}`).once("value");
          const owner = ownerSnap.val() || {};
          const ownerDisplayLower = String(owner.displayNameLower || owner.displayName || "").toLowerCase();
          stillTaken = ownerSnap.exists() && ownerDisplayLower === displayNameLower;
        }catch{
          stillTaken = true;
        }

        if (stillTaken) return { ok:false, reason:"taken" };
        try{ await ref.remove(); }catch{}
      } else if (!currentCode){
        try{ await ref.remove(); }catch{}
      }
    }

    await ref.set({ d: displayNameLower, code: ownerCode });
  }catch{
    return { ok:true, cleaned, displayNameLower, hash, ref:null };
  }

  return { ok:true, cleaned, displayNameLower, hash, ref };
}

async function releaseDisplayName(displayName, code){
  const cleaned = sanitizeUsername(displayName);
  const ownerCode = String(code || "").trim();
  if (!cleaned || !ownerCode) return;

  const displayNameLower = cleaned.toLowerCase();
  const hash = await sha256Hex(displayNameLower);
  const ref = db.ref(`${DISPLAY_NAME_INDEX_NODE}/${hash}`);

  try{
    const snap = await ref.once("value");
    const current = snap.val();
    const currentCode = (typeof current === "string")
      ? current
      : String(current?.code || current?.c || "").trim();
    const currentName = (typeof current === "object" && current)
      ? String(current.d || current.displayNameLower || "").toLowerCase()
      : displayNameLower;
    if (currentCode === ownerCode && (!currentName || currentName === displayNameLower)){
      await ref.remove();
    }
  }catch{}
}

function buildDisplayNameFallback(base, ownerCode, n = 0){
  const suffix = n <= 0 ? "" : String(ownerCode || "").slice(-Math.min(4, n + 1));
  const joiner = suffix ? "-" : "";
  const maxBaseLen = Math.max(1, 20 - joiner.length - suffix.length);
  const root = String(base || "User").slice(0, maxBaseLen) || "User";
  return `${root}${joiner}${suffix}`;
}

async function ensureOwnedDisplayNameForUser(code, rec){
  const ownerCode = String(code || "").trim();
  if (!ownerCode) return { displayName:"User", displayNameLower:"user" };

  const username = sanitizeUsername(rec?.username || "") || "User";
  const currentDisplay = sanitizeUsername(rec?.displayName || "") || username;
  const currentDisplayLower = String(rec?.displayNameLower || currentDisplay).toLowerCase();

  const candidates = [];
  const seen = new Set();
  const addCandidate = (value) => {
    const cleaned = sanitizeUsername(value);
    if (!cleaned) return;
    const lower = cleaned.toLowerCase();
    if (seen.has(lower)) return;
    seen.add(lower);
    candidates.push(cleaned);
  };

  addCandidate(currentDisplay);
  addCandidate(username);
  for (let i = 1; i <= 4; i += 1){
    addCandidate(buildDisplayNameFallback(username, ownerCode, i));
  }

  let claim = null;
  for (const candidate of candidates){
    claim = await claimDisplayName(candidate, ownerCode);
    if (claim?.ok) break;
  }

  if (!claim?.ok){
    const forced = buildDisplayNameFallback("User", ownerCode, 4);
    claim = await claimDisplayName(forced, ownerCode);
  }

  if (!claim?.ok){
    throw new Error("Could not secure a unique display name.");
  }

  const nextDisplayName = claim.cleaned;
  const nextDisplayNameLower = claim.displayNameLower;

  if (currentDisplayLower !== nextDisplayNameLower){
    void releaseDisplayName(currentDisplay, ownerCode);
  }

  if (rec?.displayName !== nextDisplayName || String(rec?.displayNameLower || "").toLowerCase() !== nextDisplayNameLower){
    await db.ref(`users/${ownerCode}`).update({
      displayName: nextDisplayName,
      displayNameLower: nextDisplayNameLower
    });
  }

  return {
    displayName: nextDisplayName,
    displayNameLower: nextDisplayNameLower
  };
}

/* -------------------- Account code helpers -------------------- */
function randomCode16(){
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let out = "";
  const bytes = new Uint8Array(16);
  crypto.getRandomValues(bytes);
  for (let i=0;i<16;i++) out += chars[bytes[i] % chars.length];
  return out;
}
function formatCode(code16){
  const s = code16.replace(/[^A-Za-z0-9]/g, "").toUpperCase().slice(0,16);
  return s.match(/.{1,4}/g)?.join("-") ?? s;
}
function normalizeCodeInput(s){
  let out = String(s ?? "").trim();

  // Spaces become dashes
  out = out.replace(/\s+/g, "-");

  // Keep only safe characters for Firebase keys + DOM selectors
  out = out.replace(/[^A-Za-z0-9_-]+/g, "-").toUpperCase();

  // Collapse / trim dashes
  out = out.replace(/-+/g, "-").replace(/^-+|-+$/g, "");

  if (!out) return null;
  if (out.length > 20) return null;

  // Legacy convenience: if user typed a 16-char code without dashes, auto-format it
  const raw16 = out.replace(/[^A-Z0-9]/g, "");
  if (raw16.length === 16 && !out.includes("-") && !out.includes("_")){
    return raw16.match(/.{1,4}/g)?.join("-") ?? raw16;
  }

  return out;
}

/* -------------------- Profile picture (create account) -------------------- */
const pfpImg = $("pfp-img");
const pfpClip = $("pfp-clip");
const pfpInput = $("create-pfp");
const cropControls = $("crop-controls");
const zoomSlider = $("zoom");

const pfpState = {
  usingDefault: true,
  dataURL: defaultStickmanDataURL(),
  scale: 1.0,
  x: 0,
  y: 0,
  dragging: false,
  dragStartX: 0,
  dragStartY: 0,
  startX: 0,
  startY: 0
};

function clipSizePx(){
  const r = pfpClip.getBoundingClientRect();
  return Math.max(1, Math.round(r.width || 84));
}

/* Store offsets as RELATIVE so avatars look the same at all sizes. */
function packTransformForStorage(){
  const size = clipSizePx();
  return { unit: "rel", scale: pfpState.scale, x: (pfpState.x || 0) / size, y: (pfpState.y || 0) / size };
}
function normalizeTransformToRel(t, legacySizePx = 84){
  if (!t) return { unit:"rel", scale: 1, x: 0, y: 0 };
  if (t.unit === "rel") return { unit:"rel", scale: Number(t.scale) || 1, x: Number(t.x) || 0, y: Number(t.y) || 0 };
  // Legacy: pixel offsets were saved from the editor surface that created them.
  const assumed = Math.max(1, Number(legacySizePx) || 84);
  return { unit:"rel", scale: Number(t.scale) || 1, x: (Number(t.x) || 0) / assumed, y: (Number(t.y) || 0) / assumed };
}
function transformToPixels(t, sizePx, legacySizePx = 84){
  const size = Math.max(1, Number(sizePx) || 1);
  const tr = normalizeTransformToRel(t, legacySizePx);
  return { scale: tr.scale, x: tr.x * size, y: tr.y * size, unit: "px" };
}

function applyPfpTransformPreview(){
  pfpImg.style.transform = `translate(calc(-50% + ${pfpState.x}px), calc(-50% + ${pfpState.y}px)) scale(${pfpState.scale})`;
}

function setDefaultPfp(){
  pfpState.usingDefault = true;
  pfpState.dataURL = defaultStickmanDataURL();
  pfpState.scale = 1.0;
  pfpState.x = 0;
  pfpState.y = 0;
  zoomSlider.value = String(pfpState.scale);
  cropControls.hidden = false;
  pfpImg.src = pfpState.dataURL;
  applyPfpTransformPreview();
}
function setUploadedPfp(dataURL){
  pfpState.usingDefault = false;
  pfpState.dataURL = dataURL;
  pfpState.scale = 1.0;
  pfpState.x = 0;
  pfpState.y = 0;
  zoomSlider.value = String(pfpState.scale);
  cropControls.hidden = false;
  pfpImg.src = pfpState.dataURL;
  applyPfpTransformPreview();
}

function fileTypeOk(file){
  const t = (file.type || "").toLowerCase();
  return t === "image/png" || t === "image/jpeg" || t === "image/jpg" || t === "image/gif";
}

function chatFileKind(file){
  const t = (file.type || "").toLowerCase();
  const n = (file.name || "").toLowerCase();
  if (t === "image/png" || t === "image/jpeg" || t === "image/jpg" || t === "image/gif") return "image";
  if (t === "video/mp4" || t === "video/webm" || t === "video/ogg" || t === "video/quicktime" || n.endsWith(".mov")) return "video";
  if (t.startsWith("audio/") || n.endsWith(".mp3") || n.endsWith(".wav") || n.endsWith(".ogg") || n.endsWith(".m4a") || n.endsWith(".aac") || n.endsWith(".flac")) return "audio";
  if (t === "text/html" || t === "application/xhtml+xml" || n.endsWith(".html") || n.endsWith(".htm")) return "html";

  // Any other/unknown/custom type -> download-only
  return "code";
}

function getMediaMimeType(item){
  const raw = String(item?.mimeType || item?.type || item?.sub || "").trim().toLowerCase();
  if (raw) return raw;

  const name = String(item?.fileName || item?.name || "").trim().toLowerCase();
  if (name.endsWith(".mov") || name.endsWith(".qt")) return "video/quicktime";
  if (name.endsWith(".mp4")) return "video/mp4";
  if (name.endsWith(".webm")) return "video/webm";
  if (name.endsWith(".ogv") || name.endsWith(".ogg")) return "video/ogg";
  if (name.endsWith(".mp3")) return "audio/mpeg";
  if (name.endsWith(".wav")) return "audio/wav";
  if (name.endsWith(".m4a")) return "audio/mp4";
  if (name.endsWith(".aac")) return "audio/aac";
  if (name.endsWith(".flac")) return "audio/flac";
  return "";
}

function canInlineVideoMedia(item){
  const mimeType = getMediaMimeType(item);
  const fileName = String(item?.fileName || item?.name || "").trim().toLowerCase();
  const looksQuickTime = mimeType === "video/quicktime" || fileName.endsWith(".mov") || fileName.endsWith(".qt");

  if (!mimeType) return !looksQuickTime;

  try{
    const probe = document.createElement("video");
    const support = String(probe.canPlayType(mimeType) || "").toLowerCase();
    if (support === "probably" || support === "maybe") return true;
  }catch{}

  return !looksQuickTime;
}

const INLINE_VIDEO_LIGHTBOX_THRESHOLD_BYTES = 80 * 1024 * 1024;

function shouldDeferInlineVideoPreview(item){
  return Number(item?.size || 0) >= INLINE_VIDEO_LIGHTBOX_THRESHOLD_BYTES;
}

function videoSourceMarkup(src, mimeType = ""){
  const safeSrc = escapeHtml(String(src || ""));
  const safeType = escapeHtml(String(mimeType || "").trim());
  return safeType
    ? `<source src="${safeSrc}" type="${safeType}" />`
    : `<source src="${safeSrc}" />`;
}

pfpClip.addEventListener("pointerdown", (e) => {
  pfpState.dragging = true;
  pfpState.dragStartX = e.clientX;
  pfpState.dragStartY = e.clientY;
  pfpState.startX = pfpState.x;
  pfpState.startY = pfpState.y;
  pfpClip.setPointerCapture(e.pointerId);
});
pfpClip.addEventListener("pointermove", (e) => {
  if (!pfpState.dragging) return;
  const dx = e.clientX - pfpState.dragStartX;
  const dy = e.clientY - pfpState.dragStartY;
  pfpState.x = pfpState.startX + dx;
  pfpState.y = pfpState.startY + dy;
  applyPfpTransformPreview();
});
pfpClip.addEventListener("pointerup", () => { pfpState.dragging = false; });

zoomSlider.addEventListener("input", () => {
  pfpState.scale = Number(zoomSlider.value);
  applyPfpTransformPreview();
});

$("btn-create-choose-pfp").addEventListener("click", () => { try{ pfpInput.click(); }catch{} });
$("btn-create-use-default").addEventListener("click", () => { try{ pfpInput.value = ""; }catch{} setDefaultPfp(); });
$("btn-center").addEventListener("click", () => { pfpState.x = 0; pfpState.y = 0; applyPfpTransformPreview(); });
$("btn-reset").addEventListener("click", () => {
  pfpState.scale = 1.0;
  pfpState.x = 0;
  pfpState.y = 0;
  zoomSlider.value = String(pfpState.scale);
  applyPfpTransformPreview();
});

pfpInput.addEventListener("change", async () => {
  hideError("create");
  const file = pfpInput.files?.[0];
  if (!file){ setDefaultPfp(); return; }
  if (!fileTypeOk(file)){
    setError("create", "Profile picture must be PNG, JPG/JPEG, or GIF.");
    pfpInput.value = "";
    setDefaultPfp();
    return;
  }
  const reader = new FileReader();
  reader.onload = () => setUploadedPfp(String(reader.result));
  reader.onerror = () => {
    setError("create", "Could not read that file.");
    pfpInput.value = "";
    setDefaultPfp();
    return;
  };
  reader.readAsDataURL(file);
});

/* -------------------- Toast (animated timer + optional actions) -------------------- */
let toastTimer = null;
let toastHideTimer = null;
let toastOnClose = null;
let toastCloseSeq = 0;

function showToast(opts = {}){
  if (typeof opts === "string") opts = { body: opts };
  else if (!opts || typeof opts !== "object") opts = {};

  const {
    title="Notice",
    body="",
    bodyHTML=null,
    code=null,
    showCopy=false,
    duration=10000,
    onClose=null
  } = opts;

  const toastEl = $("toast");
  const titleEl = $("toast-title");
  const bodyEl = $("toast-body");
  const codeEl = $("toast-code");
  const copyBtn = $("btn-copy-code");
  const bar = $("toast-timer-bar");

  clearTimeout(toastTimer);
  clearTimeout(toastHideTimer);

  // If a toast is already showing, treat this as replacement and run prior onClose.
  if (toastEl && !toastEl.hidden && typeof toastOnClose === "function"){
    try{ toastOnClose("replaced"); }catch{}
    toastOnClose = null;
  }

  toastCloseSeq += 1;
  toastOnClose = (typeof onClose === "function") ? onClose : null;

  if (titleEl) titleEl.textContent = title;

  if (bodyEl){
    if (bodyHTML != null) bodyEl.innerHTML = bodyHTML;
    else bodyEl.textContent = body;
  }

  if (codeEl){
    if (code){
      codeEl.hidden = false;
      codeEl.textContent = code;
    } else {
      codeEl.hidden = true;
      codeEl.textContent = "";
    }
  }

  if (copyBtn) copyBtn.hidden = !showCopy;

  if (toastEl){
    toastEl.hidden = false;
    toastEl.classList.remove("is-leaving");
    void toastEl.offsetHeight;
    toastEl.classList.add("is-showing");
  }

  if (bar){
    bar.style.animation = "none";
    void bar.offsetHeight;
    bar.style.animation = `toastbar ${duration}ms linear forwards`;
  }

  toastTimer = setTimeout(() => closeToast("timeout"), Math.max(0, Number(duration) || 0));
}

function closeToast(reason="manual"){
  clearTimeout(toastTimer);
  clearTimeout(toastHideTimer);

  const toastEl = $("toast");
  activePingToastRoomId = null;

  const cb = toastOnClose;
  toastOnClose = null;
  if (typeof cb === "function"){
    try{ cb(reason); }catch{}
  }

  if (!toastEl || toastEl.hidden) return;

  const closeSeq = ++toastCloseSeq;
  toastEl.classList.remove("is-showing");
  toastEl.classList.add("is-leaving");

  toastHideTimer = setTimeout(() => {
    if (closeSeq !== toastCloseSeq) return;
    toastEl.hidden = true;
    toastEl.classList.remove("is-leaving");
  }, 180);
}

$("btn-toast-close").addEventListener("click", () => closeToast("manual"));

$("btn-copy-code").addEventListener("click", async () => {
  const code = $("toast-code").textContent || "";
  try{ await navigator.clipboard.writeText(code); }
  catch{
    const ta = document.createElement("textarea");
    ta.value = code;
    document.body.appendChild(ta);
    ta.select();
    document.execCommand("copy");
    ta.remove();
  }
});

/* -------------------- Eye toggle (login) -------------------- */
let loginHidden = true;
