async function callTuneAudioSender(sender){
  if (!sender || typeof sender.getParameters !== "function" || typeof sender.setParameters !== "function") return;
  try{
    const p = sender.getParameters() || {};
    p.encodings = p.encodings && p.encodings.length ? p.encodings : [{}];
    p.encodings[0].maxBitrate = 64000;
    p.encodings[0].priority = "high";
    p.encodings[0].networkPriority = "high";
    await sender.setParameters(p);
  }catch{}
}

async function callTuneScreenSender(sender){
  if (!sender || typeof sender.getParameters !== "function" || typeof sender.setParameters !== "function") return;
  try{
    const p = sender.getParameters() || {};
    p.encodings = p.encodings && p.encodings.length ? p.encodings : [{}];
    p.encodings[0].maxBitrate = 2500000;
    p.encodings[0].maxFramerate = 24;
    p.encodings[0].priority = "high";
    p.encodings[0].networkPriority = "high";
    await sender.setParameters(p);
  }catch{}
}

function callCleanupSpatialAudioForPeer(peerCode){
  const code = String(peerCode || "");
  const nodes = callSpatialAudioNodes.get(code);
  if (!nodes) return;

  try{ nodes.source?.disconnect?.(); }catch{}
  try{ nodes.panner?.disconnect?.(); }catch{}
  try{ nodes.dryGain?.disconnect?.(); }catch{}
  try{ nodes.roomDelay?.disconnect?.(); }catch{}
  try{ nodes.roomGain?.disconnect?.(); }catch{}
  try{ nodes.roomFilter?.disconnect?.(); }catch{}
  try{ nodes.roomConvolver?.disconnect?.(); }catch{}
  callSpatialAudioNodes.delete(code);
}

function callCloseSpatialAudioNodes({ closeContext=true } = {}){
  for (const code of Array.from(callSpatialAudioNodes.keys())){
    callCleanupSpatialAudioForPeer(code);
  }
  if (closeContext && callSpatialAudioCtx){
    callSpatialRoomConvolver = null;
    try{ callSpatialAudioCtx.close(); }catch{}
    callSpatialAudioCtx = null;
  }
}

async function callEnsureSpatialAudioContext(){
  const AC = callGetAudioContextCtor();
  if (!AC) return null;

  if (!callSpatialAudioCtx || callSpatialAudioCtx.state === "closed"){
    try{
      callSpatialAudioCtx = new AC({ latencyHint:"interactive" });
    }catch{
      try{ callSpatialAudioCtx = new AC(); }catch{ callSpatialAudioCtx = null; }
    }
  }

  const ctx = callSpatialAudioCtx;
  if (!ctx) return null;

  try{
    const listener = ctx.listener;
    if (listener){
      if (listener.positionX){
        listener.positionX.value = 0;
        listener.positionY.value = 1.55;
        listener.positionZ.value = 0;
      } else if (listener.setPosition) {
        listener.setPosition(0, 1.55, 0);
      }

      if (listener.forwardX){
        listener.forwardX.value = 0;
        listener.forwardY.value = -0.08;
        listener.forwardZ.value = -1;
        listener.upX.value = 0;
        listener.upY.value = 1;
        listener.upZ.value = 0;
      } else if (listener.setOrientation) {
        listener.setOrientation(0, -0.08, -1, 0, 1, 0);
      }
    }
  }catch{}

  try{
    if (ctx.state === "suspended") await ctx.resume();
  }catch{}

  return ctx;
}

function callSetPannerPosition(panner, x, y, z){
  try{
    if (panner.positionX){
      panner.positionX.value = x;
      panner.positionY.value = y;
      panner.positionZ.value = z;
    } else if (panner.setPosition) {
      panner.setPosition(x, y, z);
    }
  }catch{}
}

function callBuildSpatialRoomImpulse(ctx){
  const rate = ctx.sampleRate || 48000;
  const seconds = 0.42;
  const length = Math.max(1, Math.floor(rate * seconds));
  const impulse = ctx.createBuffer(2, length, rate);

  for (let ch = 0; ch < impulse.numberOfChannels; ch += 1){
    const data = impulse.getChannelData(ch);
    for (let i = 0; i < length; i += 1){
      const t = i / length;
      const early = i < rate * 0.055 ? 1 : 0.42;
      data[i] = (Math.random() * 2 - 1) * Math.pow(1 - t, 2.75) * early * 0.14;
    }
  }

  return impulse;
}

function callGetSpatialRoomConvolver(ctx){
  if (callSpatialRoomConvolver?.ctx === ctx && callSpatialRoomConvolver?.node){
    return callSpatialRoomConvolver.node;
  }

  try{
    const node = ctx.createConvolver();
    node.normalize = true;
    node.buffer = callBuildSpatialRoomImpulse(ctx);
    callSpatialRoomConvolver = { ctx, node };
    return node;
  }catch{
    callSpatialRoomConvolver = null;
    return null;
  }
}

function callSpatialPositionForPeer(peerCode){
  const peer = String(peerCode || "");
  const codes = Array.from(callRemoteAudioEls.keys()).map(String).sort();
  const idx = Math.max(0, codes.indexOf(peer));
  const count = Math.max(1, codes.length);
  const spread = Math.min(Math.PI * 1.12, Math.PI * (0.34 + (count * 0.12)));
  const angle = count === 1 ? 0 : (-spread / 2) + (spread * (idx / Math.max(1, count - 1)));
  const radius = 1.45 + Math.min(0.65, idx * 0.1);

  return {
    x: Math.sin(angle) * radius,
    y: 1.42 + ((idx % 2) ? 0.06 : -0.04),
    z: -Math.cos(angle) * radius - 0.25
  };
}

async function callApplySpatialAudioForPeer(peerCode, stream){
  const code = String(peerCode || "");
  const audio = callRemoteAudioEls.get(code);
  if (!audio) return;

  if (!callSpatialAudio || callDeafened || !stream){
    callCleanupSpatialAudioForPeer(code);
    try{ audio.muted = !!callDeafened; }catch{}
    try{
      const p = audio.play();
      if (p && typeof p.catch === "function") p.catch(()=>{});
    }catch{}
    return;
  }

  const ctx = await callEnsureSpatialAudioContext();
  if (!ctx){
    callSpatialAudio = false;
    callCleanupSpatialAudioForPeer(code);
    try{ audio.muted = !!callDeafened; }catch{}
    syncCallControlsUI();
    return;
  }

  try{ audio.muted = true; }catch{}

  let nodes = callSpatialAudioNodes.get(code);
  if (!nodes || nodes.stream !== stream || nodes.ctx !== ctx){
    callCleanupSpatialAudioForPeer(code);

    const source = ctx.createMediaStreamSource(stream);
    const panner = ctx.createPanner();
    const dryGain = ctx.createGain();
    const roomDelay = ctx.createDelay(0.12);
    const roomGain = ctx.createGain();
    const roomFilter = ctx.createBiquadFilter();
    const roomConvolver = callGetSpatialRoomConvolver(ctx);

    panner.panningModel = "HRTF";
    panner.distanceModel = "inverse";
    panner.refDistance = 1.05;
    panner.maxDistance = 8;
    panner.rolloffFactor = 0.58;
    panner.coneInnerAngle = 210;
    panner.coneOuterAngle = 330;
    panner.coneOuterGain = 0.42;

    dryGain.gain.value = 0.96;
    roomDelay.delayTime.value = 0.026 + (Math.random() * 0.018);
    roomGain.gain.value = 0.16;
    roomFilter.type = "lowpass";
    roomFilter.frequency.value = 3600;

    source.connect(panner);
    panner.connect(dryGain);
    dryGain.connect(ctx.destination);

    panner.connect(roomDelay);
    roomDelay.connect(roomFilter);
    roomFilter.connect(roomGain);
    if (roomConvolver){
      roomGain.connect(roomConvolver);
      roomConvolver.connect(ctx.destination);
    } else {
      roomGain.connect(ctx.destination);
    }

    nodes = { ctx, stream, source, panner, dryGain, roomDelay, roomGain, roomFilter, roomConvolver };
    callSpatialAudioNodes.set(code, nodes);
  }

  const pos = callSpatialPositionForPeer(code);
  callSetPannerPosition(nodes.panner, pos.x, pos.y, pos.z);

  try{
    const p = audio.play();
    if (p && typeof p.catch === "function") p.catch(()=>{});
  }catch{}
}

function callUpdateSpatialAudioForAll(){
  for (const [code, audio] of callRemoteAudioEls.entries()){
    void callApplySpatialAudioForPeer(code, audio?.srcObject || null);
  }
}

function callToggleSpatialAudio(){
  if (!currentCallRoomId) return;
  callSpatialAudio = !callSpatialAudio;

  if (!callSpatialAudio){
    callCloseSpatialAudioNodes({ closeContext:true });
  }

  callUpdateSpatialAudioForAll();
  syncCallControlsUI();

  showToast({
    title: callSpatialAudio ? "Spatial Audio enabled" : "Spatial Audio disabled",
    body: callSpatialAudio ? "Remote voices are positioned locally for this call only." : "Remote voices are back to normal stereo output.",
    duration: 1800
  });
}

async function callRequestMicPermission(){
  if (!navigator.mediaDevices?.getUserMedia){
    showToast({ title:"Microphone unavailable", body:"This runtime does not expose microphone access.", duration: 4500 });
    return null;
  }

  const prep = (stream) => {
    try{
      for (const track of stream.getAudioTracks()){
        try{ track.contentHint = "speech"; }catch{}
        try{
          track.applyConstraints({
            echoCancellation: { ideal:true },
            noiseSuppression: { ideal:true },
            autoGainControl: { ideal:true },
            channelCount: { ideal:1 },
            sampleRate: { ideal:48000 }
          });
        }catch{}
      }
    }catch{}
    return stream;
  };

  try{
    return prep(await navigator.mediaDevices.getUserMedia(CALL_AUDIO_CONSTRAINTS));
  }catch{}

  try{
    return prep(await navigator.mediaDevices.getUserMedia({ audio:true }));
  }catch{
    showToast({ title:"Microphone permission denied", body:"Allow microphone access to join the call.", duration: 5000 });
    return null;
  }
}

// Advisory relay preflight: relay-only calls must gather a TURN relay candidate.
async function callPreflightStun(){
  if (!window.RTCPeerConnection) return false;

  let pc = null;
  try{
    pc = new RTCPeerConnection(callMakeRtcConfig());
    pc.createDataChannel("turn-preflight");

    let sawRelay = false;

    const offer = await pc.createOffer({ offerToReceiveAudio:false, offerToReceiveVideo:false });
    await pc.setLocalDescription(offer);

    const ok = await new Promise((resolve) => {
      let done = false;
      const finish = (v) => {
        if (done) return;
        done = true;
        resolve(!!v);
      };

      pc.onicecandidate = (e) => {
        const c = e.candidate?.candidate || "";
        if (!c) return;
        if (/\btyp\s+relay\b/i.test(c)){
          sawRelay = true;
          finish(true);
        }
      };

      pc.addEventListener("icegatheringstatechange", () => {
        if (pc.iceGatheringState === "complete") finish(sawRelay);
      });

      setTimeout(() => finish(sawRelay), 2200);
    });

    return ok;
  }catch{
    return false;
  }finally{
    try{ pc?.close?.(); }catch{}
  }
}

function callFirebaseMediaBackendPath(roomId=currentCallRoomId, code=currentUser?.code, sessionId=callSessionId){
  const r = sanitizeCallRoom(roomId);
  const c = String(code || "");
  const s = String(sessionId || "");
  if (!r || !c || !s) return "";
  return `calls/${r}/mediaBackend/${c}/${s}`;
}

function callGetFirebaseMediaBackendPayload(reason="state"){
  const audioTrack = callLocalStream?.getAudioTracks?.()[0] || null;
  const screenTrack = callScreenTrack || callScreenStream?.getVideoTracks?.()[0] || null;

  return {
    reason: String(reason || "state"),
    transport: "turn-relay",
    firebaseBackend: true,
    audio: {
      present: !!audioTrack,
      enabled: !!(audioTrack && audioTrack.enabled),
      muted: !!callMuted,
      deafened: !!callDeafened,
      readyState: audioTrack ? String(audioTrack.readyState || "") : ""
    },
    screen: {
      present: !!screenTrack,
      enabled: !!(screenTrack && screenTrack.enabled),
      sharing: !!callSharing,
      readyState: screenTrack ? String(screenTrack.readyState || "") : ""
    },
    peerCount: callPeerMap.size,
    updatedAt: firebase.database.ServerValue.TIMESTAMP
  };
}

function callPublishFirebaseMediaBackendState(reason="state"){
  const path = callFirebaseMediaBackendPath();
  if (!path) return;

  try{
    db.ref(path).update(callGetFirebaseMediaBackendPayload(reason));
  }catch{}
}

function callStartFirebaseMediaBackend(){
  callStopFirebaseMediaBackend({ remove:false });
  callPublishFirebaseMediaBackendState("start");

  callFirebaseMediaStateTimer = setInterval(() => {
    callPublishFirebaseMediaBackendState("heartbeat");
  }, 4000);

  try{
    const path = callFirebaseMediaBackendPath();
    if (path) db.ref(path).onDisconnect().remove();
  }catch{}
}

function callStopFirebaseMediaBackend({ roomId=null, sessionId=null, remove=true } = {}){
  if (callFirebaseMediaStateTimer){
    try{ clearInterval(callFirebaseMediaStateTimer); }catch{}
    callFirebaseMediaStateTimer = null;
  }

  if (!remove || !currentUser) return;

  const path = callFirebaseMediaBackendPath(roomId || currentCallRoomId, currentUser.code, sessionId || callSessionId);
  if (!path) return;

  try{ db.ref(path).remove(); }catch{}
}

function callAttachLocalStream(stream, { resetToggles=true } = {}){
  if (resetToggles){
    // Reset local toggles on each join. Spatial Audio is intentionally off every join.
    callMuted = false;
    callDeafened = false;
    callSpatialAudio = false;
    callCloseSpatialAudioNodes({ closeContext:true });
  }

  // Stop any existing VAD cleanly (don't spam DB during swap)
  callStopSpeakingMonitor({ clearDb:false });

  // Stop/replace any prior stream cleanly
  if (callLocalStream && callLocalStream !== stream){
    try{ callLocalStream.getTracks().forEach(t => { try{ t.stop(); }catch{}; }); }catch{}
  }

  callLocalStream = stream;

  try{
    for (const t of callLocalStream.getAudioTracks()){
      try{ t.contentHint = "speech"; }catch{}
    }
  }catch{}

  syncCallControlsUI();
  callApplyLocalMuteState();

  // Start local voice activity detection -> drives Firebase `speaking` + green aura
  callStartSpeakingMonitor();
}

function callApplyLocalMuteState(){
  if (!callLocalStream) return;

  const shouldSend = !(callMuted || callDeafened);
  for (const t of callLocalStream.getAudioTracks()){
    try{ t.enabled = shouldSend; }catch{}
  }

  for (const [code, a] of callRemoteAudioEls.entries()){
    try{ a.muted = !!(callDeafened || callSpatialAudio); }catch{}
    if (callDeafened) callCleanupSpatialAudioForPeer(code);
  }

  callUpdateSpatialAudioForAll();
  callPublishFirebaseMediaBackendState("audio-state");
}

function callSetLocalSpeaking(isSpeaking, { force=false } = {}){
  const v = !!isSpeaking;

  // Keep local state in sync (and avoid redundant work)
  if (!force && v === callVadSpeaking) return;
  callVadSpeaking = v;

  // Update local cache + current menu DOM immediately (Firebase will also reconcile)
  try{
    const my = String(currentUser?.code || "");
    if (my){
      const row = callMembersCache.find(m => String(m.code || "") === my);
      if (row) row.speaking = v;

      if (callMenuOpen){
        const sel = `.call-user-avatar[data-usercode="${my}"]`;
        document.querySelectorAll(sel).forEach(el => el.classList.toggle("speaking", v));
      }
    }
  }catch{}

  // Push to Firebase (throttled)
  if (!currentCallRoomId || !currentUser) return;

  const now = Date.now();
  if (!force && (now - callVadLastDbMs) < CALL_VAD.DB_MIN_MS) return;
  callVadLastDbMs = now;

  try{
    db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
      speaking: v,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}
}

function callStopSpeakingMonitor({ clearDb=true } = {}){
  if (callVadTimer){
    try{ clearInterval(callVadTimer); }catch{}
    callVadTimer = null;
  }

  if (callVadSource){
    try{ callVadSource.disconnect(); }catch{}
    callVadSource = null;
  }

  if (callVadAnalyser){
    try{ callVadAnalyser.disconnect(); }catch{}
    callVadAnalyser = null;
  }

  if (callVadCtx){
    try{ callVadCtx.close(); }catch{}
    callVadCtx = null;
  }

  callVadFloat = null;
  callVadByte = null;
  callVadLastVoiceMs = 0;

  if (clearDb){
    callSetLocalSpeaking(false, { force:true });
  } else {
    callVadSpeaking = false;
  }
}

function callStartSpeakingMonitor(){
  // Restart cleanly
  callStopSpeakingMonitor({ clearDb:false });

  if (!callLocalStream || !currentUser) return;

  const AC = window.AudioContext || window.webkitAudioContext;
  if (!AC) return;

  try{
    callVadCtx = new AC();

    callVadAnalyser = callVadCtx.createAnalyser();
    callVadAnalyser.fftSize = 2048;
    callVadAnalyser.smoothingTimeConstant = 0.85;

    callVadSource = callVadCtx.createMediaStreamSource(callLocalStream);
    callVadSource.connect(callVadAnalyser);

    if (typeof callVadAnalyser.getFloatTimeDomainData === "function"){
      callVadFloat = new Float32Array(callVadAnalyser.fftSize);
      callVadByte = null;
    } else {
      callVadByte = new Uint8Array(callVadAnalyser.fftSize);
      callVadFloat = null;
    }

    // Join is a user gesture, but resume anyway for browsers that start suspended
    try{ if (callVadCtx.state === "suspended") callVadCtx.resume(); }catch{}

    callVadLastVoiceMs = 0;
    callVadLastDbMs = 0;

    callVadTimer = setInterval(() => {
      // Not in a call anymore => force off
      if (!callLocalStream || !currentUser || !currentCallRoomId){
        callSetLocalSpeaking(false);
        return;
      }

      // Muted/deafened => never speaking
      if (callMuted || callDeafened){
        callSetLocalSpeaking(false);
        return;
      }

      if (!callVadAnalyser) return;

      let rms = 0;

      if (callVadFloat){
        callVadAnalyser.getFloatTimeDomainData(callVadFloat);
        let sum = 0;
        for (let i=0;i<callVadFloat.length;i++){
          const v = callVadFloat[i];
          sum += v * v;
        }
        rms = Math.sqrt(sum / callVadFloat.length);
      } else if (callVadByte){
        callVadAnalyser.getByteTimeDomainData(callVadByte);
        let sum = 0;
        for (let i=0;i<callVadByte.length;i++){
          const v = (callVadByte[i] - 128) / 128;
          sum += v * v;
        }
        rms = Math.sqrt(sum / callVadByte.length);
      }

      const now = Date.now();

      // Start speaking quickly when we cross the start threshold
      if (rms >= CALL_VAD.START_RMS){
        callVadLastVoiceMs = now;
        callSetLocalSpeaking(true);
        return;
      }

      // While speaking: use stop threshold + hold time to avoid flicker
      if (callVadSpeaking){
        if (rms >= CALL_VAD.STOP_RMS) callVadLastVoiceMs = now;

        if (callVadLastVoiceMs && (now - callVadLastVoiceMs) > CALL_VAD.HOLD_MS){
          callSetLocalSpeaking(false);
        }
      } else {
        // Ensure false (no-op if already false)
        callSetLocalSpeaking(false);
      }
    }, CALL_VAD.SAMPLE_MS);
  }catch(e){
    console.warn("VAD init failed:", e);
    callStopSpeakingMonitor({ clearDb:false });
  }
}

function callToggleMute(){
  if (!currentCallRoomId || !currentUser) return;

  // Can't be both: muting clears deafen
  if (callDeafened) callDeafened = false;
  callMuted = !callMuted;

  callApplyLocalMuteState();
  syncCallControlsUI();

  try{
    db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
      muted: !!callMuted,
      deafened: false,
      speaking: false,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}
}

function callToggleDeafen(){
  if (!currentCallRoomId || !currentUser) return;

  // Can't be both: deafening clears mute
  if (callMuted) callMuted = false;
  callDeafened = !callDeafened;

  callApplyLocalMuteState();
  syncCallControlsUI();

  try{
    db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
      muted: false,
      deafened: !!callDeafened,
      speaking: false,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}
}

function syncCallControlsUI(){
  const bMute = $("btn-call-mute");
  const bDeafen = $("btn-call-deafen");
  const bShare = $("btn-call-share");
  const bSpatial = $("btn-call-spatialaudio");
  const bRefreshMic = $("btn-call-refreshmic");

  if (bMute){
    bMute.textContent = callMuted ? "Unmute" : "Mute";
    bMute.classList.toggle("primary", callMuted);
    bMute.disabled = !currentCallRoomId;
  }
  if (bDeafen){
    bDeafen.textContent = callDeafened ? "Undeafen" : "Deafen";
    bDeafen.classList.toggle("primary", callDeafened);
    bDeafen.disabled = !currentCallRoomId;
  }
  if (bShare){
    bShare.textContent = callSharing ? "End Share Screen" : "Share Screen";
    bShare.classList.toggle("primary", callSharing);
    bShare.disabled = !currentCallRoomId;
  }
  if (bSpatial){
    bSpatial.textContent = callSpatialAudio ? "Spatial Audio: On" : "Spatial Audio: Off";
    bSpatial.classList.toggle("primary", callSpatialAudio);
    bSpatial.disabled = !currentCallRoomId || callDeafened;
  }
  if (bRefreshMic){
    bRefreshMic.disabled = !currentCallRoomId;
  }

  callSyncMenuStatusDisplay();
}

async function callRefreshMic(){
  if (!currentCallRoomId || !currentUser) return;

  const stream = await callRequestMicPermission();
  if (!stream) return;

  callAttachLocalStream(stream, { resetToggles:false });

  const audioTrack = callLocalStream?.getAudioTracks?.()[0] || null;
  if (audioTrack){
    for (const [peerCode, pc] of callPeerMap.entries()){
      if (!pc?.getSenders) continue;
      try{
        let sender = pc.getSenders().find((s) => s && s.track && s.track.kind === "audio");
        if (sender){
          await sender.replaceTrack(audioTrack);
        } else if (typeof pc.addTrack === "function") {
          sender = pc.addTrack(audioTrack, callLocalStream);
          callRequestPeerMediaRefresh(peerCode, "mic-refresh");
        }
        await callTuneAudioSender(sender);
      }catch{}
    }
  }

  callApplyLocalMuteState();

  try{
    await db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
      muted: !!callMuted,
      deafened: !!callDeafened,
      speaking: false,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}

  showToast({ title:"Microphone refreshed", body:"Your mic track was reacquired and re-sent to the call.", duration: 2200 });
}

async function callToggleShareScreen(){
  if (!currentCallRoomId || !currentUser) return;

  if (callSharing){
    callStopShareScreen();
    return;
  }

  if (!navigator.mediaDevices?.getDisplayMedia){
    showToast({ title:"Screen share unavailable", body:"This runtime does not expose screen sharing.", duration: 4500 });
    return;
  }

  try{
    const stream = await navigator.mediaDevices.getDisplayMedia(CALL_SCREEN_CONSTRAINTS);

    const track = stream.getVideoTracks?.()[0] || null;
    if (!track){
      try{ stream.getTracks().forEach(t => { try{ t.stop(); }catch{}; }); }catch{}
      return;
    }

    try{ track.contentHint = "detail"; }catch{}

    callSharing = true;
    callScreenStream = stream;
    callScreenTrack = track;

    // Make self share viewable locally (same UI as viewing others).
    try{ callRemoteVideoStreams.set(String(currentUser.code), stream); }catch{}
    if (shareViewOpen && shareViewUserCode === String(currentUser.code)){
      syncShareViewStream();
    }

    // If the user ends share from browser UI, stop sharing immediately.
    track.onended = () => {
      callStopShareScreen(true);
    };

    // Apply to every current peer and force a media refresh so late/rejoined peers load it.
    for (const [peerCode, pc] of callPeerMap.entries()){
      try{
        if (!pc.__screenTx && pc.addTransceiver){
          pc.__screenTx = pc.addTransceiver("video", { direction:"sendrecv" });
        }
        if (pc.__screenTx){
          try{ pc.__screenTx.direction = "sendrecv"; }catch{}
          await pc.__screenTx.sender.replaceTrack(callScreenTrack);
          await callTuneScreenSender(pc.__screenTx.sender);
          callRequestPeerMediaRefresh(peerCode, "share-start");
        }
      }catch{}
    }

    // Update Firebase member flag after the track is attached.
    try{
      db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
        sharing: true,
        updatedAt: firebase.database.ServerValue.TIMESTAMP
      });
    }catch{}
    callPublishFirebaseMediaBackendState("share-start");

    syncCallControlsUI();
    if (callMenuOpen) renderCallMenu();
  }catch(e){
    // User cancelled or permission denied.
    callSharing = false;
    callScreenStream = null;
    callScreenTrack = null;
    syncCallControlsUI();
  }
}

function callStopShareScreen(quiet=false){
  if (!currentCallRoomId || !currentUser) return;

  callSharing = false;

  // Detach from peers and notify them to remove stale screen tracks.
  for (const [peerCode, pc] of callPeerMap.entries()){
    try{
      if (pc.__screenTx){
        pc.__screenTx.sender.replaceTrack(null);
        callRequestPeerMediaRefresh(peerCode, "share-stop");
      }
    }catch{}
  }

  // Stop local tracks.
  if (callScreenStream){
    try{ callScreenStream.getTracks().forEach(t => { try{ t.stop(); }catch{}; }); }catch{}
  }
  callScreenStream = null;
  callScreenTrack = null;

  // Clear local self-cache for share viewer.
  try{ callRemoteVideoStreams.delete(String(currentUser.code)); }catch{}

  // Update Firebase.
  try{
    db.ref(`calls/${currentCallRoomId}/members/${currentUser.code}`).update({
      sharing: false,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}
  callPublishFirebaseMediaBackendState("share-stop");

  // If I was watching my own share view, close it.
  if (shareViewOpen && shareViewUserCode === String(currentUser.code)){
    closeShareView(true);
  }

  if (!quiet){
    showToast({ title:"Screen share ended", body:"Your screen is no longer being shared.", duration: 1800 });
  }

  syncCallControlsUI();
  if (callMenuOpen) renderCallMenu();
}

function openShareView(userCode, username){
  const { shareMenu: el } = ensureCallRuntimeModals();
  if (!el) return;

  shareViewOpen = true;
  shareViewUserCode = String(userCode || "");
  shareViewUsername = String(username || "User");

  const title = $("share-menu-title");
  if (title) title.textContent = `Screen Share — ${shareViewUsername}`;

  el.hidden = false;
  el.classList.remove("is-open");
  requestAnimationFrame(() => {
    if (!el.hidden) el.classList.add("is-open");
  });

  syncShareViewStream();
}

function closeShareView(immediate=false){
  const el = $("share-menu");

  shareViewOpen = false;
  shareViewUserCode = null;
  shareViewUsername = null;

  const v = $("share-video");
  const ph = $("share-placeholder");
  if (v){
    try{ v.pause(); }catch{}
    try{ v.srcObject = null; }catch{}
  }
  if (ph) ph.style.display = "";

  if (!el) return;

  const finish = () => {
    el.classList.remove("is-open");
    el.hidden = true;
  };

  if (immediate || (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches)){
    finish();
    return;
  }

  setTimeout(finish, 180);
  el.classList.remove("is-open");
}

function syncShareViewStream(){
  if (!shareViewOpen || !shareViewUserCode) return;

  ensureCallRuntimeModals();

  const v = $("share-video");
  const ph = $("share-placeholder");
  if (!v || !ph) return;

  const viewingSelf = !!(currentUser && String(currentUser.code) === String(shareViewUserCode));
  const s = viewingSelf ? (callScreenStream || null) : (callRemoteVideoStreams.get(shareViewUserCode) || null);

  if (!s){
    ph.style.display = "";
    try{ v.srcObject = null; }catch{}

    const target = callGetMemberByCode(shareViewUserCode);
    if (!viewingSelf && target?.sharing){
      callRequestPeerMediaRefresh(shareViewUserCode, "share-viewer-waiting");
    }
    return;
  }

  const hasLiveVideo = s.getVideoTracks?.().some((t) => t.readyState !== "ended") ?? true;
  if (!hasLiveVideo){
    ph.style.display = "";
    try{ v.srcObject = null; }catch{}
    if (!viewingSelf) callRequestPeerMediaRefresh(shareViewUserCode, "share-track-ended");
    return;
  }

  ph.style.display = "none";
  try{ v.muted = true; }catch{}
  if (v.srcObject !== s){
    v.srcObject = s;
  }

  try{
    const p = v.play();
    if (p && typeof p.catch === "function") p.catch(()=>{});
  }catch{}
}

function makeCallSessionId(){
  return `call_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

function callGetMemberByCode(code){
  const id = String(code || "");
  return callMembersCache.find((m) => String(m?.code || "") === id) || null;
}

function callGetPeerSessionId(peerCode){
  return String(callGetMemberByCode(peerCode)?.sessionId || "");
}

function callSyncMenuStatusDisplay(){
  const roomEl = $("call-menu-room");
  const qualityEl = $("call-menu-quality");
  const statusEl = $("call-menu-status");
  const metaEl = $("call-menu-meta");

  if (roomEl){
    roomEl.textContent = (currentCallRoomId || observedCallRoomId || currentRoomId || "—");
  }

  const connectedMembers = callMembersCache.filter((m) => m && m.connected !== false).length;
  const statusText = currentCallRoomId
    ? (callConnectionQuality.level === "reconnecting" ? "Reconnecting" : "In call")
    : (callActive ? "Live call" : "No live call");
  const metaText = connectedMembers
    ? `${connectedMembers} participant${connectedMembers === 1 ? "" : "s"}`
    : "Nobody else is here yet.";

  if (qualityEl){
    qualityEl.textContent = callConnectionQuality.label || "Idle";
    qualityEl.className = `call-quality-chip ${callConnectionQuality.level || "idle"}`;
    qualityEl.title = callConnectionQuality.detail || "";
  }
  if (statusEl) statusEl.textContent = statusText;
  if (metaEl) metaEl.textContent = metaText;
}

async function callReadPeerStats(pc){
  let packetsLost = 0;
  let packetsTotal = 0;
  let rttMs = null;

  try{
    const stats = await pc.getStats();
    stats.forEach((report) => {
      if (report.type === "inbound-rtp" && report.kind === "audio" && !report.isRemote){
        const lost = Number(report.packetsLost || 0);
        const received = Number(report.packetsReceived || 0);
        packetsLost += Math.max(0, lost);
        packetsTotal += Math.max(0, lost + received);
      }
      if (report.type === "candidate-pair" && report.state === "succeeded" && (report.nominated || report.selected)){
        const ms = Number(report.currentRoundTripTime || 0) * 1000;
        if (Number.isFinite(ms) && ms > 0){
          if (rttMs == null || ms < rttMs) rttMs = ms;
        }
      }
    });
  }catch{}

  return {
    lossPct: packetsTotal > 0 ? (packetsLost / packetsTotal) * 100 : 0,
    rttMs
  };
}

async function callUpdateConnectionQuality(){
  if (!currentCallRoomId){
    callConnectionQuality = {
      level: "idle",
      label: "Idle",
      detail: "Join a call to measure connection quality.",
      rttMs: null,
      lossPct: null
    };
    callSyncMenuStatusDisplay();
    return;
  }

  const pcs = Array.from(callPeerMap.values());
  if (!pcs.length){
    callConnectionQuality = {
      level: "self",
      label: "Solo",
      detail: "Connected. Waiting for other participants.",
      rttMs: null,
      lossPct: null
    };
    callSyncMenuStatusDisplay();
    return;
  }

  let hasFailed = false;
  let hasConnecting = false;
  let totalLoss = 0;
  let totalRtt = 0;
  let rttCount = 0;

  for (const [peerCode, pc] of callPeerMap.entries()){
    const connectionState = String(pc?.connectionState || "");
    const iceConnectionState = String(pc?.iceConnectionState || "");
    const receivingAudio = !!callRemoteAudioEls.get(peerCode)?.srcObject;

    callPeerStatusCache.set(String(peerCode), {
      connectionState,
      iceConnectionState,
      receivingAudio,
      peerSessionId: String(pc?.__peerSessionId || "")
    });

    if (["failed", "closed"].includes(connectionState) || ["failed", "closed"].includes(iceConnectionState)){
      hasFailed = true;
      continue;
    }
    if (["new", "connecting", "disconnected"].includes(connectionState) || ["new", "checking", "disconnected"].includes(iceConnectionState)){
      hasConnecting = true;
    }

    const stats = await callReadPeerStats(pc);
    totalLoss += Number(stats.lossPct || 0);
    if (Number.isFinite(stats.rttMs) && stats.rttMs != null){
      totalRtt += stats.rttMs;
      rttCount += 1;
    }
  }

  const avgLoss = pcs.length ? (totalLoss / pcs.length) : 0;
  const avgRtt = rttCount ? (totalRtt / rttCount) : null;

  let level = "excellent";
  let label = "Excellent";
  if (hasFailed){
    level = "reconnecting";
    label = "Reconnecting";
  } else if (hasConnecting){
    level = "fair";
    label = "Stabilizing";
  } else if ((avgLoss >= 10) || (avgRtt != null && avgRtt >= 350)){
    level = "poor";
    label = "Poor";
  } else if ((avgLoss >= 4) || (avgRtt != null && avgRtt >= 220)){
    level = "fair";
    label = "Fair";
  } else if ((avgLoss >= 1.5) || (avgRtt != null && avgRtt >= 120)){
    level = "good";
    label = "Good";
  }

  const detailBits = [];
  if (avgRtt != null) detailBits.push(`${Math.round(avgRtt)} ms RTT`);
  if (avgLoss > 0) detailBits.push(`${avgLoss.toFixed(1)}% loss`);

  callConnectionQuality = {
    level,
    label,
    detail: detailBits.length ? detailBits.join(" • ") : "Audio path looks stable.",
    rttMs: avgRtt,
    lossPct: avgLoss
  };
  callSyncMenuStatusDisplay();
}

function callStartQualityMonitor(){
  callStopQualityMonitor();
  callQualityTimer = setInterval(() => {
    void callUpdateConnectionQuality();
  }, CALL_QUALITY_POLL_MS);
  void callUpdateConnectionQuality();
}

function callStopQualityMonitor(){
  if (callQualityTimer){
    try{ clearInterval(callQualityTimer); }catch{}
  }
  callQualityTimer = null;
  callConnectionQuality = {
    level: "idle",
    label: "Idle",
    detail: "Join a call to measure connection quality.",
    rttMs: null,
    lossPct: null
  };
  callSyncMenuStatusDisplay();
}

function callWeRtcPath(roomId, toCode, toSessionId, fromCode, fromSessionId){
  return `calls/${roomId}/webrtc/${toCode}/${toSessionId}/${fromCode}/${fromSessionId}`;
}

function callRequestPeerMediaRefresh(peerCode, reason="media-refresh"){
  if (!currentUser || !currentCallRoomId || !callSessionId) return;

  const peer = String(peerCode || "");
  const peerSessionId = callGetPeerSessionId(peer);
  if (!peer || !peerSessionId) return;

  const now = Date.now();
  const last = Number(callShareSyncRequestAt.get(peer) || 0);
  if ((now - last) < 2500) return;
  callShareSyncRequestAt.set(peer, now);

  const my = String(currentUser.code);
  if (my.localeCompare(peer) < 0){
    void callSendOffer(peer, currentCallRoomId, { iceRestart:true });
  } else {
    try{
      db.ref(callWeRtcPath(currentCallRoomId, peer, peerSessionId, my, callSessionId)).update({
        restart: firebase.database.ServerValue.TIMESTAMP,
        reason: String(reason || "media-refresh")
      });
    }catch{}
  }
}

async function callDrainPendingIce(pc){
  const pending = (pc && Array.isArray(pc.__pendingCandidates)) ? pc.__pendingCandidates : null;
  if (!pending || !pending.length) return;
  pc.__pendingCandidates = [];
  for (const c of pending){
    if (!c || !c.candidate) continue;
    try{ await pc.addIceCandidate(new RTCIceCandidate(c)); }catch{}
  }
}

function callDetachPeerSignals(peerCode){
  const code = String(peerCode || "");
  const ref = callPeerSignalRefs.get(code);
  if (!ref) return;
  try{ ref.child("offer").off(); }catch{}
  try{ ref.child("answer").off(); }catch{}
  try{ ref.child("restart").off(); }catch{}
  try{ ref.child("candidates").off(); }catch{}
  callPeerSignalRefs.delete(code);
}

function callDestroyPeer(peerCode, roomId, { removeSignaling=true } = {}){
  const code = String(peerCode || "");
  const id = sanitizeCallRoom(roomId || currentCallRoomId);
  const peerSessionId = callGetPeerSessionId(code);

  const pc = callPeerMap.get(code);
  if (pc){
    try{ pc.__closing = true; }catch{}
    if (pc.__connectTimer){
      try{ clearTimeout(pc.__connectTimer); }catch{}
      pc.__connectTimer = null;
    }
    try{ pc.close(); }catch{}
    callPeerMap.delete(code);
  }

  callDetachPeerSignals(code);
  callPeerStatusCache.delete(code);

  const a = callRemoteAudioEls.get(code);
  if (a){
    try{ a.srcObject = null; }catch{}
    try{ a.remove(); }catch{}
  }
  callRemoteAudioEls.delete(code);

  try{ callRemoteVideoStreams.delete(code); }catch{}
  if (shareViewOpen && String(shareViewUserCode) === code){
    closeShareView(true);
  }

  if (removeSignaling && id && currentUser && callSessionId && peerSessionId){
    const my = String(currentUser.code);
    try{ db.ref(callWeRtcPath(id, code, peerSessionId, my, callSessionId)).remove(); }catch{}
    try{ db.ref(callWeRtcPath(id, my, callSessionId, code, peerSessionId)).remove(); }catch{}
  }
}

async function callSendOffer(peerCode, roomId, { iceRestart=false } = {}){
  if (!currentUser || !currentCallRoomId || !callSessionId) return;

  const id = sanitizeCallRoom(roomId || currentCallRoomId);
  const peer = String(peerCode || "");
  const peerSessionId = callGetPeerSessionId(peer);
  if (!id || !peer || !peerSessionId) return;

  const pc = callPeerMap.get(peer);
  if (!pc) return;

  const my = String(currentUser.code);
  if (my.localeCompare(peer) >= 0) return;

  if (pc.__sendingOffer) return;
  if (pc.signalingState !== "stable"){
    const started = Date.now();
    while (pc.signalingState !== "stable" && (Date.now() - started) < 3000){
      await new Promise(r => setTimeout(r, 60));
    }
    if (pc.signalingState !== "stable") return;
  }

  pc.__sendingOffer = true;
  try{
    const offer = await pc.createOffer(iceRestart ? { iceRestart:true } : undefined);
    await pc.setLocalDescription(offer);

    await db.ref(callWeRtcPath(id, peer, peerSessionId, my, callSessionId)).update({
      offer: { type: pc.localDescription.type, sdp: pc.localDescription.sdp }
    });
  }catch(e){
    console.error("offer send failed:", e);
  }finally{
    pc.__sendingOffer = false;
  }
}

async function callHardRestartPeer(peerCode, roomId, reason=""){
  const id = sanitizeCallRoom(roomId || currentCallRoomId);
  const peer = String(peerCode || "");
  if (!id || !peer) return;

  const old = callPeerMap.get(peer);
  if (old && old.__hardRestarting) return;
  if (old) old.__hardRestarting = true;

  callDestroyPeer(peer, id, { removeSignaling:true });
  callCreatePeer(peer, id);

  try{ await callSendOffer(peer, id); }catch{}
}

function callWatchPeerSignals(peerCode, roomId){
  if (!currentUser || !callSessionId) return;
  const code = String(peerCode || "");
  const peerSessionId = callGetPeerSessionId(code);
  if (!peerSessionId) return;

  callDetachPeerSignals(code);

  const incomingRef = db.ref(callWeRtcPath(roomId, currentUser.code, callSessionId, code, peerSessionId));
  callPeerSignalRefs.set(code, incomingRef);

  incomingRef.child("offer").on("value", async (snap) => {
    const offer = snap.val();
    if (!offer || !offer.sdp) return;
    if (callGetPeerSessionId(code) !== peerSessionId) return;

    const pc = callPeerMap.get(code) || callCreatePeer(code, roomId);
    if (pc.__handlingOffer) return;
    pc.__handlingOffer = true;

    try{
      if (pc.signalingState !== "stable"){
        const started = Date.now();
        while (pc.signalingState !== "stable" && (Date.now() - started) < 3000){
          await new Promise(r => setTimeout(r, 60));
        }
        if (pc.signalingState !== "stable") return;
      }

      const offerSdp = String(offer.sdp || "");
      if (pc.__lastOfferSdp === offerSdp){
        try{ snap.ref.remove(); }catch{}
        return;
      }
      pc.__lastOfferSdp = offerSdp;

      await pc.setRemoteDescription(new RTCSessionDescription(offer));
      try{ await callDrainPendingIce(pc); }catch{}

      const ans = await pc.createAnswer();
      await pc.setLocalDescription(ans);

      await db.ref(callWeRtcPath(roomId, code, peerSessionId, currentUser.code, callSessionId)).update({
        answer: { type: pc.localDescription.type, sdp: pc.localDescription.sdp }
      });

      try{ snap.ref.remove(); }catch{}
    }catch(e){
      console.error("offer handling failed:", e);
    }finally{
      pc.__handlingOffer = false;
    }
  });

  incomingRef.child("answer").on("value", async (snap) => {
    const answer = snap.val();
    if (!answer || !answer.sdp) return;
    if (callGetPeerSessionId(code) !== peerSessionId) return;

    const pc = callPeerMap.get(code);
    if (!pc) return;

    try{
      if (pc.signalingState === "have-local-offer" && !pc.currentRemoteDescription){
        await pc.setRemoteDescription(new RTCSessionDescription(answer));
        try{ await callDrainPendingIce(pc); }catch{}
      }
      try{ snap.ref.remove(); }catch{}
    }catch(e){
      console.error("answer handling failed:", e);
    }
  });

  incomingRef.child("restart").on("value", async (snap) => {
    const v = snap.val();
    if (!v) return;
    if (callGetPeerSessionId(code) !== peerSessionId) return;

    callPeerMap.get(code) || callCreatePeer(code, roomId);
    try{ await callSendOffer(code, roomId, { iceRestart:true }); }catch{}
    try{ snap.ref.remove(); }catch{}
  });

  incomingRef.child("candidates").on("child_added", async (snap) => {
    const c = snap.val();
    if (!c || !c.candidate) return;
    if (callGetPeerSessionId(code) !== peerSessionId) return;

    const pc = callPeerMap.get(code);
    if (!pc) return;

    try{
      if (pc.remoteDescription && pc.remoteDescription.type){
        await pc.addIceCandidate(new RTCIceCandidate(c));
      } else {
        pc.__pendingCandidates = pc.__pendingCandidates || [];
        pc.__pendingCandidates.push(c);
      }
    }catch{
      pc.__pendingCandidates = pc.__pendingCandidates || [];
      pc.__pendingCandidates.push(c);
    }
    try{ snap.ref.remove(); }catch{}
  });
}

function callCreatePeer(peerCode, roomId){
  const peerSessionId = callGetPeerSessionId(peerCode);
  const pc = new RTCPeerConnection(callMakeRtcConfig());

  pc.__pendingCandidates = [];
  pc.__restartAttempts = 0;
  pc.__discTimer = null;
  pc.__lastIceRestartAt = 0;
  pc.__peerSessionId = peerSessionId;
  pc.__connectTimer = setTimeout(() => {
    if (pc.__closing) return;
    const conn = String(pc.connectionState || "");
    const ice = String(pc.iceConnectionState || "");
    if (conn === "connected" || ice === "connected" || ice === "completed") return;

    const n = bumpRestartAttempt();
    if (n <= 2) requestIceRestart(true);
    else callHardRestartPeer(peerCode, roomId, "connect-timeout");
  }, 12000);


  const requestIceRestart = (force=false) => {
    if (!currentUser || !currentCallRoomId || !callSessionId || !peerSessionId) return;

    const my = String(currentUser.code);
    const peer = String(peerCode || "");

    const now = Date.now();
    const last = Number(pc.__lastIceRestartAt || 0);
    if (!force && (now - last) < 8000) return;
    pc.__lastIceRestartAt = now;

    if (my.localeCompare(peer) < 0){
      callSendOffer(peer, roomId, { iceRestart:true });
    } else {
      try{
        db.ref(callWeRtcPath(roomId, peer, peerSessionId, my, callSessionId)).update({
          restart: firebase.database.ServerValue.TIMESTAMP
        });
      }catch{}
    }
  };

  const clearDiscTimer = () => {
    if (pc.__discTimer){
      try{ clearTimeout(pc.__discTimer); }catch{}
      pc.__discTimer = null;
    }
  };

  const clearConnectTimer = () => {
    if (pc.__connectTimer){
      try{ clearTimeout(pc.__connectTimer); }catch{}
      pc.__connectTimer = null;
    }
  };

  const bumpRestartAttempt = () => {
    pc.__restartAttempts = Number(pc.__restartAttempts || 0) + 1;
    return pc.__restartAttempts;
  };

  pc.oniceconnectionstatechange = () => {
    if (pc.__closing) return;
    const st = pc.iceConnectionState;

    callPeerStatusCache.set(String(peerCode), {
      connectionState: String(pc.connectionState || ""),
      iceConnectionState: st,
      receivingAudio: !!callRemoteAudioEls.get(String(peerCode))?.srcObject,
      peerSessionId
    });
    void callUpdateConnectionQuality();

    if (st === "connected" || st === "completed"){
      pc.__restartAttempts = 0;
      clearDiscTimer();
      clearConnectTimer();
      return;
    }

    if (st === "disconnected"){
      clearDiscTimer();
      pc.__discTimer = setTimeout(() => {
        if (pc.iceConnectionState !== "disconnected") return;
        const n = bumpRestartAttempt();
        if (n <= 2) requestIceRestart(false);
        else callHardRestartPeer(peerCode, roomId, "ice-disconnected");
      }, 4500);
      return;
    }

    if (st === "failed"){
      clearDiscTimer();
      const n = bumpRestartAttempt();
      if (n <= 2) requestIceRestart(true);
      else callHardRestartPeer(peerCode, roomId, "ice-failed");
    }
  };

  pc.onconnectionstatechange = () => {
    if (pc.__closing) return;
    const st = pc.connectionState;

    callPeerStatusCache.set(String(peerCode), {
      connectionState: st,
      iceConnectionState: String(pc.iceConnectionState || ""),
      receivingAudio: !!callRemoteAudioEls.get(String(peerCode))?.srcObject,
      peerSessionId
    });
    void callUpdateConnectionQuality();

    if (st === "connected"){
      pc.__restartAttempts = 0;
      clearDiscTimer();
    } else if (st === "failed"){
      clearDiscTimer();
      const n = bumpRestartAttempt();
      if (n <= 2) requestIceRestart(true);
      else callHardRestartPeer(peerCode, roomId, "conn-failed");
    }
  };

  if (callLocalStream){
    for (const t of callLocalStream.getTracks()){
      try{
        const sender = pc.addTrack(t, callLocalStream);
        if (t.kind === "audio") void callTuneAudioSender(sender);
      }catch{}
    }
  }

  try{
    if (!pc.__screenTx && pc.addTransceiver){
      pc.__screenTx = pc.addTransceiver("video", { direction: "sendrecv" });
    }
    if (pc.__screenTx){
      try{ pc.__screenTx.direction = "sendrecv"; }catch{}
      if (callSharing && callScreenTrack){
        try{ pc.__screenTx.sender.replaceTrack(callScreenTrack); }catch{}
        void callTuneScreenSender(pc.__screenTx.sender);
      }
    }
  }catch{}

  pc.ontrack = (ev) => {
    let stream = (ev.streams && ev.streams[0]) ? ev.streams[0] : null;
    if (!ev.track) return;

    if (!stream){
      try{ stream = new MediaStream([ev.track]); }catch{ return; }
    }

    if (ev.track.kind === "audio"){
      callEnsureAudioHost();

      let audio = callRemoteAudioEls.get(peerCode);
      if (!audio){
        audio = document.createElement("audio");
        audio.autoplay = true;
        audio.playsInline = true;
        audio.muted = !!(callDeafened || callSpatialAudio);
        callAudioHost.appendChild(audio);
        callRemoteAudioEls.set(peerCode, audio);
      }

      if (audio.srcObject !== stream){
        audio.srcObject = stream;
      }

      void callApplySpatialAudioForPeer(peerCode, stream);

      callPeerStatusCache.set(String(peerCode), {
        connectionState: String(pc.connectionState || ""),
        iceConnectionState: String(pc.iceConnectionState || ""),
        receivingAudio: true,
        peerSessionId
      });
      void callUpdateConnectionQuality();

      try{
        const p = audio.play();
        if (p && typeof p.catch === "function") p.catch(()=>{});
      }catch{}
      return;
    }

    if (ev.track.kind === "video"){
      try{
        if (!stream.getVideoTracks().includes(ev.track)) stream.addTrack(ev.track);
      }catch{}

      callRemoteVideoStreams.set(peerCode, stream);
      callShareSyncRequestAt.delete(peerCode);

      const cleanupShare = () => {
        const live = stream?.getVideoTracks?.().some((t) => t.readyState !== "ended");
        if (live) return;

        try{ callRemoteVideoStreams.delete(peerCode); }catch{}
        if (shareViewOpen && shareViewUserCode === peerCode){
          syncShareViewStream();
        }
      };

      try{ ev.track.onended = cleanupShare; }catch{}
      try{
        ev.track.onmute = () => {
          if (shareViewOpen && shareViewUserCode === peerCode){
            syncShareViewStream();
            callRequestPeerMediaRefresh(peerCode, "share-track-muted");
          }
        };
      }catch{}
      try{
        ev.track.onunmute = () => {
          callRemoteVideoStreams.set(peerCode, stream);
          callShareSyncRequestAt.delete(peerCode);
          if (shareViewOpen && shareViewUserCode === peerCode){
            syncShareViewStream();
          }
        };
      }catch{}

      if (shareViewOpen && shareViewUserCode === peerCode){
        syncShareViewStream();
      }
    }
  };

  pc.onicecandidate = (e) => {
    const cand = e.candidate;
    if (!cand || !currentUser || !currentCallRoomId || !callSessionId || !peerSessionId) return;

    const path = callWeRtcPath(roomId, peerCode, peerSessionId, currentUser.code, callSessionId) + "/candidates";
    try{
      db.ref(path).push({
        candidate: cand.candidate,
        sdpMid: cand.sdpMid,
        sdpMLineIndex: cand.sdpMLineIndex
      });
    }catch{}
  };

  callPeerMap.set(peerCode, pc);
  callWatchPeerSignals(peerCode, roomId);
  return pc;
}

async function callEnsurePeers(roomId){
  if (!currentUser || !currentCallRoomId || !callSessionId) return;

  const my = String(currentUser.code);

  const peers = callMembersCache
    .filter((m) => m && m.connected && String(m.code || "") !== my && String(m.sessionId || ""))
    .map((m) => ({
      code: String(m.code || ""),
      sessionId: String(m.sessionId || "")
    }));

  const peerCodes = peers.map((p) => p.code);

  for (const [code] of callPeerMap.entries()){
    if (!peerCodes.includes(code)){
      callDestroyPeer(code, roomId, { removeSignaling:true });
    }
  }

  for (const peer of peers){
    const existing = callPeerMap.get(peer.code);
    if (existing && String(existing.__peerSessionId || "") !== peer.sessionId){
      callDestroyPeer(peer.code, roomId, { removeSignaling:true });
    }

    const pc = callPeerMap.get(peer.code) || callCreatePeer(peer.code, roomId);

    try{
      const at = (callLocalStream && callLocalStream.getAudioTracks) ? (callLocalStream.getAudioTracks()[0] || null) : null;
      if (pc.getSenders){
        let s = pc.getSenders().find((x) => x && x.track && x.track.kind === "audio");
        if (s && s.track !== at){
          await s.replaceTrack(at || null);
        } else if (!s && at && typeof pc.addTrack === "function") {
          s = pc.addTrack(at, callLocalStream);
          pc.__madeOffer = false;
        }
        await callTuneAudioSender(s);
      }
    }catch{}

    try{
      if (!pc.__screenTx && pc.addTransceiver){
        pc.__screenTx = pc.addTransceiver("video", { direction: "sendrecv" });
        pc.__madeOffer = false;
      }
      if (pc.__screenTx?.sender){
        try{ pc.__screenTx.direction = "sendrecv"; }catch{}
        const wantedTrack = callSharing ? (callScreenTrack || null) : null;
        if (pc.__screenTx.sender.track !== wantedTrack){
          await pc.__screenTx.sender.replaceTrack(wantedTrack);
          if (callSharing) pc.__madeOffer = false;
        }
        if (wantedTrack){
          await callTuneScreenSender(pc.__screenTx.sender);
        }
      }
    }catch{}

    const iOffer = my.localeCompare(peer.code) < 0;

    if (iOffer && !pc.__madeOffer){
      pc.__madeOffer = true;
      try{ await callSendOffer(peer.code, roomId); }catch{}
    }
  }

  void callUpdateConnectionQuality();
}

function callStartWebRTC(roomId){
  if (!currentUser || !callSessionId) return;
  callEnsureAudioHost();
  callApplyLocalMuteState();
  callStartFirebaseMediaBackend();

  try{ db.ref(`calls/${roomId}/webrtc/${currentUser.code}/${callSessionId}`).onDisconnect().remove(); }catch{}

  void callEnsurePeers(roomId);
  setTimeout(() => { if (currentCallRoomId === roomId) void callEnsurePeers(roomId); }, 700);
  setTimeout(() => { if (currentCallRoomId === roomId) void callEnsurePeers(roomId); }, 1800);

  callStartQualityMonitor();

  try{
    const my = String(currentUser.code);
    for (const peer of callPeerMap.keys()){
      const p = String(peer || "");
      callRequestPeerMediaRefresh(p, my.localeCompare(p) < 0 ? "call-start-offer" : "call-start-request");
    }
  }catch{}
}

function callStopWebRTC({ roomId=null } = {}){
  const id = sanitizeCallRoom(roomId || currentCallRoomId);
  const sessionId = callSessionId;

  callStopSpeakingMonitor();
  callStopQualityMonitor();
  callStopFirebaseMediaBackend({ roomId:id, sessionId });

  try{
    for (const code of Array.from(callPeerSignalRefs.keys())){
      callDetachPeerSignals(code);
    }
  }catch{}
  callPeerSignalRefs.clear();
  callMemberSharingCache.clear();
  callPeerStatusCache.clear();
  callShareSyncRequestAt.clear();

  callCloseSpatialAudioNodes({ closeContext:true });

  for (const pc of callPeerMap.values()){
    try{ pc.close(); }catch{}
  }
  callPeerMap.clear();

  for (const a of callRemoteAudioEls.values()){
    try{ a.srcObject = null; }catch{}
    try{ a.remove(); }catch{}
  }
  callRemoteAudioEls.clear();

  if (callLocalStream){
    try{ callLocalStream.getTracks().forEach((t) => { try{ t.stop(); }catch{}; }); }catch{}
  }
  callLocalStream = null;

  if (callScreenStream){
    try{ callScreenStream.getTracks().forEach((t) => { try{ t.stop(); }catch{}; }); }catch{}
  }
  callScreenStream = null;
  callScreenTrack = null;
  callSharing = false;

  callRemoteVideoStreams.clear();
  closeShareView(true);

  if (id && currentUser && sessionId){
    const my = String(currentUser.code);
    try{ db.ref(`calls/${id}/webrtc/${my}/${sessionId}`).remove(); }catch{}
  }

  callMuted = false;
  callDeafened = false;
  callSpatialAudio = false;
  syncCallControlsUI();
}

function detachCallObserver(){
  if (callsRoomRef && callsRoomCb){
    try{ callsRoomRef.off("value", callsRoomCb); }catch{}
  }
  callsRoomRef = null;
  callsRoomCb = null;
  observedCallRoomId = null;
  callMembersCache = [];
  callMemberSharingCache.clear();
  callActive = false;
}

function attachCallObserver(roomId){
  const id = sanitizeCallRoom(roomId);
  if (!id) { detachCallObserver(); syncCallButton(); return; }
  if (observedCallRoomId === id && callsRoomRef) return;

  detachCallObserver();

  observedCallRoomId = id;
  callsRoomRef = db.ref(`calls/${id}`);
  callsRoomCb = (snap) => {
    const rec = snap.val() || null;

    const membersObj = (rec && rec.members) ? rec.members : null;
    const allMembers = membersObj ? Object.values(membersObj) : [];

    const now = Date.now();
    const members = allMembers.filter((m) => {
      if (!m || !m.sessionId) return false;
      if (m.connected === false){
        const last = Number(m.lastSeenAt || m.disconnectedAt || m.updatedAt || m.joinedAt) || 0;
        return (now - last) <= CALL_STALE_MEMBER_MS;
      }
      return true;
    });

    for (const m of members){
      if (m && m.code) ensureLiveUserListener(String(m.code));
    }

    members.sort((a,b) => {
      const an = String(a?.displayNameLower || a?.usernameLower || a?.displayName || a?.username || "").toLowerCase();
      const bn = String(b?.displayNameLower || b?.usernameLower || b?.displayName || b?.username || "").toLowerCase();
      const c = an.localeCompare(bn);
      if (c) return c;
      return String(a?.code||"").localeCompare(String(b?.code||""));
    });

    callMembersCache = members.map((m) => ({
      code: m.code || "",
      sessionId: String(m.sessionId || ""),
      username: m.username || "User",
      usernameLower: m.usernameLower || String(m.username || "user").toLowerCase(),
      displayName: m.displayName || m.username || "User",
      displayNameLower: m.displayNameLower || String(m.displayName || m.username || "user").toLowerCase(),
      photoDataURL: m.photoDataURL || null,
      photoTransform: m.photoTransform || null,
      muted: !!m.muted,
      deafened: !!m.deafened,
      speaking: !!m.speaking,
      sharing: !!m.sharing,
      connected: (m.connected !== false),
      lastSeenAt: Number(m.lastSeenAt) || 0,
      disconnectedAt: Number(m.disconnectedAt) || 0,
      updatedAt: Number(m.updatedAt) || 0,
      joinedAt: Number(m.joinedAt) || 0
    }));

    try{
      const seen = new Set();
      for (const m of callMembersCache){
        const code = String(m.code || "");
        if (!code) continue;
        seen.add(code);

        const prev = callMemberSharingCache.get(code);
        callMemberSharingCache.set(code, !!m.sharing);

        if (prev === true && !m.sharing){
          try{ callRemoteVideoStreams.delete(code); }catch{}
          if (shareViewOpen && String(shareViewUserCode) === code){
            closeShareView(true);
          }
        }
      }

      for (const code of Array.from(callMemberSharingCache.keys())){
        if (!seen.has(code)){
          callMemberSharingCache.delete(code);
          try{ callRemoteVideoStreams.delete(code); }catch{}
          if (shareViewOpen && String(shareViewUserCode) === code){
            closeShareView(true);
          }
        }
      }
    }catch{}

    callActive = callMembersCache.length > 0;
    syncCallButton();
    callSyncMenuStatusDisplay();
    if (callMenuOpen) renderCallMenu();

    if (currentCallRoomId === id){
      callEnsurePeers(id);
    }
  };
  callsRoomRef.on("value", callsRoomCb);
}

function setCallButtonHidden(hidden){
  const btn = $("btn-side-call");
  if (!btn) return;
  btn.hidden = !!hidden;
}

function syncCallButton(){
  const btn = $("btn-side-call");
  if (!btn){
    detachCallObserver();
    return;
  }

  const place = localStorage.getItem(LS.PLACE) || "";
  const viewingRoom = /^room:/.test(place);
  const targetRoom = currentCallRoomId || (viewingRoom ? currentRoomId : null) || null;

  // Button only exists if a room is open OR you are actively in a call.
  setCallButtonHidden(!targetRoom);

  // If not visible, also close menu.
  if (!targetRoom){
    closeCallMenu(true);
    return;
  }

  // Observe calls for the active room context:
  // - If you are in a call, always observe that call's room.
  // - Else, observe the currently opened room.
  const observeRoom = currentCallRoomId || currentRoomId;
  attachCallObserver(observeRoom);

  const amInCall = !!(currentCallRoomId && currentUser);
  const isThisRoomsCall = !!(observeRoom && (sanitizeCallRoom(observeRoom) === sanitizeCallRoom(targetRoom)));

  // Determine tooltip + state
  let state = "none";
  let tooltipTitle = "Start Call";

  if (amInCall && isThisRoomsCall){
    state = "in";
    tooltipTitle = "Call Menu";
  } else if (callActive){
    state = "active";
    tooltipTitle = "Join Call";
  } else {
    state = "none";
    tooltipTitle = "Start Call";
  }

  btn.dataset.callState = state;

  btn.classList.toggle("call-active", state === "active");
  btn.classList.toggle("call-in", state === "in");

  const label = $("call-label");
  if (label) label.textContent = tooltipTitle;
}

function ensureCallRuntimeModals(){
  let callMenu = $("call-menu");
  let shareMenu = $("share-menu");

  document.querySelectorAll("#call-menu").forEach((node, idx) => {
    if (idx > 0) node.remove();
  });
  document.querySelectorAll("#share-menu").forEach((node, idx) => {
    if (idx > 0) node.remove();
  });

  if (!callMenu){
    callMenu = document.createElement("div");
    callMenu.className = "call-menu";
    callMenu.id = "call-menu";
    callMenu.hidden = true;
    callMenu.dataset.runtimeModal = "1";
    callMenu.innerHTML = `
      <div class="call-menu-backdrop" aria-hidden="true"></div>
      <div class="call-menu-card" role="dialog" aria-modal="true" aria-label="Call menu">
        <div class="call-menu-head">
          <div class="call-menu-head-main">
            <div class="call-menu-head-top">
              <div class="call-menu-title">Call - Room <span class="call-menu-room" id="call-menu-room">—</span></div>
              <div class="call-quality-chip idle" id="call-menu-quality">Idle</div>
            </div>
            <div class="call-menu-head-sub">
              <div class="call-menu-status-copy">
                <div class="call-menu-status" id="call-menu-status">No live call</div>
                <div class="call-menu-meta" id="call-menu-meta">Nobody else is here yet.</div>
              </div>
            </div>
          </div>
          <button class="icon-btn call-menu-close" id="btn-call-menu-close" type="button" aria-label="Close call menu">
            <svg viewBox="0 0 24 24" width="18" height="18" fill="none">
              <path d="M6 6l12 12M18 6 6 18" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"/>
            </svg>
          </button>
        </div>

        <div class="call-menu-list scrollbar-chatlike" id="call-menu-list"></div>

        <div class="call-menu-foot">
          <div class="call-menu-controls">
            <button class="btn" id="btn-call-mute" type="button">Mute</button>
            <button class="btn" id="btn-call-deafen" type="button">Deafen</button>
            <button class="btn" id="btn-call-share" type="button">Share Screen</button>
            <button class="btn" id="btn-call-spatialaudio" type="button">Spatial Audio: Off</button>
            <button class="btn" id="btn-call-refreshmic" type="button">Refresh Mic</button>
            <button class="btn danger" id="btn-call-leave" type="button">Leave Call</button>
          </div>
        </div>
      </div>`;
    document.body.appendChild(callMenu);
  } else if (callMenu.parentNode !== document.body) {
    document.body.appendChild(callMenu);
  }

  if (!shareMenu){
    shareMenu = document.createElement("div");
    shareMenu.className = "share-menu";
    shareMenu.id = "share-menu";
    shareMenu.hidden = true;
    shareMenu.dataset.runtimeModal = "1";
    shareMenu.innerHTML = `
      <div class="share-menu-backdrop" aria-hidden="true"></div>
      <div class="share-menu-card" role="dialog" aria-modal="true" aria-label="Screen share">
        <div class="share-menu-head">
          <div class="share-menu-title" id="share-menu-title">Screen Share</div>
          <button class="btn share-menu-back" id="btn-share-back" type="button">Back</button>
        </div>

        <div class="share-menu-body">
          <div class="share-placeholder" id="share-placeholder">Waiting for screen share…</div>
          <video class="share-video" id="share-video" autoplay playsinline muted></video>
        </div>
      </div>`;
    document.body.appendChild(shareMenu);
  } else if (shareMenu.parentNode !== document.body) {
    document.body.appendChild(shareMenu);
  }

  return { callMenu, shareMenu };
}

function openCallMenu(){
  const { callMenu: el } = ensureCallRuntimeModals();
  if (!el) return;
  callMenuOpen = true;

  el.hidden = false;
  el.classList.remove("is-open");
  requestAnimationFrame(() => {
    if (!el.hidden) el.classList.add("is-open");
  });

  renderCallMenu();
  syncCallControlsUI();
}

function closeCallMenu(immediate=false){
  const el = $("call-menu");
  callMenuOpen = false;
  if (!el) return;

  const finish = () => {
    el.classList.remove("is-open");
    el.hidden = true;
  };

  if (immediate || (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches)){
    finish();
    return;
  }

  el.classList.remove("is-open");
  setTimeout(finish, 180);
}

function getLiveOrStoredCallUser(m){
  const base = m || {};
  const code = String(base?.code || "").trim();
  if (!code) return base;

  const live = liveUserCache.get(code);
  if (!live) return base;

  // Merge live (display name/username/pfp) into call-state (mute/deafen/speaking)
  return {
    ...base,
    username: live.username ?? base.username,
    usernameLower: (live.usernameLower ?? base.usernameLower) || String(live.username || base.username || "user").toLowerCase(),
    displayName: live.displayName ?? base.displayName ?? live.username ?? base.username,
    displayNameLower: (live.displayNameLower ?? base.displayNameLower) || String(live.displayName || base.displayName || live.username || base.username || "user").toLowerCase(),
    photoDataURL: live.photoDataURL ?? base.photoDataURL,
    photoTransform: live.photoTransform ?? base.photoTransform
  };
}

function renderCallMenu(){
  const list = $("call-menu-list");
  if (!list) return;

  callSyncMenuStatusDisplay();
  list.innerHTML = "";
  const frag = document.createDocumentFragment();

  for (const raw of callMembersCache){
    const u = getLiveOrStoredCallUser(raw);

    const outer = document.createElement("div");
    outer.className = "call-user";

    const bubble = document.createElement("div");
    bubble.className = "call-user-bubble";

    const ava = document.createElement("div");
    ava.className = "call-user-avatar";
    if (u && u.code) ava.dataset.usercode = String(u.code);

    if (raw?.speaking) ava.classList.add("speaking");

    const name = document.createElement("div");
    name.className = "call-user-name";
    if (u?.code) name.dataset.displayNameUsercode = String(u.code);
    name.textContent = u?.displayName || u?.username || "User";

    const badges = document.createElement("div");
    badges.className = "call-user-badges";

    const addBadge = (text, kind="neutral") => {
      const badge = document.createElement("span");
      badge.className = `call-user-badge ${kind}`;
      badge.textContent = text;
      badges.appendChild(badge);
    };

    if (currentUser && String(raw?.code || "") === String(currentUser.code)) addBadge("You", "self");
    if (raw?.muted) addBadge("Muted", "danger");
    if (raw?.deafened) addBadge("Deafened", "danger");
    if (raw?.sharing) addBadge("Sharing", "primary");

    const peerStatus = callPeerStatusCache.get(String(raw?.code || ""));
    if (peerStatus && String(raw?.code || "") !== String(currentUser?.code || "")){
      const isReconnecting =
        ["connecting", "disconnected", "failed"].includes(String(peerStatus.connectionState || "")) ||
        ["checking", "disconnected", "failed"].includes(String(peerStatus.iceConnectionState || ""));
      if (isReconnecting){
        addBadge("Reconnecting", "warn");
      } else if (peerStatus.receivingAudio){
        addBadge("Audio live", "success");
      }
    }

    applyAvatar(ava, u);

    const muted = !!raw?.muted;
    const deafened = !!raw?.deafened;
    const sharing = !!raw?.sharing;

    if (muted || deafened || sharing){
      const ind = document.createElement("div");
      ind.className = "call-user-indicator";

      if (muted || deafened){
        const icon = document.createElement("div");
        icon.className = "indicator-icon";
        icon.innerHTML = deafened ? `
        <svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
          <path d="M4 12a8 8 0 0 1 16 0" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M4 12v6a2 2 0 0 0 2 2h1v-8H6a2 2 0 0 0-2 2Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M20 12v6a2 2 0 0 1-2 2h-1v-8h1a2 2 0 0 1 2 2Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M4 4 20 20" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>` : `
        <svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
          <path d="M12 14a3 3 0 0 0 3-3V7a3 3 0 0 0-6 0v4a3 3 0 0 0 3 3Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M5 11a7 7 0 0 0 11.2 5.6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M12 18v3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M8 21h8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M4 4 20 20" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>`;
        ind.appendChild(icon);
      }

      if (sharing){
        const icon2 = document.createElement("div");
        icon2.className = "indicator-icon share";
        icon2.innerHTML = `
        <svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
          <path d="M4 6.5A2.5 2.5 0 0 1 6.5 4h11A2.5 2.5 0 0 1 20 6.5v7A2.5 2.5 0 0 1 17.5 16h-11A2.5 2.5 0 0 1 4 13.5v-7Z" stroke="currentColor" stroke-width="2"/>
          <path d="M9 20h6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          <path d="M12 16v4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>`;
        ind.appendChild(icon2);
      }

      bubble.appendChild(ind);
    }

    ava.addEventListener("click", () => {
      if (!raw?.sharing) return;
      openShareView(String(raw.code || ""), String(u?.displayName || u?.username || "User"));
    });

    bubble.appendChild(ava);
    bubble.appendChild(name);
    if (badges.childNodes.length) bubble.appendChild(badges);
    outer.appendChild(bubble);

    frag.appendChild(outer);
  }

  list.appendChild(frag);
}

function callStartHeartbeat(){
  if (!myCallMemberRef) return;
  if (callHeartbeatTimer) clearInterval(callHeartbeatTimer);

  callHeartbeatTimer = setInterval(() => {
    if (!myCallMemberRef || !currentUser || !currentCallRoomId) return;
    try{
      myCallMemberRef.update({
        connected: true,
        lastSeenAt: firebase.database.ServerValue.TIMESTAMP,
        updatedAt: firebase.database.ServerValue.TIMESTAMP
      });
    }catch{}
  }, CALL_HEARTBEAT_MS);
}

function callStopHeartbeat(){
  if (callHeartbeatTimer){
    try{ clearInterval(callHeartbeatTimer); }catch{}
  }
  callHeartbeatTimer = null;
}

async function joinCall(roomId, { openMenu=true } = {}){
  if (!currentUser) return;
  const id = sanitizeCallRoom(roomId);
  if (!id) return;

  const opToken = ++callLifecycleToken;

  // If already in another call, do nothing (button should represent that call)
  if (currentCallRoomId && sanitizeCallRoom(currentCallRoomId) !== id) return;

  // Hard-reset any lingering transport/signaling before a fresh join to this room.
  if (currentCallRoomId === id){
    callStopHeartbeat();
    callStopWebRTC({ roomId: id });
  }
  if (callConnRef && callConnCb){
    try{ callConnRef.off("value", callConnCb); }catch{}
  }
  callConnRef = null;
  callConnCb = null;
  if (myCallMemberRef){
    try{ myCallMemberRef.onDisconnect().cancel(); }catch{}
  }
  myCallMemberRef = null;

  // 1) Ask for microphone permission first
  const stream = await callRequestMicPermission();
  if (!stream) return;

  if (callLifecycleToken !== opToken){
    try{ stream.getTracks().forEach((t) => { try{ t.stop(); }catch{}; }); }catch{}
    return;
  }

  // 2) Advisory connectivity preflight. It never blocks joins and never shows a false TURN failure.
  void callPreflightStun();

  // Now we can open the menu
  if (openMenu) openCallMenu();

  // Ensure we observe this room now
  attachCallObserver(id);

  // Initialize local call audio state
  callAttachLocalStream(stream);

  if (callLifecycleToken !== opToken){
    callStopWebRTC({ roomId: id });
    return;
  }

  currentCallRoomId = id;
  const sessionId = makeCallSessionId();
  callSessionId = sessionId;

  // Persist "in call" so refresh will force-leave on next load
  try{ localStorage.setItem(LS.CALL_ROOM, id); }catch{}

  // Optimistically show yourself instantly in the menu (then realtime will correct)
  const self = {
    code: currentUser.code,
    sessionId,
    username: currentUser.username || "User",
    usernameLower: String(currentUser.username || "User").toLowerCase(),
    displayName: currentUser.displayName || currentUser.username || "User",
    displayNameLower: String(currentUser.displayName || currentUser.username || "User").toLowerCase(),
    photoDataURL: currentUser.photoDataURL || null,
    photoTransform: currentUser.photoTransform || null,
    muted: false,
    deafened: false,
    speaking: false,
    sharing: false,
    connected: true,
    joinedAt: Date.now()
  };
  if (!callMembersCache.some((x) => String(x.code||"") === String(self.code))){
    callMembersCache = [self, ...callMembersCache];
  } else {
    callMembersCache = callMembersCache.map((x) => String(x.code||"") === String(self.code) ? { ...x, ...self } : x);
  }
  callMembersCache.sort((a,b) => String(a.displayNameLower || a.usernameLower || "").localeCompare(String(b.displayNameLower || b.usernameLower || "")));
  syncCallButton();
  if (callMenuOpen) renderCallMenu();

  // Create/refresh member record
  const memberRef = db.ref(`calls/${id}/members/${currentUser.code}`);
  myCallMemberRef = memberRef;

  const payload = {
    code: currentUser.code,
    sessionId,
    username: currentUser.username || "User",
    usernameLower: String(currentUser.username || "User").toLowerCase(),
    displayName: currentUser.displayName || currentUser.username || "User",
    displayNameLower: String(currentUser.displayName || currentUser.username || "User").toLowerCase(),
    photoDataURL: currentUser.photoDataURL || null,
    photoTransform: currentUser.photoTransform || null,
    muted: false,
    deafened: false,
    speaking: false,
    sharing: false,
    connected: true,
    lastSeenAt: firebase.database.ServerValue.TIMESTAMP,
    joinedAt: firebase.database.ServerValue.TIMESTAMP,
    updatedAt: firebase.database.ServerValue.TIMESTAMP
  };

  // onDisconnect safety: if tab closes, user leaves call
  try{
    await memberRef.onDisconnect().update({
      connected: false,
      disconnectedAt: firebase.database.ServerValue.TIMESTAMP,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}

  if (callLifecycleToken !== opToken){
    try{ memberRef.onDisconnect().cancel(); }catch{}
    try{ await memberRef.remove(); }catch{}
    return;
  }

  try{
    await db.ref().update({
      [`calls/${id}/active`]: true,
      [`calls/${id}/updatedAt`]: firebase.database.ServerValue.TIMESTAMP,
      [`calls/${id}/members/${currentUser.code}`]: payload
    });
  }catch(e){
    console.error("joinCall failed:", e);
    if (callLifecycleToken === opToken && currentCallRoomId === id && callSessionId === sessionId){
      currentCallRoomId = null;
      callSessionId = null;
      try{ memberRef.onDisconnect().cancel(); }catch{}
      if (myCallMemberRef === memberRef) myCallMemberRef = null;
      try{ localStorage.removeItem(LS.CALL_ROOM); }catch{}
      syncCallButton();
    }
    try{ stream.getTracks().forEach((t) => { try{ t.stop(); }catch{}; }); }catch{}
    return;
  }

  if (callLifecycleToken !== opToken || currentCallRoomId !== id || callSessionId !== sessionId || myCallMemberRef !== memberRef){
    try{ memberRef.onDisconnect().cancel(); }catch{}
    try{ await memberRef.remove(); }catch{}
    return;
  }

  playSfx("join");

  // Re-assert on reconnect and force peer refreshes so rejoin/network blips do not leave stale media.
  callConnRef = db.ref(".info/connected");
  callConnCb = (snap) => {
    if (callLifecycleToken !== opToken) return;
    if (snap.val() === true && myCallMemberRef === memberRef && currentUser && currentCallRoomId === id && callSessionId === sessionId){
      try{
        memberRef.onDisconnect().update({
          connected: false,
          disconnectedAt: firebase.database.ServerValue.TIMESTAMP,
          updatedAt: firebase.database.ServerValue.TIMESTAMP
        });
      }catch{}
      try{
        memberRef.update({
          sessionId,
          muted: !!callMuted,
          deafened: !!callDeafened,
          sharing: !!callSharing,
          connected: true,
          lastSeenAt: firebase.database.ServerValue.TIMESTAMP,
          updatedAt: firebase.database.ServerValue.TIMESTAMP
        });
      }catch{}
      setTimeout(() => {
        if (currentCallRoomId === id && callSessionId === sessionId){
          void callEnsurePeers(id);
          for (const peer of callPeerMap.keys()) callRequestPeerMediaRefresh(peer, "firebase-reconnect");
        }
      }, 350);
    }
  };
  callConnRef.on("value", callConnCb);
  callStartHeartbeat();

  syncCallButton();
  syncCallControlsUI();
  callStartWebRTC(id);
  if (callMenuOpen) renderCallMenu();
}

async function leaveCall({ roomId=null, quiet=false } = {}){
  const id = sanitizeCallRoom(roomId || currentCallRoomId);
  if (!id) return;

  const opToken = ++callLifecycleToken;
  const leavingRoomId = String(currentCallRoomId || id);
  const leavingMemberRef = myCallMemberRef;
  const leavingConnRef = callConnRef;
  const leavingConnCb = callConnCb;

  playSfx("leave");

  // Stop heartbeat + share first so others don't see frozen/share artifacts
  callStopHeartbeat();
  if (callSharing) callStopShareScreen(true);
  closeShareView(true);

  callStopWebRTC({ roomId: id });
  try{ localStorage.removeItem(LS.CALL_ROOM); }catch{}

  // Detach connection listener
  if (leavingConnRef && leavingConnCb){
    try{ leavingConnRef.off("value", leavingConnCb); }catch{}
  }
  if (callConnRef === leavingConnRef) callConnRef = null;
  if (callConnCb === leavingConnCb) callConnCb = null;

  // Remove my membership record
  if (leavingMemberRef){
    try{ leavingMemberRef.onDisconnect().cancel(); }catch{}
    try{ await leavingMemberRef.remove(); }catch{}
  } else if (currentUser){
    try{ await db.ref(`calls/${id}/members/${currentUser.code}`).remove(); }catch{}
  }
  if (myCallMemberRef === leavingMemberRef) myCallMemberRef = null;

  // If no members remain, remove the call node completely
  try{
    const snap = await db.ref(`calls/${id}/members`).once("value");
    const left = snap.val() || null;
    if (!left || !Object.keys(left).length){
      await db.ref(`calls/${id}`).remove();
    }
  }catch{}

  if (callLifecycleToken !== opToken) return;

  currentCallRoomId = null;
  callSessionId = null;

  closeCallMenu(true);

  // Switch observer back to current room (if any)
  if (currentRoomId) attachCallObserver(currentRoomId);
  else detachCallObserver();

  syncCallButton();

  if (!quiet && leavingRoomId){
    showToast({ title:"Left call", body:`You left the call in ${id}.`, duration: 2000 });
  }
}

async function leaveStaleCallFromPreviousSession(){
  if (!currentUser) return;
  const stale = sanitizeCallRoom(localStorage.getItem(LS.CALL_ROOM));
  if (!stale) return;

  // We consider refresh as "leave": remove your membership immediately
  try{ await db.ref(`calls/${stale}/members/${currentUser.code}`).remove(); }catch{}

  // Cleanup call node if it became empty
  try{
    const snap = await db.ref(`calls/${stale}/members`).once("value");
    const left = snap.val() || null;
    if (!left || !Object.keys(left).length){
      await db.ref(`calls/${stale}`).remove();
    }
  }catch{}

  try{ localStorage.removeItem(LS.CALL_ROOM); }catch{}
}

(function bindCallUI(){
  ensureCallRuntimeModals();

  const btn = $("btn-side-call");
  if (btn){
    btn.addEventListener("click", async (e) => {
      e.preventDefault();
      e.stopPropagation();

      if (currentCallRoomId){
        openCallMenu();
        return;
      }

      if (!currentRoomId) return;

      await joinCall(currentRoomId, { openMenu:true });
    });
  }

  $("btn-call-menu-close")?.addEventListener("click", () => closeCallMenu());

  $("btn-call-mute")?.addEventListener("click", () => callToggleMute());
  $("btn-call-deafen")?.addEventListener("click", () => callToggleDeafen());
  $("btn-call-share")?.addEventListener("click", () => callToggleShareScreen());
  $("btn-call-spatialaudio")?.addEventListener("click", () => callToggleSpatialAudio());
  $("btn-call-refreshmic")?.addEventListener("click", () => { void callRefreshMic(); });

  $("btn-call-leave")?.addEventListener("click", async () => {
    await leaveCall({ roomId: currentCallRoomId, quiet:true });
  });

  $("btn-share-back")?.addEventListener("click", () => closeShareView(true));

  $("call-menu")?.addEventListener("click", (e) => {
    if (e.target === $("call-menu") || e.target?.classList?.contains("call-menu-backdrop")) closeCallMenu();
  });

  $("share-menu")?.addEventListener("click", (e) => {
    if (e.target === $("share-menu") || e.target?.classList?.contains("share-menu-backdrop")) closeShareView();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (shareViewOpen){
      closeShareView();
      return;
    }
    if (callMenuOpen) closeCallMenu();
  });
})();

function hardClearComposerAndOverlays(){
  try{ cancelEditMessage({ quiet:true }); }catch{}
  try{ clearReplyState({ quiet:true }); }catch{}
  try{ clearPendingFiles({ quiet:true }); }catch{}
  try{ closePingBar({ quiet:true }); }catch{}
  try{ $("msg-input").value = ""; }catch{}
  try{ syncChatOverlayMetrics(); }catch{}
  try{ closeMsgMenu(true); }catch{}
}

async function clearRoomMessages(roomId){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  // Delete all messages + clear room preview/meta
  await db.ref(`messages/${id}`).remove();
  const clearedMetaPatch = {
    lastMessageAt: null,
    lastMessagePreview: null,
    messageCount: 0
  };
  try{
    await db.ref(`rooms/${id}`).update(clearedMetaPatch);
  }catch{}

  roomsMetaCache.set(id, { ...(roomsMetaCache.get(id) || {}), ...clearedMetaPatch });
  scheduleRoomsListCacheSave();
  updateRoomListItem(id);
  if (currentRoomId === id){
    setHeaderRoom(id);
    renderRoomSidebarHeader(id);
  }

  // Also delete ALL per-video prefs, ping inbox entries, and unread counters for this room (for all members)
  try{
    const ms = await db.ref("memberships").once("value");
    const all = ms.val() || {};
    const updates = {};
    for (const [userCode, rooms] of Object.entries(all)){
      if (rooms && Object.prototype.hasOwnProperty.call(rooms, id)){
        updates[`users/${userCode}/prefs/videoPlayerByRoom/${id}`] = null;
        updates[`memberships/${userCode}/${id}/lastSeenCount`] = 0;
        updates[`pings/${userCode}/${id}`] = null;
      }
    }
    if (Object.keys(updates).length) await db.ref().update(updates);
  }catch{}

  // If currently viewing this room, reset the entire chat window (prevents edge bugs)
  if (currentRoomId === id){
    hardClearComposerAndOverlays();     // closes reply bar + file bar instantly (your “weird scenario” fix)
    try{ hideMissedBanner({ immediate:true }); }catch{}
    try{ await openRoom(id, { quiet:true }); }catch{}   // full reset of message listeners/UI
  }
}

async function deleteRoomEverywhere(roomId){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  // Root multi-path delete (null removes)
  const updates = {
    [`rooms/${id}`]: null,
    [`messages/${id}`]: null,
    [`calls/${id}`]: null
  };

  // Remove the room from EVERYONE'S room list + delete per-room video prefs
  try{
    const ms = await db.ref("memberships").once("value");
    const all = ms.val() || {};
    for (const [userCode, rooms] of Object.entries(all)){
      if (rooms && Object.prototype.hasOwnProperty.call(rooms, id)){
        updates[`memberships/${userCode}/${id}`] = null;
        updates[`users/${userCode}/prefs/videoPlayerByRoom/${id}`] = null;
        updates[`users/${userCode}/${ADMIN_GHOST_ROOMS_NODE}/${id}`] = null;
        updates[`pings/${userCode}/${id}`] = null;
      }
    }
  }catch{}

  // Remove deleted-room pins for every user who pinned it, even if they are not currently a member.
  try{
    const usersSnap = await db.ref("users").once("value");
    const users = usersSnap.val() || {};
    for (const [userCode, user] of Object.entries(users)){
      const pinned = user?.prefs?.pinnedRooms;
      if (pinned && Object.prototype.hasOwnProperty.call(pinned, id)){
        updates[`users/${userCode}/prefs/pinnedRooms/${id}`] = null;
      }
    }
  }catch{}

  await db.ref().update(updates);

  if (pinnedRoomIds.has(id)){
    const nextPins = getPinnedRoomSet();
    nextPins.delete(id);
    setPinnedRoomSetLocal(nextPins);
    refreshRoomCollectionsUI();
  }

  // If I’m in it, leave to Home immediately
  if (currentRoomId === id){
    hardClearComposerAndOverlays();
    showLoggedInHome();
  }
}

function openAdminPanel(){
  if (!isVinny()) return;
  
  openModal({
    title: "Panel",
    bodyHTML: `
      <div class="label" style="margin:0 0 10px">School Day</div>
      <div class="settings-choice-row" id="panel-day-buttons">
        <button class="btn tiny" data-panel-day="1" type="button">1</button>
        <button class="btn tiny" data-panel-day="2" type="button">2</button>
        <button class="btn tiny" data-panel-day="3" type="button">3</button>
        <button class="btn tiny" data-panel-day="4" type="button">4</button>
        <button class="btn tiny" data-panel-day="5" type="button">5</button>
        <button class="btn tiny" data-panel-day="6" type="button">6</button>
        <button class="btn tiny primary" data-panel-day="na" type="button">N/A</button>
      </div>

      <div style="height:16px"></div>

      <div class="label" style="margin:0 0 10px">Schedule Type</div>
      <div class="settings-choice-row" id="panel-schedtypes">
        <button class="btn tiny" data-panel-schedtype="full" type="button">Full Day</button>
        <button class="btn tiny" data-panel-schedtype="half" type="button">Half Day</button>
        <button class="btn tiny" data-panel-schedtype="delay2" type="button">2 HR Delay</button>
      </div>

      <div style="height:16px"></div>

      <div class="label" style="margin:0 0 10px">Account Creation</div>
      <div class="settings-choice-row" id="panel-account-creation">
        <button class="btn tiny" data-panel-account-creation="enabled" type="button">Enabled</button>
        <button class="btn tiny primary" data-panel-account-creation="disabled" type="button">Disabled</button>
      </div>

      <div style="height:16px"></div>

      <div class="label" style="margin:0 0 10px">Room Management</div>
      <div class="panel-rooms" id="panel-rooms"><div class="muted small">Loading…</div></div>
    `,
    actionsHTML: `
      <button class="btn" id="btn-panel-refresh" type="button">Refresh</button>
    `
  });

  $("btn-panel-refresh")?.addEventListener("click", () => loadAdminPanelRooms());

  // Day + Schedule Type + Account Creation controls (Vinny only)
  startSchoolDayListener();
  startScheduleTypeListener();
  startAccountCreationListener();
  startSchedulesPeopleListener();

  const dayWrap = $("panel-day-buttons");
  const schedWrap = $("panel-schedtypes");
  const accountWrap = $("panel-account-creation");

  if (dayWrap){
    dayWrap.querySelectorAll("[data-panel-day]").forEach(btn => {
      const k = btn.getAttribute("data-panel-day") || "na";
      const isActive = (k === "na") ? !schoolDay : k === String(schoolDay || "");
      btn.classList.toggle("primary", isActive);
    });

    if (dayWrap.dataset.bound !== "1"){
      dayWrap.dataset.bound = "1";
      dayWrap.addEventListener("click", async (e) => {
        const btn = e.target.closest("button[data-panel-day]");
        if (!btn) return;

        const k = btn.getAttribute("data-panel-day") || "na";
        try{
          if (k === "na"){
            await clearSchoolDay();
            showToast({ title:"Day cleared", body:"School day set to N/A.", duration: 1600 });
          } else {
            await setSchoolDay(k);
            showToast({ title:"Day set", body:`Day ${k} saved.`, duration: 1600 });
          }
        }catch(err){
          console.error("set day failed:", err);
          showToast({ title:"Failed", body:"Could not save day. Check console / rules.", duration: 2600 });
        }
      });
    }
  }

  if (schedWrap){
    schedWrap.querySelectorAll("[data-panel-schedtype]").forEach(btn => {
      const k = btn.getAttribute("data-panel-schedtype") || "full";
      btn.classList.toggle("primary", _normalizeScheduleType(k) === _normalizeScheduleType(scheduleType));
    });

    if (schedWrap.dataset.bound !== "1"){
      schedWrap.dataset.bound = "1";
      schedWrap.addEventListener("click", async (e) => {
        const btn = e.target.closest("button[data-panel-schedtype]");
        if (!btn) return;
        const k = btn.getAttribute("data-panel-schedtype") || "full";
        try{
          await setScheduleType(k);
          showToast({ title:"Schedule type saved", body:`Now set to ${_scheduleTypeLabel(k)}.`, duration: 1700 });
        }catch(err){
          console.error("set scheduleType failed:", err);
          showToast({ title:"Failed", body:"Could not save schedule type. Check console / rules.", duration: 2600 });
        }
      });
    }
  }

  if (accountWrap){
    accountWrap.querySelectorAll("[data-panel-account-creation]").forEach(btn => {
      const k = btn.getAttribute("data-panel-account-creation") || "disabled";
      btn.classList.toggle("primary", (k === "enabled") === accountCreationEnabled);
    });

    if (accountWrap.dataset.bound !== "1"){
      accountWrap.dataset.bound = "1";
      accountWrap.addEventListener("click", async (e) => {
        const btn = e.target.closest("button[data-panel-account-creation]");
        if (!btn) return;

        const enabled = (btn.getAttribute("data-panel-account-creation") || "disabled") === "enabled";
        try{
          await setAccountCreationEnabled(enabled);
          showToast({
            title:"Account creation saved",
            body: `Account creation ${enabled ? "enabled" : "disabled"}.`,
            duration: 1700
          });
        }catch(err){
          console.error("set account creation failed:", err);
          showToast({ title:"Failed", body:"Could not save account creation. Check console / rules.", duration: 2600 });
        }
      });
    }
  }

  const listEl = $("panel-rooms");
  if (listEl && listEl.dataset.bound !== "1"){
    listEl.dataset.bound = "1";
    listEl.addEventListener("click", async (e) => {
      const btn = e.target.closest("button[data-panel-act]");
      if (!btn) return;
      const act = btn.getAttribute("data-panel-act");
      const rid = btn.getAttribute("data-room-id");
      if (!act || !rid) return;

      btn.disabled = true;
      try{
        if (act === "clear"){
          await clearRoomMessages(rid);
          showToast({ title:"Messages cleared", body:`Cleared all messages in ${rid}.`, duration: 2000 });
          await loadAdminPanelRooms();
        } else if (act === "join"){
          await joinRoomFromPanel(rid);
        } else if (act === "ghost"){
          await setGhostModeForRoom(rid, !isGhostModeEnabledForRoom(rid, currentUser.code));
          await loadAdminPanelRooms();
        } else if (act === "delete"){
          await deleteRoomFromPanel(rid);
        }
      }catch(err){
        console.error("panel action failed:", err);
        showToast({ title:"Action failed", body:"Check console / rules.", duration: 2600 });
      } finally {
        btn.disabled = false;
      }
    });
  }

  loadAdminPanelRooms();
}

async function loadAdminPanelRooms(){
  if (!isVinny()) return;
  const listEl = $("panel-rooms");
  if (!listEl) return;

  try{
    const base = String(firebaseConfig?.databaseURL || "").replace(/\/+$/, "");
    if (!base) throw new Error("Missing databaseURL.");

    const [roomsRes, ghostSnap] = await Promise.all([
      fetch(`${base}/rooms.json?shallow=true`, { cache:"no-store" }),
      db.ref(`users/${currentUser.code}/${ADMIN_GHOST_ROOMS_NODE}`).once("value")
    ]);

    if (!roomsRes.ok) throw new Error(`Room key fetch failed: ${roomsRes.status}`);

    const roomKeyData = await roomsRes.json();
    const ghostRooms = normalizeAdminGhostRooms(ghostSnap.val() || {});
    const rooms = roomKeyData && typeof roomKeyData === "object"
      ? Object.keys(roomKeyData)
          .map((rawId) => sanitizeRoomCode(rawId))
          .filter(Boolean)
          .map((id) => ({
            id,
            displayName: roomDisplayName(id, roomsMetaCache.get(id) || null) || id
          }))
      : [];

    rooms.sort((a,b) => String(a.displayName || a.id).localeCompare(String(b.displayName || b.id)));

    if (!rooms.length){
      listEl.innerHTML = `<div class="empty"><div class="empty-title">No rooms.</div><div class="empty-sub">Nothing to manage yet.</div></div>`;
      return;
    }

    listEl.innerHTML = `
      <div class="panel-room-grid">
        ${rooms.map(({ id, displayName }) => {
          const ghostOn = !!ghostRooms[id];
          return `
            <div class="panel-room ${ghostOn ? "ghost-active" : ""}">
              <div class="panel-room-card-main">
                <div class="panel-room-name" data-panel-room-name="${escapeAttr(id)}">${escapeHtml(displayName)}</div>
              </div>
              <div class="panel-room-actions">
                <button class="btn tiny" type="button" data-panel-act="join" data-room-id="${escapeAttr(id)}">Join</button>
                <button class="btn tiny" type="button" data-panel-act="clear" data-room-id="${escapeAttr(id)}">Clear</button>
                <button class="btn tiny ${ghostOn ? "primary" : ""}" type="button" data-panel-act="ghost" data-room-id="${escapeAttr(id)}">${ghostOn ? "Ghost On" : "Ghost Off"}</button>
                <button class="btn tiny danger" type="button" data-panel-act="delete" data-room-id="${escapeAttr(id)}">Delete</button>
              </div>
            </div>
          `;
        }).join("")}
      </div>
    `;

    rooms.forEach(({ id }) => {
      db.ref(`rooms/${id}/name`).once("value").then((nameSnap) => {
        const name = String(nameSnap.val() || id);
        const currentMeta = roomsMetaCache.get(id) || {};
        roomsMetaCache.set(id, { ...currentMeta, name });

        const nameEl = listEl.querySelector(`[data-panel-room-name="${CSS.escape(id)}"]`);
        if (nameEl) nameEl.textContent = name;
      }).catch(() => {});
    });

  }catch(e){
    console.error("panel load rooms failed:", e);
    listEl.innerHTML = `<div class="muted small">Failed to load rooms.</div>`;
  }
}
async function joinRoomFromPanel(roomId){
  const id = sanitizeRoomCode(roomId);
  if (!id || !currentUser || !isVinny()) return;

  const roomSnap = await db.ref(`rooms/${id}`).once("value");
  if (!roomSnap.exists()){
    showToast({ title:"Not found", body:"That room doesn’t exist anymore.", duration: 2400 });
    await loadAdminPanelRooms();
    return;
  }

  const roomMeta = roomSnap.val() || {};
  const displayName = roomDisplayName(id, roomMeta);
  const roomMessageCount = Math.max(0, Number(roomMeta?.messageCount) || 0);

  // Admin-panel join intentionally bypasses private room passwords.
  try{
    await db.ref(`memberships/${currentUser.code}/${id}`).update({
      joinedAt: firebase.database.ServerValue.TIMESTAMP,
      lastSeenAt: 0,
      lastSeenCount: roomMessageCount
    });
  }catch{}

  // Immediately reflect locally (no wait for listener)
  membershipMap.set(id, { joinedAt: Date.now(), lastSeenAt: 0, lastSeenCount: roomMessageCount });
  roomsMetaCache.set(id, roomMeta);
  renderRoomsList();

  closeModal();
  showToast({ title:"Joined", body:`Joined ${displayName}.`, duration: 2000 });
  openRoom(id);
}
async function deleteRoomFromPanel(roomId){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;
  const displayName = roomDisplayName(id, roomsMetaCache.get(id) || null);

  const confirmId = `panel_delete_confirm_${Math.random().toString(36).slice(2)}`;
  const cancelId = `panel_delete_cancel_${Math.random().toString(36).slice(2)}`;

  showToast({
    title: "Delete room?",
    bodyHTML: `
      <div class="muted small" style="margin-top:2px">Really delete <span class="strong">${escapeHtml(displayName)}</span>? This removes the room and its data.</div>
      <div style="display:flex; gap:10px; margin-top:10px">
        <button class="btn tiny danger" id="${confirmId}" type="button">Delete Room</button>
        <button class="btn tiny" id="${cancelId}" type="button">Cancel</button>
      </div>
    `,
    duration: 15000
  });

  const confirmBtn = document.getElementById(confirmId);
  const cancelBtn = document.getElementById(cancelId);

  confirmBtn?.addEventListener("click", async () => {
    closeToast();

    try{
      // If this room is open, clear UI instantly
      if (currentRoomId === id) hardClearComposerAndOverlays();

      await deleteRoomEverywhere(id);
      showToast({ title:"Room deleted", body:`Deleted room ${displayName}.`, duration: 2200 });

      // Refresh panel list if it’s still open
      try{ await loadAdminPanelRooms(); }catch{}
    }catch(err){
      console.error("delete room failed:", err);
      showToast({ title:"Delete failed", body:"Check console / rules.", duration: 2600 });
    }
  }, { once:true });

  cancelBtn?.addEventListener("click", () => closeToast(), { once:true });
}

