/* -------------------- Rooms list local cache (instant sidebar paint) -------------------- */
const ROOMS_LIST_CACHE_PREFIX = "chatapp_rooms_cache_v1:";
let roomsListCacheSaveTimer = null;

function roomsListCacheKey(){
  const code = String(currentUser?.code || "").trim();
  return code ? (ROOMS_LIST_CACHE_PREFIX + code) : null;
}

function hydrateRoomsListFromCache(){
  if (!currentUser) return false;
  const k = roomsListCacheKey();
  if (!k) return false;

  try{
    const raw = localStorage.getItem(k);
    if (!raw) return false;

    const obj = JSON.parse(raw);
    const rooms = Array.isArray(obj?.rooms) ? obj.rooms.map((r) => String(r || "").trim()).filter(Boolean) : [];
    if (!rooms.length) return false;

    // Memberships: joinedAt/lastSeenAt will be replaced by the live listener shortly.
    membershipMap = new Map(rooms.map((rid) => [rid, { joinedAt: 0, lastSeenAt: 0, lastSeenCount: 0 }]));

    // Pinned state paints instantly; live pinned-room sync reconciles shortly.
    const cachedPins = Array.isArray(obj?.pinnedRooms)
      ? obj.pinnedRooms.map((r) => sanitizeRoomCode(r)).filter(Boolean)
      : [];
    if (cachedPins.length) setPinnedRoomSetLocal(new Set(cachedPins));

    // Meta (preview/time) paints instantly; per-room listeners will reconcile.
    roomsMetaCache = new Map();
    const meta = (obj && typeof obj.meta === "object" && obj.meta) ? obj.meta : {};
    for (const [rid, m] of Object.entries(meta)){
      if (rid && m && typeof m === "object") roomsMetaCache.set(rid, m);
    }

    renderRoomsList();
    return true;
  }catch{
    return false;
  }
}

function saveRoomsListCacheNow(){
  if (!currentUser) return;
  const k = roomsListCacheKey();
  if (!k) return;

  try{
    const rooms = Array.from(new Set(membershipMap.keys())).sort((a,b) => a.localeCompare(b));
    const pinnedRooms = Array.from(getPinnedRoomSet()).sort((a,b) => a.localeCompare(b));
    const meta = {};
    for (const rid of rooms){
      const m = roomsMetaCache.get(rid);
      if (!m || typeof m !== "object") continue;
      meta[rid] = {
        name: String(m.name || ""),
        private: !!m.private,
        photoDataURL: String(m.photoDataURL || ""),
        photoTransform: (m.photoTransform && typeof m.photoTransform === "object") ? m.photoTransform : null,
        lastMessagePreview: m.lastMessagePreview || "",
        lastMessageAt: m.lastMessageAt || 0,
        messageCount: Number(m.messageCount) || 0
      };
    }
    localStorage.setItem(k, JSON.stringify({ savedAt: Date.now(), rooms, pinnedRooms, meta }));
  }catch{}
}

function scheduleRoomsListCacheSave(){
  if (roomsListCacheSaveTimer) return;
  roomsListCacheSaveTimer = setTimeout(() => {
    roomsListCacheSaveTimer = null;
    saveRoomsListCacheNow();
  }, 260);
}

