const SFX_URLS = {
  JOIN_CALL: "https://cdn.jsdelivr.net/gh/dowsy456/lumensounds@main/Join%20Call.mp3",
  LEAVE_CALL: "https://cdn.jsdelivr.net/gh/dowsy456/lumensounds@main/Leave%20Call.mp3",
  NOTIFICATION: "https://cdn.jsdelivr.net/gh/dowsy456/lumensounds@main/Pinged.mp3",
  TIMER_END: "https://cdn.jsdelivr.net/gh/dowsy456/lumensounds@main/AlarmEnd.mp3"
};
let sfxEls = null; // { join, leave, notif, timer }
let sfxUnlocked = false;
let sfxUnlockBound = false;

function initSfxEls(){
  if (sfxEls) return sfxEls;
  sfxEls = {
    join: new Audio(SFX_URLS.JOIN_CALL),
    leave: new Audio(SFX_URLS.LEAVE_CALL),
    notif: new Audio(SFX_URLS.NOTIFICATION),
    timer: new Audio(SFX_URLS.TIMER_END)
  };
  for (const a of Object.values(sfxEls)){
    try{ a.preload = "auto"; }catch{}
  }
  return sfxEls;
}

function playSfx(kind){
  if (!soundEffectsEnabled) return;
  const map = initSfxEls();
  const a = map[kind];
  if (!a) return;
  try{
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === "function") p.catch(()=>{});
  }catch{}
}

function unlockSfxOnce(){
  if (sfxUnlocked) return;
  sfxUnlocked = true;

  const map = initSfxEls();
  for (const a of Object.values(map)){
    try{
      const prevVol = a.volume;
      const prevMuted = a.muted;
      a.volume = 0;
      a.muted = true;

      const p = a.play();
      if (p && typeof p.finally === "function"){
        p.catch(()=>{}).finally(() => {
          try{ a.pause(); a.currentTime = 0; }catch{}
          try{ a.muted = prevMuted; a.volume = prevVol; }catch{}
        });
      } else {
        setTimeout(() => {
          try{ a.pause(); a.currentTime = 0; }catch{}
          try{ a.muted = prevMuted; a.volume = prevVol; }catch{}
        }, 0);
      }
    }catch{}
  }
}

function bindSfxUnlock(){
  if (sfxUnlockBound) return;
  sfxUnlockBound = true;
  const fn = () => unlockSfxOnce();
  window.addEventListener("pointerdown", fn, { once:true, capture:true });
  window.addEventListener("keydown", fn, { once:true, capture:true });
}

let accidentalClosePreventionEnabled = false;
let accidentalCloseBeforeUnloadBound = false;

function accidentalCloseBeforeUnload(e){
  e.preventDefault();
  e.returnValue = "";
  return "";
}
function syncAccidentalClosePrevention(){
  if (accidentalClosePreventionEnabled){
    if (!accidentalCloseBeforeUnloadBound){
      window.addEventListener("beforeunload", accidentalCloseBeforeUnload);
      accidentalCloseBeforeUnloadBound = true;
    }
  } else {
    if (accidentalCloseBeforeUnloadBound){
      window.removeEventListener("beforeunload", accidentalCloseBeforeUnload);
      accidentalCloseBeforeUnloadBound = false;
    }
  }
}

