// Slideshow audio players (persist across stage re-renders so selection doesn't stop playback)
const slideshowAudioPlayers = new Map(); // key -> { audio: HTMLAudioElement, uis: Map<string, Function> }
let slideshowAudioHostEl = null;

function ensureSlideshowAudioHost(){
  if (slideshowAudioHostEl && document.body.contains(slideshowAudioHostEl)) return slideshowAudioHostEl;
  let host = document.getElementById("slideshow-audio-host");
  if (!host){
    host = document.createElement("div");
    host.id = "slideshow-audio-host";
    host.style.position = "fixed";
    host.style.left = "-99999px";
    host.style.top = "0";
    host.style.width = "1px";
    host.style.height = "1px";
    host.style.overflow = "hidden";
    host.style.pointerEvents = "none";
    document.body.appendChild(host);
  }
  slideshowAudioHostEl = host;
  return host;
}

function slideshowAudioKey(slideId, objId){
  return `${String(slideId || "")}:${String(objId || "")}`;
}

function getOrCreateSlideshowAudio(slideId, objId, src){
  const key = slideshowAudioKey(slideId, objId);
  let rec = slideshowAudioPlayers.get(key);
  if (!rec){
    const audio = document.createElement("audio");
    audio.preload = "metadata";
    audio.playsInline = true;
    ensureSlideshowAudioHost().appendChild(audio);

    rec = { audio, uis: new Map() };
    slideshowAudioPlayers.set(key, rec);

    const broadcast = () => {
      for (const [uiKey, fn] of Array.from(rec.uis.entries())){
        try{ fn(); }catch{ rec.uis.delete(uiKey); }
      }
    };

    let raf = 0;
    const tick = () => {
      broadcast();
      if (!audio.paused) raf = requestAnimationFrame(tick);
      else raf = 0;
    };

    audio.addEventListener("play", () => {
      if (!raf) raf = requestAnimationFrame(tick);
      broadcast();
    });
    audio.addEventListener("pause", () => {
      if (raf){ cancelAnimationFrame(raf); raf = 0; }
      broadcast();
    });
    audio.addEventListener("ended", () => {
      if (raf){ cancelAnimationFrame(raf); raf = 0; }
      broadcast();
    });
    audio.addEventListener("timeupdate", broadcast);
    audio.addEventListener("loadedmetadata", broadcast);
    audio.addEventListener("volumechange", broadcast);
    audio.addEventListener("ratechange", broadcast);
  }
  try{
    const nextSrc = String(src || "");
    if (nextSrc && rec.audio.src !== nextSrc) rec.audio.src = nextSrc;
  }catch{}
  return rec;
}

function stopAllSlideshowAudio(){
  for (const rec of slideshowAudioPlayers.values()){
    try{
      rec.audio.pause();
      rec.audio.currentTime = 0;
    }catch{}
  }
}

function fmtAudioTime(sec){
  const s = Math.max(0, Math.floor(Number(sec) || 0));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${m}:${String(r).padStart(2,"0")}`;
}

