let noDragSelectHomeSchedulesBound = false;

function bindNoDragSelectHomeSchedules(){
  if (noDragSelectHomeSchedulesBound || !messagesListEl) return;
  noDragSelectHomeSchedulesBound = true;

  const shouldBlock = (e) => {
    const place = (localStorage.getItem(LS.PLACE) || "");
    if (place !== "home" && place !== "schedules") return false;

    const t = e.target;
    if (t instanceof HTMLElement){
      // Allow normal text selection/caret in inputs/textareas/contenteditable only.
      if (t.closest("input, textarea, [contenteditable='true'], [contenteditable='']")) return false;
    }
    return true;
  };

  messagesListEl.addEventListener("pointerdown", (e) => {
    if (shouldBlock(e)) e.preventDefault();
  }, { passive:false });

  messagesListEl.addEventListener("selectstart", (e) => {
    if (shouldBlock(e)) e.preventDefault();
  }, { passive:false });
}
bindNoDragSelectHomeSchedules();

let msgContextMenuBound = false;

let msgTextMenuEl = null;
let msgTextMenuCtx = null;
let msgTextDefinitionCache = new Map();
let msgTextDefinitionAbort = null;
let msgTextMenuCloseOnEnd = null;
let msgTextMenuCloseSeq = 0;

function isMessageTextTokenChar(ch){
  if (!ch) return false;
  try{ return /[\p{L}\p{N}_@'’-]/u.test(ch); }
  catch{ return /[A-Za-z0-9_@'’-]/.test(ch); }
}

function getCaretRangeAtClientPoint(x, y){
  try{
    if (document.caretRangeFromPoint) return document.caretRangeFromPoint(x, y);
    if (document.caretPositionFromPoint){
      const pos = document.caretPositionFromPoint(x, y);
      if (!pos) return null;
      const range = document.createRange();
      range.setStart(pos.offsetNode, pos.offset);
      range.collapse(true);
      return range;
    }
  }catch{}
  return null;
}

function selectionIsInsideBubbleText(sel, bubbleText){
  if (!sel || sel.isCollapsed || !bubbleText || !sel.rangeCount) return false;
  return bubbleText.contains(sel.anchorNode) && bubbleText.contains(sel.focusNode);
}

function pointIsInsideSelection(sel, x, y){
  if (!sel || !sel.rangeCount) return false;
  try{
    const rects = Array.from(sel.getRangeAt(0).getClientRects());
    return rects.some((r) => (
      x >= r.left - 2 &&
      x <= r.right + 2 &&
      y >= r.top - 2 &&
      y <= r.bottom + 2
    ));
  }catch{
    return false;
  }
}

function selectMessageTextTokenAtPoint(bubbleText, x, y, targetEl = null){
  const mention = targetEl?.closest?.(".mention-link");
  if (mention && bubbleText.contains(mention)){
    const text = String(mention.textContent || "").trim();
    if (!text) return "";
    try{
      const range = document.createRange();
      range.selectNodeContents(mention);
      const sel = window.getSelection?.();
      if (sel){
        sel.removeAllRanges();
        sel.addRange(range);
      }
    }catch{}
    return text;
  }

  const caretRange = getCaretRangeAtClientPoint(x, y);
  let node = caretRange?.startContainer || null;
  let offset = Number(caretRange?.startOffset || 0);

  if (node && node.nodeType !== Node.TEXT_NODE){
    const textRoot = (targetEl && typeof targetEl.nodeType === "number" && bubbleText.contains(targetEl))
      ? targetEl
      : bubbleText;
    const walker = document.createTreeWalker(textRoot, NodeFilter.SHOW_TEXT, {
      acceptNode(textNode){
        return String(textNode.nodeValue || "").trim()
          ? NodeFilter.FILTER_ACCEPT
          : NodeFilter.FILTER_REJECT;
      }
    });
    node = walker.nextNode();
    offset = 0;
  }

  if (!node || node.nodeType !== Node.TEXT_NODE || !bubbleText.contains(node)) return "";

  const text = String(node.nodeValue || "");
  if (!text.trim()) return "";

  if (offset >= text.length) offset = text.length - 1;
  if (offset > 0 && !isMessageTextTokenChar(text[offset]) && isMessageTextTokenChar(text[offset - 1])){
    offset -= 1;
  }
  if (!isMessageTextTokenChar(text[offset])) return "";

  let start = offset;
  let end = offset + 1;
  while (start > 0 && isMessageTextTokenChar(text[start - 1])) start -= 1;
  while (end < text.length && isMessageTextTokenChar(text[end])) end += 1;

  const selected = text.slice(start, end).trim();
  if (!selected) return "";

  try{
    const range = document.createRange();
    range.setStart(node, start);
    range.setEnd(node, end);
    const sel = window.getSelection?.();
    if (sel){
      sel.removeAllRanges();
      sel.addRange(range);
    }
  }catch{}

  return selected;
}

function getMessageTextContextSelection(bubbleText, e){
  const sel = window.getSelection?.();
  if (!selectionIsInsideBubbleText(sel, bubbleText)) return "";
  if (!pointIsInsideSelection(sel, e.clientX, e.clientY)) return "";

  const selected = String(sel.toString() || "");
  return selected.trim() ? selected : "";
}

function getMessageDefinitionLookupWord(text){
  let word = String(text || "").trim();
  if (!word || /\s/.test(word) || word.length > 80) return "";

  try{
    word = word
      .replace(/^[^\p{L}]+/u, "")
      .replace(/[^\p{L}'’-]+$/u, "");
    if (!/^\p{L}[\p{L}'’-]*$/u.test(word)) return "";
  }catch{
    word = word
      .replace(/^[^A-Za-z]+/, "")
      .replace(/[^A-Za-z'’-]+$/, "");
    if (!/^[A-Za-z][A-Za-z'’-]*$/.test(word)) return "";
  }

  return word.toLowerCase();
}

async function fetchMessageDefinitions(word, signal = null){
  const key = String(word || "").toLowerCase();
  if (!key) return [];
  if (msgTextDefinitionCache.has(key)) return msgTextDefinitionCache.get(key);

  const url = `https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(key)}`;
  const res = await fetch(url, { cache:"force-cache", signal });
  if (!res.ok){
    msgTextDefinitionCache.set(key, []);
    return [];
  }

  const data = await res.json();
  const definitions = [];

  (Array.isArray(data) ? data : []).forEach((entry) => {
    (Array.isArray(entry?.meanings) ? entry.meanings : []).forEach((meaning) => {
      const partOfSpeech = String(meaning?.partOfSpeech || "").trim();
      (Array.isArray(meaning?.definitions) ? meaning.definitions : []).forEach((item) => {
        const definition = String(item?.definition || "").trim();
        if (!definition) return;
        definitions.push({
          partOfSpeech,
          definition,
          example: String(item?.example || "").trim()
        });
      });
    });
  });

  msgTextDefinitionCache.set(key, definitions);
  return definitions;
}

function renderMsgTextDefinition(word, definitions){
  const box = msgTextMenuEl?.querySelector?.(".msg-text-menu-definition");
  if (!box) return;

  const items = (Array.isArray(definitions) ? definitions : [])
    .map((item, index) => {
      const part = item.partOfSpeech
        ? `<span class="msg-text-menu-part">${escapeHtml(item.partOfSpeech)}</span>`
        : "";
      const example = item.example
        ? `<div class="msg-text-menu-example">Example: ${escapeHtml(item.example)}</div>`
        : "";

      return `
        <div class="msg-text-menu-definition-row">
          <span class="msg-text-menu-definition-num">${index + 1}.</span>
          <div class="msg-text-menu-definition-copy">
            ${part}
            <div>${escapeHtml(item.definition)}</div>
            ${example}
          </div>
        </div>
      `;
    })
    .join("");

  box.innerHTML = `
    <div class="msg-text-menu-definition-title">Define: ${escapeHtml(word)}</div>
    ${items}
  `;
  box.hidden = !items;
  requestAnimationFrame(() => {
    if (!msgTextMenuEl || msgTextMenuEl.hidden || !msgTextMenuCtx) return;
    positionMsgTextMenu(msgTextMenuCtx.pointerX, msgTextMenuCtx.pointerY);
  });
}

function ensureMsgTextMenu(){
  if (msgTextMenuEl) return msgTextMenuEl;

  msgTextMenuEl = document.createElement("div");
  msgTextMenuEl.id = "msg-text-menu";
  msgTextMenuEl.className = "msg-menu msg-text-menu";
  msgTextMenuEl.hidden = true;
  msgTextMenuEl.innerHTML = `
    <div class="msg-menu-user" data-msg-text-user></div>
    <button class="msg-menu-btn" type="button" data-msg-text-act="copy">
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none"><path d="M8 8h10v12H8V8Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M6 16H5a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>
      </span>
      <span class="msg-menu-label">Copy Text</span>
    </button>
    <button class="msg-menu-btn" type="button" data-msg-text-act="search">
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none"><circle cx="11" cy="11" r="7" stroke="currentColor" stroke-width="2"/><path d="m16.2 16.2 3.8 3.8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>
      </span>
      <span class="msg-menu-label">Search Google</span>
    </button>
    <button class="msg-menu-btn" type="button" data-msg-text-act="define" hidden>
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none"><path d="M6 4h11a2 2 0 0 1 2 2v14H8a2 2 0 0 0-2 2V4Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M6 4H5a2 2 0 0 0-2 2v14a2 2 0 0 1 2-2h1" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M9 8h6M9 12h5M9 16h4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>
      </span>
      <span class="msg-menu-label">Define</span>
    </button>
    <div class="msg-text-menu-definition" hidden></div>
  `;

  document.body.appendChild(msgTextMenuEl);

  msgTextMenuEl.addEventListener("click", async (e) => {
    const btn = e.target?.closest?.("[data-msg-text-act]");
    if (!btn || !msgTextMenuEl.contains(btn) || !msgTextMenuCtx) return;
    const act = btn.getAttribute("data-msg-text-act");
    const selectedText = String(msgTextMenuCtx.text || "");

    if (act === "copy"){
      try{
        await copyTextToClipboard(selectedText);
        showToast({ title:"Copied", body:"Selected text copied.", duration:1400 });
      }catch{
        showToast({ title:"Copy failed", body:"Could not copy selected text.", duration:2000 });
      }
      closeMsgTextMenu();
      return;
    }

    if (act === "search"){
      const q = selectedText.trim();
      if (q) window.open(`https://www.google.com/search?q=${encodeURIComponent(q)}`, "_blank", "noopener,noreferrer");
      closeMsgTextMenu();
      return;
    }

    if (act === "define"){
      if (msgTextMenuCtx.word && Array.isArray(msgTextMenuCtx.definitions) && msgTextMenuCtx.definitions.length){
        renderMsgTextDefinition(msgTextMenuCtx.word, msgTextMenuCtx.definitions);
      }
    }
  });

  document.addEventListener("pointerdown", (e) => {
    if (!msgTextMenuEl || msgTextMenuEl.hidden) return;
    if (msgTextMenuEl.contains(e.target)) return;
    closeMsgTextMenu();
  }, true);

  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeMsgTextMenu(true);
  }, true);

  window.addEventListener("resize", () => closeMsgTextMenu(true));
  window.addEventListener("blur", () => closeMsgTextMenu(true));

  return msgTextMenuEl;
}

function positionMsgTextMenu(x, y){
  if (!msgTextMenuEl || msgTextMenuEl.hidden) return;

  const margin = 8;
  const vw = Math.max(document.documentElement.clientWidth || 0, window.innerWidth || 0);
  const vh = Math.max(document.documentElement.clientHeight || 0, window.innerHeight || 0);
  const r = msgTextMenuEl.getBoundingClientRect();

  let left = Number(x || 0);
  let top = Number(y || 0);

  left = Math.max(margin, Math.min(left, vw - r.width - margin));
  top = Math.max(margin, Math.min(top, vh - r.height - margin));

  msgTextMenuEl.style.left = `${Math.round(left)}px`;
  msgTextMenuEl.style.top = `${Math.round(top)}px`;
}

function closeMsgTextMenu(immediate = false){
  if (!msgTextMenuEl || msgTextMenuEl.hidden) return;

  msgTextMenuCloseSeq += 1;
  const seq = msgTextMenuCloseSeq;

  if (msgTextDefinitionAbort){
    try{ msgTextDefinitionAbort.abort(); }catch{}
    msgTextDefinitionAbort = null;
  }

  if (msgTextMenuCloseOnEnd){
    msgTextMenuEl.removeEventListener("animationend", msgTextMenuCloseOnEnd);
    msgTextMenuCloseOnEnd = null;
  }

  const clearCtx = () => {
    msgTextMenuCtx = null;
    const box = msgTextMenuEl?.querySelector?.(".msg-text-menu-definition");
    if (box){
      box.hidden = true;
      box.innerHTML = "";
    }
  };

  if (immediate){
    msgTextMenuEl.hidden = true;
    msgTextMenuEl.classList.remove("open","closing");
    clearCtx();
    return;
  }

  msgTextMenuEl.classList.remove("open");
  msgTextMenuEl.classList.add("closing");

  msgTextMenuCloseOnEnd = () => {
    if (seq !== msgTextMenuCloseSeq) return;
    msgTextMenuCloseOnEnd = null;
    if (msgTextMenuEl){
      msgTextMenuEl.hidden = true;
      msgTextMenuEl.classList.remove("closing");
    }
    clearCtx();
  };
  msgTextMenuEl.addEventListener("animationend", msgTextMenuCloseOnEnd, { once:true });
}

function openMsgTextMenu({ x, y, text, word, username, displayName }){
  const selectedText = String(text || "");
  if (!selectedText.trim()) return;

  ensureMsgTextMenu();
  const userEl = msgTextMenuEl?.querySelector?.(".msg-menu-user");
  if (userEl) userEl.textContent = String(username || displayName || "User");
  closeMsgMenu(true);

  msgTextMenuCloseSeq += 1;
  if (msgTextMenuCloseOnEnd){
    msgTextMenuEl.removeEventListener("animationend", msgTextMenuCloseOnEnd);
    msgTextMenuCloseOnEnd = null;
  }

  if (msgTextDefinitionAbort){
    try{ msgTextDefinitionAbort.abort(); }catch{}
    msgTextDefinitionAbort = null;
  }

  const defineBtn = msgTextMenuEl.querySelector('[data-msg-text-act="define"]');
  const definitionBox = msgTextMenuEl.querySelector(".msg-text-menu-definition");
  if (defineBtn) defineBtn.hidden = true;
  if (definitionBox){
    definitionBox.hidden = true;
    definitionBox.innerHTML = "";
  }

  const token = Symbol("definition-request");
  msgTextMenuCtx = {
    text: selectedText,
    word: word || "",
    definitions: [],
    pointerX: x,
    pointerY: y,
    token
  };

  msgTextMenuEl.hidden = false;
  msgTextMenuEl.classList.remove("closing");
  msgTextMenuEl.classList.add("open");
  msgTextMenuEl.style.left = `${Math.round(x)}px`;
  msgTextMenuEl.style.top = `${Math.round(y)}px`;
  requestAnimationFrame(() => positionMsgTextMenu(x, y));

  if (!word) return;

  msgTextDefinitionAbort = new AbortController();
  fetchMessageDefinitions(word, msgTextDefinitionAbort.signal)
    .then((definitions) => {
      if (!msgTextMenuCtx || msgTextMenuCtx.token !== token) return;
      msgTextMenuCtx.definitions = definitions;
      const btn = msgTextMenuEl?.querySelector?.('[data-msg-text-act="define"]');
      if (btn) btn.hidden = !(Array.isArray(definitions) && definitions.length);
      requestAnimationFrame(() => positionMsgTextMenu(x, y));
    })
    .catch(() => {});
}

function ensureMsgContextMenuDelegation(){
  if (msgContextMenuBound || !messagesListEl) return;
  msgContextMenuBound = true;

  messagesListEl.addEventListener("contextmenu", (e) => {
    const ava = e.target?.closest?.(".msg-avatar");
    const bubbleText = ava ? null : e.target?.closest?.(".bubble-text");
    const bub = ava ? null : e.target?.closest?.(".bubble");
    const node = ava || bub;
    if (!node) return;

    const row = node.closest?.(".msg-row");
    const msgKey = row?.dataset?.msgkey || "";
    const msg = msgKey ? (msgDataByKey.get(msgKey) || null) : null;

    if (!msg && !ava) return;

    if (bubbleText){
      const selectedText = getMessageTextContextSelection(bubbleText, e);
      if (String(selectedText || "").trim()){
        e.preventDefault();
        e.stopPropagation();
        const code = row?.dataset?.usercode || (msg?.userCode || "");
        const live = code ? liveUserCache.get(code) : null;
        openMsgTextMenu({
          x: e.clientX,
          y: e.clientY,
          text: selectedText,
          word: getMessageDefinitionLookupWord(selectedText),
          username: (live?.username || msg?.username || "User"),
          displayName: (live?.displayName || msg?.displayName || live?.username || msg?.username || "User")
        });
        return;
      }
    }

    closeMsgTextMenu(true);

    e.preventDefault();
    e.stopPropagation();

    if (ava){
      const code = row?.dataset?.usercode || (msg?.userCode || "");
      const latest = code ? liveUserCache.get(code) : null;
      const uname = String(latest?.username || msg?.username || "User");
      const dname = String(latest?.displayName || msg?.displayName || uname);
      const photoDataURL = String(latest?.photoDataURL || msg?.photoDataURL || defaultStickmanDataURL());
      const bannerDataURL = String(latest?.bannerDataURL || msg?.bannerDataURL || "");
      const ext = inferImageExt(photoDataURL);
      const fn = `${safeFileBaseName(uname)}.${ext}`;
      const bannerFn = `${safeFileBaseName(uname)}-banner.${bannerDataURL ? inferImageExt(bannerDataURL) : "png"}`;

      openMsgMenuFor(ava, {
        menu: "avatar",
        userCode: code,
        username: uname,
        displayName: dname,
        imageDataURL: photoDataURL,
        imageFileName: fn,
        bannerDataURL,
        bannerFileName: bannerFn,
        pointerX: e.clientX,
        pointerY: e.clientY
      });
      return;
    }

    const code = row?.dataset?.usercode || (msg?.userCode || "");
    const live = code ? liveUserCache.get(code) : null;
    openMsgMenuFor(row, {
      key: msgKey,
      userCode: code,
      username: (live?.username || msg?.username || "User"),
      displayName: (live?.displayName || msg?.displayName || live?.username || msg?.username || "User"),
      text: (msg?.text || ""),
      canEdit: !!(currentUser && String(msg?.userCode || "") === String(currentUser.code || "") && !msg?.__stub),
      canReply: true,
      pointerX: e.clientX,
      pointerY: e.clientY
    });
  }, { passive:false });
}
ensureMsgContextMenuDelegation();

let globalAvatarContextMenuBound = false;
function openAvatarContextMenuFor(targetEl, userCode, event = null){
  const code = String(userCode || "").trim();
  if (!code || !targetEl) return;

  const live = liveUserCache.get(code) || null;
  const fallbackSelf = (currentUser && String(currentUser.code || "") === code) ? currentUser : null;
  const user = live || fallbackSelf || {
    code,
    username: "User",
    photoDataURL: defaultStickmanDataURL(),
    photoTransform: null
  };

  const uname = String(user?.username || "User");
  const photoDataURL = String(user?.photoDataURL || defaultStickmanDataURL());
  const bannerDataURL = String(user?.bannerDataURL || "");
  const ext = inferImageExt(photoDataURL);
  const bannerExt = bannerDataURL ? inferImageExt(bannerDataURL) : "png";
  const fn = `${safeFileBaseName(uname)}.${ext}`;
  const bannerFn = `${safeFileBaseName(uname)}-banner.${bannerExt}`;

  openMsgMenuFor(targetEl, {
    menu: "avatar",
    userCode: code,
    username: uname,
    displayName: String(user?.displayName || uname),
    imageDataURL: photoDataURL,
    imageFileName: fn,
    bannerDataURL,
    bannerFileName: bannerFn,
    pointerX: event?.clientX,
    pointerY: event?.clientY
  });
}

function resolveUserProfileAvatarTarget(target){
  const avatarEl = target?.closest?.(
    ".msg-avatar, .sched-avatar, .reply-preview-avatar, .slideshow-loc-ava, .tip-ava, .call-user-avatar, .online-ava, .online-ava-img"
  );
  if (!avatarEl) return null;

  if (avatarEl.classList.contains("call-user-avatar") && avatarEl.closest(".call-menu-card")){
    return null;
  }

  // Slideshow editing indicator avatars are navigation controls, not profile controls.
  // This intentionally does NOT affect the members list.
  if (
    document.body.classList.contains("slideshow-full") &&
    avatarEl.closest(".online-pill") &&
    !avatarEl.closest(".members-sidebar")
  ){
    return null;
  }

  const host = avatarEl.closest?.("[data-usercode]") || avatarEl;
  const code = String(host?.dataset?.usercode || "").trim();
  if (!code) return null;

  return {
    avatarEl,
    host,
    code,
    anchorEl: avatarEl.closest?.(".online-ava") || host
  };
}

function ensureGlobalAvatarContextMenuDelegation(){
  if (globalAvatarContextMenuBound) return;
  globalAvatarContextMenuBound = true;

  document.addEventListener("contextmenu", (e) => {
    const hit = resolveUserProfileAvatarTarget(e.target);
    if (!hit || hit.avatarEl.classList.contains("msg-avatar")) return;

    e.preventDefault();
    e.stopPropagation();
    openAvatarContextMenuFor(hit.anchorEl, hit.code, e);
  }, { passive:false });
}
ensureGlobalAvatarContextMenuDelegation();

let userProfileOpen = false;
let userProfileCloseTimer = 0;
let userProfilePinnedCode = "";
let userProfileAnchorEl = null;
const userProfileEl = $("user-profile-popover");
const userProfileCardEl = $("user-profile-card");
let userProfileRenderSeq = 0;

function getUserProfileRecord(userCode){
  const code = String(userCode || "").trim();
  if (!code) return null;
  if (currentUser && String(currentUser.code || "") === code) return currentUser;
  return liveUserCache.get(code) || null;
}

function getUserHtmlActivity(user){
  const raw = user?.htmlActivity;
  if (!raw || typeof raw !== "object") return null;

  const type = String(raw.type || "").toLowerCase() === "upload" ? "upload" : "library";
  const title = String(raw.title || raw.fileName || "").trim();
  if (!title) return null;

  return {
    type,
    title,
    libraryId: String(raw.libraryId || ""),
    fileName: String(raw.fileName || "").trim(),
    updatedAt: Number(raw.updatedAt || 0)
  };
}
function getUserSlideshowActivity(user){
  const raw = user?.slideshowActivity;
  if (!raw || typeof raw !== "object") return null;
  if (raw.active === false) return null;

  return {
    label: "Editing Slideshow",
    updatedAt: Number(raw.updatedAt || 0)
  };
}
function getUserActivityItems(user){
  const items = [];
  const htmlActivity = getUserHtmlActivity(user);
  if (htmlActivity){
    items.push({
      kind: "html",
      label: `Playing ${htmlActivity.title}`,
      activity: htmlActivity
    });
  }

  const slideshowActivity = getUserSlideshowActivity(user);
  if (slideshowActivity){
    items.push({
      kind: "slideshow",
      label: slideshowActivity.label,
      activity: slideshowActivity
    });
  }

  return items;
}
function getUserHtmlActivityLabel(user){
  const activity = getUserHtmlActivity(user);
  return activity ? `Playing ${activity.title}` : "";
}
function getUserActivityLabel(user){
  return getUserActivityItems(user).map((item) => item.label).join(" · ");
}
function htmlActivityIconMarkup(className = ""){
  return `<span class="html-activity-icon${className ? ` ${className}` : ``}" aria-hidden="true">&lt;/&gt;</span>`;
}
function slideshowActivityIconMarkup(className = ""){
  return `
    <span class="slideshow-activity-icon${className ? ` ${className}` : ``}" aria-hidden="true">
      <svg viewBox="0 0 24 24" fill="none">
        <rect x="3.75" y="4.5" width="13.5" height="9.5" rx="2.1" stroke="currentColor" stroke-width="2"/>
        <path d="M7 17h6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        <path d="M10 14v3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        <path d="m14.2 18.55 5.05-5.05a1.75 1.75 0 0 1 2.48 2.48l-5.05 5.05-3.2.75.72-3.23Z" stroke="currentColor" stroke-width="1.9" stroke-linejoin="round"/>
      </svg>
    </span>
  `;
}
function userActivityIconsMarkup(items, className = ""){
  return (Array.isArray(items) ? items : [])
    .map((item) => item?.kind === "slideshow" ? slideshowActivityIconMarkup(className) : htmlActivityIconMarkup(className))
    .join("");
}
function refreshOpenUserProfileCard(){
  if (!userProfileOpen || !userProfileCardEl || !userProfilePinnedCode) return;
  const user = getUserProfileRecord(userProfilePinnedCode);
  if (!user){
    closeUserProfile(true);
    return;
  }
  userProfileCardEl.innerHTML = buildUserProfileCardHTML(user);
  userProfileCardEl.scrollTop = 0;
  if (userProfileAnchorEl?.isConnected) positionUserProfile(userProfileAnchorEl);
}
function buildUserProfileCardHTML(user, { preview=false } = {}){
  const displayName = String(user?.displayName || user?.username || "User");
  const username = String(user?.username || "user");
  const bio = String(user?.bio || "").slice(0, 400);
  const photoDataURL = String(user?.photoDataURL || defaultStickmanDataURL());
  const bannerDataURL = String(user?.bannerDataURL || "");
  const pfpTransform = formatMediaTransform(user?.photoTransform, 92, 84);
  const bannerTransform = formatMediaTransformCss(user?.bannerTransform, "min(340px, calc(100vw - 24px))", 340);

  const bannerMarkup = bannerDataURL
    ? `<img class="user-profile-banner-img" src="${escapeHtml(bannerDataURL)}" alt="" style="transform:${escapeAttr(bannerTransform)}" />`
    : `<div class="user-profile-banner-fallback"></div>`;
  const activityItems = getUserActivityItems(user);
  const activityLabel = getUserActivityLabel(user);
  const activityKinds = activityItems.map((item) => item.kind).join(" ");

  return `
    <div class="user-profile-shell${preview ? ` is-preview` : ``}" data-usercode="${escapeHtml(String(user?.code || ""))}">
      <div class="user-profile-banner">
        ${bannerMarkup}
        <button class="user-profile-more" type="button" ${preview ? `hidden` : ``} aria-label="Profile actions">
          <svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
            <circle cx="5" cy="12" r="1.8" fill="currentColor"></circle>
            <circle cx="12" cy="12" r="1.8" fill="currentColor"></circle>
            <circle cx="19" cy="12" r="1.8" fill="currentColor"></circle>
          </svg>
        </button>
      </div>
      <div class="user-profile-body">
        <div class="user-profile-avatar-wrap">
          <div class="user-profile-avatar">
            <img src="${escapeHtml(photoDataURL)}" alt="${escapeHtml(displayName)}" draggable="false" style="transform:${escapeAttr(pfpTransform)}" />
          </div>
        </div>
        <div class="user-profile-names">
          <div class="user-profile-display">${escapeHtml(displayName)}</div>
          <div class="user-profile-username">${escapeHtml(username)}</div>
          ${activityLabel ? `<div class="user-profile-activity" data-activity-kinds="${escapeAttr(activityKinds)}">${userActivityIconsMarkup(activityItems)}<span class="user-profile-activity-text">${escapeHtml(activityLabel)}</span></div>` : ``}
        </div>
        ${bio ? `<div class="user-profile-bio">${escapeHtml(bio)}</div>` : ``}
      </div>
    </div>
  `;
}

function closeUserProfile(immediate=false){
  if (!userProfileEl) return;

  const seq = ++userProfileRenderSeq;
  clearTimeout(userProfileCloseTimer);

  if (immediate || userProfileEl.hidden){
    userProfileEl.hidden = true;
    userProfileEl.classList.remove("is-open","is-closing");
    userProfileCardEl.innerHTML = "";
    userProfileOpen = false;
    userProfilePinnedCode = "";
    userProfileAnchorEl = null;
    return;
  }

  userProfileEl.classList.remove("is-open");
  void userProfileEl.offsetHeight;
  userProfileEl.classList.add("is-closing");
  userProfileCloseTimer = window.setTimeout(() => {
    if (seq !== userProfileRenderSeq) return;
    userProfileEl.hidden = true;
    userProfileEl.classList.remove("is-closing");
    userProfileCardEl.innerHTML = "";
    userProfileOpen = false;
    userProfilePinnedCode = "";
    userProfileAnchorEl = null;
  }, 110);
}

function positionUserProfile(anchorEl){
  if (!userProfileEl || !anchorEl) return;
  const anchorRect = anchorEl.getBoundingClientRect();
  const cardRect = userProfileEl.getBoundingClientRect();
  const gap = 12;
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  let left = anchorRect.right + gap;
  let top = anchorRect.top;

  if (left + cardRect.width > vw - 12){
    left = anchorRect.left - cardRect.width - gap;
  }
  if (left < 12){
    left = Math.max(12, Math.min(vw - cardRect.width - 12, anchorRect.left + (anchorRect.width / 2) - (cardRect.width / 2)));
  }

  if (top + cardRect.height > vh - 12){
    top = Math.max(12, vh - cardRect.height - 12);
  }
  if (top < 12) top = 12;

  userProfileEl.style.left = `${Math.round(left)}px`;
  userProfileEl.style.top = `${Math.round(top)}px`;
}

function openUserProfileAt(anchorEl, userCode, { sourceMenu=false } = {}){
  if (!userProfileEl || !userProfileCardEl || !anchorEl) return;
  const code = String(userCode || "").trim();
  const user = getUserProfileRecord(code);
  if (!user) return;

  const seq = ++userProfileRenderSeq;
  clearTimeout(userProfileCloseTimer);
  userProfileEl.hidden = false;
  userProfileEl.classList.remove("is-open", "is-closing");

  userProfileAnchorEl = anchorEl;
  userProfilePinnedCode = code;
  userProfileCardEl.innerHTML = buildUserProfileCardHTML(user);
  userProfileCardEl.scrollTop = 0;
  positionUserProfile(anchorEl);

  requestAnimationFrame(() => {
    if (seq !== userProfileRenderSeq) return;
    if (!userProfileEl.hidden && userProfilePinnedCode === code){
      userProfileEl.classList.add("is-open");
    }
  });

  userProfileOpen = true;

  const moreBtn = userProfileCardEl.querySelector(".user-profile-more");
  if (moreBtn){
    moreBtn.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();

      const isSameAvatarMenuOpen =
        !!msgMenuEl &&
        !msgMenuEl.hidden &&
        msgMenuCtx?.menu === "avatar" &&
        String(msgMenuCtx?.userCode || "") === code &&
        msgMenuAnchorEl === moreBtn;

      if (isSameAvatarMenuOpen){
        closeMsgMenu();
        return;
      }

      openAvatarContextMenuFor(moreBtn, code);
    });
  }

  if (!sourceMenu) closeMsgMenu(true);
}

document.addEventListener("click", (e) => {
  const avatarHit = resolveUserProfileAvatarTarget(e.target);
  if (avatarHit){
    e.preventDefault();
    e.stopPropagation();

    if (userProfileOpen && userProfilePinnedCode === avatarHit.code){
      closeUserProfile(true);
      return;
    }

    openUserProfileAt(avatarHit.anchorEl, avatarHit.code);
    return;
  }

  const displayNameTarget = e.target?.closest?.("[data-display-name-usercode], [data-mention-usercode]");
  if (displayNameTarget){
    e.preventDefault();
    e.stopPropagation();

    const code = String(displayNameTarget.dataset.displayNameUsercode || displayNameTarget.dataset.mentionUsercode || "").trim();
    if (userProfileOpen && userProfilePinnedCode === code){
      closeUserProfile(true);
      return;
    }

    openUserProfileAt(displayNameTarget, code);
    return;
  }

  const userHost = e.target?.closest?.("[data-usercode]");
  const clickedNameLike = e.target?.closest?.(".bubble-name, .member-name, .sched-person-name, .sched-person-title, .call-user-name");
  if (clickedNameLike && userHost?.dataset?.usercode){
    e.preventDefault();
    e.stopPropagation();

    const code = String(userHost.dataset.usercode || "").trim();
    if (userProfileOpen && userProfilePinnedCode === code){
      closeUserProfile(true);
      return;
    }

    openUserProfileAt(clickedNameLike, code);
    return;
  }

  if (userProfileOpen){
    if (userProfileEl?.contains?.(e.target)) return;
    closeUserProfile();
  }
}, true);

window.addEventListener("resize", () => {
  if (!userProfileOpen) return;
  if (!userProfileAnchorEl?.isConnected){
    closeUserProfile(true);
    return;
  }
  positionUserProfile(userProfileAnchorEl);
});
window.addEventListener("blur", () => closeUserProfile(true));

document.addEventListener("scroll", () => {
  if (!userProfileOpen) return;
  if (!userProfileAnchorEl?.isConnected){
    closeUserProfile(true);
    return;
  }
  positionUserProfile(userProfileAnchorEl);
}, true);

const roomsListEl = $("rooms-list");
const onlinePill = $("online-pill");
const roomSummaryEl = $("room-summary");
const roomLabelEl = $("room-label");
const roomIconButtonEl = $("room-icon-button");
const roomIconImageEl = $("room-icon-image");
const roomIconInputEl = $("room-icon-input");
const onlineLabelEl = $("online-label");
const onlineListEl = $("online-list");
const typingBarEl = $("typing-bar");
const typingBarUsersEl = $("typing-bar-users");
const missedBannerEl = $("missed-banner");
const missedBannerTitleEl = $("missed-banner-title");
const missedBannerSubEl = $("missed-banner-sub");
const missedBannerJumpEl = $("missed-banner-jump");
const missedBannerCloseEl = $("missed-banner-close");
let typingBarHideTimer = 0;
let missedBannerHideTimer = 0;
let missedBannerFirstKey = "";
let missedBannerRoomId = "";
let currentRoomOpenMessageCount = 0;

/* -------------------- Clock (sidebar) -------------------- */
const clockTimeEl = $("clock-time");
const clockClassEl = $("clock-class");
const clockTimerEl = $("clock-timer");
const btnClockSet = $("btn-clock-set");
const btnTimeDisplay = $("btn-time-display");

const EST_TZ = "America/New_York";

// ---- Atomic-clock synchronized "now" (Time.is-style offset sync) ----
// We sync to a server time source and compute an offset + RTT-adjusted midpoint.
// Then we run the display updates exactly at the start of each second.
const ATOMIC_TIME_ENDPOINTS = [
  // Primary: timeapi.io (typically CORS-friendly and reliable)
  "https://timeapi.io/api/Time/current/zone?timeZone=UTC",
  // Secondary: worldtimeapi (kept as fallback only)
  "https://worldtimeapi.org/api/timezone/Etc/UTC"
];

const ATOMIC_SYNC_TIMEOUT_MS = 3500;

let atomicSync = {
  ok: false,
  offsetMs: 0,
  baseMs: 0,
  perfMs: 0,
  rttMs: 0,
  lastSyncAt: 0
};

let atomicSyncInterval = null;
let atomicSyncBound = false;

function accurateNowMs(){
  if (!atomicSync.ok) return Date.now();
  const elapsed = (typeof performance !== "undefined" && performance.now) ? (performance.now() - atomicSync.perfMs) : 0;
  return atomicSync.baseMs + elapsed;
}

function getAccurateNow(){
  return new Date(accurateNowMs());
}

async function syncAtomicClock({ force=false } = {}){
  const wallNow = Date.now();
  if (!force && atomicSync.lastSyncAt && (wallNow - atomicSync.lastSyncAt) < 30000) return; // 30s throttle
  atomicSync.lastSyncAt = wallNow;

  const t0 = (typeof performance !== "undefined" && performance.now) ? performance.now() : 0;
  const r0 = Date.now();

  try{
    // Try multiple time sources (failover). If one is blocked/reset, move on.
    for (const base of ATOMIC_TIME_ENDPOINTS){
      const ctrl = new AbortController();
      const to = setTimeout(() => ctrl.abort(), ATOMIC_SYNC_TIMEOUT_MS);

      // Per-attempt timestamps (NTP-style midpoint uses the attempt window)
      const t0a = (typeof performance !== "undefined" && performance.now) ? performance.now() : t0;
      const r0a = Date.now();

      try{
        const sep = base.includes("?") ? "&" : "?";
        const url = `${base}${sep}_=${Math.random().toString(36).slice(2)}`;

        const res = await fetch(url, { cache: "no-store", signal: ctrl.signal });
        if (!res.ok) throw new Error(`atomic time HTTP ${res.status}`);

        const data = await res.json();

        const t1 = (typeof performance !== "undefined" && performance.now) ? performance.now() : t0a;
        const r1 = Date.now();
        const rtt = t1 - t0a;

        // Accept several common payload shapes:
        // - worldtimeapi: { unixtime: <seconds> }
        // - timeapi.io:   { dateTime: "YYYY-MM-DDTHH:mm:ss.fffffff" ... } (interpretable as UTC when requesting UTC)
        // - other APIs:   { unixTime / epoch / timestamp }
        let serverMs = NaN;

        if (data && Number.isFinite(Number(data.unixtime))) serverMs = Number(data.unixtime) * 1000;
        else if (data && Number.isFinite(Number(data.unixTime))) serverMs = Number(data.unixTime) * 1000;
        else if (data && Number.isFinite(Number(data.epoch))) serverMs = Number(data.epoch) * 1000;
        else if (data && Number.isFinite(Number(data.timestamp))) serverMs = Number(data.timestamp) * 1000;
        else if (data && typeof data.dateTime === "string"){
          let s = String(data.dateTime || "").trim();
          // If the timestamp has no timezone, treat it as UTC (TimeAPI UTC endpoint often omits "Z")
          if (s && !/[zZ]$/.test(s) && !/[+-]\d{2}:\d{2}$/.test(s)) s += "Z";
          const ms = Date.parse(s);
          if (Number.isFinite(ms)) serverMs = ms;
        } else if (data && typeof data.datetime === "string"){
          let s = String(data.datetime || "").trim();
          if (s && !/[zZ]$/.test(s) && !/[+-]\d{2}:\d{2}$/.test(s)) s += "Z";
          const ms = Date.parse(s);
          if (Number.isFinite(ms)) serverMs = ms;
        }

        if (!Number.isFinite(serverMs)) throw new Error("atomic time payload missing usable timestamp");

        // Midpoint estimate (NTP-style)
        const clientMidMs = r0a + ((r1 - r0a) / 2);
        const offsetMs = serverMs - clientMidMs;

        atomicSync.ok = true;
        atomicSync.offsetMs = offsetMs;
        atomicSync.perfMs = t1;
        atomicSync.baseMs = r1 + offsetMs;
        atomicSync.rttMs = rtt;

        clearTimeout(to);
        return; // success: stop trying endpoints
      }catch{
        // try next endpoint
      }finally{
        clearTimeout(to);
      }
    }
  }catch{
    // Keep the last known good sync if we have one; otherwise fall back to device time.
  }
}

function startAtomicClockSync(){
  if (atomicSyncInterval) return;

  // Do an immediate sync (best effort)
  syncAtomicClock({ force: true });

  // Periodic resync
  atomicSyncInterval = setInterval(() => syncAtomicClock(), 60000);

  // Resync on focus/visibility like Time.is does when conditions change
  if (!atomicSyncBound){
    atomicSyncBound = true;
    document.addEventListener("visibilitychange", () => {
      if (!document.hidden) syncAtomicClock({ force: true });
    });
    window.addEventListener("focus", () => syncAtomicClock({ force: true }));
  }
}

let clockInterval = null;
let clockTimeout = null;
let clockClassInterval = null;

// Schedules module loads later in the file; avoid touching schedule vars until ready.
let schedulesModuleReady = false;

let timerInterval = null;
let timerTargetMs = null;
let timerTargetLabel = "";
let timerStartedAtMs = null;

function formatESTClock(date = new Date()){
  try{
    return new Intl.DateTimeFormat("en-US", {
      timeZone: EST_TZ,
      hour: "numeric",
      minute: "2-digit",
      second: "2-digit",
      hour12: true
    }).format(date);
  }catch{
    return date.toLocaleTimeString("en-US", { hour:"numeric", minute:"2-digit", second:"2-digit", hour12:true });
  }
}

function getESTParts(date = new Date()){
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: EST_TZ,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(date);

  const out = {};
  for (const p of parts){
    if (p.type !== "literal") out[p.type] = p.value;
  }
  return {
    year: Number(out.year),
    month: Number(out.month),
    day: Number(out.day),
    hour: Number(out.hour),
    minute: Number(out.minute),
    second: Number(out.second)
  };
}

function makeESTDate(parts){
  // parts: {year,month,day,hour,minute,second}
  let d = new Date(Date.UTC(parts.year, parts.month - 1, parts.day, parts.hour, parts.minute, parts.second || 0));
  for (let i = 0; i < 2; i++){
    const got = getESTParts(d);
    const gotUTC = Date.UTC(got.year, got.month - 1, got.day, got.hour, got.minute, got.second || 0);
    const wantUTC = Date.UTC(parts.year, parts.month - 1, parts.day, parts.hour, parts.minute, parts.second || 0);
    const diff = gotUTC - wantUTC;
    if (!diff) break;
    d = new Date(d.getTime() - diff);
  }
  return d;
}

function stopSidebarClock(){
  try{ if (clockInterval) clearInterval(clockInterval); }catch{}
  try{ if (clockTimeout) clearTimeout(clockTimeout); }catch{}
  try{ if (clockClassInterval) clearInterval(clockClassInterval); }catch{}
  clockInterval = null;
  clockTimeout = null;
  clockClassInterval = null;
}

function startSidebarClock(){
  if (!clockTimeEl) return;
  stopSidebarClock();
  startAtomicClockSync();

  const tick = () => {
    const timeText = formatESTClock(getAccurateNow());
    clockTimeEl.textContent = timeText;
    const modalTimeEl = $("time-display-modal-time");
    if (modalTimeEl) modalTimeEl.textContent = timeText;
    updateLiveMessageTimestamps();
  };
  tick();
  updateClockClassUI();
  renderOnlineIndicator();

  const msToNextSecond = 1000 - (accurateNowMs() % 1000);
  clockTimeout = setTimeout(() => {
    tick();
    clockInterval = setInterval(tick, 1000);
  }, msToNextSecond);

  // Keep the clock live without rebuilding the member list every 250ms.
  clockClassInterval = setInterval(() => {
    updateClockClassUI();
    refreshOnlineIndicatorStatusTexts();
  }, 1000);
}

function _assignedSchedulePersonForUser(dayType, username){
  const uname = String(username || "").trim();
  if (!uname) return null;

  const bucket = SCHEDULES?.[dayType];
  if (!bucket || typeof bucket !== "object") return null;

  if (bucket[uname]) return uname;

  const want = uname.toLowerCase();
  for (const k of Object.keys(bucket)){
    if (String(k).toLowerCase() === want) return k;
  }
  return null;
}

function getClockClassText(){
  if (!currentUser || !schedulesModuleReady) return "Class: None";

  const dayType = scheduleType || "full";
  const person = _assignedSchedulePersonForUser(dayType, currentUser.username);
  if (!person) return "Class: None";

  const activeKey = _getActiveScheduleBlockKey(dayType, person);
  if (!activeKey) return "Class: None";

  const c = _getClassForBlock(dayType, person, activeKey);
  const name = String(c?.className || "").trim() || "None";
  return `Class: ${name}`;
}

function updateClockClassUI(){
  const classText = getClockClassText();
  const modalClassEl = $("time-display-modal-class");
  if (modalClassEl) modalClassEl.textContent = classText;

  if (!clockClassEl) return;

  // If user isn't assigned a schedule (or schedules not loaded yet), show nothing in the sidebar.
  if (!currentUser || !schedulesModuleReady){
    clockClassEl.hidden = true;
    return;
  }

  const dayType = scheduleType || "full";
  const person = _assignedSchedulePersonForUser(dayType, currentUser.username);

  if (!person){
    clockClassEl.hidden = true;
    return;
  }

  clockClassEl.hidden = false;
  clockClassEl.textContent = classText;
}

function pad2(n){ return String(n).padStart(2, "0"); }

function formatDuration(ms){
  const total = Math.max(0, Math.floor(ms / 1000));
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  return `${pad2(h)}:${pad2(m)}:${pad2(s)}`;
}

function formatTimerPercent(value){
  const n = Math.max(0, Math.min(100, Number(value) || 0));
  const fixed = n.toFixed(2);
  return n < 10 ? `0${fixed}%` : `${fixed}%`;
}

function getTimerDisplayState(){
  if (!timerTargetMs){
    return {
      active:false,
      remaining:"",
      detail:"Set a target time from the Timer button.",
      progress:0,
      progressText:"",
      showProgress:false
    };
  }

  const now = accurateNowMs();
  const diff = timerTargetMs - now;
  if (diff <= 0){
    return {
      active:false,
      remaining:"00:00:00",
      detail:`Reached ${timerTargetLabel}.`,
      progress:100,
      progressText:"100.00%",
      showProgress:true
    };
  }

  const started = Number(timerStartedAtMs || now);
  const total = Math.max(1, timerTargetMs - started);
  const elapsed = Math.min(total, Math.max(0, now - started));
  const progress = Math.max(0, Math.min(100, (elapsed / total) * 100));
  return {
    active:true,
    remaining:formatDuration(diff),
    detail:`Target: ${timerTargetLabel}`,
    progress,
    progressText:formatTimerPercent(progress),
    showProgress:true
  };
}

function renderTimeDisplayModal(){
  const timeEl = $("time-display-modal-time");
  const classEl = $("time-display-modal-class");
  const remainEl = $("time-display-modal-timer-remaining");
  const percentEl = $("time-display-modal-timer-percent");
  const detailEl = $("time-display-modal-timer-detail");
  const barEl = $("time-display-modal-timer-bar");
  const progressEl = barEl?.closest(".time-display-modal-progress");

  if (timeEl) timeEl.textContent = formatESTClock(getAccurateNow());
  if (classEl) classEl.textContent = getClockClassText();

  const timer = getTimerDisplayState();
  if (remainEl){
    remainEl.textContent = timer.remaining;
    remainEl.hidden = !timer.remaining;
  }
  if (percentEl){
    percentEl.textContent = timer.progressText;
    percentEl.hidden = !timer.progressText;
  }
  if (detailEl) detailEl.textContent = timer.detail;
  if (barEl) barEl.style.width = `${timer.progress}%`;
  if (progressEl) progressEl.hidden = !timer.showProgress;
}

function updateTimerUI(){
  const timer = getTimerDisplayState();

  if (clockTimerEl){
    clockTimerEl.textContent = timer.active
      ? `Timer: ${timer.remaining} left.`
      : (timerTargetMs ? `Timer reached ${timerTargetLabel}.` : "No timer set.");
  }

  renderTimeDisplayModal();

  if (timerTargetMs && !timer.active){
    showToast({ title:"Timer", body:`Reached ${timerTargetLabel} (EST).`, duration: 4000 });
    playSfx("timer");
    clearClockTimer();
  }
}

function startTimerCountdown(){
  try{ if (timerInterval) clearInterval(timerInterval); }catch{}
  timerInterval = null;

  updateTimerUI();

  timerInterval = setInterval(updateTimerUI, 100);
}

function clearClockTimer(){
  timerTargetMs = null;
  timerTargetLabel = "";
  timerStartedAtMs = null;
  try{ if (timerInterval) clearInterval(timerInterval); }catch{}
  timerInterval = null;
  updateTimerUI();
}

function openTimeDisplayModal(){
  openModal({
    title: "Time Display",
    size: "wide",
    bodyHTML: `
      <div class="time-display-modal-ui">
        <div class="time-display-modal-clock">
          <div class="time-display-modal-label">Current time</div>
          <div class="time-display-modal-time" id="time-display-modal-time">—</div>
          <div class="time-display-modal-class" id="time-display-modal-class">Class: None</div>
        </div>

        <div class="time-display-modal-timer">
          <div class="time-display-modal-timer-head">
            <div class="time-display-modal-label">Timer</div>
            <div class="time-display-modal-timer-metrics">
              <div class="time-display-modal-timer-remaining" id="time-display-modal-timer-remaining"></div>
              <div class="time-display-modal-timer-percent" id="time-display-modal-timer-percent" hidden></div>
            </div>
          </div>
          <div class="time-display-modal-progress">
            <div class="time-display-modal-progress-bar" id="time-display-modal-timer-bar"></div>
          </div>
          <div class="time-display-modal-timer-detail" id="time-display-modal-timer-detail">Set a target time from the Timer button.</div>
        </div>
      </div>
    `,
    actionsHTML: `
      ${timerTargetMs ? `<button class="btn" id="time-display-modal-clear" type="button">Clear Timer</button>` : ``}
      <button class="btn primary" id="time-display-modal-set" type="button">Set Timer</button>
    `
  });

  renderTimeDisplayModal();

  $("time-display-modal-set")?.addEventListener("click", openClockTimerModal);
  $("time-display-modal-clear")?.addEventListener("click", () => {
    clearClockTimer();
    renderTimeDisplayModal();
  });
}

function openClockTimerModal(){
  openModal({
    title: "Set Timer",
    bodyHTML: `
      <div class="muted small">Choose a target time.</div>

      <div class="timer-grid">
        <div class="timer-field">
          <div class="timer-label">Hour</div>
          <input class="input" id="timer-hour" inputmode="numeric" autocomplete="off" placeholder="1-12" maxlength="2" />
        </div>
        <div class="timer-field">
          <div class="timer-label">Minute</div>
          <input class="input" id="timer-minute" inputmode="numeric" autocomplete="off" placeholder="0-59" maxlength="2" />
        </div>
        <div class="timer-field">
          <div class="timer-label">Second</div>
          <input class="input" id="timer-second" inputmode="numeric" autocomplete="off" placeholder="0-59" maxlength="2" />
        </div>
      </div>

      <div class="timer-ampm">
        <button class="btn tiny" id="timer-am" type="button">AM</button>
        <button class="btn tiny" id="timer-pm" type="button">PM</button>
      </div>

      <div class="timer-hint muted small" id="timer-preview">—</div>
    `,
    actionsHTML: `
      ${timerTargetMs ? `<button class="btn" id="timer-clear" type="button">Clear Timer</button>` : ``}
      <button class="btn primary" id="timer-start" type="button">Start</button>
    `
  });

  let ampm = "AM";

  function syncPreview(){
    const hRaw = $("timer-hour")?.value || "";
    const mRaw = $("timer-minute")?.value || "";
    const sRaw = $("timer-second")?.value || "";
    const h = Number(hRaw);
    const m = Number(mRaw);
    const s = Number(sRaw);
    const prev = $("timer-preview");
    if (!prev) return;

    if (!hRaw || Number.isNaN(h) || h < 1 || h > 12) { prev.textContent = "Enter an hour (1–12)."; return; }
    if (mRaw && (Number.isNaN(m) || m < 0 || m > 59)) { prev.textContent = "Minute must be 00–59."; return; }
    if (sRaw && (Number.isNaN(s) || s < 0 || s > 59)) { prev.textContent = "Second must be 00–59."; return; }

    prev.textContent = `Target: ${h}:${pad2(mRaw ? m : 0)}:${pad2(sRaw ? s : 0)} ${ampm}`;
  }

  function setAMPM(next){
    ampm = next;
    $("timer-am")?.classList.toggle("primary", ampm === "AM");
    $("timer-pm")?.classList.toggle("primary", ampm === "PM");
    syncPreview();
  }

  $("timer-am")?.addEventListener("click", () => setAMPM("AM"));
  $("timer-pm")?.addEventListener("click", () => setAMPM("PM"));

  function sanitizeTimerInput(id, min, max){
    const el = $(id);
    if (!el) return;
    el.addEventListener("input", () => {
      let v = el.value.replace(/\D/g, "").slice(0, 2);
      if (v){
        const n = Number(v);
        if (Number.isFinite(n)) v = String(Math.min(max, Math.max(min, n)));
      }
      el.value = v;
      syncPreview();
    });
  }

  sanitizeTimerInput("timer-hour", 1, 12);
  sanitizeTimerInput("timer-minute", 0, 59);
  sanitizeTimerInput("timer-second", 0, 59);

  setAMPM("AM");
  syncPreview();

  $("timer-clear")?.addEventListener("click", () => {
    clearClockTimer();
    closeModal();
  });

  $("timer-start")?.addEventListener("click", () => {
    const h = Number($("timer-hour")?.value || "");
    const m = Number($("timer-minute")?.value || "0");
    const s = Number($("timer-second")?.value || "0");

    if (!Number.isFinite(h) || h < 1 || h > 12){
      showToast({ title:"Invalid time", body:"Hour must be 1–12.", duration: 2400 });
      return;
    }
    if (!Number.isFinite(m) || m < 0 || m > 59){
      showToast({ title:"Invalid time", body:"Minute must be 00–59.", duration: 2400 });
      return;
    }
    if (!Number.isFinite(s) || s < 0 || s > 59){
      showToast({ title:"Invalid time", body:"Second must be 00–59.", duration: 2400 });
      return;
    }

    let h24 = (h % 12);
    if (ampm === "PM") h24 += 12;

    const now = getAccurateNow();
    const nowParts = getESTParts(now);

    let target = makeESTDate({
      year: nowParts.year,
      month: nowParts.month,
      day: nowParts.day,
      hour: h24,
      minute: m,
      second: s
    });

    if (target.getTime() <= accurateNowMs()){
      target = new Date(target.getTime() + 24 * 60 * 60 * 1000);
    }

    timerTargetMs = target.getTime();
    timerTargetLabel = `${h}:${pad2(m)}:${pad2(s)} ${ampm}`;
    timerStartedAtMs = accurateNowMs();

    startTimerCountdown();
    closeModal();
  });
}

