/* -------------------- Admin Panel state (Day + Schedule Type + Account Creation) -------------------- */
// Saved in Firebase at /admin/day. Value is 1–6, or null (N/A).
// Schedule type is saved at /admin/scheduleType. Value is "full" | "half" | "delay2".
// Account creation is saved at /admin/accountCreationEnabled. Value is true | false.
const ADMIN_DAY_PATH = "admin/day";
const ADMIN_SCHEDULETYPE_PATH = "admin/scheduleType";
const ADMIN_ACCOUNTCREATION_PATH = "admin/accountCreationEnabled";

let schoolDay = null; // "1".."6" or null
let scheduleType = "full"; // "full" | "half" | "delay2"

let schoolDayListener = null;
let scheduleTypeListener = null;
let accountCreationListener = null;

function _normalizeSchoolDay(v){
  const s = String(v ?? "").trim();
  return /^[1-6]$/.test(s) ? s : null;
}

function _normalizeScheduleType(v){
  const s = String(v ?? "").trim();
  return (s === "full" || s === "half" || s === "delay2") ? s : "full";
}

function _normalizeAccountCreationEnabled(v){
  return v === true;
}

function _scheduleTypeLabel(key){
  const k = _normalizeScheduleType(key);
  return (SCHEDULE_DAY_TYPES.find(x => x.key === k)?.label) || "Full Day";
}

function startScheduleTypeListener(){
  if (scheduleTypeListener) return;

  const ref = db.ref(ADMIN_SCHEDULETYPE_PATH);
  const cb = (snap) => {
    scheduleType = _normalizeScheduleType(snap.val());

    // Update Panel UI (if open)
    const wrap = $("panel-schedtypes");
    if (wrap){
      wrap.querySelectorAll("[data-panel-schedtype]").forEach(btn => {
        const k = btn.getAttribute("data-panel-schedtype") || "full";
        btn.classList.toggle("primary", _normalizeScheduleType(k) === scheduleType);
      });
    }

    // Live update schedules page
    if (localStorage.getItem(LS.PLACE) === "schedules"){
      schedulesState.dayType = scheduleType;
      try{ scheduleRenderSchedulesUI(); }catch{}
    }
  };

  ref.on("value", cb);
  scheduleTypeListener = { ref, cb };
}

function stopScheduleTypeListener(){
  if (!scheduleTypeListener) return;
  try{ scheduleTypeListener.ref.off("value", scheduleTypeListener.cb); }catch{}
  scheduleTypeListener = null;
  scheduleType = "full";
}

async function setScheduleType(key){
  const k = _normalizeScheduleType(key);
  await db.ref(ADMIN_SCHEDULETYPE_PATH).set(k);
}

function startSchoolDayListener(){
  if (schoolDayListener) return;
  const ref = db.ref(ADMIN_DAY_PATH);
  const cb = (snap) => {
    schoolDay = _normalizeSchoolDay(snap.val());

    // Update Panel UI (if open)
    const wrap = $("panel-day-buttons");
    if (wrap){
      wrap.querySelectorAll("[data-panel-day]").forEach(btn => {
        const k = btn.getAttribute("data-panel-day") || "na";
        const isActive = (k === "na") ? !schoolDay : k === String(schoolDay || "");
        btn.classList.toggle("primary", isActive);
      });
    }

    // Live update schedules page
    if (localStorage.getItem(LS.PLACE) === "schedules"){
      try{ scheduleRenderSchedulesUI(); }catch{}
    }
  };
  ref.on("value", cb);
  schoolDayListener = { ref, cb };
}

function stopSchoolDayListener(){
  if (!schoolDayListener) return;
  try{ schoolDayListener.ref.off("value", schoolDayListener.cb); }catch{}
  schoolDayListener = null;
  schoolDay = null;
}

async function setSchoolDay(day){
  const d = _normalizeSchoolDay(day);
  if (!d) throw new Error("Invalid day");
  await db.ref(ADMIN_DAY_PATH).set(Number(d));
}

async function clearSchoolDay(){
  // set(null) removes the key in RTDB => Day becomes N/A
  await db.ref(ADMIN_DAY_PATH).set(null);
}

function startAccountCreationListener(){
  if (accountCreationListener) return;

  const ref = db.ref(ADMIN_ACCOUNTCREATION_PATH);
  const cb = (snap) => {
    accountCreationEnabled = _normalizeAccountCreationEnabled(snap.val());
    bindCreateAccountButton();

    const wrap = $("panel-account-creation");
    if (wrap){
      wrap.querySelectorAll("[data-panel-account-creation]").forEach(btn => {
        const k = btn.getAttribute("data-panel-account-creation") || "disabled";
        btn.classList.toggle("primary", (k === "enabled") === accountCreationEnabled);
      });
    }
  };

  ref.on("value", cb);
  accountCreationListener = { ref, cb };
}

function stopAccountCreationListener(){
  if (!accountCreationListener) return;
  try{ accountCreationListener.ref.off("value", accountCreationListener.cb); }catch{}
  accountCreationListener = null;
  accountCreationEnabled = false;
  bindCreateAccountButton();
}

async function setAccountCreationEnabled(enabled){
  await db.ref(ADMIN_ACCOUNTCREATION_PATH).set(!!enabled);
}

