function _getClassForBlock(dayType, person, blockKey, schoolDayOverride = schoolDay){
  const base = (SCHEDULES[dayType] && SCHEDULES[dayType][person] && SCHEDULES[dayType][person][blockKey])
    ? SCHEDULES[dayType][person][blockKey]
    : { className: "", teacher: "", room: "" };

  if (person === "santini" && blockKey === "P7"){
    const p = getESTParts(getAccurateNow());
    const idx = new Date(Date.UTC(p.year, p.month - 1, p.day)).getUTCDay();
    return _getSantiniSpecialClassByWeekdayIndex(idx);
  }

  if ((blockKey === "P3" || blockKey === "P4") && person !== "santini"){
    const d = _normalizeSchoolDay(schoolDayOverride);
    if (d){
      const ov = DAY_CYCLE_P3P4?.[person]?.[blockKey]?.[d];
      if (ov && typeof ov === "object"){
        return {
          className: ov.className ?? "",
          teacher: ov.teacher ?? "",
          room: ov.room ?? "",
        };
      }
      // Optional alternate format: store P3/P4 directly keyed by day inside SCHEDULES
      const alt = (base && typeof base === "object") ? base[d] : null;
      if (alt && typeof alt === "object"){
        return { className: alt.className ?? "", teacher: alt.teacher ?? "", room: alt.room ?? "" };
      }
    }
  }

  if (base && typeof base === "object"){
    return {
      className: base.className ?? "",
      teacher: base.teacher ?? "",
      room: base.room ?? "",
    };
  }
  return { className: "", teacher: "", room: "" };
}

/* Current-period highlight (EST) */
let schedulesHighlightTimer = null;

function _nowMinutesEST(){
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: "America/New_York",
    hour12: false,
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit"
  }).formatToParts(new Date());
  const h = parseInt(parts.find(p => p.type === "hour")?.value || "0", 10);
  const m = parseInt(parts.find(p => p.type === "minute")?.value || "0", 10);
  const s = parseInt(parts.find(p => p.type === "second")?.value || "0", 10);
  return (h * 60) + m + (s / 60);
}

function _timeToMinutes(t){
  const m = String(t || "").trim().match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (!m) return null;
  let hh = parseInt(m[1], 10);
  const mm = parseInt(m[2], 10);
  const ap = m[3].toUpperCase();
  if (hh === 12) hh = 0;
  if (ap === "PM") hh += 12;
  return hh * 60 + mm;
}

function _parseRangeMinutes(range){
  const s = String(range || "").trim();
  const m = s.match(/(\d{1,2}:\d{2}\s*(?:AM|PM))\s*[-–—]\s*(\d{1,2}:\d{2}\s*(?:AM|PM))/i);
  if (!m) return null;
  const a = _timeToMinutes(m[1]);
  const b = _timeToMinutes(m[2]);
  if (a === null || b === null) return null;
  return { start: a, end: b };
}

const SANTINO_SCHED_LABELS = {
  AM_HR: "AM Homeroom",
  P1: "Period 1",
  P2: "Period 2 (Half 1)",
  P3: "Lunch",
  P4: "Period 2 (Half 2)",
  P5: "Recess",
  P7: "Special",
  P8: "Period 3",
  PM_HR: "PM Homeroom",
};

const SANTINO_SCHED_TIMES_FULL = {
  AM_HR: { time: "9:00 AM - 9:10 AM", duration: "10 minutes" },
  P1:    { time: "9:10 AM - 10:25 AM", duration: "75 minutes" },
  P2:    { time: "10:25 AM - 11:20 AM", duration: "55 minutes" },
  P3:    { time: "11:20 AM - 12:00 PM", duration: "40 minutes" },
  P4:    { time: "12:00 PM - 12:25 PM", duration: "25 minutes" },
  P5:    { time: "12:25 PM - 12:40 PM", duration: "15 minutes" },
  P7:    { time: "12:40 PM - 1:30 PM", duration: "50 minutes" },
  P8:    { time: "1:30 PM - 2:50 PM", duration: "80 minutes" },
  PM_HR: { time: "2:50 PM - 3:00 PM", duration: "10 minutes" },
};

function _getActiveScheduleBlockKey(dayType, person){
  const isSantino = person === "santini";

  const times = isSantino
    ? (dayType === "full" ? SANTINO_SCHED_TIMES_FULL : null)
    : (SCHEDULE_TIMES[dayType] || {});

  if (isSantino && !times) return null;

  const p = getESTParts(getAccurateNow());
  const weekdayIndex = new Date(Date.UTC(p.year, p.month - 1, p.day)).getUTCDay();
  if (weekdayIndex === 0 || weekdayIndex === 6) return null;

  const now = (p.hour * 60) + p.minute + (p.second / 60);
  for (const b of SCHEDULE_BLOCKS){
    if (isSantino && b.key === "P6") continue;
    const r = _parseRangeMinutes(times?.[b.key]?.time || "");
    if (!r) continue;
    if (now >= r.start && now < r.end) return b.key;
  }
  return null;
}

function applySchedulesActiveHighlight(){
  if (!messagesListEl) return;
  if (localStorage.getItem(LS.PLACE) !== "schedules") return;
  const dayType = schedulesState.dayType || "full";
  const active = _getActiveScheduleBlockKey(dayType, schedulesState.person);

  messagesListEl.querySelectorAll(".sched-grid-row[data-sched-block]").forEach(row => {
    const k = row.getAttribute("data-sched-block");
    row.classList.toggle("is-active", !!active && k === active);
  });

  messagesListEl.querySelectorAll(".sched-times-row[data-sched-block]").forEach(row => {
    const k = row.getAttribute("data-sched-block");
    row.classList.toggle("is-active", !!active && k === active);
  });
}

function startSchedulesHighlightTimer(){
  if (schedulesHighlightTimer) return;
  schedulesHighlightTimer = setInterval(() => {
    if (localStorage.getItem(LS.PLACE) !== "schedules") return;
    applySchedulesActiveHighlight();
  }, 250);
}

function stopSchedulesHighlightTimer(){
  if (!schedulesHighlightTimer) return;
  clearInterval(schedulesHighlightTimer);
  schedulesHighlightTimer = null;
}

let schedulesState = {
  dayType: "full",   // default when opening page
  previewDay: null,  // day preview shown on Schedules page only
  person: null
};

let schedulesRenderRaf = 0;

function scheduleRenderSchedulesUI(){
  if (schedulesRenderRaf) return;
  schedulesRenderRaf = requestAnimationFrame(() => {
    schedulesRenderRaf = 0;
    if ((localStorage.getItem(LS.PLACE) || "") !== "schedules") return;
    renderSchedulesUI();
  });
}

function setHeaderSchedules(){
  $("room-title").textContent = "Schedules";
  $("room-sub").textContent = "View schedules, times, and live current-period highlights.";
}

function _schedVal(v){
  const s = String(v ?? "").trim();
  return s ? escapeHtml(s) : "";
}

function _renderScheduleTimesCard(dayType, person = null){
  const isSantino = person === "santini";

  const t = isSantino
    ? (dayType === "full" ? SANTINO_SCHED_TIMES_FULL : {})
    : (SCHEDULE_TIMES[dayType] || {});

  const activeKey = _getActiveScheduleBlockKey(dayType, person);

  let rows = "";
  for (const b of SCHEDULE_BLOCKS){
    if (isSantino && b.key === "P6") continue;
    const label = isSantino ? (SANTINO_SCHED_LABELS[b.key] || b.label) : b.label;

    const rec = (isSantino && dayType !== "full")
      ? { time: "N/A", duration: "N/A" }
      : (t[b.key] || { time: "", duration: "" });

    const isActive = !!activeKey && b.key === activeKey;

    rows += `
      <div class="sched-times-row${isActive ? " is-active" : ""}" data-sched-block="${escapeHtml(b.key)}">
        <div class="sched-times-period">${escapeHtml(label)}</div>
        <div class="sched-times-time">${_schedVal(rec.time)}</div>
        <div class="sched-times-dur">${_schedVal(rec.duration)}</div>
      </div>`;
  }

  return `
    <div class="sched-card">
      <div class="sched-card-title">Schedule Times</div>
      <div class="sched-times">
        <div class="sched-times-head">
          <div>Period</div>
          <div>Time</div>
          <div>Minutes</div>
        </div>
        ${rows}
      </div>
    </div>
  `;
}

function _renderScheduleTable(dayType, person){
  const isSantino = person === "santini";
  const previewDay = _normalizeSchoolDay(
    schedulesState?.previewDay == null ? schoolDay : schedulesState.previewDay
  );

  const times = isSantino
    ? (dayType === "full" ? SANTINO_SCHED_TIMES_FULL : {})
    : (SCHEDULE_TIMES[dayType] || {});

  const activeKey = _getActiveScheduleBlockKey(dayType, person);

  const hasScheduleAssigned = !!(SCHEDULES?.[dayType]?.[person]);
  if (!hasScheduleAssigned){
    return `
      <div class="sched-card">
        <div class="sched-card-title">Schedule — ${escapeHtml(person)}</div>
        <div class="sched-grid">
          <div class="sched-grid-head">
            <div>Period</div>
            <div>Time</div>
            <div>Minutes</div>
            <div>Class Name</div>
            <div>Teacher</div>
            <div>Room</div>
          </div>
          <div class="sched-grid-row sched-grid-empty">
            <div class="sched-cell sched-cell-empty">No schedule assigned.</div>
          </div>
        </div>
      </div>
    `;
  }

  let rows = "";
  for (const b of SCHEDULE_BLOCKS){
    if (isSantino && b.key === "P6") continue;
    const label = isSantino ? (SANTINO_SCHED_LABELS[b.key] || b.label) : b.label;

    const t = (isSantino && dayType !== "full")
      ? { time: "N/A", duration: "N/A" }
      : (times[b.key] || { time: "", duration: "" });

    const c = _getClassForBlock(dayType, person, b.key, previewDay);
    const room = (isSantino && dayType !== "full") ? "N/A" : c.room;

    const isActive = !!activeKey && b.key === activeKey;

    rows += `
      <div class="sched-grid-row${isActive ? " is-active" : ""}" data-sched-block="${escapeHtml(b.key)}">
        <div class="sched-cell sched-cell-period">${escapeHtml(label)}</div>
        <div class="sched-cell sched-cell-time">${_schedVal(t.time)}</div>
        <div class="sched-cell sched-cell-duration">${_schedVal(t.duration)}</div>
        <div class="sched-cell sched-cell-class">${_schedVal(c.className)}</div>
        <div class="sched-cell sched-cell-teacher">${_schedVal(c.teacher)}</div>
        <div class="sched-cell sched-cell-room">${_schedVal(room)}</div>
      </div>
    `;
  }

  return `
    <div class="sched-card">
      <div class="sched-card-title">Schedule — ${escapeHtml(person)}</div>
      <div class="sched-grid">
        <div class="sched-grid-head">
          <div>Period</div>
          <div>Time</div>
          <div>Minutes</div>
          <div>Class Name</div>
          <div>Teacher</div>
          <div>Room</div>
        </div>
        ${rows}
      </div>
    </div>
  `;
}

function renderSchedulesUI(){
  if (!messagesListEl) return;

  // Schedule type is controlled by Panel (Firebase)
  schedulesState.dayType = scheduleType || schedulesState.dayType || "full";

  const dayType = schedulesState.dayType || "full";
  const person = schedulesState.person;

  const previewDay = _normalizeSchoolDay(
    schedulesState.previewDay == null ? schoolDay : schedulesState.previewDay
  );
  schedulesState.previewDay = previewDay;

  const typeLabel = _scheduleTypeLabel(dayType);
  const dayLabel = schoolDay ? `Day ${schoolDay}` : "Day N/A";

  const typeIcon = (k) => {
    const key = _normalizeScheduleType(k);
    if (key === "half"){
      return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
        <path d="M21 12.5A8.5 8.5 0 1 1 11.5 3a6.5 6.5 0 1 0 9.5 9.5Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
      </svg>`;
    }
    if (key === "delay2"){
      return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
        <circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="2"/>
        <path d="M12 7v6l4 2" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>`;
    }
    return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none" aria-hidden="true">
      <path d="M12 2v3M12 19v3M4.2 4.2l2.1 2.1M17.7 17.7l2.1 2.1M2 12h3M19 12h3M4.2 19.8l2.1-2.1M17.7 6.3l2.1-2.1" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
      <circle cx="12" cy="12" r="5" stroke="currentColor" stroke-width="2"/>
    </svg>`;
  };

  const personIcon = (u) => {
    const code = String(u?.code || "");
    return `<div class="sched-avatar" data-usercode="${escapeHtml(code)}" aria-hidden="true"></div>`;
  };

  const people = Array.isArray(schedulesPeopleCache) ? schedulesPeopleCache : [];
  const selectedPersonUser = person ? schedulesPeopleByUsername.get(String(person)) : null;

  const emptyLabel = schedulesPeopleLoadedOnce
    ? `No accounts found.`
    : `Loading accounts...`;

  const peopleGrid = people.length ? people.map(u => {
    const uname = String(u?.username || "User"), dname = String(u?.displayName || uname), code = String(u?.code || "");
    return `
      <button class="sched-person-card" data-sched-person="${escapeHtml(uname)}" type="button">
        ${personIcon(u)}
        <div class="sched-person-meta">
          <div class="sched-person-name" data-display-name-usercode="${escapeHtml(code)}">${escapeHtml(dname)}</div>
        </div>
        <div class="sched-person-go" aria-hidden="true">
          <svg viewBox="0 0 24 24" width="18" height="18" fill="none">
            <path d="M9 6l6 6-6 6" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/>
          </svg>
        </div>
      </button>
    `;
  }).join("") : `<div class="muted small" style="padding:6px 2px">${escapeHtml(emptyLabel)}</div>`;

  const previewButtons = ["1","2","3","4","5","6"].map((d) => `
    <button class="sched-preview-btn${previewDay === d ? " is-active" : ""}" data-sched-preview-day="${d}" type="button">${d}</button>
  `).join("") + (!schoolDay ? `
    <button class="sched-preview-btn${previewDay ? "" : " is-active"}" data-sched-preview-day="" type="button">N/A</button>
  ` : "");

  const top = `
    <div class="sched-topcard">
      <div class="sched-top-left">
        <div class="sched-top-ico" aria-hidden="true">
          <svg viewBox="0 0 24 24" width="18" height="18" fill="none">
            <path d="M7 4h10a2 2 0 0 1 2 2v14l-3-2-4 2-4-2-3 2V6a2 2 0 0 1 2-2Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
            <path d="M9 8h6M9 12h6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
          </svg>
        </div>
        <div>
          <div class="sched-title">Schedules</div>
          <div class="sched-sub">${escapeHtml(dayLabel)}</div>
        </div>
      </div>

      <div class="sched-top-right">
        <div class="sched-preview-days" aria-label="Preview day">
          ${previewButtons}
        </div>
        <div class="sched-type-badge" title="Controlled by Admin Panel">
          <span class="sched-type-ico">${typeIcon(dayType)}</span>
          <span class="sched-type-text">${escapeHtml(typeLabel)}</span>
        </div>
      </div>
    </div>
  `;

  let body = "";

  if (!person){
    body = `
      <div class="sched-split">
        <div class="sched-card sched-card-people">
          <div class="sched-card-title">People</div>
          <div class="sched-people-grid">
            ${peopleGrid}
          </div>
        </div>

        ${_renderScheduleTimesCard(dayType, null)}
      </div>
    `;
  } else {
    body = `
      <div class="sched-view-head">
        <button class="btn tiny" data-sched-back="1" type="button">Back</button>
        <div class="sched-person-title"${selectedPersonUser?.code ? ` data-display-name-usercode="${escapeHtml(String(selectedPersonUser.code))}"` : ``}>${escapeHtml(String(selectedPersonUser?.displayName || person))}</div>
      </div>

      ${_renderScheduleTable(dayType, person)}
      <div style="height:12px"></div>
      ${_renderScheduleTimesCard(dayType, person)}
    `;
  }

  messagesListEl.innerHTML = `
    <div class="sched-page">
      ${top}
      ${body}
    </div>
  `;

  // Hydrate avatars + keep them live
  messagesListEl.querySelectorAll(".sched-avatar[data-usercode]").forEach(el => {
    const code = el.getAttribute("data-usercode") || "";
    const u = schedulesPeopleByCode.get(code);
    if (u) applyAvatar(el, u);
    ensureLiveUserListener(code);
  });

  // Wire preview day buttons
  messagesListEl.querySelectorAll("[data-sched-preview-day]").forEach(btn => {
    btn.addEventListener("click", () => {
      const raw = btn.getAttribute("data-sched-preview-day");
      schedulesState.previewDay = _normalizeSchoolDay(raw);
      renderSchedulesUI();
    });
  });

  // Wire name cards
  messagesListEl.querySelectorAll("[data-sched-person]").forEach(btn => {
    btn.addEventListener("click", () => {
      schedulesState.person = btn.getAttribute("data-sched-person");
      renderSchedulesUI();
    });
  });

  // Wire back
  const backBtn = messagesListEl.querySelector("[data-sched-back]");
  if (backBtn){
    backBtn.addEventListener("click", () => {
      schedulesState.person = null;
      renderSchedulesUI();
    });
  }

  // Keep the yellow "active period" highlight updating live
  startSchedulesHighlightTimer();
  applySchedulesActiveHighlight();
}

function clearMessagesToSchedules(){
  renderSchedulesUI();
}

function showSchedulesPage(personOverride = null){
  // Always open to the name-picker screen (schedule type is controlled by Panel)
  schedulesState.dayType = scheduleType || "full";
  schedulesState.previewDay = schoolDay;
  schedulesState.person = personOverride ? String(personOverride).trim() || null : null;

  // Exit slideshow mode if needed
  stopSlideshowPresence();
  detachSlideshowSlides();
  detachSlideshowDividers();
  detachSlideshowTitles();
  detachSlideshowDoc();
  detachSlideshowThumbDocs();

  try{ slideshowReorderStopAutoScroll(); }catch{}
  try{ if (slideshowReorderMode) slideshowCancelReorderMode(); }catch{}
  try{
    for (const t of slideshowTitleSaveTimers.values()) clearTimeout(t);
    slideshowTitleSaveTimers.clear();
  }catch{}

  slideshowDividerInsertMode = false;
  slideshowSelectedDividerBeforeId = null;
  slideshowTitleInsertMode = false;
  slideshowSelectedTitleBeforeId = null;
  slideshowEditingTitleBeforeId = null;

  document.body.classList.remove("slideshow-full");

  stopAllChatAudio();
  stopAllSlideshowAudio();
  resetSlideshowCopyPasteStatus();
  stopRoomPresence();
  detachOnlineIndicator();
  detachMessages();

  try{ clearReplyState({ quiet:true }); }catch{}
  try{ clearPendingFiles({ quiet:true }); }catch{}
  try{ closePingBar({ quiet:true }); }catch{}
  try{ $("msg-input").value = ""; $("msg-input").blur(); }catch{}

  currentRoomId = null;
  syncCallButton();
  setHeaderSchedules();
  setComposerEnabled(false);
  abortFirebaseUploadsForPlaceChange("schedules");
  localStorage.setItem(LS.PLACE, "schedules");
  syncSidebarNavActive();
  syncSidebarRoomActiveStates();
  try{ applySlideshowComposerRules(); }catch{}
  try{ syncEmojiButtonVisibility(); }catch{}
  try{
    if (messagesEl) messagesEl.scrollTop = 0;
    window.scrollTo(0, 0);
  }catch{}

  if (messagesListEl){
    messagesListEl.innerHTML = `
      <div class="sched-page">
        <div class="sched-card">
          <div class="sched-card-title">Schedules</div>
          <div class="muted small">Loading schedules...</div>
        </div>
      </div>
    `;
  }

  requestAnimationFrame(() => {
    startSchoolDayListener();
    startScheduleTypeListener();
    startSchedulesPeopleListener();
    clearMessagesToSchedules();
  });
}

/* -------------------- Slideshow (global) -------------------- */
let slideshowUIRenderQueued = false;
function scheduleRenderSlideshowUI(){
  if (slideshowUIRenderQueued) return;
  slideshowUIRenderQueued = true;
  const q = (typeof queueMicrotask === "function") ? queueMicrotask : (fn) => Promise.resolve().then(fn);
  q(() => {
    slideshowUIRenderQueued = false;
    renderSlideshowUI();
  });
}

function setHeaderSlideshow(){
  $("room-title").textContent = "";
  $("room-sub").textContent = "";
}

function clearMessagesToSlideshow(){
  scheduleRenderSlideshowUI();
}

function showSlideshowPage(){
  // Leave any room/schedules state
  stopAllChatAudio();
  stopAllSlideshowAudio();
  stopRoomPresence();
  detachOnlineIndicator();
  detachMessages();
  stopSchedulesHighlightTimer();
  stopSchedulesPeopleListener();

  // Reset slideshow listeners before re-attaching
  stopSlideshowPresence();
  detachSlideshowSlides();
  detachSlideshowDividers();
  detachSlideshowTitles();
  detachSlideshowDoc();
  detachSlideshowThumbDocs();

  try{ clearReplyState({ quiet:true }); }catch{}
  try{ clearPendingFiles({ quiet:true }); }catch{}
  try{ closePingBar({ quiet:true }); }catch{}
  try{ $("msg-input").value = ""; $("msg-input").blur(); }catch{}

  currentRoomId = null;
  setHeaderSlideshow();
  abortFirebaseUploadsForPlaceChange("slideshow");
  localStorage.setItem(LS.PLACE, "slideshow");
  syncSidebarNavActive();
  syncSidebarRoomActiveStates();
  document.body.classList.add("slideshow-full");

  setComposerEnabled(true);
  slideshowDividerInsertMode = false;
  slideshowSelectedDividerBeforeId = null;
  slideshowTitleInsertMode = false;
  slideshowSelectedTitleBeforeId = null;
  slideshowEditingTitleBeforeId = null;
  slideshowSelectedObjId = null;
  slideshowSelectedObjType = null;
  slideshowFilePickMode = "object";
  applySlideshowComposerRules();
  try{ syncEmojiButtonVisibility(); }catch{}
  clearMessagesToSlideshow();
  bindSlideshowDividerOutsideClick();
  bindSlideshowTitleOutsideClick();

  attachSlideshowIndicator();
  startSlideshowPresence();
  attachSlideshowLocations();
  attachSlideshowDividers();
  attachSlideshowTitles();
  attachSlideshowSlides();
}

function detachSlideshowSlides(){
  if (slideshowSlidesRef && slideshowSlidesCb){
    try{ slideshowSlidesRef.off("value", slideshowSlidesCb); }catch{}
  }
  slideshowSlidesRef = null;
  slideshowSlidesCb = null;
  slideshowOrderReady = false;
}

function detachSlideshowDividers(){
  if (slideshowDividersRef && slideshowDividersCb){
    try{ slideshowDividersRef.off("value", slideshowDividersCb); }catch{}
  }
  slideshowDividersRef = null;
  slideshowDividersCb = null;
  slideshowDividersReady = false;
}

function detachSlideshowTitles(){
  if (slideshowTitlesRef && slideshowTitlesCb){
    try{ slideshowTitlesRef.off("value", slideshowTitlesCb); }catch{}
  }
  slideshowTitlesRef = null;
  slideshowTitlesCb = null;
  slideshowTitlesMap = new Map();
}

function attachSlideshowDividers(){
  if (!currentUser) return;

  detachSlideshowDividers();
  slideshowDividersRef = db.ref("slideshow/dividers");
  slideshowDividersCb = (snap) => {
    const v = snap.exists() ? (snap.val() || {}) : {};
    const set = new Set();
    for (const k of Object.keys(v)){
      if (k) set.add(k);
    }
    slideshowDividersSet = set;
    slideshowDividersReady = true;
    if (!set.size) slideshowTitleInsertMode = false;
    if (slideshowOrderReady) scheduleSlideshowTitlesCleanup(slideshowOrder);
    scheduleRenderSlideshowUI();
  };
  slideshowDividersRef.on("value", slideshowDividersCb);
}

function attachSlideshowTitles(){
  if (!currentUser) return;

  detachSlideshowTitles();
  slideshowTitlesRef = db.ref("slideshow/titles");
  slideshowTitlesCb = (snap) => {
    const v = snap.exists() ? (snap.val() || {}) : {};
    const map = new Map();
    for (const [k, rec] of Object.entries(v)){
      if (!k) continue;
      map.set(k, {
        text: String(rec?.text ?? ""),
        createdAt: Number(rec?.createdAt) || 0,
        updatedAt: Number(rec?.updatedAt) || 0
      });
    }
    slideshowTitlesMap = map;
    if (slideshowOrderReady) scheduleSlideshowTitlesCleanup(slideshowOrder);

    // Prevent the picker from re-rendering while typing, which recreates the textarea
    // and causes focus loss after 1 character.
    if (slideshowEditingTitleBeforeId) return;

    scheduleRenderSlideshowUI();
  };
  slideshowTitlesRef.on("value", slideshowTitlesCb);
}

function scheduleSlideshowDividersCleanup(validOrder){
  if (!currentUser) return;
  if (!slideshowOrderReady) return;
  if (slideshowDividersCleanupTimer) clearTimeout(slideshowDividersCleanupTimer);
  const ids = Array.isArray(validOrder) ? validOrder.slice() : [];
  slideshowDividersCleanupTimer = setTimeout(() => {
    cleanupOrphanSlideshowDividers(ids);
  }, 800);
}

async function cleanupOrphanSlideshowDividers(validOrder){
  if (!currentUser) return;
  try{
    const snap = await db.ref("slideshow/dividers").once("value");
    const divs = snap.exists() ? (snap.val() || {}) : {};
    const keep = new Set(validOrder || []);
    const first = Array.isArray(validOrder) && validOrder.length ? String(validOrder[0]) : null;
    const updates = {};
    for (const id of Object.keys(divs)){
      if (!keep.has(id)){
        updates[`slideshow/dividers/${id}`] = null;
      }
    }
    if (Object.keys(updates).length){
      await db.ref().update(updates);
    }
  }catch{}
}

function scheduleSlideshowTitlesCleanup(validOrder){
  if (!currentUser) return;
  if (!slideshowOrderReady) return;
  if (!slideshowDividersReady) return;
  if (slideshowTitlesCleanupTimer) clearTimeout(slideshowTitlesCleanupTimer);
  const ids = Array.isArray(validOrder) ? validOrder.slice() : [];
  slideshowTitlesCleanupTimer = setTimeout(() => {
    cleanupOrphanSlideshowTitles(ids);
  }, 800);
}

async function cleanupOrphanSlideshowTitles(validOrder){
  if (!currentUser) return;
  if (!slideshowDividersReady) return;
  try{
    const snap = await db.ref("slideshow/titles").once("value");
    const titles = snap.exists() ? (snap.val() || {}) : {};
    const keep = new Set(validOrder || []);
    const first = Array.isArray(validOrder) && validOrder.length ? String(validOrder[0]) : null;
    const divSet = (slideshowDividersSet instanceof Set) ? slideshowDividersSet : new Set();
    const updates = {};
    for (const id of Object.keys(titles)){
      if (!keep.has(id)){
        updates[`slideshow/titles/${id}`] = null;
        continue;
      }
      // Allow a title at the very top of Slide 1 (stored under the first slide id)
      if (first && id === first) continue;

      // All other titles must live directly under an existing divider
      if (!divSet.has(id)){
        updates[`slideshow/titles/${id}`] = null;
      }
    }
    if (Object.keys(updates).length){
      await db.ref().update(updates);
    }
  }catch{}
}

let slideshowDocsCleanupTimer = null;

function scheduleSlideshowDocsCleanup(validIds){
  if (!currentUser) return;
  if (slideshowDocsCleanupTimer) clearTimeout(slideshowDocsCleanupTimer);
  const ids = Array.isArray(validIds) ? validIds.slice() : [];
  slideshowDocsCleanupTimer = setTimeout(() => {
    cleanupOrphanSlideshowDocs(ids);
  }, 800);
}

async function cleanupOrphanSlideshowDocs(validIds){
  if (!currentUser) return;
  try{
    const base = String(firebaseConfig?.databaseURL || "").replace(/\/+$/, "");
    if (!base) return;

    const res = await fetch(`${base}/slideshow/docs.json?shallow=true`, { cache:"no-store" });
    if (!res.ok) return;

    const docs = await res.json();
    const keep = new Set(validIds || []);
    const updates = {};

    for (const id of Object.keys(docs || {})){
      if (!keep.has(id)){
        updates[`slideshow/docs/${id}`] = null;
      }
    }

    if (Object.keys(updates).length){
      await db.ref().update(updates);
    }
  }catch{}
}

function detachSlideshowLocations(){
  if (slideshowLocationsRef && slideshowLocationsCb){
    try{ slideshowLocationsRef.off("value", slideshowLocationsCb); }catch{}
  }
  slideshowLocationsRef = null;
  slideshowLocationsCb = null;
  slideshowLocationsCache.clear();
  renderSlideshowThumbLocations();
  if (onlineIndicatorMode === "slideshow") renderOnlineIndicator();
}

function attachSlideshowLocations(){
  if (!currentUser) return;

  detachSlideshowLocations();

  slideshowLocationsRef = db.ref("slideshow/locations");
  slideshowLocationsCb = (snap) => {
    slideshowLocationsCache.clear();
    const v = snap.exists() ? (snap.val() || {}) : {};
    const prevSelected = slideshowSelectedId;
    for (const [code, rec] of Object.entries(v)){
      if (!code) continue;
      const slideId = String(rec?.slideId || "");
      if (!slideId) continue;
      slideshowLocationsCache.set(code, {
        slideId,
        selectedObjId: String(rec?.selectedObjId || ""),
        updatedAt: Number(rec?.updatedAt) || 0
      });
      ensureLiveUserListener(code);
    }
    renderSlideshowThumbLocations();
    renderSlideshowRemoteSelections();
    if (onlineIndicatorMode === "slideshow") renderOnlineIndicator();
  };
  slideshowLocationsRef.on("value", slideshowLocationsCb);
}

function setMySlideshowLocation(slideId){
  if (!currentUser) return;

  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  if (placeNow !== "slideshow"){
    if (mySlideshowLocationRef){
      try{ mySlideshowLocationRef.onDisconnect().cancel(); }catch{}
      try{ mySlideshowLocationRef.remove(); }catch{}
    }
    mySlideshowLocationRef = null;
    mySlideshowLocationSlideId = null;
    return;
  }

  const sid = (slideId && Array.isArray(slideshowOrder) && slideshowOrder.includes(slideId)) ? String(slideId) : null;

  if (!sid){
    if (mySlideshowLocationRef){
      try{ mySlideshowLocationRef.onDisconnect().cancel(); }catch{}
      try{ mySlideshowLocationRef.remove(); }catch{}
    }
    mySlideshowLocationRef = null;
    mySlideshowLocationSlideId = null;
    return;
  }

  mySlideshowLocationRef = db.ref(`slideshow/locations/${currentUser.code}`);
  mySlideshowLocationSlideId = sid;

  try{ mySlideshowLocationRef.onDisconnect().remove(); }catch{}
  try{
    mySlideshowLocationRef.set({
      slideId: sid,
      selectedObjId: slideshowSelectedObjId ? String(slideshowSelectedObjId) : "",
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    });
  }catch{}
}

function slideshowJumpToSlide(slideId){
  const sid = (slideId || "").trim();
  if (!sid) return;
  if (!Array.isArray(slideshowOrder) || !slideshowOrder.length) return;
  if (!slideshowOrder.includes(sid)) return;

  stopAllSlideshowAudio();

  try{
    if (slideshowReorderMode) slideshowCancelReorderMode();
  }catch{}
  slideshowDividerInsertMode = false;
  slideshowSelectedDividerBeforeId = null;
  slideshowTitleInsertMode = false;
  slideshowSelectedTitleBeforeId = null;
  slideshowEditingTitleBeforeId = null;

  slideshowSelectedId = sid;
  slideshowClearSelection({ quiet:true });
  setMySlideshowLocation(sid);
  scheduleRenderSlideshowUI();
}

function renderSlideshowThumbLocations(){
  const thumbsEl = $("slideshow-thumbs");
  if (!thumbsEl) return;

  const bySlide = new Map();
  for (const [code, rec] of slideshowLocationsCache){
    const sid = String(rec?.slideId || "");
    if (!sid) continue;
    if (!bySlide.has(sid)) bySlide.set(sid, []);
    bySlide.get(sid).push(code);
  }

  for (const sid of (Array.isArray(slideshowOrder) ? slideshowOrder : [])){
    const left = thumbsEl.querySelector(`[data-thumb-locs-left="${CSS.escape(sid)}"]`);
    const right = thumbsEl.querySelector(`[data-thumb-locs-right="${CSS.escape(sid)}"]`);
    if (!left) continue;

    const codes = bySlide.get(sid) || [];
    const sorted = codes.slice().sort((a,b) => {
      const au = (liveUserCache.get(a)?.usernameLower || a).toLowerCase();
      const bu = (liveUserCache.get(b)?.usernameLower || b).toLowerCase();
      const c = au.localeCompare(bu);
      return c !== 0 ? c : a.localeCompare(b);
    });

    const showCodes = sorted.slice(0,6);

    const frag = document.createDocumentFragment();
    for (const code of showCodes){
      const ava = document.createElement("div");
      ava.className = "mini-avatar slideshow-loc-ava";
      ava.dataset.usercode = code;
      const live = liveUserCache.get(code) || null;
      applyAvatar(ava, live || { code, username:"User", photoDataURL: defaultStickmanDataURL(), photoTransform: null });
      frag.appendChild(ava);
    }

    left.replaceChildren(frag);
    if (right) right.replaceChildren();
  }
}

function attachSlideshowSlides(){
  if (!currentUser) return;

  detachSlideshowSlides();
  slideshowSlidesRef = db.ref("slideshow/slides");
  slideshowSlidesCb = (snap) => {
    const v = snap.exists() ? (snap.val() || {}) : {};
    const arr = [];
    for (const [id, rec] of Object.entries(v)){
      const createdAt = Number(rec?.createdAt) || 0;
      const order = (rec?.order !== undefined && rec?.order !== null) ? Number(rec.order) : NaN;
      arr.push({ id, createdAt, order });
    }

    const hasOrder = arr.some(x => Number.isFinite(x.order));
    const missingOrder = arr.some(x => !Number.isFinite(x.order));

    if (hasOrder){
      // Respect explicit order; push missing-order slides to the end deterministically.
      arr.sort((a,b) => {
        const ao = Number.isFinite(a.order) ? a.order : Number.POSITIVE_INFINITY;
        const bo = Number.isFinite(b.order) ? b.order : Number.POSITIVE_INFINITY;
        return (ao - bo) || (a.createdAt - b.createdAt) || a.id.localeCompare(b.id);
      });
    } else {
      // Legacy: order by createdAt (then id)
      arr.sort((a,b) => (a.createdAt - b.createdAt) || a.id.localeCompare(b.id));
    }

    // Initialize missing order values once, so Reordering can persist.
    if (missingOrder){
      const updates = {};
      arr.forEach((x, idx) => {
        if (!Number.isFinite(x.order)){
          const ord = idx + 1;
          x.order = ord;
          updates[`slideshow/slides/${x.id}/order`] = ord;
        }
      });
      if (Object.keys(updates).length){
        db.ref().update(updates).catch(()=>{});
      }
    }

    // Final order (now always by order)
    arr.sort((a,b) => (Number(a.order) - Number(b.order)) || a.id.localeCompare(b.id));
    slideshowOrder = arr.map(x => x.id);
    slideshowOrderReady = true;

    // Cache order map + max (used for new slides and reordering)
    slideshowOrderMap = new Map(arr.map(x => [x.id, Number(x.order) || 0]));
    slideshowMaxOrder = arr.reduce((m,x) => Math.max(m, Number(x.order) || 0), 0);

    if (slideshowPendingSelectId && slideshowOrder.includes(slideshowPendingSelectId)){
      slideshowSelectedId = slideshowPendingSelectId;
      slideshowPendingSelectId = null;
    }

    if (!slideshowSelectedId || !slideshowOrder.includes(slideshowSelectedId)){
      slideshowSelectedId = slideshowOrder[0] || null;
    }

    // Keep /docs clean (prevents deleted slides from lingering in slideshow/docs)
    scheduleSlideshowDocsCleanup(slideshowOrder);
    scheduleSlideshowDividersCleanup(slideshowOrder);
    scheduleSlideshowTitlesCleanup(slideshowOrder);

    setMySlideshowLocation(slideshowSelectedId);
    scheduleRenderSlideshowUI();
  };
  slideshowSlidesRef.on("value", slideshowSlidesCb);
}

async function slideshowAddSlide(){
  if (!currentUser) return;

  // Capture selection BEFORE we preselect the new slide (so insert position is correct)
  const prevSel = String(slideshowSelectedId || "");

  const ref = db.ref("slideshow/slides").push();
  const newId = ref.key || null;

  // Preselect immediately to avoid the race where the slides listener fires before await resolves.
  if (newId){
    stopAllSlideshowAudio();
    slideshowPendingSelectId = newId;
    slideshowSelectedId = newId;
    slideshowClearSelection({ quiet:true });
    setMySlideshowLocation(newId);
    scheduleRenderSlideshowUI();
  }

  // Insert AFTER the currently selected slide (or at end if none)
  const baseOrder = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  const selIdx = prevSel ? baseOrder.indexOf(prevSel) : -1;
  const insertAt = (selIdx >= 0) ? (selIdx + 1) : baseOrder.length;

  // Optimistically update local order so the picker updates immediately
  if (newId){
    baseOrder.splice(insertAt, 0, newId);
    slideshowOrder = baseOrder;
    slideshowOrderMap = new Map(baseOrder.map((id, idx) => [id, idx + 1]));
    slideshowMaxOrder = baseOrder.length;
  }

  const payload = {
    createdAt: firebase.database.ServerValue.TIMESTAMP,
    createdBy: currentUser.code || "",
    order: insertAt + 1
  };

  // Persist: shift existing slide orders down to make room (keeps integer order values)
  const updates = {};
  for (let i = 0; i < baseOrder.length; i++){
    const id = String(baseOrder[i] || "");
    if (!id || id === newId) continue;
    updates[`slideshow/slides/${id}/order`] = i + 1;
  }
  if (newId){
    updates[`slideshow/slides/${newId}`] = payload;
  }

  try{
    await db.ref().update(updates);
  }catch{
    // If creation failed, undo optimistic insert + revert selection to a valid slide (if any)
    if (newId){
      const j = slideshowOrder.indexOf(newId);
      if (j >= 0) slideshowOrder.splice(j, 1);
      slideshowOrderMap = new Map(slideshowOrder.map((id, idx) => [id, idx + 1]));
      slideshowMaxOrder = slideshowOrder.length;
    }

    if (slideshowSelectedId === newId){
      slideshowSelectedId = slideshowOrder[0] || null;
      slideshowPendingSelectId = null;
      slideshowClearSelection({ quiet:true });
      scheduleRenderSlideshowUI();
    }
  }
}

async function slideshowDeleteSelectedSlide(){
  if (!currentUser) return;
  const id = slideshowSelectedId;
  if (!id) return;

  // Select the slide above the deleted one (or next if deleting the first)
  const idx = slideshowOrder.indexOf(id);
  let nextSel = null;
  if (idx > 0) nextSel = slideshowOrder[idx - 1] || null;
  else if (idx === 0) nextSel = slideshowOrder[1] || null;

  // Preselect BEFORE deleting to avoid listener races that snap back to Slide 1 / scroll to top
  stopAllSlideshowAudio();
  slideshowPendingSelectId = nextSel;
  slideshowSelectedId = nextSel;

  slideshowClearSelection({ quiet:true });
  setMySlideshowLocation(nextSel);
  detachSlideshowDoc();
  scheduleRenderSlideshowUI();

  // Delete both slide record and its doc (prevents orphaned docs)
  try{
    await db.ref().update({
      [`slideshow/slides/${id}`]: null,
      [`slideshow/docs/${id}`]: null
    });
  }catch{}
}

function bindSlideshowDividerOutsideClick(){
  if (slideshowDividerOutsideClickBound) return;
  slideshowDividerOutsideClickBound = true;

  document.addEventListener("pointerdown", (e) => {
    if (!document.body.classList.contains("slideshow-full")) return;
    if (!slideshowSelectedDividerBeforeId) return;

    const t = e.target;
    if (!(t instanceof HTMLElement)) return;

    // Click-away to close the divider tooltip
    if (t.closest(".slideshow-divider-wrap") || t.closest(".slideshow-divider-tooltip") || t.closest(".slideshow-divider-del")) return;

    slideshowSelectedDividerBeforeId = null;
    scheduleRenderSlideshowUI();
  }, true);
}

function bindSlideshowTitleOutsideClick(){
  if (slideshowTitleOutsideClickBound) return;
  slideshowTitleOutsideClickBound = true;

  document.addEventListener("pointerdown", (e) => {
    if (!document.body.classList.contains("slideshow-full")) return;
    if (!slideshowEditingTitleBeforeId && !slideshowSelectedTitleBeforeId) return;

    const t = e.target;
    if (!(t instanceof HTMLElement)) return;

    // Click-away closes selection/editor; ignore clicks inside title UI
    if (
      t.closest(".slideshow-title-wrap") ||
      t.closest(".slideshow-title-tooltip") ||
      t.closest("[data-title-edit]") ||
      t.closest("[data-title-del]") ||
      t.closest(".slideshow-title-input")
    ) return;

    const beforeId = slideshowEditingTitleBeforeId;

    // Save current value if the input exists (unless we are deleting it)
    if (beforeId && !isSlideshowTitleDeleteGuarded(beforeId)){
      try{
        const sel = `[data-title-input="${CSS.escape(beforeId)}"]`;
        const inp = document.querySelector(sel);
        if (inp && inp instanceof HTMLInputElement){
          void saveSlideshowTitleNow(beforeId, inp.value);
        }
      }catch{}
    }

    slideshowSelectedTitleBeforeId = null;
    slideshowEditingTitleBeforeId = null;
    scheduleRenderSlideshowUI();
  }, true);
}

function slideshowSelectedIndex(){
  const order = Array.isArray(slideshowOrder) ? slideshowOrder : [];
  if (!order.length) return -1;
  const selected = String(slideshowSelectedId || "");
  const idx = order.indexOf(selected);
  return idx >= 0 ? idx : 0;
}

function slideshowFindOpenDividerBeforeId(){
  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  if (order.length < 2) return "";

  const used = (slideshowDividersSet instanceof Set) ? slideshowDividersSet : new Set();
  const start = Math.max(0, slideshowSelectedIndex());
  const candidates = [];

  if (start > 0) candidates.push(start);
  for (let i = start + 1; i < order.length; i += 1) candidates.push(i);
  for (let i = start - 1; i > 0; i -= 1) candidates.push(i);

  for (const idx of candidates){
    const id = String(order[idx] || "");
    if (id && idx > 0 && !used.has(id)) return id;
  }
  return "";
}

async function slideshowCreateDividerBefore(beforeId, { select = true } = {}){
  if (!currentUser) return false;
  beforeId = String(beforeId || "");

  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  const idx = order.indexOf(beforeId);
  if (!beforeId || idx <= 0) return false;

  if (slideshowDividersSet instanceof Set && slideshowDividersSet.has(beforeId)){
    if (select) slideshowSelectedDividerBeforeId = beforeId;
    slideshowDividerInsertMode = false;
    scheduleRenderSlideshowUI();
    return true;
  }

  try{
    if (slideshowDividersSet instanceof Set) slideshowDividersSet.add(beforeId);
    slideshowDividerInsertMode = false;
    slideshowTitleInsertMode = false;
    slideshowSelectedTitleBeforeId = null;
    slideshowEditingTitleBeforeId = null;
    if (select) slideshowSelectedDividerBeforeId = beforeId;
    scheduleRenderSlideshowUI();

    await db.ref(`slideshow/dividers/${beforeId}`).set({
      createdAt: firebase.database.ServerValue.TIMESTAMP,
      createdBy: currentUser.code || ""
    });
    return true;
  }catch{
    try{ if (slideshowDividersSet instanceof Set) slideshowDividersSet.delete(beforeId); }catch{}
    showToast("Failed to add divider.");
    scheduleRenderSlideshowUI();
    return false;
  }
}

function slideshowToggleDividerInsertMode(){
  void slideshowAddDividerInstant();
}

async function slideshowAddDividerInstant(){
  if (!currentUser || slideshowSelectedObjId) return;

  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  if (order.length < 2){
    showToast("You need at least 2 slides to add a divider.");
    return;
  }

  const beforeId = slideshowFindOpenDividerBeforeId();
  if (!beforeId){
    showToast("Every available section break already has a divider.");
    return;
  }

  await slideshowCreateDividerBefore(beforeId, { select:true });
}

let slideshowTitleSaveTimers = new Map();
let slideshowTitleDeleteGuards = new Map(); // beforeId -> untilMs (prevents title resurrection after delete)

function markSlideshowTitleDeleted(beforeId, ms = 4000){
  beforeId = String(beforeId || "");
  if (!beforeId) return;
  const until = Date.now() + ms;
  slideshowTitleDeleteGuards.set(beforeId, until);
  setTimeout(() => {
    if ((slideshowTitleDeleteGuards.get(beforeId) || 0) <= Date.now()){
      slideshowTitleDeleteGuards.delete(beforeId);
    }
  }, ms + 50);
}

function isSlideshowTitleDeleteGuarded(beforeId){
  beforeId = String(beforeId || "");
  const until = slideshowTitleDeleteGuards.get(beforeId) || 0;
  return until > Date.now();
}

function slideshowResolveTitleBeforeId(){
  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  if (!order.length) return "";
  const idx = slideshowSelectedIndex();
  return String(order[idx >= 0 ? idx : 0] || order[0] || "");
}

async function slideshowOpenTitleEditor(beforeId, { ensureDivider = false } = {}){
  if (!currentUser) return;
  beforeId = String(beforeId || "");
  if (!beforeId) return;

  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  const idx = order.indexOf(beforeId);
  if (idx < 0) return;

  if (idx > 0 && ensureDivider){
    const ok = await slideshowCreateDividerBefore(beforeId, { select:false });
    if (!ok) return;
  }

  await ensureSlideshowTitle(beforeId);

  if (slideshowTitlesMap instanceof Map && !slideshowTitlesMap.has(beforeId)){
    slideshowTitlesMap.set(beforeId, { text:"", createdAt:Date.now(), updatedAt:Date.now() });
  }
  slideshowStartEditingTitle(beforeId);
}

function slideshowToggleTitleInsertMode(){
  void slideshowAddTitleInstant();
}

async function slideshowAddTitleInstant(){
  if (!currentUser || slideshowSelectedObjId) return;

  const beforeId = slideshowResolveTitleBeforeId();
  if (!beforeId){
    showToast("Create a slide before adding a title.");
    return;
  }

  await slideshowOpenTitleEditor(beforeId, { ensureDivider:true });
}

async function ensureSlideshowTitle(beforeId){
  if (!currentUser) return;
  beforeId = String(beforeId || "");
  if (!beforeId) return;

  const forceReset = isSlideshowTitleDeleteGuarded(beforeId);

  try{
    await db.ref(`slideshow/titles/${beforeId}`).transaction((cur) => {
      if (!forceReset && cur && typeof cur === "object") return cur;
      return {
        text: "",
        createdAt: firebase.database.ServerValue.TIMESTAMP,
        createdBy: currentUser.code || "",
        updatedAt: firebase.database.ServerValue.TIMESTAMP,
        updatedBy: currentUser.code || ""
      };
    });
    if (forceReset) slideshowTitleDeleteGuards.delete(beforeId);
  }catch{}
}

async function saveSlideshowTitleNow(beforeId, text){
  if (!currentUser) return;
  beforeId = String(beforeId || "");
  if (!beforeId) return;
  if (isSlideshowTitleDeleteGuarded(beforeId)) return;

  try{
    await db.ref(`slideshow/titles/${beforeId}`).update({
      text: String(text ?? ""),
      updatedAt: firebase.database.ServerValue.TIMESTAMP,
      updatedBy: currentUser.code || ""
    });
  }catch{}
}

function slideshowStartEditingTitle(beforeId){
  beforeId = String(beforeId || "");
  if (!beforeId) return;

  slideshowSelectedDividerBeforeId = null;
  slideshowSelectedTitleBeforeId = beforeId;
  slideshowEditingTitleBeforeId = beforeId;
  slideshowTitleInsertMode = false;
  scheduleRenderSlideshowUI();

  requestAnimationFrame(() => {
    try{
      const ta = messagesListEl?.querySelector(`[data-title-input="${CSS.escape(beforeId)}"]`);
      if (ta){ ta.focus(); ta.select?.(); }
    }catch{}
  });
}

async function slideshowDeleteTitle(beforeId){
  if (!currentUser) return;
  beforeId = String(beforeId || "");
  if (!beforeId) return;

  // Prevent any late focusout/click-away saves from re-creating the title
  markSlideshowTitleDeleted(beforeId);

  // Optimistic UI (instant feedback)
  try{ if (slideshowTitlesMap instanceof Map) slideshowTitlesMap.delete(beforeId); }catch{}
  if (slideshowSelectedTitleBeforeId === beforeId) slideshowSelectedTitleBeforeId = null;
  if (slideshowEditingTitleBeforeId === beforeId) slideshowEditingTitleBeforeId = null;
  slideshowTitleInsertMode = false;
  scheduleRenderSlideshowUI();

  try{
    await db.ref(`slideshow/titles/${beforeId}`).remove();
  }catch{
    showToast("Failed to delete title.");
  }

  // Ensure closed even if the DB op failed
  if (slideshowSelectedTitleBeforeId === beforeId) slideshowSelectedTitleBeforeId = null;
  if (slideshowEditingTitleBeforeId === beforeId) slideshowEditingTitleBeforeId = null;
  slideshowTitleInsertMode = false;
  scheduleRenderSlideshowUI();
}

async function slideshowAddDividerAt(slideId, pos){
  if (!currentUser) return;

  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  if (order.length < 2) return;
  const idx = order.indexOf(slideId);
  if (idx < 0) return;

  let beforeId = "";
  if (pos === "above"){
    beforeId = idx > 0 ? String(slideId || "") : "";
  } else if (pos === "below"){
    beforeId = idx < (order.length - 1) ? String(order[idx + 1] || "") : "";
  }

  if (!beforeId){
    showToast("That divider position is not available.");
    return;
  }

  await slideshowCreateDividerBefore(beforeId, { select:true });
}

async function slideshowDeleteDivider(beforeId){
  if (!currentUser) return;
  beforeId = String(beforeId || "");
  if (!beforeId) return;

  // Never allow a divider before the first slide
  if (Array.isArray(slideshowOrder) && slideshowOrder[0] === beforeId) return;

  // Divider delete also deletes its title; guard against resurrection
  markSlideshowTitleDeleted(beforeId);

  // Optimistic UI
  try{ if (slideshowDividersSet instanceof Set) slideshowDividersSet.delete(beforeId); }catch{}
  try{ if (slideshowTitlesMap instanceof Map) slideshowTitlesMap.delete(beforeId); }catch{}
  if (slideshowSelectedDividerBeforeId === beforeId) slideshowSelectedDividerBeforeId = null;
  if (slideshowSelectedTitleBeforeId === beforeId) slideshowSelectedTitleBeforeId = null;
  if (slideshowEditingTitleBeforeId === beforeId) slideshowEditingTitleBeforeId = null;
  slideshowDividerInsertMode = false;
  slideshowTitleInsertMode = false;
  scheduleRenderSlideshowUI();

  try{
    await db.ref().update({
      [`slideshow/dividers/${beforeId}`]: null,
      [`slideshow/titles/${beforeId}`]: null
    });
  }catch{
    showToast("Failed to delete divider.");
  }

  if (slideshowSelectedDividerBeforeId === beforeId) slideshowSelectedDividerBeforeId = null;
  scheduleRenderSlideshowUI();
}

/* -------------------- Slideshow editor (objects + background) -------------------- */
function slideshowDocPath(slideId){
  return `slideshow/docs/${slideId}`;
}

function detachSlideshowDoc(){
  if (slideshowDocRef && slideshowDocCb){
    try{ slideshowDocRef.off("value", slideshowDocCb); }catch{}
  }
  slideshowDocRef = null;
  slideshowDocCb = null;
  slideshowDocActiveId = null;
}

let slideshowThumbDocRefs = new Map(); // slideId -> { ref, cb }
let slideshowThumbRenderRAF = new Map(); // slideId -> raf id

function detachSlideshowThumbDocs(){
  for (const [id, rec] of slideshowThumbDocRefs.entries()){
    try{ rec.ref.off("value", rec.cb); }catch{}
  }
  slideshowThumbDocRefs.clear();

  for (const [id, raf] of slideshowThumbRenderRAF.entries()){
    try{ cancelAnimationFrame(raf); }catch{}
  }
  slideshowThumbRenderRAF.clear();
}

function syncSlideshowThumbDocs(order){
  if (!currentUser){
    detachSlideshowThumbDocs();
    return;
  }

  const all = (Array.isArray(order) ? order : []).map(x => String(x || "")).filter(Boolean);
  const selectedIdx = Math.max(0, all.indexOf(String(slideshowSelectedId || "")));

  // PERF: do not attach a live /docs listener for every slide in huge decks.
  // Keep the selected slide plus nearby thumbnails live; stale previews are detached.
  const start = Math.max(0, selectedIdx - 8);
  const end = Math.min(all.length, selectedIdx + 13);
  const want = new Set(all.slice(start, end));
  if (slideshowSelectedId) want.add(String(slideshowSelectedId));

  // Detach stale
  for (const [id, rec] of slideshowThumbDocRefs.entries()){
    if (!want.has(id)){
      try{ rec.ref.off("value", rec.cb); }catch{}
      slideshowThumbDocRefs.delete(id);
      const raf = slideshowThumbRenderRAF.get(id);
      if (raf) try{ cancelAnimationFrame(raf); }catch{}
      slideshowThumbRenderRAF.delete(id);
    }
  }

  // Attach missing
  for (const id of want){
    if (slideshowThumbDocRefs.has(id)) continue;

    const ref = db.ref(slideshowDocPath(id));
    const cb = (snap) => {
      let doc = snap.exists() ? (snap.val() || {}) : null;
      if (!doc) doc = { bg:{ type:"solid", color:"#ffffff" }, objects:{} };
      if (!doc.bg) doc.bg = { type:"solid", color:"#ffffff" };
      if (!doc.objects) doc.objects = {};

      slideshowDocCache.set(id, doc);
      scheduleSlideshowThumbRender(id, doc);
    };

    slideshowThumbDocRefs.set(id, { ref, cb });
    ref.on("value", cb);

    // Ensure it exists (first creator)
    ensureSlideshowDoc(id);
  }
}

function scheduleSlideshowThumbRender(slideId, doc){
  slideId = String(slideId || "");
  if (!slideId) return;

  const prev = slideshowThumbRenderRAF.get(slideId);
  if (prev) try{ cancelAnimationFrame(prev); }catch{}

  slideshowThumbRenderRAF.set(slideId, requestAnimationFrame(() => {
    slideshowThumbRenderRAF.delete(slideId);
    renderSlideshowThumbPreview(slideId, doc);
  }));
}

function renderSlideshowThumbPreview(slideId, doc){
  if (!messagesListEl) return;
  slideId = String(slideId || "");
  if (!slideId) return;

  let host = null;
  try{
    host = messagesListEl.querySelector(`[data-thumb-preview="${CSS.escape(slideId)}"]`);
  }catch{
    return;
  }
  if (!host) return;

  host.innerHTML = "";

  const stage = document.createElement("div");
  stage.className = "slideshow-thumb-preview-stage";
  stage.setAttribute("aria-hidden", "true");

  // Thumbnails use the same immutable 16:9 design space as the main slide.
  try{
    const DESIGN_W = 1600;
    const DESIGN_H = 900;
    const hostW = host.clientWidth || 1;
    const hostH = host.clientHeight || 1;
    const scale = Math.max(0.01, Math.min(hostW / DESIGN_W, hostH / DESIGN_H));

    stage.style.inset = "auto";
    stage.style.width = `${DESIGN_W}px`;
    stage.style.height = `${DESIGN_H}px`;
    stage.style.transformOrigin = "top left";
    stage.style.transform = `scale(${scale})`;
    stage.style.left = `${Math.round((hostW - (DESIGN_W * scale)) / 2)}px`;
    stage.style.top = `${Math.round((hostH - (DESIGN_H * scale)) / 2)}px`;
  }catch{}

  const bg = doc?.bg || { type:"solid", color:"#ffffff" };
  applySlideshowBackground(stage, bg);

  const objs = doc?.objects || {};
  for (const [objId, obj] of Object.entries(objs)){
    const el = buildSlideObjectEl(objId, obj);
    if (el) stage.appendChild(el);
  }

  // Disable interactive media/controls inside previews
  stage.querySelectorAll("video").forEach(v => {
    try{
      v.controls = false;
      v.muted = true;
      v.pause?.();
    }catch{}
  });
  stage.querySelectorAll("audio").forEach(a => {
    try{
      a.pause?.();
      a.currentTime = 0;
    }catch{}
  });
  stage.querySelectorAll("[data-audio='toggle']").forEach(btn => {
    try{ btn.remove(); }catch{}
  });

  host.appendChild(stage);
}

async function ensureSlideshowDoc(slideId){
  if (!slideId) return;
  try{
    const ref = db.ref(slideshowDocPath(slideId));
    const snap = await ref.once("value");
    if (snap.exists()) return;
    await ref.set({
      bg: { type:"solid", color:"#ffffff" },
      objects: {}
    });
  }catch{}
}

function attachSlideshowDoc(slideId){
  if (!currentUser) return;
  if (!slideId) return;

  if (slideshowDocActiveId === slideId && slideshowDocRef) return;

  detachSlideshowDoc();
  slideshowDocActiveId = slideId;

  slideshowDocRef = db.ref(slideshowDocPath(slideId));
  slideshowDocCb = (snap) => {
    let doc = snap.exists() ? (snap.val() || {}) : null;
    if (!doc) doc = { bg:{ type:"solid", color:"#ffffff" }, objects:{} };
    if (!doc.bg) doc.bg = { type:"solid", color:"#ffffff" };
    if (!doc.objects) doc.objects = {};
    slideshowDocCache.set(slideId, doc);

    // Re-render stage if it exists.
    // IMPORTANT PERF: while dragging/resizing/rotating, do NOT rebuild the whole stage
    // (renderSlideshowStage clears/recreates DOM and causes massive lag).
    if (slideDragState && slideshowSelectedId === slideId){
      slideshowDeferredRender = true;
      slideshowDeferredSlideId = slideId;
      try{ applySlideshowBackground($("slideshow-stage"), doc.bg); }catch{}
      return;
    }
    renderSlideshowStage(slideId, doc);
  };
  slideshowDocRef.on("value", slideshowDocCb);

  // Ensure it exists (first creator)
  ensureSlideshowDoc(slideId);
}

function getActiveSlideshowDoc(){
  if (!slideshowDocActiveId) return null;
  return slideshowDocCache.get(slideshowDocActiveId) || null;
}

function getUsersSelectingSlideObject(slideId, objId){
  const out = [];
  const sid = String(slideId || "");
  const oid = String(objId || "");
  if (!sid || !oid) return out;

  for (const [code, rec] of slideshowLocationsCache){
    if (!code || code === currentUser?.code) continue;
    if (String(rec?.slideId || "") !== sid) continue;
    if (String(rec?.selectedObjId || "") !== oid) continue;
    out.push(code);
  }

  return out;
}

function renderSlideshowRemoteSelections(){
  const stage = $("slideshow-stage");
  if (!stage) return;

  stage.querySelectorAll(".slide-remote-selectors").forEach(el => el.remove());
  if (!slideshowSelectedId) return;

  const doc = getActiveSlideshowDoc();
  const objs = doc?.objects || {};
  const now = Date.now();

  for (const [objId] of Object.entries(objs)){
    const selectors = getUsersSelectingSlideObject(slideshowSelectedId, objId)
      .filter((code) => {
        const rec = slideshowLocationsCache.get(code);
        const updatedAt = Number(rec?.updatedAt || 0);
        if (updatedAt && Math.abs(now - updatedAt) > 45000) return false;
        return !!liveUserCache.get(code);
      });

    if (!selectors.length) continue;

    const objEl = stage.querySelector(`[data-obj-id="${CSS.escape(objId)}"]`);
    if (!objEl) continue;

    const box = document.createElement("div");
    box.className = "slide-remote-selectors";

    const avatars = document.createElement("div");
    avatars.className = "slide-remote-avatars";

    selectors.slice(0, 8).forEach((code) => {
      const user = liveUserCache.get(code) || {};
      const ava = document.createElement("div");
      ava.className = "slide-remote-avatar";
      ava.dataset.usercode = code;
      applyAvatar(ava, user || { code, username:"User", photoDataURL: defaultStickmanDataURL(), photoTransform: null });
      avatars.appendChild(ava);
    });

    box.appendChild(avatars);
    objEl.appendChild(box);
  }
}

function renderSlideshowStage(slideId, doc){
  const stage = $("slideshow-stage");
  if (!stage) return;

  // Ensure the stage fills the full slide canvas
  try{ fitSlideshowStage(); }catch{}

  // Background must be applied to the stage only.
  // Keep the surrounding canvas plain to prevent "double background" layering.
  const bg = doc?.bg || { type:"solid", color:"#ffffff" };

  const canvas = $("slideshow-canvas");
  if (canvas){
    canvas.style.backgroundImage = "";
    canvas.style.backgroundColor = "#ffffff";
  }

  // Clear old object/progress DOM before applying the background so upload progress overlays stay mounted at 0%.
  stage.innerHTML = "";
  applySlideshowBackground(stage, bg);

  // Objects
  const objs = doc?.objects || {};
  for (const [objId, obj] of Object.entries(objs)){
    const el = buildSlideObjectEl(objId, obj);
    if (el) stage.appendChild(el);
  }

  renderSlideshowRemoteSelections();

  // Re-apply selection visuals
  if (slideshowSelectedObjId){
    const selEl = stage.querySelector(`[data-obj-id="${CSS.escape(slideshowSelectedObjId)}"]`);
    if (!selEl){
      slideshowClearSelection({ quiet:true });
    } else {
      updateSlideSelectionUI();
    }
  } else {
    updateSlideSelectionUI();
  }
}

function applySlideshowBackground(slideEl, bg){
  if (!slideEl) return;
  const t = (bg?.type || "solid");

  try{ slideEl.querySelectorAll?.(":scope > .slide-bg-upload-progress").forEach((el) => el.remove()); }catch{}

  if (t === "image"){
    const src = readChunkedField(bg, "src") || String(bg?.src || "");
    slideEl.style.backgroundImage = src ? `url(${src})` : "";
    slideEl.style.backgroundSize = "cover";
    slideEl.style.backgroundPosition = "center";
    slideEl.style.backgroundRepeat = "no-repeat";
    slideEl.style.backgroundColor = "#ffffff";

    if (Number(bg?.srcUploadPending || 0) > 0){
      const loading = document.createElement("div");
      loading.className = "slide-upload-progress slide-bg-upload-progress";
      loading.textContent = formatUploadPercentText(bg?.srcUploadProgress ?? 0);
      slideEl.appendChild(loading);
    }
  } else {
    const c = String(bg?.color || "#ffffff");
    slideEl.style.backgroundImage = "";
    slideEl.style.backgroundSize = "";
    slideEl.style.backgroundPosition = "";
    slideEl.style.backgroundRepeat = "";
    slideEl.style.backgroundColor = c;
  }
}

function fitSlideshowStage(){
  const stage = $("slideshow-stage");
  const canvas = $("slideshow-canvas");
  if (!stage || !canvas) return;

  const DESIGN_W = 1600;
  const DESIGN_H = 900;
  const cw = Math.max(1, canvas.clientWidth || 1);
  const ch = Math.max(1, canvas.clientHeight || 1);
  const scale = Math.max(0.01, Math.min(cw / DESIGN_W, ch / DESIGN_H));

  stage.style.width = `${DESIGN_W}px`;
  stage.style.height = `${DESIGN_H}px`;
  stage.style.maxWidth = "none";
  stage.style.maxHeight = "none";
  stage.style.left = "50%";
  stage.style.top = "50%";
  stage.style.transformOrigin = "center center";
  stage.style.transform = `translate(-50%, -50%) scale(${scale})`;
}

function pct(n, min, max){
  const x = Number(n);
  if (!Number.isFinite(x)) return min;
  return Math.max(min, Math.min(max, x));
}

function normalizeSlideTextUrl(raw){
  const s = String(raw || "").trim();
  if (!s) return "";

  const m = s.match(/^([a-zA-Z][a-zA-Z0-9+.-]*):\/\//);
  if (m){
    const sch = m[1].toLowerCase();
    if (sch === "http" || sch === "https" || sch === "file") return s;
    return "";
  }

  if (s.startsWith("//")) return "https:" + s;
  return "https://" + s;
}

function buildSlideObjectEl(objId, obj){
  if (!obj || typeof obj !== "object") return null;

  const type = String(obj.type || "");
  const wrap = document.createElement("div");
  wrap.className = `slide-obj slide-obj-${type}`;
  wrap.setAttribute("data-obj-id", objId);
  wrap.setAttribute("data-obj-type", type);

  const x = pct(obj.x, 0, 100);
  const y = pct(obj.y, 0, 100);
  const w = pct(obj.w, 1, 100);
  const h = pct(obj.h, 1, 100);
  const rot = Number(obj.rot || 0) || 0;
  const layer = pct(obj.layer, 1, 100);

  wrap.style.left = `${x}%`;
  wrap.style.top = `${y}%`;
  wrap.style.width = `${w}%`;
  wrap.style.height = `${h}%`;
  wrap.style.zIndex = String(layer);
  wrap.style.transform = `rotate(${rot}deg)`;

  const mediaUploadPending = ["image", "video", "audio"].includes(type) && Number(obj.srcUploadPending || obj.uploadPending || 0) > 0;
  const mediaUploadText = formatUploadPercentText(obj.srcUploadProgress ?? obj.uploadProgress ?? 0);
  const appendSlideUploadOverlay = () => {
    if (!mediaUploadPending) return;
    const loading = document.createElement("div");
    loading.className = "slide-upload-progress";
    loading.textContent = mediaUploadText;
    wrap.dataset.loading = "1";
    wrap.appendChild(loading);
  };

  // Disable native menus inside slideshow objects
  wrap.addEventListener("contextmenu", (e) => e.preventDefault());

  if (type === "text"){
    const s = obj.style || {};
    const url = String(obj.url || "").trim();
    const el = document.createElement("div");
    el.className = "slide-text";

    // Linked text: show icon + allow Ctrl+Click to open.
    if (url){
      const ico = document.createElement("span");
      ico.className = "slide-url-ico";
      ico.setAttribute("aria-hidden", "true");
      el.appendChild(ico);

      wrap.setAttribute("data-has-url", "1");
      wrap.addEventListener("click", (e) => {
        if (!(e.ctrlKey || e.metaKey)) return;
        const openUrl = normalizeSlideTextUrl(url);
        if (!openUrl) return;
        e.preventDefault();
        e.stopPropagation();
        try{ window.open(openUrl, "_blank", "noopener"); }catch{}
      });
    }

    const txt = document.createElement("span");
    txt.className = "slide-text-content";
    txt.textContent = String(obj.text || "Insert text here");
    el.appendChild(txt);

    el.style.color = String(s.color || "#000000");
    el.style.fontSize = `${pct(s.size, 8, 200)}px`;
    el.style.fontFamily = String(s.font || SLIDESHOW_FONTS[0]);

    const stroke = s.stroke || {};
    if (stroke.on){
      el.style.webkitTextStroke = `${pct(stroke.size, 1, 16)}px ${String(stroke.color || "#000000")}`;
    } else {
      el.style.webkitTextStroke = "";
    }

    const fx = s.effects || {};
    if (fx.shadow){
      el.style.textShadow = `0 6px 18px rgba(0,0,0,.28)`;
    } else {
      el.style.textShadow = "";
    }

    wrap.appendChild(el);
    return wrap;
  }

  if (type === "shape"){
    const s = obj.style || {};
    const kind = String(obj.shape || "rect");
    const fill = String(s.fill || "#111827");

    const stroke = s.stroke || {};
    const strokeOn = !!stroke.on;
    const strokeSize = pct(stroke.size, 1, 20);
    const strokeColor = String(stroke.color || "#111827");

    const svgNS = "http://www.w3.org/2000/svg";
    const svg = document.createElementNS(svgNS, "svg");
    svg.setAttribute("viewBox", "0 0 100 100");
    svg.setAttribute("preserveAspectRatio", "none");
    svg.classList.add("slide-shape-svg");
    svg.setAttribute("aria-hidden", "true");

    const dByKind = {
      rect: "M0 0H100V100H0Z",
      rounded: "M12 0H88A12 12 0 0 1 100 12V88A12 12 0 0 1 88 100H12A12 12 0 0 1 0 88V12A12 12 0 0 1 12 0Z",
      circle: "M50 0A50 50 0 1 1 49.999 0Z",
      ellipse: "M50 0A50 35 0 1 1 49.999 0Z",
      triangle: "M50 0L0 100L100 100Z",
      diamond: "M50 0L100 50L50 100L0 50Z",
      star: "M50 0L61 35L98 35L68 57L79 91L50 70L21 91L32 57L2 35L39 35Z",
      arrow: "M0 35H65V15L100 50L65 85V65H0Z",
      line: "M0 45H100V55H0Z",
      heart: "M50 92C35 80 10 62 10 38C10 22 22 10 38 10C46 10 53 14 50 20C47 14 54 10 62 10C78 10 90 22 90 38C90 62 65 80 50 92Z",
      pentagon: "M50 0L100 38L82 100H18L0 38Z",
      hexagon: "M25 0H75L100 50L75 100H25L0 50Z"
    };

    const d = dByKind[kind] || dByKind.rect;

    const p = document.createElementNS(svgNS, "path");
    p.setAttribute("d", d);
    p.setAttribute("fill", fill);

    if (strokeOn){
      p.setAttribute("stroke", strokeColor);
      p.setAttribute("stroke-width", String(strokeSize));
      p.setAttribute("vector-effect", "non-scaling-stroke");
      p.setAttribute("stroke-linejoin", "round");
      p.setAttribute("stroke-linecap", "round");
      p.setAttribute("paint-order", "stroke fill");
    }

    svg.appendChild(p);
    wrap.appendChild(svg);
    return wrap;
  }

  if (type === "image"){
    const s = obj.style || {};
    const img = document.createElement("img");
    img.className = "slide-media";
    img.alt = "Slide image";
    img.draggable = false;
    img.src = mediaUploadPending ? String(obj.previewURL || readChunkedField(obj, "src") || "") : readChunkedField(obj, "src");

    const stroke = s.stroke || {};
    if (stroke.on){
      img.style.border = `${pct(stroke.size, 1, 20)}px solid ${String(stroke.color || "#111827")}`;
    } else {
      img.style.border = "none";
    }

    wrap.appendChild(img);
    appendSlideUploadOverlay();
    return wrap;
  }

  if (type === "video"){
    const s = obj.style || {};
    const src = mediaUploadPending ? String(obj.previewURL || readChunkedField(obj, "src") || "") : readChunkedField(obj, "src");
    const name = String(obj.name || "video.mp4");
    const mimeType = getMediaMimeType(obj);
    const canInlineVideo = !!src && canInlineVideoMedia({ ...obj, src });

    if (mediaUploadPending && !src){
      const box = document.createElement("div");
      box.className = "slide-upload-shell";
      wrap.appendChild(box);
      appendSlideUploadOverlay();
      return wrap;
    }

    if (!canInlineVideo){
      const box = document.createElement("div");
      box.className = "slide-audio";
      box.innerHTML = `
        <div class="slide-audio-top">
          <button class="slide-audio-btn" type="button" data-video="download">Download</button>
          <div class="slide-audio-title">${escapeHtml(name)}</div>
        </div>
        <div class="slide-audio-mid">
          <div class="slide-audio-time">This video format is sent correctly, but this browser can't play it inline.</div>
        </div>
      `;

      const btn = box.querySelector('[data-video="download"]');
      const swallow = (e) => { e.stopPropagation(); };
      box.querySelectorAll("button").forEach(el => {
        el.addEventListener("pointerdown", swallow);
        el.addEventListener("click", swallow);
      });
      btn?.addEventListener("click", async (e) => {
        e.preventDefault();
        e.stopPropagation();
        await downloadFileViaObjectURL(src, name);
      });

      wrap.appendChild(box);
      return wrap;
    }

    // Slideshow video uses the same static thumbnail treatment as chat video cards.
    // Clicking the slide object still only selects/edits it; playback opens from the video object's edit menu.
    const box = document.createElement("div");
    box.className = "slide-video-thumb";
    box.setAttribute("aria-label", name);

    const stroke = s.stroke || {};
    if (stroke.on){
      box.style.border = `${pct(stroke.size, 1, 20)}px solid ${String(stroke.color || "#111827")}`;
    } else {
      box.style.border = "none";
    }

    box.innerHTML = `
      <video class="slide-video-poster" preload="metadata" muted playsinline>${videoSourceMarkup(src, mimeType)}</video>
      <div class="slide-video-fallback"></div>
      <span class="slide-video-play" aria-hidden="true">${svgIcon("play")}</span>
    `;

    const poster = box.querySelector(".slide-video-poster");
    const fallbackEl = box.querySelector(".slide-video-fallback");
    if (poster){
      let posterShown = false;
      const showPoster = () => {
        if (posterShown || !box.isConnected) return;
        posterShown = true;
        try{
          poster.style.opacity = "";
          if (fallbackEl && fallbackEl.isConnected) fallbackEl.remove();
        }catch{}
      };

      poster.addEventListener("loadedmetadata", () => {
        try{
          const dur = Number(poster.duration);
          if (Number.isFinite(dur) && dur > 0) poster.currentTime = Math.min(0.12, Math.max(0.01, dur * 0.01));
        }catch{}
      }, { once:true });
      poster.addEventListener("loadeddata", showPoster, { once:true });
      poster.addEventListener("canplay", showPoster, { once:true });
      try{ poster.load(); }catch{}
    }

    wrap.appendChild(box);

    return wrap;
  }

  if (type === "audio"){
    const s = obj.style || {};
    if (mediaUploadPending && !readChunkedField(obj, "src")){
      const placeholder = document.createElement("div");
      placeholder.className = "slide-audio slide-upload-shell";
      wrap.appendChild(placeholder);
      appendSlideUploadOverlay();
      return wrap;
    }

    const box = document.createElement("div");
    box.className = "slide-audio";

    const fill = normalizeHex6(s.fill || "#111827");
    box.style.background = fill;
    try{
      const rgb = hexToRgb(fill);
      const lum = (0.2126*rgb.r + 0.7152*rgb.g + 0.0722*rgb.b);
      box.style.color = lum > 170 ? "#0b1220" : "#ffffff";
    }catch{}

    box.innerHTML = `
      <div class="slide-audio-top">
        <div class="slide-audio-main">
          <button class="slide-audio-btn" type="button" data-audio="toggle" aria-label="Play/Pause">Play</button>
          <div class="slide-audio-copy">
            <div class="slide-audio-title">${escapeHtml(String(obj.name || "Audio"))}</div>
            <div class="slide-audio-sub">${escapeHtml(String(obj.mimeType || obj.sub || "Audio object"))}</div>
          </div>
        </div>
      </div>
      <div class="slide-audio-mid">
        <input class="slide-audio-range" type="range" min="0" max="1000" value="0" data-audio="seek" />
        <div class="slide-audio-time" data-audio="time">0:00 / 0:00</div>
      </div>
      <div class="slide-audio-opts">
        <label class="slide-audio-loop"><input type="checkbox" data-audio="loop"/> Loop</label>
        <div class="slide-audio-vol">
          <span>Vol</span>
          <input class="slide-audio-vol-range" type="range" min="0" max="1" step="0.01" value="1" data-audio="vol" />
        </div>
        <label class="slide-audio-speed">
          <span>Speed</span>
          <select data-audio="rate">
            <option value="0.25">0.25×</option>
            <option value="0.5">0.5×</option>
            <option value="0.75">0.75×</option>
            <option value="1" selected>1×</option>
            <option value="1.25">1.25×</option>
            <option value="1.5">1.5×</option>
            <option value="1.75">1.75×</option>
            <option value="2">2×</option>
          </select>
        </label>
      </div>
    `;

    const slideId = slideshowDocActiveId || slideshowSelectedId || "";
    const srcValue = readChunkedField(obj, "src");
    const rec = getOrCreateSlideshowAudio(slideId, objId, srcValue);
    const audio = rec.audio;

    const stroke = s.stroke || {};
    if (stroke.on){
      box.style.border = `${pct(stroke.size, 1, 20)}px solid ${String(stroke.color || "#111827")}`;
    } else {
      box.style.border = "none";
    }

    const btn = box.querySelector('[data-audio="toggle"]');
    const seek = box.querySelector('[data-audio="seek"]');
    const timeEl = box.querySelector('[data-audio="time"]');
    const loop = box.querySelector('[data-audio="loop"]');
    const vol = box.querySelector('[data-audio="vol"]');
    const rate = box.querySelector('[data-audio="rate"]');

    const uiKey = `ui-${Math.random().toString(16).slice(2)}`;
    let uiEverConnected = false;
    const syncUI = () => {
      if (box.isConnected) uiEverConnected = true;
      else if (uiEverConnected){ rec.uis.delete(uiKey); return; }

      const dur = Number(audio.duration);
      const hasDur = Number.isFinite(dur) && dur > 0;
      const cur = Number(audio.currentTime) || 0;

      const atStart = cur <= 0.05;
      const atEnd = hasDur && cur >= Math.max(0, dur - 0.05);

      if (btn) btn.textContent = audio.paused ? (atStart || atEnd ? "Play" : "Resume") : "Pause";
      if (loop instanceof HTMLInputElement) loop.checked = !!audio.loop;
      if (vol instanceof HTMLInputElement) vol.value = String(Number.isFinite(audio.volume) ? audio.volume : 1);
      if (rate instanceof HTMLSelectElement) rate.value = String(Number.isFinite(audio.playbackRate) ? audio.playbackRate : 1);

      if (seek instanceof HTMLInputElement){
        if (hasDur){
          const p = Math.round((cur / dur) * 1000);
          if (!seek.matches(":active")) seek.value = String(clampNum(p, 0, 1000));
        } else if (!seek.matches(":active")){
          seek.value = "0";
        }
      }

      if (timeEl){
        timeEl.textContent = `${fmtAudioTime(cur)} / ${hasDur ? fmtAudioTime(dur) : "0:00"}`;
      }
    };

    rec.uis.set(uiKey, syncUI);
    syncUI();

    const swallow = (e) => { e.stopPropagation(); };
    box.querySelectorAll("button, input, label, select").forEach(el => {
      el.addEventListener("pointerdown", swallow);
      el.addEventListener("click", swallow);
    });

    btn?.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      const dur = Number(audio.duration);
      const hasDur = Number.isFinite(dur) && dur > 0;
      const atEnd = hasDur && Number(audio.currentTime || 0) >= Math.max(0, dur - 0.05);
      if (audio.paused){
        if (atEnd) audio.currentTime = 0;
        audio.play().catch(()=>{});
      } else {
        audio.pause();
      }
      syncUI();
    });

    if (seek instanceof HTMLInputElement){
      seek.addEventListener("input", (e) => {
        e.preventDefault();
        e.stopPropagation();
        const dur = Number(audio.duration);
        if (!Number.isFinite(dur) || dur <= 0) return;
        const v = clampNum(Number(seek.value), 0, 1000) / 1000;
        audio.currentTime = v * dur;
        syncUI();
      });
    }

    if (loop instanceof HTMLInputElement){
      loop.addEventListener("change", (e) => {
        e.preventDefault();
        e.stopPropagation();
        audio.loop = !!loop.checked;
        syncUI();
      });
    }

    if (vol instanceof HTMLInputElement){
      vol.addEventListener("input", (e) => {
        e.preventDefault();
        e.stopPropagation();
        audio.volume = clampNum(Number(vol.value), 0, 1);
        syncUI();
      });
    }

    if (rate instanceof HTMLSelectElement){
      rate.addEventListener("change", (e) => {
        e.preventDefault();
        e.stopPropagation();
        audio.playbackRate = clampNum(Number(rate.value), 0.25, 2, 1);
        syncUI();
      });
    }

    wrap.appendChild(box);
    return wrap;
  }
}

async function slideshowUpdateObject(objId, patch){
  const slideId = slideshowSelectedId;
  if (!slideId) return;
  if (!objId) return;

  // Prevent recreating deleted objects (update() after remove() would re-create the node).
  // If the object no longer exists in our latest cache, ignore late updates.
  const doc = slideshowDocCache.get(slideId);
  if (doc?.objects && !Object.prototype.hasOwnProperty.call(doc.objects, objId) && objId !== slideshowSelectedObjId){
    return;
  }

  try{
    await db.ref(`${slideshowDocPath(slideId)}/objects/${objId}`).update(patch);
  }catch{}
}

async function writeSlideshowChunkedRecordToRef(ref, record, fieldName = "src", options = {}){
  if (!ref || !record || typeof record !== "object") return;

  const signal = options.signal || null;
  const sourceBlob = record.fileObject instanceof Blob ? record.fileObject : null;
  const source = sourceBlob ? "" : (readChunkedField(record, fieldName) || String(record[fieldName] || ""));
  const nextCount = sourceBlob ? countDataURLChunksForBlob(sourceBlob) : countChunkedPartsForValue(source);
  let prevCount = 0;

  try{
    const prevSnap = await ref.child(`${fieldName}ChunkCount`).once("value");
    prevCount = Math.max(0, Number(prevSnap.val() || 0));
  }catch{}

  const meta = stripChunkedField(record, fieldName);
  delete meta.fileObject;
  delete meta.previewURL;
  meta[`${fieldName}ChunkCount`] = nextCount;
  meta[`${fieldName}UploadPending`] = (sourceBlob || source) ? 1 : null;
  meta[`${fieldName}UploadProgress`] = (sourceBlob || source) ? 0 : null;

  await updateRefWithRetry(ref, meta, RTDB_CHUNK_UPLOAD_RETRIES, signal);

  if (sourceBlob){
    await writeBlobDataURLToRef(ref, fieldName, sourceBlob, {
      signal,
      progressField:`${fieldName}UploadProgress`
    });
  } else if (source){
    await writeChunkedFieldToRef(ref, fieldName, source, {
      signal,
      progressField:`${fieldName}UploadProgress`
    });
  } else {
    await updateRefWithRetry(ref, { [fieldName]: "" }, RTDB_CHUNK_UPLOAD_RETRIES, signal);
  }

  const cleanup = {
    [`${fieldName}UploadPending`]: null,
    [`${fieldName}UploadProgress`]: 100
  };
  for (let i = nextCount + 1; i <= prevCount; i += 1){
    cleanup[i === 1 ? fieldName : `${fieldName}${i}`] = null;
  }
  await updateRefWithRetry(ref, cleanup, RTDB_CHUNK_UPLOAD_RETRIES, signal);
}

async function slideshowSetBackground(bg){
  const slideId = slideshowSelectedId || slideshowDocActiveId;
  if (!slideId || !bg) return;

  const bgRef = db.ref(`${slideshowDocPath(slideId)}/bg`);
  const sourceBlob = bg.fileObject instanceof Blob ? bg.fileObject : null;
  const nextDb = sourceBlob ? { type:"image", src:"", fileObject:bg.fileObject, srcUploadPending:1, srcUploadProgress:0 } : serializeSlideshowBgForDb(bg);
  const nextUi = sourceBlob
    ? { type:"image", src:String(bg.previewURL || ""), srcUploadPending:1, srcUploadProgress:0 }
    : ((nextDb && String(nextDb.type || "solid") === "image")
      ? { ...stripChunkedField(nextDb, "src"), src: readChunkedField(nextDb, "src") }
      : nextDb);

  const scope = sourceBlob ? createFirebaseUploadScope({
    type:"slideshow-bg",
    place:"slideshow",
    disconnectRefs:[bgRef],
    cleanup: async () => {
      try{ await bgRef.remove(); }catch{}
      if (String(bg.previewURL || "").startsWith("blob:")){
        try{ URL.revokeObjectURL(bg.previewURL); }catch{}
      }
    }
  }) : null;

  try{
    if (scope) await armFirebaseUploadDisconnect(scope);

    if (String(nextDb?.type || "solid") === "image"){
      await writeSlideshowChunkedRecordToRef(bgRef, nextDb, "src", { signal:scope?.signal || null });
    } else {
      await bgRef.set(nextDb);
    }

    if (scope) await finishFirebaseUploadScope(scope);
  }catch(e){
    if (scope) await cleanupFirebaseUploadScope(scope, e?.message || "slideshow background upload failed");
    if (!isUploadAbortError(e)) console.error("slideshow background upload failed:", e);
    return;
  }

  const doc = slideshowDocCache.get(slideId) || {};
  doc.bg = nextUi;
  slideshowDocCache.set(slideId, doc);

  try{ applySlideshowBackground($("slideshow-stage") || $("slideshow-canvas"), nextUi); }catch{}
}

async function slideshowAddObject(obj, slideIdOverride = slideshowSelectedId){
  if (!slideIdOverride) return;
  const slideId = slideIdOverride;
  let previewURLToRevoke = "";
  let scope = null;
  try{
    const ref = db.ref(`${slideshowDocPath(slideId)}/objects`).push();
    const objId = ref.key || null;
    const type = String(obj?.type || "");
    const hasMediaBlob = ["image", "video", "audio"].includes(type) && obj?.fileObject instanceof Blob;
    previewURLToRevoke = hasMediaBlob ? String(obj.previewURL || "") : "";

    const dbObj = hasMediaBlob
      ? { ...obj, src:"", srcUploadPending:1, srcUploadProgress:0 }
      : serializeSlideshowObjectForDb(obj);
    if (dbObj && typeof dbObj === "object"){
      delete dbObj.fileObject;
      delete dbObj.previewURL;
    }

    const uiObj = hasMediaBlob
      ? { ...dbObj, src:String(obj.previewURL || ""), srcUploadPending:1, srcUploadProgress:0 }
      : ((dbObj && typeof dbObj === "object")
        ? { ...stripChunkedField(dbObj, "src"), src: readChunkedField(dbObj, "src") }
        : dbObj);

    scope = hasMediaBlob ? createFirebaseUploadScope({
      type:"slideshow-object",
      place:"slideshow",
      targetPath:`${slideshowDocPath(slideId)}/objects/${objId}`,
      slideId,
      objectId: objId,
      disconnectRefs:[ref],
      cleanup: async () => {
        try{ await ref.remove(); }catch{}
        if (previewURLToRevoke.startsWith("blob:")){
          try{ URL.revokeObjectURL(previewURLToRevoke); }catch{}
        }
      }
    }) : null;

    slideshowSetSelectedObject(objId, type || "");

    const doc = slideshowDocCache.get(slideId) || {};
    doc.objects = (doc.objects && typeof doc.objects === "object") ? doc.objects : {};
    if (objId) doc.objects[objId] = uiObj;
    slideshowDocCache.set(slideId, doc);

    try{
      if (slideshowDocActiveId === slideId && !(slideDragState && slideshowSelectedId === slideId)){
        renderSlideshowStage(slideId, doc);
      }
    }catch{}

    if (scope) await armFirebaseUploadDisconnect(scope);

    if (hasMediaBlob){
      await writeSlideshowChunkedRecordToRef(ref, { ...dbObj, fileObject:obj.fileObject }, "src", { signal:scope.signal });
      await finishFirebaseUploadScope(scope);
    } else if (["image", "video", "audio"].includes(String(dbObj?.type || ""))){
      await writeSlideshowChunkedRecordToRef(ref, dbObj, "src");
    } else {
      await ref.set(dbObj);
    }
  }catch(e){
    if (scope) await cleanupFirebaseUploadScope(scope, e?.message || "slideshow object upload failed");
    if (!isUploadAbortError(e)) console.error("slideshow object upload failed:", e);
  }
}

function slideshowAddTextBox(){
  const obj = {
    type:"text",
    x: 32, y: 43, w: 36, h: 14,
    rot: 0,
    layer: 50,
    text: "Insert text here",
    style: {
      font: SLIDESHOW_FONTS[0],
      size: 40,
      color: "#000000",
      stroke: { on:false, size: 2, color:"#000000" },
      effects: { shadow:false }
    }
  };
  slideshowAddObject(obj);
}

function slideshowAddShape(kind){
  kind = String(kind || "rect");

  // Defaults
  let w = 22, h = 22;

  // Better “correct shape” defaults
  if (kind === "circle") { w = 22; h = 22; }
  else if (kind === "ellipse") { w = 32; h = 20; }
  else if (kind === "line") { w = 55; h = 6; }
  else if (kind === "arrow") { w = 36; h = 20; }
  else if (kind === "heart") { w = 28; h = 26; }
  else if (kind === "pentagon") { w = 26; h = 26; }
  else if (kind === "hexagon") { w = 28; h = 24; }

  const obj = {
    type:"shape",
    shape: kind,
    x: 50, y: 50, w, h,
    rot: 0,
    layer: 50,
    style: {
      fill: "#111827",
      stroke: { on:false, size: 4, color:"#111827" }
    }
  };
  slideshowAddObject(obj);
}

async function fileToDataURL(file, options = {}){
  return await readBlobAsDataURLString(file, options);
}

const RTDB_DATA_CHUNK_SIZE = 300000;
const RTDB_BLOB_READ_BYTES = 786432; // 768 KiB and divisible by 3, so middle base64 slices never add padding.
const RTDB_STRING_UPLOAD_BATCH_SIZE = 3;
const RTDB_CHUNK_UPLOAD_CONCURRENCY = 4;
const RTDB_CHUNK_UPLOAD_RETRIES = 4;

const activeFirebaseUploads = new Map();
let activeFirebaseUploadSeq = 0;

function isUploadAbortError(err){
  return !!(
    err?.name === "AbortError" ||
    err?.code === "UPLOAD_ABORTED" ||
    /upload aborted|aborted/i.test(String(err?.message || ""))
  );
}

function createUploadAbortError(reason = "upload aborted"){
  const err = new Error(reason);
  err.name = "AbortError";
  err.code = "UPLOAD_ABORTED";
  return err;
}

function throwIfUploadAborted(signal){
  if (signal?.aborted) throw createUploadAbortError(signal.reason || "upload aborted");
}

function formatUploadPercentText(value){
  const n = Number(value);
  const pct = Number.isFinite(n) ? Math.max(0, Math.min(100, n)) : 0;
  return `${pct.toFixed(2).padStart(5, "0")}%`;
}

function calcUploadPercent(done, total){
  const d = Math.max(0, Number(done) || 0);
  const t = Math.max(0, Number(total) || 0);
  if (!t) return 100;
  return Math.max(0, Math.min(100, (d / t) * 100));
}

function dataURLPrefixForBlob(blob){
  return `data:${String(blob?.type || "application/octet-stream")};base64,`;
}

function dataURLCharLengthForBlob(blob){
  const size = Math.max(0, Number(blob?.size || 0));
  return dataURLPrefixForBlob(blob).length + (Math.ceil(size / 3) * 4);
}

function countDataURLChunksForBlob(blob){
  return Math.max(1, Math.ceil(dataURLCharLengthForBlob(blob) / RTDB_DATA_CHUNK_SIZE));
}

function arrayBufferToBase64(buffer){
  const bytes = new Uint8Array(buffer || 0);
  let binary = "";
  const stride = 0x8000;
  for (let i = 0; i < bytes.length; i += stride){
    const chunk = bytes.subarray(i, i + stride);
    binary += String.fromCharCode.apply(null, chunk);
  }
  return btoa(binary);
}

async function readBlobSliceAsBase64(blob, start, end, signal){
  throwIfUploadAborted(signal);
  const buffer = await blob.slice(start, end).arrayBuffer();
  throwIfUploadAborted(signal);
  return arrayBufferToBase64(buffer);
}

async function readBlobAsDataURLString(blob, { signal, onProgress } = {}){
  if (!(blob instanceof Blob)) return "";
  const prefix = dataURLPrefixForBlob(blob);
  const total = Math.max(0, Number(blob.size || 0));
  if (!total){
    if (typeof onProgress === "function") onProgress(100);
    return prefix;
  }

  const parts = [prefix];
  let loaded = 0;
  for (let start = 0; start < total; start += RTDB_BLOB_READ_BYTES){
    const end = Math.min(total, start + RTDB_BLOB_READ_BYTES);
    const base64 = await readBlobSliceAsBase64(blob, start, end, signal);
    parts.push(base64);
    loaded = end;
    if (typeof onProgress === "function") onProgress(calcUploadPercent(loaded, total));
    await new Promise((resolve) => setTimeout(resolve, 0));
  }
  if (typeof onProgress === "function") onProgress(100);
  return parts.join("");
}

function stripChunkedField(record, fieldName){
  const out = { ...(record || {}) };
  delete out[fieldName];
  for (let i = 2; ; i++){
    const key = `${fieldName}${i}`;
    if (!(key in out)) break;
    delete out[key];
  }
  return out;
}

function readChunkedField(record, fieldName){
  if (!record || typeof record !== "object") return "";
  const first = record[fieldName];
  if (typeof first !== "string") return "";
  let out = first;
  for (let i = 2; ; i++){
    const part = record[`${fieldName}${i}`];
    if (typeof part !== "string") break;
    out += part;
  }
  return out;
}

function writeChunkedField(record, fieldName, value){
  const out = stripChunkedField(record, fieldName);
  const s = String(value || "");
  if (!s){
    out[fieldName] = "";
    return out;
  }
  let idx = 0;
  for (let i = 0; i < s.length; i += RTDB_DATA_CHUNK_SIZE){
    const part = s.slice(i, i + RTDB_DATA_CHUNK_SIZE);
    out[idx === 0 ? fieldName : `${fieldName}${idx + 1}`] = part;
    idx += 1;
  }
  return out;
}

function countChunkedPartsForValue(value){
  const s = String(value || "");
  return Math.max(1, Math.ceil(s.length / RTDB_DATA_CHUNK_SIZE));
}

function hasAllChunkedFieldParts(record, fieldName, expectedCount){
  const total = Math.max(1, Number(expectedCount || 0));
  for (let i = 1; i <= total; i++){
    const key = (i === 1) ? fieldName : `${fieldName}${i}`;
    if (typeof record?.[key] !== "string") return false;
  }
  return true;
}

function attachmentHasPendingChunkedData(file){
  if (!file || typeof file !== "object") return false;

  const expectedCount = Math.max(1, Number(file.dataChunkCount || 0));
  const hasAllParts = hasAllChunkedFieldParts(file, "dataURL", expectedCount);
  const existingDataURL = hasAllParts
    ? (readChunkedField(file, "dataURL") || String(file.dataURL || ""))
    : String(file.dataURL || "");

  if (existingDataURL) return false;
  if (Number(file.uploadPending || 0) > 0) return true;
  return !hasAllParts;
}

function messageHasPendingChunkedMedia(msg){
  if (!msg || typeof msg !== "object") return false;
  const groups = [];
  if (Array.isArray(msg.files)) groups.push(msg.files);
  if (Array.isArray(msg.gifs)) groups.push(msg.gifs);

  for (const list of groups){
    for (const file of list){
      if (attachmentHasPendingChunkedData(file)) return true;
    }
  }
  return false;
}

function normalizeChunkedAttachment(file){
  if (!file || typeof file !== "object") return file;
  const out = stripChunkedField(file, "dataURL");
  const expectedCount = Math.max(1, Number(file.dataChunkCount || 0));
  if (hasAllChunkedFieldParts(file, "dataURL", expectedCount)){
    out.dataURL = readChunkedField(file, "dataURL");
    delete out.previewURL;
    delete out.__loading;
    delete out.uploadPending;
    delete out.uploadProgress;
    delete out.dataChunkCount;
  }
  return out;
}

function serializeChunkedAttachmentForDb(file){
  if (!file || typeof file !== "object") return file;
  const dataURL = readChunkedField(file, "dataURL") || String(file.dataURL || "");
  const out = dataURL
    ? writeChunkedField(stripChunkedField(file, "dataURL"), "dataURL", dataURL)
    : stripChunkedField(file, "dataURL");
  delete out.fileObject;
  delete out.dataURLPromise;
  delete out.previewURL;
  out.dataChunkCount = countChunkedPartsForValue(dataURL);
  if (dataURL){
    delete out.__loading;
    delete out.uploadPending;
    delete out.uploadProgress;
  }
  return out;
}

function splitChunkedFieldEntries(fieldName, value){
  const s = String(value || "");
  if (!s) return [[fieldName, ""]];

  const entries = [];
  let idx = 0;
  for (let i = 0; i < s.length; i += RTDB_DATA_CHUNK_SIZE){
    const key = idx === 0 ? fieldName : `${fieldName}${idx + 1}`;
    entries.push([key, s.slice(i, i + RTDB_DATA_CHUNK_SIZE)]);
    idx += 1;
  }
  return entries;
}

async function runTaskPool(taskFns, limit = 1){
  const total = Array.isArray(taskFns) ? taskFns.length : 0;
  if (!total) return;

  const max = Math.max(1, Number(limit) || 1);
  let cursor = 0;

  const worker = async () => {
    while (cursor < total){
      const idx = cursor++;
      await taskFns[idx]();
    }
  };

  const workers = [];
  for (let i = 0; i < Math.min(max, total); i++) workers.push(worker());
  await Promise.all(workers);
}

function isRtdbPayloadTooLargeError(err){
  const msg = String(err?.message || err || "");
  return /payload is too large|request a location with less data|less data/i.test(msg);
}

async function updateRefPayloadChildrenWithRetry(ref, payload, attempts = RTDB_CHUNK_UPLOAD_RETRIES, signal = null){
  const entries = Object.entries(payload || {});
  for (const [key, value] of entries){
    throwIfUploadAborted(signal);
    await setRefWithRetry(ref.child(key), value, attempts, signal);
  }
}

async function updateRefWithRetry(ref, payload, attempts = RTDB_CHUNK_UPLOAD_RETRIES, signal = null){
  let lastErr = null;
  const maxAttempts = Math.max(1, Number(attempts) || 1);
  const canSplitPayload = payload && typeof payload === "object" && !Array.isArray(payload);

  for (let attempt = 1; attempt <= maxAttempts; attempt++){
    throwIfUploadAborted(signal);
    try{
      await ref.update(payload);
      throwIfUploadAborted(signal);
      return;
    }catch(e){
      if (isUploadAbortError(e)) throw e;
      if (canSplitPayload && isRtdbPayloadTooLargeError(e)){
        await updateRefPayloadChildrenWithRetry(ref, payload, maxAttempts, signal);
        return;
      }
      lastErr = e;
      if (attempt >= maxAttempts) break;
      await new Promise((resolve) => setTimeout(resolve, attempt * 250));
    }
  }

  throw lastErr || new Error("chunk upload failed");
}

async function setRefWithRetry(ref, payload, attempts = RTDB_CHUNK_UPLOAD_RETRIES, signal = null){
  let lastErr = null;
  const maxAttempts = Math.max(1, Number(attempts) || 1);

  for (let attempt = 1; attempt <= maxAttempts; attempt++){
    throwIfUploadAborted(signal);
    try{
      await ref.set(payload);
      throwIfUploadAborted(signal);
      return;
    }catch(e){
      if (isUploadAbortError(e)) throw e;
      lastErr = e;
      if (attempt >= maxAttempts) break;
      await new Promise((resolve) => setTimeout(resolve, attempt * 250));
    }
  }

  throw lastErr || new Error("set failed");
}

async function writeChunkedFieldToRef(ref, fieldName, value, options = {}){
  const entries = splitChunkedFieldEntries(fieldName, value);
  const signal = options.signal || null;
  const progressField = options.progressField || "";
  const onProgress = typeof options.onProgress === "function" ? options.onProgress : null;
  const batchSize = Math.max(1, Number(options.batchSize || RTDB_STRING_UPLOAD_BATCH_SIZE) || RTDB_STRING_UPLOAD_BATCH_SIZE);
  const total = Math.max(1, entries.length);
  let written = 0;

  for (let i = 0; i < entries.length; i += batchSize){
    throwIfUploadAborted(signal);
    const batchEntries = entries.slice(i, i + batchSize);
    const batch = Object.fromEntries(batchEntries);
    written = Math.min(total, i + batchEntries.length);
    const pct = calcUploadPercent(written, total);
    if (progressField) batch[progressField] = pct;
    await updateRefWithRetry(ref, batch, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    if (onProgress) onProgress(pct);
  }

  return entries.length;
}

async function writeBlobDataURLToRef(ref, fieldName, blob, options = {}){
  if (!(blob instanceof Blob)) return await writeChunkedFieldToRef(ref, fieldName, "", options);

  const signal = options.signal || null;
  const progressField = options.progressField || "";
  const onProgress = typeof options.onProgress === "function" ? options.onProgress : null;
  const batchSize = Math.max(1, Number(options.batchSize || RTDB_STRING_UPLOAD_BATCH_SIZE) || RTDB_STRING_UPLOAD_BATCH_SIZE);
  const totalChars = Math.max(1, dataURLCharLengthForBlob(blob));
  const totalBytes = Math.max(0, Number(blob.size || 0));
  let committedChars = 0;
  let pending = dataURLPrefixForBlob(blob);
  let chunkIndex = 1;
  let payload = {};
  let payloadCount = 0;
  let lastProgress = 0;

  const flushPayload = async (pct) => {
    if (!payloadCount) return;
    const safePct = Math.max(0, Math.min(100, Number(pct) || 0));
    if (progressField) payload[progressField] = safePct;
    await updateRefWithRetry(ref, payload, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    lastProgress = safePct;
    if (onProgress) onProgress(safePct);
    payload = {};
    payloadCount = 0;
  };

  const queuePart = async (part) => {
    const key = chunkIndex === 1 ? fieldName : `${fieldName}${chunkIndex}`;
    chunkIndex += 1;
    committedChars += part.length;
    payload[key] = part;
    payloadCount += 1;

    const pct = calcUploadPercent(committedChars, totalChars);
    if (payloadCount >= batchSize) await flushPayload(pct);
  };

  const flushAvailable = async (force = false) => {
    while (pending.length >= RTDB_DATA_CHUNK_SIZE || (force && pending.length)){
      throwIfUploadAborted(signal);
      const part = force && pending.length <= RTDB_DATA_CHUNK_SIZE
        ? pending
        : pending.slice(0, RTDB_DATA_CHUNK_SIZE);
      pending = pending.slice(part.length);
      await queuePart(part);
    }
  };

  await flushAvailable(false);

  if (!totalBytes){
    await flushAvailable(true);
    if (payloadCount) await flushPayload(100);
    else if (progressField && lastProgress < 100) await updateRefWithRetry(ref, { [progressField]:100 }, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    if (onProgress && lastProgress < 100) onProgress(100);
    return chunkIndex - 1;
  }

  for (let start = 0; start < totalBytes; start += RTDB_BLOB_READ_BYTES){
    const end = Math.min(totalBytes, start + RTDB_BLOB_READ_BYTES);
    pending += await readBlobSliceAsBase64(blob, start, end, signal);
    await flushAvailable(false);
  }

  await flushAvailable(true);
  if (payloadCount) await flushPayload(100);
  else if (progressField && lastProgress < 100) await updateRefWithRetry(ref, { [progressField]:100 }, RTDB_CHUNK_UPLOAD_RETRIES, signal);
  if (onProgress && lastProgress < 100) onProgress(100);
  return chunkIndex - 1;
}

async function writeTextFileChunksToRef(ref, fieldName, file, options = {}){
  if (!(file instanceof Blob)) return await writeHtmlStringChunksToRef(ref, fieldName, "", options);

  const signal = options.signal || null;
  const progressField = options.progressField || "";
  const onProgress = typeof options.onProgress === "function" ? options.onProgress : null;
  const batchSize = Math.max(1, Number(options.batchSize || RTDB_STRING_UPLOAD_BATCH_SIZE) || RTDB_STRING_UPLOAD_BATCH_SIZE);
  const totalBytes = Math.max(0, Number(file.size || 0));
  const decoder = new TextDecoder("utf-8", { fatal:false });
  const chunkLimit = Math.max(50000, Number(options.chunkSize || HTML_LIBRARY_CHUNK_SIZE) || HTML_LIBRARY_CHUNK_SIZE);
  let pending = "";
  let part = 1;
  let loadedBytes = 0;
  let payload = {};
  let payloadCount = 0;

  const flushPayload = async (pct) => {
    if (!payloadCount) return;
    if (progressField) payload[progressField] = pct;
    await updateRefWithRetry(ref, payload, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    if (onProgress) onProgress(pct);
    payload = {};
    payloadCount = 0;
  };

  const queueTextPart = async (text) => {
    const key = part === 1 ? fieldName : `${fieldName}${part}`;
    part += 1;
    const pct = totalBytes ? calcUploadPercent(loadedBytes, totalBytes) : 100;
    payload[key] = text;
    payloadCount += 1;
    if (payloadCount >= batchSize) await flushPayload(pct);
  };

  const flushText = async (force = false) => {
    while (pending.length >= chunkLimit || (force && pending.length)){
      throwIfUploadAborted(signal);
      const text = force && pending.length <= chunkLimit ? pending : pending.slice(0, chunkLimit);
      pending = pending.slice(text.length);
      await queueTextPart(text);
    }
  };

  if (!totalBytes){
    await updateRefWithRetry(ref, { [fieldName]:"", [`${fieldName}ChunkCount`]:1, ...(progressField ? { [progressField]:100 } : {}) }, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    if (onProgress) onProgress(100);
    return 1;
  }

  for (let start = 0; start < totalBytes; start += RTDB_BLOB_READ_BYTES){
    const end = Math.min(totalBytes, start + RTDB_BLOB_READ_BYTES);
    throwIfUploadAborted(signal);
    const buffer = await file.slice(start, end).arrayBuffer();
    throwIfUploadAborted(signal);
    loadedBytes = end;
    pending += decoder.decode(buffer, { stream:end < totalBytes });
    await flushText(false);
  }

  pending += decoder.decode();
  loadedBytes = totalBytes;
  await flushText(true);

  const count = Math.max(1, part - 1);
  payload[`${fieldName}ChunkCount`] = count;
  payloadCount += 1;
  if (progressField) payload[progressField] = 100;
  await updateRefWithRetry(ref, payload, RTDB_CHUNK_UPLOAD_RETRIES, signal);
  if (onProgress) onProgress(100);
  return count;
}

async function writeHtmlStringChunksToRef(ref, fieldName, html, options = {}){
  const signal = options.signal || null;
  const s = String(html || "");
  const batchSize = Math.max(1, Number(options.batchSize || RTDB_STRING_UPLOAD_BATCH_SIZE) || RTDB_STRING_UPLOAD_BATCH_SIZE);
  const total = Math.max(1, Math.ceil(s.length / HTML_LIBRARY_CHUNK_SIZE));
  let part = 1;
  let payload = {};
  let payloadCount = 0;

  const flushPayload = async (pct) => {
    if (!payloadCount) return;
    if (options.progressField) payload[options.progressField] = pct;
    await updateRefWithRetry(ref, payload, RTDB_CHUNK_UPLOAD_RETRIES, signal);
    if (typeof options.onProgress === "function") options.onProgress(pct);
    payload = {};
    payloadCount = 0;
  };

  for (let i = 0; i < s.length || (i === 0 && !s); i += HTML_LIBRARY_CHUNK_SIZE){
    throwIfUploadAborted(signal);
    const key = part === 1 ? fieldName : `${fieldName}${part}`;
    const pct = calcUploadPercent(part, total);
    payload[key] = s.slice(i, i + HTML_LIBRARY_CHUNK_SIZE);
    payloadCount += 1;
    if (payloadCount >= batchSize) await flushPayload(pct);
    part += 1;
  }

  const count = Math.max(1, part - 1);
  payload[`${fieldName}ChunkCount`] = count;
  payloadCount += 1;
  if (options.progressField) payload[options.progressField] = 100;
  await updateRefWithRetry(ref, payload, RTDB_CHUNK_UPLOAD_RETRIES, signal);
  if (typeof options.onProgress === "function") options.onProgress(100);
  return count;
}

function createFirebaseUploadScope({ type, place, cleanup, disconnectRefs = [], targetPath = "", slideId = "", objectId = "" } = {}){
  const controller = new AbortController();
  const id = `upload_${Date.now().toString(36)}_${(++activeFirebaseUploadSeq).toString(36)}`;
  const scope = {
    id,
    type: String(type || "upload"),
    place: String(place || ""),
    targetPath: String(targetPath || ""),
    slideId: String(slideId || ""),
    objectId: String(objectId || ""),
    controller,
    signal: controller.signal,
    cleanup: typeof cleanup === "function" ? cleanup : async () => {},
    disconnectRefs: Array.isArray(disconnectRefs) ? disconnectRefs.filter(Boolean) : [],
    done:false,
    cleaning:false
  };

  scope.abort = (reason = "upload aborted") => {
    if (!scope.signal.aborted){
      try{ scope.controller.abort(reason); }catch{}
    }
    void cleanupFirebaseUploadScope(scope, reason);
  };

  activeFirebaseUploads.set(scope.id, scope);
  return scope;
}

async function armFirebaseUploadDisconnect(scope){
  if (!scope || !Array.isArray(scope.disconnectRefs)) return;
  for (const ref of scope.disconnectRefs){
    try{ await ref.onDisconnect().remove(); }catch{}
  }
}

async function finishFirebaseUploadScope(scope){
  if (!scope) return;
  scope.done = true;
  activeFirebaseUploads.delete(scope.id);
  if (Array.isArray(scope.disconnectRefs)){
    for (const ref of scope.disconnectRefs){
      try{ await ref.onDisconnect().cancel(); }catch{}
    }
  }
}

async function cleanupFirebaseUploadScope(scope, reason = "upload aborted"){
  if (!scope || scope.cleaning || scope.done) return;
  scope.cleaning = true;
  activeFirebaseUploads.delete(scope.id);
  try{
    if (!scope.signal.aborted){
      try{ scope.controller.abort(reason); }catch{}
    }
  }catch{}
  try{ await scope.cleanup(reason); }catch{}
}

async function abortFirebaseUploadsForSlideshowObject(slideId, objId){
  if (!slideId || !objId) return;
  const targetPath = `${slideshowDocPath(slideId)}/objects/${objId}`;
  const matches = Array.from(activeFirebaseUploads.values()).filter((scope) => {
    return scope?.type === "slideshow-object" && (
      scope.targetPath === targetPath ||
      (scope.slideId === String(slideId) && scope.objectId === String(objId))
    );
  });

  await Promise.all(matches.map((scope) => cleanupFirebaseUploadScope(scope, "slideshow object deleted")));
}

function abortFirebaseUploadsForPlaceChange(nextPlace){
  const next = String(nextPlace || "");
  for (const scope of Array.from(activeFirebaseUploads.values())){
    if (!scope.place || scope.place === next) continue;
    scope.abort("page changed");
  }
}

function abortAllFirebaseUploads(reason = "page unload"){
  for (const scope of Array.from(activeFirebaseUploads.values())){
    try{
      if (!scope.signal.aborted) scope.controller.abort(reason);
    }catch{}
  }
}

window.addEventListener("pagehide", () => abortAllFirebaseUploads("page hidden"), { capture:true });
window.addEventListener("beforeunload", () => abortAllFirebaseUploads("page unload"), { capture:true });

async function writeMessageAttachmentsToRef(messageRef, files = [], gifs = [], options = {}){
  const signal = options.signal || null;
  const taskFns = [];

  const onItemProgress = (group, index, pct) => {
    if (typeof options.onProgress === "function"){
      options.onProgress({ group, index, progress:pct });
    }
  };

  const writeAttachment = async (childRef, item, group, index) => {
    throwIfUploadAborted(signal);

    const existing = readChunkedField(item, "dataURL") || String(item?.dataURL || "");
    const blob = item?.fileObject instanceof Blob ? item.fileObject : null;
    const count = blob ? countDataURLChunksForBlob(blob) : countChunkedPartsForValue(existing);

    await updateRefWithRetry(childRef, {
      uploadPending: 1,
      uploadProgress: 0,
      dataChunkCount: count
    }, RTDB_CHUNK_UPLOAD_RETRIES, signal);

    if (blob){
      await writeBlobDataURLToRef(childRef, "dataURL", blob, {
        signal,
        progressField:"uploadProgress",
        onProgress:(pct) => onItemProgress(group, index, pct)
      });
    } else {
      await writeChunkedFieldToRef(childRef, "dataURL", existing, {
        signal,
        progressField:"uploadProgress",
        onProgress:(pct) => onItemProgress(group, index, pct)
      });
    }

    await updateRefWithRetry(childRef, {
      uploadPending: null,
      uploadProgress: 100
    }, RTDB_CHUNK_UPLOAD_RETRIES, signal);

    delete item.previewURL;
    delete item.__loading;
    delete item.uploadPending;
    item.uploadProgress = 100;
    item.dataChunkCount = count;
  };

  for (let i = 0; i < files.length; i++){
    taskFns.push(() => writeAttachment(messageRef.child(`files/${i}`), files[i], "files", i));
  }

  for (let i = 0; i < gifs.length; i++){
    taskFns.push(() => writeAttachment(messageRef.child(`gifs/${i}`), gifs[i], "gifs", i));
  }

  await runTaskPool(taskFns, RTDB_CHUNK_UPLOAD_CONCURRENCY);
  await updateRefWithRetry(messageRef, { attachmentsSyncedAt: firebase.database.ServerValue.TIMESTAMP }, RTDB_CHUNK_UPLOAD_RETRIES, signal);
}

function normalizeMessageMedia(msg){
  if (!msg || typeof msg !== "object") return msg;

  const out = stripChunkedField(msg, "dataURL");
  const rootDataURL = readChunkedField(msg, "dataURL");
  if (rootDataURL) out.dataURL = rootDataURL;

  if (Array.isArray(out.files)) out.files = out.files.map(normalizeChunkedAttachment);
  if (Array.isArray(out.gifs)) out.gifs = out.gifs.map(normalizeChunkedAttachment);

  return out;
}

function mergeChunkedAttachmentForDisplay(nextFile, prevFile){
  const next = normalizeChunkedAttachment(nextFile);
  const prev = normalizeChunkedAttachment(prevFile);
  if (!next || typeof next !== "object") return next;

  const mergedDataURL = String(next.dataURL || prev?.dataURL || "");
  const mergedPreviewURL = String(next.previewURL || prev?.previewURL || "");

  if (!mergedDataURL){
    return mergedPreviewURL ? { ...next, previewURL: mergedPreviewURL } : next;
  }

  const merged = { ...next, dataURL: mergedDataURL };
  delete merged.previewURL;
  delete merged.__loading;
  delete merged.uploadPending;
  delete merged.dataChunkCount;
  return merged;
}

function mergeMessageMediaForDisplay(nextMsg, prevMsg){
  const next = normalizeMessageMedia(nextMsg);
  if (!next || typeof next !== "object") return next;

  const prev = normalizeMessageMedia(prevMsg);
  if (prev && typeof prev === "object"){
    if (!next.dataURL && prev.dataURL) next.dataURL = prev.dataURL;

    if (Array.isArray(next.files) && Array.isArray(prev.files)){
      next.files = next.files.map((file, i) => mergeChunkedAttachmentForDisplay(file, prev.files[i]));
    }

    if (Array.isArray(next.gifs) && Array.isArray(prev.gifs)){
      next.gifs = next.gifs.map((file, i) => mergeChunkedAttachmentForDisplay(file, prev.gifs[i]));
    }
  }

  delete next.__stub;
  return next;
}

const pendingMessageMediaRefreshTimers = new Map();

function scheduleMessageMediaRefresh(roomId, msgKey, delay = 120){
  const rid = String(roomId || "");
  const key = String(msgKey || "");
  if (!rid || !key) return;

  const timerKey = `${rid}:${key}`;
  const prevTimer = pendingMessageMediaRefreshTimers.get(timerKey);
  if (prevTimer) clearTimeout(prevTimer);

  const waitMs = Math.max(0, Number(delay) || 0);
  const timer = setTimeout(() => {
    pendingMessageMediaRefreshTimers.delete(timerKey);

    db.ref(`messages/${rid}/${key}`).once("value").then((freshSnap) => {
      const freshRaw = freshSnap.val();
      if (!freshRaw) return;

      const prev = msgDataByKey.get(key) || null;
      const freshMsg = mergeMessageMediaForDisplay(
        normalizeMessageMedia({ _key:key, ...freshRaw }),
        prev
      );

      replaceMessageRowByKey(freshMsg);
      refreshReplyPreviewDependents(key);

      if (messageHasPendingChunkedMedia(freshMsg)){
        scheduleMessageMediaRefresh(rid, key, Math.min(1500, Math.max(180, Math.round(waitMs * 1.8) || 180)));
      }
    }).catch(() => {});
  }, waitMs);

  pendingMessageMediaRefreshTimers.set(timerKey, timer);
}

function serializeSlideshowBgForDb(bg){
  if (String(bg?.type || "solid") === "image"){
    return writeChunkedField({ type:"image" }, "src", readChunkedField(bg, "src"));
  }
  return { type:"solid", color: normalizeHex6(bg?.color || "#ffffff") };
}

function serializeSlideshowObjectForDb(obj){
  if (!obj || typeof obj !== "object") return obj;
  const out = { ...obj };
  if (["image", "video", "audio"].includes(String(out.type || ""))){
    return writeChunkedField(out, "src", readChunkedField(out, "src"));
  }
  return out;
}

async function addPendingFile(file, options = {}){
  if (!file) return false;

  const kind = chatFileKind(file);
  let previewURL = "";
  try{
    previewURL = URL.createObjectURL(file);
  }catch{
    previewURL = "";
  }

  const isVoiceMessage = !!options.isVoiceMessage;

  pendingFiles.push({
    id: Math.random().toString(36).slice(2),
    kind,
    name: file.name || "file",
    fileName: file.name || "file",
    displayName: isVoiceMessage ? String(options.displayName || "Voice Message") : "",
    isVoiceMessage,
    voiceTrimStartSec: Math.max(0, Number(options.voiceTrimStartSec) || 0),
    type: file.type || "",
    mimeType: file.type || getMediaMimeType(file) || "",
    size: Number(file.size || 0),
    previewURL,
    fileObject: file
  });

  renderFilesBar();
  syncChatOverlayMetrics();
  return true;
}

async function slideshowAddMediaFiles(files){
  if (!slideshowSelectedId) return;
  const targetSlideId = slideshowSelectedId;

  const taskFns = [];

  for (const file of files){
    const mime = String(file.type || getMediaMimeType(file) || "").toLowerCase();
    const kind = chatFileKind(file);
    if (!(kind === "image" || kind === "video" || kind === "audio")){
      showToast({ title:"Not supported", body:"Slideshows only support images/GIFs/videos/audio.", duration: 2600 });
      continue;
    }

    let previewURL = "";
    try{ previewURL = URL.createObjectURL(file); }catch{ previewURL = ""; }

    if (kind === "audio"){
      taskFns.push(() => slideshowAddObject({
        type:"audio",
        x: 50, y: 55, w: 38, h: 12,
        rot: 0,
        layer: 50,
        src:"",
        previewURL,
        fileObject:file,
        name: file.name || "Audio",
        sub: mime,
        mimeType: mime
      }, targetSlideId));
    } else if (kind === "video"){
      taskFns.push(() => slideshowAddObject({
        type:"video",
        x: 50, y: 50, w: 50, h: 34,
        rot: 0,
        layer: 50,
        src:"",
        previewURL,
        fileObject:file,
        name: file.name || "Video",
        mimeType: mime
      }, targetSlideId));
    } else {
      taskFns.push(() => slideshowAddObject({
        type:"image",
        x: 50, y: 50, w: 42, h: 30,
        rot: 0,
        layer: 50,
        src:"",
        previewURL,
        fileObject:file
      }, targetSlideId));
    }
  }

  await runTaskPool(taskFns, RTDB_CHUNK_UPLOAD_CONCURRENCY);
}

/* -------------------- Slideshow selection + menus -------------------- */
function slideshowSetSelectedObject(objId, objType){
  slideshowSelectedObjId = objId;
  slideshowSelectedObjType = objType || null;

  const input = $("msg-input");
  if (input){
    if (objType === "text"){
      const doc = getActiveSlideshowDoc();
      const obj = doc?.objects?.[objId] || null;
      input.value = obj ? String(obj.text || "") : "";
    } else {
      input.value = "";
    }
  }

  setMySlideshowLocation(slideshowSelectedId);
  applySlideshowComposerRules();
  updateSlideSelectionUI();
}

function slideshowClearSelection(opts={}){
  slideshowSelectedObjId = null;
  slideshowSelectedObjType = null;
  if (!opts.quiet){
    try{ $("msg-input").value = ""; }catch{}
  }
  setMySlideshowLocation(slideshowSelectedId);
  applySlideshowComposerRules();
  updateSlideSelectionUI();
  renderSlideshowRemoteSelections();
}

/* -------------------- Slideshow copy/paste -------------------- */
function deepCloneSlideObject(obj){
  if (!obj || typeof obj !== "object") return null;
  try{ return structuredClone(obj); }catch{}
  try{ return JSON.parse(JSON.stringify(obj)); }catch{}
  return null;
}

function slideshowCopySelectedObject(){
  if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
  if (!slideshowSelectedId || !slideshowSelectedObjId) return;

  const doc = slideshowDocCache.get(slideshowSelectedId) || getActiveSlideshowDoc();
  const obj = doc?.objects?.[slideshowSelectedObjId] || null;
  const copy = deepCloneSlideObject(obj);
  if (!copy) return;

  slideshowClipboard = copy; // copying something new replaces the old copy
  applySlideshowComposerRules(); // enable Paste immediately (real-time)
}

async function slideshowPasteClipboardObject(){
  if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
  if (!slideshowSelectedId) return;
  if (!slideshowClipboard) return;

  const next = deepCloneSlideObject(slideshowClipboard);
  if (!next) return;

  // Place in the center of the slide (x/y are top-left in % units)
  const w = pct(next.w, 1, 100);
  const h = pct(next.h, 1, 100);
  next.w = w;
  next.h = h;
  next.x = clampNum(50 - (w / 2), 0, 100);
  next.y = clampNum(50 - (h / 2), 0, 100);

  // This selects the pasted object and unselects the prior one.
  await slideshowAddObject(next);
}

async function slideshowCopyPasteSelectedObject(){
  // Copy + Pasting something puts it as your copy.
  slideshowCopySelectedObject();
  await slideshowPasteClipboardObject();
}

async function slideshowDuplicateSelectedObject(){
  if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
  if (!slideshowSelectedId || !slideshowSelectedObjId) return;

  const doc = slideshowDocCache.get(slideshowSelectedId) || getActiveSlideshowDoc();
  const obj = doc?.objects?.[slideshowSelectedObjId] || null;
  const next = deepCloneSlideObject(obj);
  if (!next) return;

  const w = pct(next.w, 1, 100);
  const h = pct(next.h, 1, 100);
  next.w = w;
  next.h = h;
  next.x = clampNum((Number(next.x) || 0) + 3, 0, Math.max(0, 100 - w));
  next.y = clampNum((Number(next.y) || 0) + 3, 0, Math.max(0, 100 - h));

  // Duplicate does not touch slideshowClipboard.
  await slideshowAddObject(next);
}

function updateSlideSelectionUI(){
  const stage = $("slideshow-stage");
  const side = $("slideshow-side");
  const inspector = $("slideshow-inspector");
  const floatingMenu = $("slide-menu"); // legacy (kept hidden)

  if (!stage || !side || !inspector) return;

  stage.querySelectorAll(".slide-obj").forEach(el => {
    el.classList.toggle("is-selected", el.getAttribute("data-obj-id") === slideshowSelectedObjId);
  });

  // Always hide the legacy floating menu
  if (floatingMenu){
    floatingMenu.hidden = true;
    floatingMenu.innerHTML = "";
  }

  if (!slideshowSelectedObjId){
    inspector.hidden = true;
    inspector.innerHTML = "";
    side.classList.remove("is-inspecting");
    removeSlideHandles();
    return;
  }

  const doc = getActiveSlideshowDoc();
  const obj = doc?.objects?.[slideshowSelectedObjId] || null;
  if (!obj){
    inspector.hidden = true;
    inspector.innerHTML = "";
    side.classList.remove("is-inspecting");
    removeSlideHandles();
    return;
  }

  buildSlideMenu(obj, inspector);
  inspector.hidden = false;
  side.classList.add("is-inspecting");
  addSlideHandles();
}

function positionSlideMenu(){
  const menu = $("slide-menu");
  const stage = $("slideshow-stage");
  if (!menu || !stage || !slideshowSelectedObjId) return;

  const el = stage.querySelector(`[data-obj-id="${CSS.escape(slideshowSelectedObjId)}"]`);
  if (!el) return;

  const r = el.getBoundingClientRect();
  const sr = stage.getBoundingClientRect();
  const pad = 10;

  // Default: above, centered
  let anchorX = (r.left - sr.left) + (r.width / 2);
  let anchorY = (r.top - sr.top) - 12;
  let above = true;

  menu.style.transform = "translate(-50%,-100%)";
  menu.style.left = `${anchorX}px`;
  menu.style.top = `${anchorY}px`;

  requestAnimationFrame(() => {
    const mr = menu.getBoundingClientRect();
    const menuW = mr.width || 0;
    const menuH = mr.height || 0;

    // Flip below if we don't have room above
    if ((r.top - sr.top) - 12 - menuH < pad){
      above = false;
      menu.style.transform = "translate(-50%,0)";
      anchorY = (r.bottom - sr.top) + 12;
      menu.style.top = `${anchorY}px`;
    }

    // Clamp X within stage
    const stageW = sr.width || 0;
    const minX = pad + (menuW / 2);
    const maxX = Math.max(minX, stageW - pad - (menuW / 2));
    anchorX = clampNum(anchorX, minX, maxX);

    // Clamp Y within stage (keep menu visible even when flipped)
    const stageH = sr.height || 0;
    if (above){
      // anchor is bottom of menu
      const minY = pad + menuH;
      const maxY = Math.max(minY, stageH - pad);
      anchorY = clampNum(anchorY, minY, maxY);
    } else {
      // anchor is top of menu
      const minY = pad;
      const maxY = Math.max(minY, stageH - pad - menuH);
      anchorY = clampNum(anchorY, minY, maxY);
    }

    menu.style.left = `${anchorX}px`;
    menu.style.top = `${anchorY}px`;
  });
}

function clampNum(n, min, max, fallback = min){
  const x = Number(n);
  if (!Number.isFinite(x)) return fallback;
  return Math.min(max, Math.max(min, x));
}

let slideColorPickerBound = false;

function hexToRgb(hex){
  const h = String(hex || "").trim().replace(/^#/, "");
  if (!/^[0-9a-fA-F]{6}$/.test(h)) return { r:0, g:0, b:0 };
  return {
    r: parseInt(h.slice(0,2), 16),
    g: parseInt(h.slice(2,4), 16),
    b: parseInt(h.slice(4,6), 16)
  };
}
function rgbToHex(r,g,b){
  const to2 = (n) => {
    const v = clampNum(Math.round(n), 0, 255).toString(16).padStart(2,"0");
    return v;
  };
  return `#${to2(r)}${to2(g)}${to2(b)}`;
}

function normalizeHex6(hex){
  let v = String(hex || "").trim();
  if (!v) return "#000000";
  if (!v.startsWith("#")) v = `#${v}`;
  v = v.replace(/^#/, "");
  if (/^[0-9a-fA-F]{3}$/.test(v)){
    v = `${v[0]}${v[0]}${v[1]}${v[1]}${v[2]}${v[2]}`;
  }
  if (!/^[0-9a-fA-F]{6}$/.test(v)) return "#000000";
  return `#${v.toLowerCase()}`;
}

function buildColorButton({ id, label, value, disabled=false }){
  const v = normalizeHex6(value);
  return `
    <button class="color-btn" type="button" id="${escapeHtml(id)}" ${disabled ? "disabled" : ""}>
      <span class="color-swatch" style="background:${escapeHtml(v)}"></span>
      <span class="color-name">${escapeHtml(v)}</span>
    </button>
    ${label ? `<div class="slide-menu-label">${escapeHtml(label)}</div>` : ""}
  `;
}

async function openCustomColorPicker({ title="Pick color", value="#000000" } = {}){
  value = normalizeHex6(value);

  const presets = [
    "#000000","#111827","#374151","#6b7280","#9ca3af","#d1d5db","#e5e7eb","#f3f4f6","#ffffff",
    "#ef4444","#f97316","#f59e0b","#eab308","#84cc16","#22c55e","#10b981","#14b8a6",
    "#06b6d4","#0ea5e9","#3b82f6","#6366f1","#8b5cf6","#a855f7","#d946ef","#ec4899"
  ];

  const rgb = hexToRgb(value);
  let hue = 0;
  let sat = 0;
  let val = 0;

  // rgb -> hsv
  {
    const r = rgb.r/255, g = rgb.g/255, b = rgb.b/255;
    const mx = Math.max(r,g,b), mn = Math.min(r,g,b);
    const d = mx-mn;
    val = mx;
    sat = mx === 0 ? 0 : d/mx;

    if (d === 0) hue = 0;
    else if (mx === r) hue = ((g-b)/d) % 6;
    else if (mx === g) hue = ((b-r)/d) + 2;
    else hue = ((r-g)/d) + 4;
    hue = Math.round(hue * 60);
    if (hue < 0) hue += 360;
  }

  const modalId = `cp-${Math.random().toString(16).slice(2)}`;
  const bodyHTML = `
    <div class="color-picker" id="${modalId}">
      <div class="cp-top">
        <div class="cp-swatch" id="${modalId}-sw" style="background:${escapeHtml(value)}"></div>
        <input class="cp-hex" id="${modalId}-hex" value="${escapeHtml(value)}" />
      </div>

      <div class="cp-preset">
        ${presets.map(c => `<button class="cp-chip" type="button" data-cp="${escapeHtml(c)}" style="background:${escapeHtml(c)}"></button>`).join("")}
      </div>

      <div class="cp-advanced">
        <canvas class="cp-sv" id="${modalId}-sv" height="160"></canvas>
        <input class="cp-hue" id="${modalId}-h" type="range" min="0" max="360" value="${hue}">
      </div>

      <div class="cp-actions">
        <button class="btn" id="${modalId}-cancel" type="button">Cancel</button>
        <button class="btn primary" id="${modalId}-ok" type="button">Apply</button>
      </div>
    </div>
  `;

  openModal({ title, bodyHTML });

  const root = $(modalId);
  const sw = $(`${modalId}-sw`);
  const hex = $(`${modalId}-hex`);
  const sv = $(`${modalId}-sv`);
  const hueEl = $(`${modalId}-h`);
  const ok = $(`${modalId}-ok`);
  const cancel = $(`${modalId}-cancel`);

  let cur = normalizeHex6(value);

  const setHex = (h) => {
    cur = normalizeHex6(h);
    if (sw) sw.style.background = cur;
    if (hex) hex.value = cur;
  };

  const hsvToRgb = (h,s,v) => {
    const c = v*s;
    const x = c*(1-Math.abs(((h/60)%2)-1));
    const m = v-c;
    let r=0,g=0,b=0;
    if (h<60){r=c;g=x;b=0}
    else if (h<120){r=x;g=c;b=0}
    else if (h<180){r=0;g=c;b=x}
    else if (h<240){r=0;g=x;b=c}
    else if (h<300){r=x;g=0;b=c}
    else {r=c;g=0;b=x}
    return { r:Math.round((r+m)*255), g:Math.round((g+m)*255), b:Math.round((b+m)*255) };
  };

  const drawSV = () => {
    if (!(sv instanceof HTMLCanvasElement)) return;
    const ctx = sv.getContext("2d");
    if (!ctx) return;
    const w = sv.width, h = sv.height;

    // base hue
    ctx.clearRect(0,0,w,h);
    ctx.fillStyle = `hsl(${hue}, 100%, 50%)`;
    ctx.fillRect(0,0,w,h);

    // white -> transparent left to right (saturation)
    const g1 = ctx.createLinearGradient(0,0,w,0);
    g1.addColorStop(0,"rgba(255,255,255,1)");
    g1.addColorStop(1,"rgba(255,255,255,0)");
    ctx.fillStyle = g1;
    ctx.fillRect(0,0,w,h);

    // transparent -> black top to bottom (value)
    const g2 = ctx.createLinearGradient(0,0,0,h);
    g2.addColorStop(0,"rgba(0,0,0,0)");
    g2.addColorStop(1,"rgba(0,0,0,1)");
    ctx.fillStyle = g2;
    ctx.fillRect(0,0,w,h);
  };

  const applyFromSV = (clientX, clientY) => {
    if (!(sv instanceof HTMLCanvasElement)) return;
    const r = sv.getBoundingClientRect();
    const x = clampNum((clientX - r.left) / r.width, 0, 1);
    const y = clampNum((clientY - r.top) / r.height, 0, 1);
    sat = x;
    val = 1 - y;
    const rgb2 = hsvToRgb(hue, sat, val);
    setHex(rgbToHex(rgb2.r, rgb2.g, rgb2.b));
  };

  drawSV();

  if (root){
    root.querySelectorAll("[data-cp]").forEach(btn => {
      btn.addEventListener("click", () => setHex(btn.getAttribute("data-cp") || "#000000"));
    });
  }

  hex?.addEventListener("input", () => setHex(hex.value || "#000000"));

  hueEl?.addEventListener("input", () => {
    hue = Number(hueEl.value) || 0;
    drawSV();
    const rgb2 = hsvToRgb(hue, sat, val);
    setHex(rgbToHex(rgb2.r, rgb2.g, rgb2.b));
  });

  if (sv){
    const onDown = (e) => {
      e.preventDefault();
      applyFromSV(e.clientX, e.clientY);
      const onMove = (ev) => applyFromSV(ev.clientX, ev.clientY);
      const onUp = () => {
        window.removeEventListener("pointermove", onMove);
        window.removeEventListener("pointerup", onUp);
      };
      window.addEventListener("pointermove", onMove);
      window.addEventListener("pointerup", onUp, { once:true });
    };
    sv.addEventListener("pointerdown", onDown);
  }

  return await new Promise((resolve) => {
    ok?.addEventListener("click", () => {
      closeModal();
      resolve(cur);
    }, { once:true });
    cancel?.addEventListener("click", () => {
      closeModal();
      resolve(null);
    }, { once:true });
  });
}

function slideMenuLayerPill(layer){
  const v = pct(layer, 1, 100);
  return `<span class="slide-layer-pill">Layer ${v}</span>`;
}

async function slideshowDeleteObject(objId){
  const slideId = slideshowSelectedId;
  if (!slideId || !objId) return;

  const objectRef = db.ref(`${slideshowDocPath(slideId)}/objects/${objId}`);
  const abortUploadPromise = abortFirebaseUploadsForSlideshowObject(slideId, objId);

  // If this is an audio object, stop and dispose its persistent player so it doesn't keep playing after delete.
  try{
    const doc = slideshowDocCache.get(slideId) || getActiveSlideshowDoc();
    const t = String(doc?.objects?.[objId]?.type || "");
    if (t === "audio"){
      const key = slideshowAudioKey(slideId, objId);
      const rec = slideshowAudioPlayers.get(key);
      if (rec){
        rec.uis.clear();
        rec.audio.pause();
        rec.audio.currentTime = 0;
        rec.audio.remove();
        slideshowAudioPlayers.delete(key);
      }
    }
  }catch{}

  // Optimistic local cache update first so uploading objects disappear immediately.
  const doc = slideshowDocCache.get(slideId);
  if (doc?.objects && Object.prototype.hasOwnProperty.call(doc.objects, objId)){
    try{ delete doc.objects[objId]; }catch{}
    slideshowDocCache.set(slideId, doc);
  }

  // If the deleted object was selected, fully clear selection + inspector/menu + handles
  if (slideshowSelectedObjId === objId){
    slideshowClearSelection();
  }

  // If stage is present, remove the element immediately (listener will re-render anyway)
  try{
    const stage = $("slideshow-stage");
    stage?.querySelector(`[data-obj-id="${CSS.escape(objId)}"]`)?.remove();
  }catch{}

  // Stop the active chunk upload and remove all Firebase data for the object.
  try{ await abortUploadPromise; }catch{}

  try{
    await objectRef.remove();
  }catch{}

  // Firebase writes already in flight cannot be canceled; remove once more after they settle.
  setTimeout(() => {
    try{ objectRef.remove(); }catch{}
  }, 750);
}

function buildSlideMenu(obj, mountEl){
  const menu = mountEl || $("slide-menu");
  if (!menu) return;
  menu.hidden = false;

  const objId = slideshowSelectedObjId;
  const type = String(obj.type || "");
  const layer = pct(obj.layer, 1, 100);
  const fontLabel = (fam) => String(fam || "").split(",")[0].trim().replace(/^["']|["']$/g, "");

  const layering = `
    <div class="slide-menu-row">
      <div class="slide-menu-label">Align</div>
      <div class="slide-menu-actions">
        <button class="btn tiny" type="button" data-action="centerX">Center X</button>
        <button class="btn tiny" type="button" data-action="centerY">Center Y</button>
        <button class="btn tiny" type="button" data-action="centerBoth">Center Both</button>
      </div>
    </div>
    <div class="slide-menu-row">
      <div class="slide-menu-label">Layer</div>
      <div class="slide-menu-actions">
        ${slideMenuLayerPill(layer)}
        <button class="btn tiny" type="button" data-layer="-1" ${layer<=1 ? "disabled" : ""}>Move Backward</button>
        <button class="btn tiny" type="button" data-layer="toBack" ${layer<=1 ? "disabled" : ""}>Go To Back</button>
        <button class="btn tiny" type="button" data-layer="+1" ${layer>=100 ? "disabled" : ""}>Move Forward</button>
        <button class="btn tiny" type="button" data-layer="toFront" ${layer>=100 ? "disabled" : ""}>Go To Front</button>
      </div>
    </div>
  `;

  const footer = `
    <div class="slide-menu-row slide-menu-row-end">
      <button class="btn danger tiny" type="button" data-action="delete">Delete</button>
    </div>
  `;

  const colorRow = (label, prop, val, disabled=false) => `
    <div class="slide-menu-row">
      <div class="slide-menu-label">${escapeHtml(label)}</div>
      <button class="color-btn" type="button" data-color-prop="${escapeHtml(prop)}" ${disabled ? "disabled" : ""}>
        <span class="color-swatch" style="background:${escapeHtml(normalizeHex6(val))}"></span>
        <span class="color-name">${escapeHtml(normalizeHex6(val))}</span>
      </button>
    </div>
  `;

  const strokeRow = (stroke, sizeDefault, colorDefault) => `
    <div class="slide-menu-row">
      <label class="slide-check">
        <input type="checkbox" data-prop="strokeOn" ${stroke.on ? "checked" : ""}/>
        <span>Stroke</span>
      </label>
      <input class="input slide-num" data-prop="strokeSize" value="${escapeHtml(String(stroke.size || sizeDefault))}" ${stroke.on ? "" : "disabled"} />
      <button class="color-btn" type="button" data-color-prop="strokeColor" ${stroke.on ? "" : "disabled"}>
        <span class="color-swatch" style="background:${escapeHtml(normalizeHex6(stroke.color || colorDefault))}"></span>
        <span class="color-name">${escapeHtml(normalizeHex6(stroke.color || colorDefault))}</span>
      </button>
    </div>
  `;

  if (type === "text"){
    const s = obj.style || {};
    const stroke = s.stroke || {};
    const fx = s.effects || {};

    menu.innerHTML = `
      <div class="slide-menu-card">
        <div class="slide-menu-row">
          <div class="slide-menu-label">Font</div>
          <div class="font-dd" data-font-dd>
            <button class="input font-dd-btn" type="button" data-font-dd-btn>${escapeHtml(fontLabel(s.font || SLIDESHOW_FONTS[0]))}</button>
            <div class="font-dd-pop" data-font-dd-pop hidden>
              ${SLIDESHOW_FONTS.map(f => `<button class="font-dd-opt" type="button" data-font="${escapeHtml(f)}">${escapeHtml(fontLabel(f))}</button>`).join("")}
            </div>
            <select class="input slide-select font-native" data-prop="font" tabindex="-1" aria-hidden="true">
              ${SLIDESHOW_FONTS.map(f => `<option value="${escapeHtml(f)}" ${String(s.font||"")===f ? "selected" : ""}>${escapeHtml(fontLabel(f))}</option>`).join("")}
            </select>
          </div>
        </div>

        <div class="slide-menu-row">
          <div class="slide-menu-label">URL</div>
          <input class="input slide-url" data-prop="url" value="${escapeHtml(String(obj.url || ""))}" placeholder="https://example.com" />
        </div>

        <div class="slide-menu-row">
          <div class="slide-menu-label">Size</div>
          <input class="input slide-num" data-prop="size" value="${escapeHtml(String(s.size || 40))}" />
        </div>

        ${colorRow("Color", "color", (s.color || "#000000"))}

        ${strokeRow(stroke, 2, "#000000")}

        <div class="slide-menu-row">
          <label class="slide-check">
            <input type="checkbox" data-prop="shadow" ${fx.shadow ? "checked" : ""}/>
            <span>Shadow</span>
          </label>
        </div>

        ${layering}
        ${footer}
      </div>
    `;
  } else {
    const s = obj.style || {};
    const stroke = s.stroke || {};

    const videoTools = type === "video" ? `
      <div class="slide-menu-row">
        <button class="btn tiny" type="button" data-action="playVideo">Play Video</button>
      </div>
    ` : "";

    // Single “color” control:
    // - shapes: Fill
    // - everything else: Stroke color (and checkbox controls whether it's on)
    if (type === "shape" || type === "audio"){
      menu.innerHTML = `
        <div class="slide-menu-card">
          ${colorRow("Fill", "fill", (s.fill || "#111827"))}
          ${strokeRow(stroke, 4, "#111827")}
          ${layering}
          ${footer}
        </div>
      `;
    } else {
      menu.innerHTML = `
        <div class="slide-menu-card">
          ${videoTools}
          ${strokeRow(stroke, 4, "#111827")}
          ${layering}
          ${footer}
        </div>
      `;
    }
  }

  menu.hidden = false;

  // Custom font dropdown (replaces native select UI)
  const fontDD = menu.querySelector("[data-font-dd]");
  if (fontDD){
    const btn = fontDD.querySelector("[data-font-dd-btn]");
    const pop = fontDD.querySelector("[data-font-dd-pop]");
    const sel = fontDD.querySelector('select[data-prop="font"]');

    // Portal state (so the menu renders like a real Chrome menu, not inside the editor scroll frame)
    let portalOpen = false;
    let popHomeParent = null;
    let popHomeNext = null;

    let cleanupScroll = null;
    let cleanupResize = null;

    const markSelected = () => {
      if (btn && sel) btn.textContent = fontLabel(sel.value || SLIDESHOW_FONTS[0]);
      if (!pop || !sel) return;
      pop.querySelectorAll(".font-dd-opt").forEach(b => {
        b.classList.toggle("is-selected", (b.getAttribute("data-font") || "") === String(sel.value || ""));
      });
    };

    const restorePopHome = () => {
      if (!pop || !popHomeParent) return;
      try{
        if (popHomeNext && popHomeNext.parentNode === popHomeParent) popHomeParent.insertBefore(pop, popHomeNext);
        else popHomeParent.appendChild(pop);
      }catch{}
      pop.classList.remove("portal");
      pop.style.left = "";
      pop.style.top = "";
      pop.style.width = "";
      pop.style.maxHeight = "";
    };

    const stopLiveRepositioning = () => {
      try{ cleanupScroll?.(); }catch{}
      try{ cleanupResize?.(); }catch{}
      cleanupScroll = null;
      cleanupResize = null;
    };

    const close = () => {
      if (pop) pop.hidden = true;
      fontDD.classList.remove("open");
      portalOpen = false;
      stopLiveRepositioning();
      restorePopHome();
    };

    const positionPortal = () => {
      if (!btn || !pop) return;

      const rect = btn.getBoundingClientRect();
      const gap = 6;

      // Match Chrome: dropdown is its own menu below the control, not merged into the input
      pop.style.width = Math.max(120, rect.width) + "px";
      pop.style.maxHeight = "204px"; // ~6 options, then scroll

      // First, place below
      let left = rect.left;
      let top = rect.bottom + gap;

      // Clamp horizontally
      const vw = window.innerWidth || document.documentElement.clientWidth || 0;
      const maxLeft = Math.max(0, vw - (parseFloat(pop.style.width) || rect.width));
      if (left > maxLeft) left = maxLeft;
      if (left < 0) left = 0;

      pop.style.left = left + "px";
      pop.style.top = top + "px";

      // If it would go off-screen at the bottom, flip above
      try{
        const pr = pop.getBoundingClientRect();
        const vh = window.innerHeight || document.documentElement.clientHeight || 0;
        if (pr.bottom > (vh - 8) && rect.top > pr.height + gap + 8){
          pop.style.top = (rect.top - pr.height - gap) + "px";
        }
      }catch{}
    };

    const open = () => {
      if (!pop) return;

      // Save where the popup lives so we can restore it later
      popHomeParent = pop.parentNode;
      popHomeNext = pop.nextSibling;

      // Move to body and use fixed positioning so it doesn't get trapped inside any scrolling pane
      try{ document.body.appendChild(pop); }catch{}
      pop.classList.add("portal");

      pop.hidden = false;
      fontDD.classList.add("open");
      portalOpen = true;

      markSelected();
      positionPortal();

      // Keep the selected item visible
      try{
        if (sel){
          const v = String(sel.value || "");
          const active = pop.querySelector(`[data-font="${CSS.escape(v)}"]`);
          active?.scrollIntoView({ block:"nearest" });
        }
      }catch{}

      // Close on outside click / Escape
      document.addEventListener("pointerdown", (e) => {
        const t = e.target;
        if (!(t instanceof Node)) return;

        // If click is outside the dropdown, ONLY close the dropdown (do not let the click hit anything else)
        if (!fontDD.contains(t) && !pop.contains(t)){
          e.preventDefault();
          e.stopPropagation();
          try{ e.stopImmediatePropagation(); }catch{}
          close();
        }
      }, { capture:true, once:true });

      window.addEventListener("keydown", (e) => {
        if (e.key === "Escape") close();
      }, { once:true });

      // If anything scrolls/resizes, reposition (like real menus)
      const onAnyScroll = () => {
        if (!portalOpen) return;
        positionPortal();
      };
      const onResize = () => {
        if (!portalOpen) return;
        positionPortal();
      };

      window.addEventListener("scroll", onAnyScroll, { passive:true, capture:true });
      cleanupScroll = () => window.removeEventListener("scroll", onAnyScroll, { capture:true });

      window.addEventListener("resize", onResize, { passive:true });
      cleanupResize = () => window.removeEventListener("resize", onResize);
    };

    btn?.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      if (!pop) return;
      if (!pop.hidden) close();
      else open();
    });

    pop?.addEventListener("click", (e) => {
      const t = e.target;
      if (!(t instanceof HTMLElement)) return;
      const font = t.getAttribute("data-font") || "";
      if (!font) return;
      e.preventDefault();
      e.stopPropagation();
      if (sel){
        sel.value = font;
        sel.dispatchEvent(new Event("change", { bubbles:true }));
      }
      markSelected();
      close();
    });

    if (sel) sel.addEventListener("change", markSelected);
    markSelected();
  }

  // Bind color buttons
  if (!slideColorPickerBound){
    slideColorPickerBound = true;
  }

  menu.querySelectorAll("[data-color-prop]").forEach(btn => {
    btn.addEventListener("click", async () => {
      const prop = btn.getAttribute("data-color-prop") || "";
      const doc = getActiveSlideshowDoc();
      const live = doc?.objects?.[objId] || null;
      if (!live) return;

      let current = "#000000";
      if (prop === "color") current = String(live.style?.color || "#000000");
      else if (prop === "strokeColor") current = String(live.style?.stroke?.color || "#111827");
      else if (prop === "fill") current = String(live.style?.fill || "#111827");

      const picked = await openCustomColorPicker({ value: current });
      if (!picked) return;

      const patch = {};
      const s2 = { ...(live.style || {}) };
      const stroke2 = { ...(s2.stroke || {}) };

      if (prop === "color"){
        s2.color = picked;
      } else if (prop === "fill"){
        s2.fill = picked;
      } else if (prop === "strokeColor"){
        stroke2.color = picked;
        s2.stroke = stroke2;
      }

      patch.style = s2;
      await slideshowUpdateObject(objId, patch);

      // UI updates
      const sw = btn.querySelector(".color-swatch");
      const nm = btn.querySelector(".color-name");
      if (sw) sw.style.background = normalizeHex6(picked);
      if (nm) nm.textContent = normalizeHex6(picked);
    });
  });

  // Object quick actions
  menu.querySelectorAll("[data-action]").forEach(btn => {
    btn.addEventListener("click", async () => {
      const action = btn.getAttribute("data-action") || "";
      if (action === "delete") await slideshowDeleteObject(objId);
      else if (action === "centerX") await slideshowAlignSelectedObject("x");
      else if (action === "centerY") await slideshowAlignSelectedObject("y");
      else if (action === "centerBoth") await slideshowAlignSelectedObject("both");
      else if (action === "playVideo"){
        const doc = getActiveSlideshowDoc();
        const live = doc?.objects?.[objId] || null;
        if (!live || String(live.type || "") !== "video") return;
        const videoSrc = readChunkedField(live, "src");
        if (!videoSrc) return;
        openMediaModal("video", videoSrc, {
          fileName: String(live.name || "Video"),
          mimeType: getMediaMimeType(live)
        });
      }
    });
  });

  // Layering buttons
  menu.querySelectorAll("[data-layer]").forEach(btn => {
    btn.addEventListener("click", async () => {
      const v = btn.getAttribute("data-layer") || "";
      const cur = pct(obj.layer, 1, 100);
      let next = cur;
      if (v === "toFront") next = 100;
      else if (v === "toBack") next = 1;
      else if (v === "+1") next = Math.min(100, cur + 1);
      else if (v === "-1") next = Math.max(1, cur - 1);
      await slideshowUpdateObject(objId, { layer: next });
    });
  });

  // Inputs
  menu.querySelectorAll("[data-prop]").forEach(el => {
    const prop = el.getAttribute("data-prop") || "";

    const apply = async () => {
      const doc = getActiveSlideshowDoc();
      const live = doc?.objects?.[objId] || null;
      if (!live) return;

      const patch = {};

      if (type === "text"){
        const s2 = { ...(live.style || {}) };
        const stroke2 = { ...(s2.stroke || {}) };
        const fx2 = { ...(s2.effects || {}) };

        if (prop === "url") patch.url = String(el.value || "").trim();

        if (prop === "font") s2.font = String(el.value || SLIDESHOW_FONTS[0]);
        if (prop === "size") s2.size = pct(parseFloat(el.value), 8, 200);

        if (prop === "strokeOn") stroke2.on = !!el.checked;
        if (prop === "strokeSize") stroke2.size = pct(parseFloat(el.value), 1, 16);

        if (prop === "shadow") fx2.shadow = !!el.checked;

        s2.stroke = stroke2;
        s2.effects = fx2;
        patch.style = s2;
      } else {
        const s2 = { ...(live.style || {}) };
        const stroke2 = { ...(s2.stroke || {}) };

        if (prop === "strokeOn") stroke2.on = !!el.checked;
        if (prop === "strokeSize") stroke2.size = pct(parseFloat(el.value), 1, 20);

        s2.stroke = stroke2;
        patch.style = s2;
      }

      await slideshowUpdateObject(objId, patch);
    };

    if (el instanceof HTMLSelectElement){
      el.addEventListener("change", apply);
    } else if (el instanceof HTMLInputElement && el.type === "checkbox"){
      el.addEventListener("change", apply);
    } else if (el instanceof HTMLInputElement){
      // Don't live-apply on every keystroke (it rebuilds the menu and kills typing).
      // Commit on blur/unselect or Enter.
      const commit = () => apply();
      el.addEventListener("change", commit);
      el.addEventListener("blur", commit);
      el.addEventListener("keydown", (e) => {
        e.stopPropagation();
        if (e.key === "Enter"){
          e.preventDefault();
          commit();
          el.blur();
        }
      });
      el.addEventListener("mousedown", (e) => e.stopPropagation());
      el.addEventListener("click", (e) => e.stopPropagation());
    } else {
      el.addEventListener("change", apply);
    }
  });

  // Enable/disable stroke inputs + stroke color button live
  const strokeToggle = menu.querySelector('input[type="checkbox"][data-prop="strokeOn"]');
  if (strokeToggle){
    strokeToggle.addEventListener("change", () => {
      const on = !!strokeToggle.checked;
      menu.querySelectorAll('[data-prop="strokeSize"]').forEach(x => x.toggleAttribute("disabled", !on));
      menu.querySelectorAll('[data-color-prop="strokeColor"]').forEach(x => x.toggleAttribute("disabled", !on));
    });
  }
}

/* -------------------- Drag/resize/rotate (basic) -------------------- */
const SLIDESHOW_CENTER_SNAP_PCT = 1.25;
const SLIDESHOW_NUDGE_STEP_PCT = 1;
const SLIDESHOW_NUDGE_BIG_STEP_PCT = 5;

let slideDragState = null;
let slideshowPickCycle = null;
let slideshowSuppressStageClick = false;

function getSelectedSlideshowObject(){
  const slideId = slideshowSelectedId;
  const objId = slideshowSelectedObjId;
  if (!slideId || !objId) return null;

  const doc = slideshowDocCache.get(slideId) || getActiveSlideshowDoc();
  const obj = doc?.objects?.[objId] || null;
  if (!obj) return null;

  return { slideId, objId, doc, obj };
}

function setSlideshowCenterGuides({ x=false, y=false } = {}){
  const xGuide = $("slideshow-center-guide-x");
  const yGuide = $("slideshow-center-guide-y");
  if (xGuide) xGuide.dataset.active = y ? "1" : "0";
  if (yGuide) yGuide.dataset.active = x ? "1" : "0";
}

function clearSlideshowGuides(){
  setSlideshowCenterGuides({ x:false, y:false });
}

function slideshowSnapMovePatch(x, y, w, h){
  let nx = Number(x) || 0;
  let ny = Number(y) || 0;

  const centerX = nx + (Number(w) || 0) / 2;
  const centerY = ny + (Number(h) || 0) / 2;
  const snapX = Math.abs(centerX - 50) <= SLIDESHOW_CENTER_SNAP_PCT;
  const snapY = Math.abs(centerY - 50) <= SLIDESHOW_CENTER_SNAP_PCT;

  if (snapX) nx = 50 - ((Number(w) || 0) / 2);
  if (snapY) ny = 50 - ((Number(h) || 0) / 2);

  setSlideshowCenterGuides({ x:snapX, y:snapY });
  return { x:nx, y:ny };
}

async function slideshowAlignSelectedObject(axis = "both"){
  const rec = getSelectedSlideshowObject();
  if (!rec){
    showToast({ title:"Select an object", body:"Pick a slideshow object first.", duration:2200 });
    return;
  }

  const w = pct(rec.obj.w, 1, 100);
  const h = pct(rec.obj.h, 1, 100);
  const patch = {};

  if (axis === "x" || axis === "both") patch.x = pct(50 - (w / 2), 0, Math.max(0, 100 - w));
  if (axis === "y" || axis === "both") patch.y = pct(50 - (h / 2), 0, Math.max(0, 100 - h));

  await slideshowUpdateObject(rec.objId, patch);
  setSlideshowCenterGuides({ x:patch.x != null, y:patch.y != null });
  setTimeout(clearSlideshowGuides, 700);
}

async function slideshowNudgeSelectedObject(dxPct = 0, dyPct = 0){
  const rec = getSelectedSlideshowObject();
  if (!rec) return;

  const w = pct(rec.obj.w, 1, 100);
  const h = pct(rec.obj.h, 1, 100);
  const x = pct((Number(rec.obj.x) || 0) + dxPct, 0, Math.max(0, 100 - w));
  const y = pct((Number(rec.obj.y) || 0) + dyPct, 0, Math.max(0, 100 - h));

  await slideshowUpdateObject(rec.objId, { x, y });
}

async function slideshowSetSelectedObjectLayer(mode){
  const rec = getSelectedSlideshowObject();
  if (!rec) return;

  let layer = pct(rec.obj.layer, 1, 100);
  if (mode === "front") layer = 100;
  else if (mode === "back") layer = 1;
  else if (mode === "forward") layer = Math.min(100, layer + 1);
  else if (mode === "backward") layer = Math.max(1, layer - 1);

  await slideshowUpdateObject(rec.objId, { layer });
}

function removeSlideHandles(){
  const box = $("slide-handles");
  if (box) box.remove();
}

function addSlideHandles(){
  removeSlideHandles();
  const stage = $("slideshow-stage");
  if (!stage || !slideshowSelectedObjId) return;

  const el = stage.querySelector(`[data-obj-id="${CSS.escape(slideshowSelectedObjId)}"]`);
  if (!el) return;

  const handles = document.createElement("div");
  handles.id = "slide-handles";
  handles.className = "slide-handles";
  el.appendChild(handles);

  handles.innerHTML = `
    <div class="slide-handle slide-handle-rotate" data-h="rotate"></div>
    <div class="slide-handle slide-handle-resize" data-h="resize"></div>
  `;

  handles.querySelectorAll("[data-h]").forEach(h => {
    h.addEventListener("pointerdown", (e) => startSlideTransform(e, h.getAttribute("data-h") || ""));
  });

  // Drag from object itself
  el.addEventListener("pointerdown", (e) => {
    if ((e.target instanceof HTMLElement) && e.target.closest(".slide-handle")) return;

    // Ctrl+Click on linked text should open the URL (handled on click), not start a drag.
    if ((e.ctrlKey || e.metaKey) && slideshowSelectedObjType === "text"){
      const doc = getActiveSlideshowDoc();
      const live = doc?.objects?.[slideshowSelectedObjId] || null;
      const u = normalizeSlideTextUrl(live?.url || "");
      if (u) return;
    }

    startSlideTransform(e, "move");
  });
}

function startSlideTransform(e, mode){
  if (!slideshowSelectedId || !slideshowSelectedObjId) return;
  const stage = $("slideshow-stage");
  if (!stage) return;

  const objId = String(slideshowSelectedObjId);
  const slideId = String(slideshowSelectedId);
  const doc = getActiveSlideshowDoc();
  const obj = doc?.objects?.[objId] || null;
  if (!obj) return;

  e.preventDefault();
  e.stopPropagation();

  const stageRect = stage.getBoundingClientRect();
  const el = stage.querySelector(`[data-obj-id="${CSS.escape(objId)}"]`);
  if (!el) return;
  const r = el.getBoundingClientRect();

  const startObj = {
    x: pct(obj.x, 0, 100),
    y: pct(obj.y, 0, 100),
    w: pct(obj.w, 1, 100),
    h: pct(obj.h, 1, 100),
    rot: Number(obj.rot || 0) || 0,
    type: String(obj.type || ""),
    shape: String(obj.shape || "")
  };

  const start = {
    mode,
    objId,
    slideId,
    pointerId: e.pointerId,
    startX: e.clientX,
    startY: e.clientY,
    stageW: Math.max(1, stageRect.width || 1),
    stageH: Math.max(1, stageRect.height || 1),
    obj: startObj,
    center: {
      x: (r.left - stageRect.left) + (r.width / 2),
      y: (r.top - stageRect.top) + (r.height / 2)
    }
  };
  slideDragState = start;

  try{ el.setPointerCapture(e.pointerId); }catch{}

  el.style.willChange = "transform, left, top, width, height";
  el.style.touchAction = "none";

  let menuRaf = 0;
  let didDrag = false;
  let pending = null;
  let latestPatch = null;
  let tx = 0;
  let ty = 0;

  const clampMovePatch = (x, y, w = startObj.w, h = startObj.h) => {
    const cw = pct(w, 0, 100);
    const ch = pct(h, 0, 100);
    const snapped = slideshowSnapMovePatch(x, y, cw, ch);
    return {
      x: pct(snapped.x, 0, Math.max(0, 100 - cw)),
      y: pct(snapped.y, 0, Math.max(0, 100 - ch))
    };
  };

  const clampResizePatch = (w, h) => {
    const x0 = pct(startObj.x, 0, 100);
    const y0 = pct(startObj.y, 0, 100);
    let nextW = pct(w, 1, Math.max(1, 100 - x0));
    let nextH = pct(h, 1, Math.max(1, 100 - y0));

    if (startObj.type === "shape" && startObj.shape === "circle"){
      const s = Math.min(Math.max(nextW, nextH), Math.max(1, 100 - x0), Math.max(1, 100 - y0));
      nextW = s;
      nextH = s;
    }

    return { w: nextW, h: nextH };
  };

  const setTransform = (txPx, tyPx, rotDeg) => {
    const hasT = Math.abs(txPx) > 0.01 || Math.abs(tyPx) > 0.01;
    el.style.transform = hasT
      ? `translate3d(${txPx}px, ${tyPx}px, 0) rotate(${rotDeg}deg)`
      : `rotate(${rotDeg}deg)`;
  };

  const applyLocal = (patch) => {
    if (patch.x != null) el.style.left = `${patch.x}%`;
    if (patch.y != null) el.style.top = `${patch.y}%`;
    if (patch.w != null) el.style.width = `${patch.w}%`;
    if (patch.h != null) el.style.height = `${patch.h}%`;

    const rot = (patch.rot != null) ? patch.rot : startObj.rot;
    setTransform(0, 0, rot);
  };

  const scheduleMenu = () => {
    if (menuRaf) return;
    menuRaf = requestAnimationFrame(() => {
      menuRaf = 0;
      positionSlideMenu();
    });
  };

  const flushSend = () => {
    if (!pending) return;

    const patch = pending;
    pending = null;
    slideshowUpdateObject(objId, patch);
  };

  const scheduleSend = () => {
    // Keep dragging perfectly local; commit to Firebase only on pointer release.
  };

  const onMove = (ev) => {
    if (!slideDragState || slideDragState.objId !== objId) return;

    const dx = ev.clientX - start.startX;
    const dy = ev.clientY - start.startY;

    if (!didDrag && (Math.abs(dx) > 2 || Math.abs(dy) > 2)) didDrag = true;

    if (mode === "move"){
      const nx = startObj.x + (dx / start.stageW) * 100;
      const ny = startObj.y + (dy / start.stageH) * 100;
      const patch = clampMovePatch(nx, ny, startObj.w, startObj.h);

      tx = ((patch.x - startObj.x) / 100) * start.stageW;
      ty = ((patch.y - startObj.y) / 100) * start.stageH;

      latestPatch = patch;
      pending = patch;
      applyLocal(patch);
      scheduleSend();
    } else if (mode === "resize"){
      const nw = startObj.w + (dx / start.stageW) * 100;
      const nh = startObj.h + (dy / start.stageH) * 100;
      const patch = clampResizePatch(nw, nh);

      latestPatch = patch;
      pending = patch;
      applyLocal(patch);
      scheduleSend();
    } else if (mode === "rotate"){
      const sr = stage.getBoundingClientRect();
      const cx = sr.left + start.center.x;
      const cy = sr.top + start.center.y;
      const a0 = Math.atan2(start.startY - cy, start.startX - cx);
      const a1 = Math.atan2(ev.clientY - cy, ev.clientX - cx);
      const patch = { rot: startObj.rot + ((a1 - a0) * 180 / Math.PI) };

      latestPatch = patch;
      pending = patch;
      applyLocal(patch);
      scheduleSend();
    }

    scheduleMenu();
  };

  const onUp = () => {
    clearSlideshowGuides();
    window.removeEventListener("pointermove", onMove);
    window.removeEventListener("pointerup", onUp);
    window.removeEventListener("pointercancel", onUp);

    if (menuRaf){ cancelAnimationFrame(menuRaf); menuRaf = 0; }
    if (didDrag) slideshowSuppressStageClick = true;

    if (mode === "move" && latestPatch){
      el.style.left = `${latestPatch.x}%`;
      el.style.top = `${latestPatch.y}%`;
      tx = 0;
      ty = 0;
      setTransform(0, 0, startObj.rot);
    }

    flushSend(true);

    el.style.willChange = "";
    slideDragState = null;
    renderSlideshowRemoteSelections();

    if (slideshowDeferredRender && slideshowDeferredSlideId === slideshowSelectedId){
      slideshowDeferredRender = false;
      slideshowDeferredSlideId = null;
      const sid = slideshowSelectedId;
      const doc2 = getActiveSlideshowDoc();
      if (sid && doc2){
        requestAnimationFrame(() => renderSlideshowStage(sid, doc2));
      }
    }
  };

  window.addEventListener("pointermove", onMove);
  window.addEventListener("pointerup", onUp, { once:true });
  window.addEventListener("pointercancel", onUp, { once:true });
}

/* -------------------- Slideshow composer actions -------------------- */
function slideshowApplyTextFromComposer(){
  if (!slideshowSelectedId) return;
  if (!slideshowSelectedObjId) return;
  if (slideshowSelectedObjType !== "text") return;

  const input = $("msg-input");
  const next = (input?.value || "");
  slideshowUpdateObject(slideshowSelectedObjId, { text: next });
}

/* -------------------- Slideshow toolbar popups -------------------- */
function openShapePicker(){
  openModal({
    title: "Insert shape",
    bodyHTML: `
      <div class="stack">
        <div class="muted">Choose a shape</div>
        <div class="shape-grid">
          <button class="btn tiny" id="shape-rect" type="button">Rectangle</button>
          <button class="btn tiny" id="shape-rounded" type="button">Rounded</button>
          <button class="btn tiny" id="shape-circle" type="button">Circle</button>
          <button class="btn tiny" id="shape-ellipse" type="button">Ellipse</button>
          <button class="btn tiny" id="shape-triangle" type="button">Triangle</button>
          <button class="btn tiny" id="shape-diamond" type="button">Diamond</button>
          <button class="btn tiny" id="shape-star" type="button">Star</button>
          <button class="btn tiny" id="shape-arrow" type="button">Arrow</button>
          <button class="btn tiny" id="shape-line" type="button">Line</button>

          <button class="btn tiny" id="shape-heart" type="button">Heart</button>
          <button class="btn tiny" id="shape-pentagon" type="button">Pentagon</button>
          <button class="btn tiny" id="shape-hexagon" type="button">Hexagon</button>
        </div>
      </div>
    `
  });

  const wire = (id, kind) => {
    $(id)?.addEventListener("click", () => {
      closeModal();
      slideshowAddShape(kind);
    }, { once:true });
  };

  wire("shape-rect", "rect");
  wire("shape-rounded", "rounded");
  wire("shape-circle", "circle");
  wire("shape-ellipse", "ellipse");
  wire("shape-triangle", "triangle");
  wire("shape-diamond", "diamond");
  wire("shape-star", "star");
  wire("shape-arrow", "arrow");
  wire("shape-line", "line");

  wire("shape-heart", "heart");
  wire("shape-pentagon", "pentagon");
  wire("shape-hexagon", "hexagon");
}

function openBackgroundPicker(){
  const doc = getActiveSlideshowDoc();
  const curBg = doc?.bg || null;

  let solid = normalizeHex6(curBg?.type === "solid" ? (curBg.color || "#ffffff") : "#ffffff");

  openModal({
    title: "Background",
    bodyHTML: `
      <div class="stack">
        <div class="row bg-row">
          <div class="muted">Solid</div>
          <button class="color-btn" id="bg-solid-pick" type="button">
            <span class="color-swatch" id="bg-solid-swatch" style="background:${escapeHtml(solid)}"></span>
            <span class="color-name" id="bg-solid-name">${escapeHtml(solid)}</span>
          </button>
          <button class="btn tiny" id="bg-apply-solid" type="button">Apply</button>
        </div>

        <div class="row bg-row">
          <div class="muted">Image / GIF</div>
          <button class="btn tiny" id="bg-pick-file" type="button">Upload</button>
          <button class="btn tiny" id="bg-clear" type="button">Clear</button>
        </div>
      </div>
    `
  });

  const solidPick = $("bg-solid-pick");

  // IMPORTANT: Apply immediately when the color picker "Apply" is clicked
  // (because the color picker uses the same modal system and replaces this modal)
  solidPick?.addEventListener("click", async () => {
    const picked = await openCustomColorPicker({ value: solid, title: "Pick color" });
    if (!picked) return;

    solid = normalizeHex6(picked);
    await slideshowSetBackground({ type:"solid", color: solid });

    // Re-open so the user sees the updated value instantly
    openBackgroundPicker();
  });

  $("bg-apply-solid")?.addEventListener("click", async () => {
    await slideshowSetBackground({ type:"solid", color: solid });
    closeModal();
  }, { once:true });

  $("bg-clear")?.addEventListener("click", async () => {
    await slideshowSetBackground({ type:"solid", color:"#ffffff" });
    closeModal();
  }, { once:true });

  $("bg-pick-file")?.addEventListener("click", () => {
    slideshowFilePickMode = "bg";
    const fi = $("file-input");
    if (fi){
      fi.accept = "image/*,image/gif";
      fi.value = "";
      fi.click();
    }
    closeModal();
  }, { once:true });
}

function slideshowCanEnterReorderMode(){
  if (!document.body.classList.contains("slideshow-full")) return false;
  if (slideshowReorderMode) return false;

  // Reorder Mode must NOT work while adding a title/divider (insert modes) or editing a title.
  if (slideshowDividerInsertMode || slideshowTitleInsertMode) return false;
  if (slideshowEditingTitleBeforeId) return false;

  return Array.isArray(slideshowOrder) && slideshowOrder.length > 1;
}

function slideshowEnterReorderMode(){
  if (!slideshowCanEnterReorderMode()) return;

  // Snapshot current disabled state so Cancel can restore it exactly.
  slideshowReorderPrevTitleDisabled = !!$("slideshow-add-title")?.disabled;
  slideshowReorderPrevDividerDisabled = !!$("slideshow-add-divider")?.disabled;

  slideshowReorderMode = true;
  slideshowReorderDragId = null;
  scheduleRenderSlideshowUI();
  showToast("Reorder mode: drag slides to rearrange.");
}

function slideshowCancelReorderMode(){
  if (!slideshowReorderMode) return;
  slideshowReorderMode = false;
  slideshowReorderDragId = null;

  // Restore Title/Divider buttons to the exact state from before reorder mode was activated.
  slideshowReorderRestoreButtonsOnce = true;
  scheduleRenderSlideshowUI();
}

function slideshowReorderStopAutoScroll(){
  slideshowReorderAutoScrollEl = null;
  slideshowReorderAutoScrollDir = 0;
  if (slideshowReorderAutoScrollRaf){
    cancelAnimationFrame(slideshowReorderAutoScrollRaf);
    slideshowReorderAutoScrollRaf = null;
  }
}

function slideshowReorderEnsureAutoScroll(el, dir){
  if (!el || !dir){
    slideshowReorderStopAutoScroll();
    return;
  }
  slideshowReorderAutoScrollEl = el;
  slideshowReorderAutoScrollDir = dir;

  if (slideshowReorderAutoScrollRaf) return;
  const step = () => {
    const container = slideshowReorderAutoScrollEl;
    if (!container || !slideshowReorderAutoScrollDir){
      slideshowReorderStopAutoScroll();
      return;
    }
    container.scrollTop += slideshowReorderAutoScrollDir * 14;
    slideshowReorderAutoScrollRaf = requestAnimationFrame(step);
  };
  slideshowReorderAutoScrollRaf = requestAnimationFrame(step);
}

function slideshowReorderMaybeAutoScrollFromEvent(e){
  if (!slideshowReorderMode) return;
  const el = $("slideshow-thumbs");
  if (!el) return;

  const rect = el.getBoundingClientRect();
  const y = Number(e?.clientY) || 0;
  const edge = 44;

  let dir = 0;
  if (y && y < rect.top + edge) dir = -1;
  else if (y && y > rect.bottom - edge) dir = 1;

  slideshowReorderEnsureAutoScroll(el, dir);
}

async function slideshowPersistOrder(oldOrder, newOrder){
  if (!currentUser) return;

  const prev = Array.isArray(oldOrder) ? oldOrder.map(x => String(x || "")) : [];
  const ids = Array.isArray(newOrder) ? newOrder.map(x => String(x || "")) : [];
  if (!ids.length) return;

  const updates = {};
  ids.forEach((id, idx) => {
    if (!id) return;
    updates[`slideshow/slides/${id}/order`] = idx + 1;
  });

  // Keep titles/dividers fixed in their visual positions:
  // They are keyed by the slideId they appear "before", so when we reorder slides we must
  // re-key these records by index (old index -> new slideId at that index).
  try{
    const [divSnap, titleSnap] = await Promise.all([
      db.ref("slideshow/dividers").once("value"),
      db.ref("slideshow/titles").once("value")
    ]);

    const divs = divSnap.exists() ? (divSnap.val() || {}) : {};
    const titles = titleSnap.exists() ? (titleSnap.val() || {}) : {};

    const divMoves = [];
    for (const [beforeId, rec] of Object.entries(divs)){
      const from = String(beforeId || "");
      const idx = prev.indexOf(from);
      if (idx < 0) continue;
      const to = ids[idx] || "";
      if (!to || to === from) continue;
      divMoves.push({ from, to, rec });
    }
    // Null out old keys first, then write new keys so swaps don't wipe each other out.
    for (const m of divMoves){
      updates[`slideshow/dividers/${m.from}`] = null;
    }
    for (const m of divMoves){
      updates[`slideshow/dividers/${m.to}`] = m.rec;
    }

    const titleMoves = [];
    for (const [beforeId, rec] of Object.entries(titles)){
      const from = String(beforeId || "");
      const idx = prev.indexOf(from);
      if (idx < 0) continue;
      const to = ids[idx] || "";
      if (!to || to === from) continue;
      titleMoves.push({ from, to, rec });
    }
    for (const m of titleMoves){
      updates[`slideshow/titles/${m.from}`] = null;
    }
    for (const m of titleMoves){
      updates[`slideshow/titles/${m.to}`] = m.rec;
    }
  }catch{
    // If we can't read titles/dividers for some reason, still persist slide order.
  }

  // Optimistic cache so "Add Slide" gets the right next order immediately.
  slideshowOrderMap = new Map(ids.map((id, idx) => [id, idx + 1]));
  slideshowMaxOrder = ids.length;

  try{
    await db.ref().update(updates);
  }catch{}
}

function slideshowMoveSlide(fromId, toId, pos = "before"){
  fromId = String(fromId || "");
  toId = String(toId || "");
  if (!fromId || !toId || fromId === toId) return;

  const order = Array.isArray(slideshowOrder) ? slideshowOrder.slice() : [];
  const prevOrder = order.slice();
  const fromIdx = order.indexOf(fromId);
  const toIdx = order.indexOf(toId);
  if (fromIdx < 0 || toIdx < 0) return;

  order.splice(fromIdx, 1);

  let insertIdx = order.indexOf(toId);
  if (insertIdx < 0) return;
  if (pos === "after") insertIdx += 1;

  order.splice(insertIdx, 0, fromId);

  slideshowOrder = order;
  slideshowThumbsSig = "";
  scheduleRenderSlideshowUI();
  slideshowPersistOrder(prevOrder, order);
}

/* -------------------- Slideshow UI (perf) -------------------- */
let slideshowShellMounted = false;
let slideshowThumbsSig = "";
let slideshowEventsBound = false;

function ensureSlideshowShell(){
  if (slideshowShellMounted && $("slideshow-page")) return;

  messagesListEl.innerHTML = `
    <div class="slideshow-page" id="slideshow-page">
      <div class="slideshow-grid">
        <div class="slideshow-canvas-wrap">
          <div class="slideshow-canvas" id="slideshow-canvas">
            <div class="slideshow-canvas-inner" id="slideshow-canvas-inner">
              <div class="slideshow-center-guide slideshow-center-guide-x" id="slideshow-center-guide-x" aria-hidden="true"></div>
              <div class="slideshow-center-guide slideshow-center-guide-y" id="slideshow-center-guide-y" aria-hidden="true"></div>
              <div class="slideshow-stage" id="slideshow-stage"></div>
              <div class="slide-menu" id="slide-menu" hidden></div>
            </div>
            <div class="slideshow-empty" id="slideshow-empty" hidden>
              <div class="slideshow-empty-title" id="slideshow-empty-title"></div>
              <div class="slideshow-empty-sub" id="slideshow-empty-sub"></div>
            </div>
          </div>
        </div>

        <div class="slideshow-side" id="slideshow-side">
          <div class="slideshow-side-topbar" id="slideshow-side-topbar"></div>
          <div class="slideshow-side-head" id="slideshow-side-head">
            <button class="btn tiny" id="slideshow-add-title" type="button">Add Title</button>
            <button class="btn tiny" id="slideshow-add-divider" type="button">Add Divider</button>
            <button class="btn tiny" id="slideshow-reorder" type="button">Reorder</button>
            <button class="btn tiny" id="slideshow-back" type="button">Back</button>
          </div>

          <!-- Object inspector overlays the picker when an object is selected -->
          <div class="slideshow-inspector" id="slideshow-inspector" hidden></div>

          <div class="slideshow-thumbs" id="slideshow-thumbs" data-reorder="0"></div>

          <div class="slideshow-actions">
            <button class="btn" id="slideshow-add" type="button">Add Slide</button>
            <button class="btn danger" id="slideshow-del" type="button">Delete Slide</button>
          </div>
        </div>
      </div>
    </div>
  `;

  slideshowShellMounted = true;
  slideshowThumbsSig = "";

  const thumbsEl = $("slideshow-thumbs");
  if (thumbsEl && thumbsEl.dataset.boundScroll !== "1"){
    thumbsEl.dataset.boundScroll = "1";
    thumbsEl.addEventListener("scroll", () => { slideshowThumbsScrollTop = thumbsEl.scrollTop; }, { passive:true });
  }

  bindSlideshowUIEventsOnce();
  bindSlideshowStageEventsOnce();
}

function bindSlideshowUIEventsOnce(){
  if (slideshowEventsBound) return;
  slideshowEventsBound = true;

  const clearHold = () => {
    if (slideshowReorderHoldTimer) clearTimeout(slideshowReorderHoldTimer);
    slideshowReorderHoldTimer = null;
    slideshowReorderHoldSlideId = null;
    slideshowReorderHoldStart = null;
  };

  // Global safety: if the pointer-up happens outside the thumbs, still clear long-press timers.
  window.addEventListener("pointerup", () => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    clearHold();
  }, { passive:true });

  // One delegated handler for the entire slideshow UI
  messagesListEl.addEventListener("pointerdown", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    if ("button" in e && e.button !== 0) return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;

    const back = t.closest("#slideshow-back");
    if (back){
      stopAllSlideshowAudio();
      if (slideshowReorderMode) slideshowCancelReorderMode();
      else showLoggedInHome();
      return;
    }

    const reorder = t.closest("#slideshow-reorder");
    if (reorder){
      if (slideshowReorderMode) slideshowCancelReorderMode();
      else slideshowEnterReorderMode();
      return;
    }

    const addTitle = t.closest("#slideshow-add-title");
    if (addTitle){ slideshowAddTitleInstant(); return; }

    const addDiv = t.closest("#slideshow-add-divider");
    if (addDiv){ slideshowAddDividerInstant(); return; }

    const add = t.closest("#slideshow-add");
    if (add){ slideshowAddSlide(); return; }

    const del = t.closest("#slideshow-del");
    if (del){ slideshowDeleteSelectedSlide(); return; }

    const dividerDrop = t.closest("[data-divider-drop]");
    if (dividerDrop){
      e.preventDefault(); e.stopPropagation();
      const pos = dividerDrop.getAttribute("data-divider-drop") || "";
      const id = dividerDrop.getAttribute("data-divider-slide-id") || "";
      void (async () => { await slideshowAddDividerAt(id, pos); })();
      return;
    }

    const titleDrop = t.closest("[data-title-drop]");
    if (titleDrop){
      e.preventDefault(); e.stopPropagation();
      const beforeId = titleDrop.getAttribute("data-title-slide-id") || "";
      if (!beforeId) return;
      void (async () => {
        await ensureSlideshowTitle(beforeId);
        slideshowStartEditingTitle(beforeId);
      })();
      return;
    }

    const dividerDel = t.closest("[data-divider-del]");
    if (dividerDel){
      e.preventDefault(); e.stopPropagation();
      const beforeId = dividerDel.getAttribute("data-divider-del") || "";
      void (async () => { await slideshowDeleteDivider(beforeId); })();
      return;
    }

    const titleDel = t.closest("[data-title-del]");
    if (titleDel){
      e.preventDefault(); e.stopPropagation();
      const beforeId = titleDel.getAttribute("data-title-del") || "";
      if (!beforeId) return;
      markSlideshowTitleDeleted(beforeId);
      void (async () => { await slideshowDeleteTitle(beforeId); })();
      return;
    }

    if (t.closest(".slideshow-title-input")) return;

    const titleEdit = t.closest("[data-title-edit]");
    if (titleEdit){
      e.preventDefault(); e.stopPropagation();
      const beforeId = titleEdit.getAttribute("data-title-edit") || "";
      if (!beforeId) return;
      void (async () => {
        await ensureSlideshowTitle(beforeId);
        slideshowStartEditingTitle(beforeId);
      })();
      return;
    }

    const titleWrap = t.closest(".slideshow-title-wrap");
    if (titleWrap){
      e.preventDefault(); e.stopPropagation();
      const beforeId = titleWrap.getAttribute("data-title-before") || "";
      if (!beforeId) return;

      // Clicking inside the currently-open editor should NOT close it.
      if (slideshowEditingTitleBeforeId === beforeId){
        slideshowSelectedTitleBeforeId = beforeId;
        return;
      }

      // If already selected, a second click enters edit mode.
      if (slideshowSelectedTitleBeforeId === beforeId){
        void (async () => {
          await ensureSlideshowTitle(beforeId);
          slideshowStartEditingTitle(beforeId);
        })();
        return;
      }

      // Single click selects (does not force input focus).
      slideshowSelectedDividerBeforeId = null;
      slideshowSelectedTitleBeforeId = beforeId;
      slideshowEditingTitleBeforeId = null;
      slideshowTitleInsertMode = false;
      scheduleRenderSlideshowUI();
      return;
    }

    const dividerWrap = t.closest(".slideshow-divider-wrap");
    if (dividerWrap){
      e.preventDefault(); e.stopPropagation();
      const beforeId = dividerWrap.getAttribute("data-divider-before") || "";
      if (!beforeId) return;

      // If we are placing a title, clicking a divider creates/edits the title directly beneath it
      if (slideshowTitleInsertMode){
        void (async () => {
          await ensureSlideshowTitle(beforeId);
          slideshowStartEditingTitle(beforeId);
        })();
        return;
      }

      // Toggle divider selection (shows/hides tooltip)
      slideshowSelectedDividerBeforeId = (slideshowSelectedDividerBeforeId === beforeId) ? null : beforeId;
      scheduleRenderSlideshowUI();
      return;
    }

    const slideBtn = t.closest("[data-slide-id]");
    if (slideBtn){
      if (slideshowReorderMode) return;
      const id = slideBtn.getAttribute("data-slide-id") || "";
      if ((id || null) !== slideshowSelectedId) stopAllSlideshowAudio();
      slideshowSelectedId = id || null;
      slideshowClearSelection({ quiet:true });
      setMySlideshowLocation(slideshowSelectedId);
      scheduleRenderSlideshowUI();
      return;
    }
  });

  // Delegated Title input behaviors (escape + commit on click-away)

  messagesListEl.addEventListener("keydown", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    if (!t.matches || !t.matches("[data-title-input]")) return;
    if (e.key !== "Escape") return;
    const beforeId = t.getAttribute("data-title-input") || "";
    e.preventDefault();
    if (beforeId) slideshowSelectedTitleBeforeId = beforeId;
    slideshowEditingTitleBeforeId = null;
    scheduleRenderSlideshowUI();
  });

  // focusout bubbles (unlike blur), so delegation works
  messagesListEl.addEventListener("focusout", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    if (!t.matches || !t.matches("[data-title-input]")) return;

    const beforeId = t.getAttribute("data-title-input") || "";
    if (!beforeId) return;

    const rt = e.relatedTarget;
    if (rt && rt instanceof HTMLElement){
      const sameTitle = rt.closest(`.slideshow-title-wrap[data-title-before="${CSS.escape(beforeId)}"]`);
      const sameDel = rt.closest(`[data-title-del="${CSS.escape(beforeId)}"]`);
      const sameEdit = rt.closest(`[data-title-edit="${CSS.escape(beforeId)}"]`);
      if (sameTitle || sameDel || sameEdit) return;
    }

    if (!isSlideshowTitleDeleteGuarded(beforeId)){
      void saveSlideshowTitleNow(beforeId, t.value);
    }

    // Exit edit mode but keep (or transfer) selection so Delete/Edit stays available.
    if (!slideshowSelectedTitleBeforeId || slideshowSelectedTitleBeforeId === beforeId){
      slideshowSelectedTitleBeforeId = beforeId;
    }
    if (slideshowEditingTitleBeforeId){
      slideshowEditingTitleBeforeId = null;
      scheduleRenderSlideshowUI();
    }
  }, true);

  // Drag/drop for explicit Reorder Mode only.
  messagesListEl.addEventListener("dragstart", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    const btn = t.closest?.(".slideshow-thumb[data-slide-id]");
    if (!btn) return;

    if (!slideshowReorderMode) { e.preventDefault(); return; }
    const id = btn.getAttribute("data-slide-id") || "";
    if (!id) { e.preventDefault(); return; }

    slideshowReorderDragId = id;
    btn.classList.add("is-dragging");
    try{
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", id);
    }catch{}
  });

  messagesListEl.addEventListener("dragend", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (t instanceof HTMLElement){
      const btn = t.closest?.(".slideshow-thumb[data-slide-id]");
      if (btn) btn.classList.remove("is-dragging");
    }
    slideshowReorderDragId = null;
    slideshowReorderStopAutoScroll();
    const thumbs = $("slideshow-thumbs");
    if (thumbs) thumbs.querySelectorAll(".slideshow-thumb.is-drag-over, .slideshow-thumb.is-drop-before, .slideshow-thumb.is-drop-after").forEach(x => x.classList.remove("is-drag-over", "is-drop-before", "is-drop-after"));
  });

  messagesListEl.addEventListener("dragover", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    const btn = t.closest?.(".slideshow-thumb[data-slide-id]");
    if (!btn || !slideshowReorderMode) return;

    e.preventDefault();
    slideshowReorderMaybeAutoScrollFromEvent(e);

    const thumbs = $("slideshow-thumbs");
    if (thumbs) thumbs.querySelectorAll(".slideshow-thumb.is-drag-over, .slideshow-thumb.is-drop-before, .slideshow-thumb.is-drop-after").forEach(x => {
      if (x !== btn) x.classList.remove("is-drag-over", "is-drop-before", "is-drop-after");
    });

    const r = btn.getBoundingClientRect();
    const before = e.clientY < (r.top + r.height / 2);
    btn.classList.add("is-drag-over");
    btn.classList.toggle("is-drop-before", before);
    btn.classList.toggle("is-drop-after", !before);
    try{ e.dataTransfer.dropEffect = "move"; }catch{}
  });

  messagesListEl.addEventListener("dragleave", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    const btn = t.closest?.(".slideshow-thumb[data-slide-id]");
    if (!btn) return;
    btn.classList.remove("is-drag-over", "is-drop-before", "is-drop-after");
  });

  messagesListEl.addEventListener("drop", (e) => {
    if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    const btn = t.closest?.(".slideshow-thumb[data-slide-id]");
    if (!btn || !slideshowReorderMode) return;

    e.preventDefault();
    slideshowReorderStopAutoScroll();

    const targetId = btn.getAttribute("data-slide-id") || "";
    const fromId = slideshowReorderDragId || (() => {
      try{ return e.dataTransfer.getData("text/plain"); }catch{ return ""; }
    })();

    const r = btn.getBoundingClientRect();
    const before = e.clientY < (r.top + r.height / 2);

    btn.classList.remove("is-drag-over", "is-drop-before", "is-drop-after");
    slideshowMoveSlide(fromId, targetId, before ? "before" : "after");
  });
}

function bindSlideshowStageEventsOnce(){
  const stage = $("slideshow-stage");
  const canvas = $("slideshow-canvas");
  if (!stage || stage.dataset.bound === "1") return;
  stage.dataset.bound = "1";

  stage.addEventListener("contextmenu", (e) => e.preventDefault());

  const clearObjectSelectionOnEmptyCanvas = (e) => {
    const t = e.target;
    if (!(t instanceof HTMLElement)) return;
    if (t.closest(".slide-obj") || t.closest(".slide-menu") || t.closest(".slideshow-inspector")) return;
    slideshowPickCycle = null;
    if (slideshowSelectedObjId) slideshowClearSelection();
  };

  // Prevent browser drag-to-select (blue highlight) on the slideshow canvas.
  stage.addEventListener("pointerdown", (e) => {
    if ((e.target instanceof HTMLElement) && e.target.closest(".slide-obj")) return;
    clearObjectSelectionOnEmptyCanvas(e);
    e.preventDefault();
  }, { passive:false });

  if (canvas && canvas.dataset.emptyClickBound !== "1"){
    canvas.dataset.emptyClickBound = "1";
    canvas.addEventListener("pointerdown", clearObjectSelectionOnEmptyCanvas, { passive:true });
  }

  stage.addEventListener("click", (e) => {
    const x = e.clientX;
    const y = e.clientY;

    // Ignore the synthetic click that fires after a drag move.
    if (slideshowSuppressStageClick){
      slideshowSuppressStageClick = false;
      return;
    }

    // Manual hit-test so overlapping objects can be cycled by repeated clicks.
    const stack = (typeof document.elementsFromPoint === "function") ? document.elementsFromPoint(x, y) : [];
    const hits = [];
    for (const el of stack){
      if (!(el instanceof HTMLElement)) continue;
      const objEl = el.closest(".slide-obj");
      if (!objEl || !stage.contains(objEl)) continue;
      const id = objEl.getAttribute("data-obj-id") || "";
      if (!id || hits.includes(id)) continue;
      hits.push(id);
    }

    // Sort by the slide's logical layering (NOT DOM z-index), so cycling works with >2 overlaps
    // even though the selected element gets a temporary z-index bump.
    const __doc = getActiveSlideshowDoc();
    const __layerOf = (id) => {
      const o = __doc?.objects?.[id] || null;
      const z = Number(o?.layer ?? o?.z ?? o?.zIndex ?? 0);
      return Number.isFinite(z) ? z : 0;
    };
    hits.sort((a,b) => (__layerOf(b) - __layerOf(a)) || String(a).localeCompare(String(b)));

    if (!hits.length){
      slideshowPickCycle = null;
      slideshowClearSelection();
      return;
    }

    // If the click is basically at the same spot and the hit stack is the same, cycle down the stack.
    const sameSpot = slideshowPickCycle
      && Math.abs((slideshowPickCycle.x || 0) - x) <= 4
      && Math.abs((slideshowPickCycle.y || 0) - y) <= 4;
    const sameStack = sameSpot
      && Array.isArray(slideshowPickCycle.ids)
      && slideshowPickCycle.ids.length === hits.length
      && slideshowPickCycle.ids.every((v, i) => v === hits[i]);

    let idx = 0;
    if (sameStack){
      idx = (Number(slideshowPickCycle.idx) + 1) % hits.length;
    } else if (hits.length > 1 && slideshowSelectedObjId && hits.includes(slideshowSelectedObjId)){
      // If the currently-selected object is in the hit stack, advance one step immediately.
      // (Prevents "selected z-index bump" from eating the click and supports >2 overlaps.)
      const selIdx = hits.indexOf(slideshowSelectedObjId);
      idx = (selIdx >= 0) ? ((selIdx + 1) % hits.length) : 0;
    }
    const objId = hits[idx];
    const objType = stage.querySelector(`[data-obj-id="${CSS.escape(objId)}"]`)?.getAttribute("data-obj-type") || "";

    slideshowPickCycle = { x, y, ids: hits, idx };
    slideshowSetSelectedObject(objId, objType);
  });
}

function renderSlideshowThumbsInto(thumbsEl, { hasSlides, selected }){
  if (!thumbsEl) return;
  if (!hasSlides){ thumbsEl.innerHTML = ""; return; }

  thumbsEl.innerHTML = slideshowOrder.map((id, idx) => {
    const active = (id === selected) ? " is-active" : "";

    const showDivider = idx > 0 && (slideshowDividersSet instanceof Set) && slideshowDividersSet.has(id);
    const isDividerSelected = showDivider && (slideshowSelectedDividerBeforeId === id);

    const titleRec = (slideshowTitlesMap instanceof Map) ? (slideshowTitlesMap.get(id) || null) : null;
    const titleText = String(titleRec?.text ?? "");
    const canRenderTitle = (idx === 0) || showDivider;
    const showTitle = canRenderTitle && ((slideshowEditingTitleBeforeId === id) || ((slideshowTitlesMap instanceof Map) && slideshowTitlesMap.has(id)));
    const isTitleEditing = (slideshowEditingTitleBeforeId === id);
    const isTitleSelected = !isTitleEditing && (slideshowSelectedTitleBeforeId === id);
    const titleHtml = showTitle ? `
      <div class="slideshow-title-wrap${isTitleEditing ? " is-editing" : ""}${isTitleSelected ? " is-selected" : ""}" tabindex="0" data-title-before="${id}" data-title-top="${idx === 0 ? "1" : "0"}">
        ${isTitleEditing
          ? `<div class="slideshow-title-editrow">
              <input class="input slideshow-title-input" type="text" data-title-input="${id}" value="${escapeAttr(titleText)}" placeholder="Section title" maxlength="64" />
              <button class="btn tiny danger slideshow-title-del" type="button" data-title-del="${id}">Delete</button>
            </div>`
          : `${isTitleSelected ? `<div class="slideshow-title-tooltip" role="tooltip">
                <button class="btn tiny" type="button" data-title-edit="${id}">Edit</button>
                <button class="btn tiny danger" type="button" data-title-del="${id}">Delete</button>
              </div>` : ""}
              <div class="slideshow-title-text" data-title-text="${id}">${escapeHtml(titleText || "Untitled section")}</div>`
        }
      </div>` : "";

    const dividerHtml = showDivider ? `
      <div class="slideshow-divider-wrap${isDividerSelected ? " is-selected" : ""}" data-divider-before="${id}">
        <div class="slideshow-divider" data-divider-before="${id}"></div>
        ${isDividerSelected ? `<div class="slideshow-divider-tooltip" role="tooltip">
          <button class="btn tiny danger slideshow-divider-del" type="button" data-divider-del="${id}">Delete</button>
        </div>` : ""}
      </div>` : "";

    return `
      ${dividerHtml}
      ${titleHtml}
      <div class="slideshow-thumb-wrap">
        <button class="slideshow-thumb${active}${slideshowReorderMode ? " is-reorder" : ""}" type="button" data-slide-id="${id}" ${slideshowReorderMode ? 'draggable="true"' : ""}>
          <div class="slideshow-thumb-box">
            <div class="slideshow-thumb-preview" data-thumb-preview="${id}" aria-hidden="true"></div>
            <div class="slideshow-thumb-num">${idx + 1}</div>
            <div class="slideshow-thumb-locs">
              <div class="slideshow-thumb-locs-left" data-thumb-locs-left="${id}" aria-hidden="true"></div>
            </div>
          </div>
        </button>
      </div>
    `;
  }).join("");
}

function renderSlideshowUI(){
  if (!messagesListEl) return;

  const isLoadingSlides = !slideshowOrderReady;
  const hasSlides = !isLoadingSlides && Array.isArray(slideshowOrder) && slideshowOrder.length > 0;
  const hasAnyDividers = (slideshowDividersSet instanceof Set) && slideshowDividersSet.size > 0;
  const hasAnyTitles = (slideshowTitlesMap instanceof Map) && slideshowTitlesMap.size > 0;

  // Preserve slide picker scroll across updates
  try{
    const prevThumbs = $("slideshow-thumbs");
    if (prevThumbs) slideshowThumbsScrollTop = prevThumbs.scrollTop;
  }catch{}

  ensureSlideshowShell();

  // Determine selected slide (force valid)
  let selected = hasSlides ? String(slideshowSelectedId || "") : "";
  if (hasSlides && (!selected || !slideshowOrder.includes(selected))){
    selected = String(slideshowOrder[0] || "");
    slideshowSelectedId = selected || null;
  }
  if (!hasSlides) slideshowSelectedId = null;

  // Update empty/loaded canvas states without rebuilding the stage
  const emptyEl = $("slideshow-empty");
  const emptyTitle = $("slideshow-empty-title");
  const emptySub = $("slideshow-empty-sub");
  const canvasInner = $("slideshow-canvas-inner");
  if (emptyEl && canvasInner){
    if (hasSlides){
      emptyEl.hidden = true;
      canvasInner.style.display = "";
    } else {
      canvasInner.style.display = "none";
      emptyEl.hidden = false;
      if (isLoadingSlides){
        if (emptyTitle) emptyTitle.textContent = "Loading slides...";
        if (emptySub) emptySub.textContent = "Just a moment.";
      } else {
        if (emptyTitle) emptyTitle.textContent = "No slides yet";
        if (emptySub) emptySub.textContent = "Create a slide to begin.";
      }
    }
  }

  // Button states
  const btnBack = $("slideshow-back");
  if (btnBack) btnBack.textContent = slideshowReorderMode ? "Cancel" : "Back";

  const btnReorder = $("slideshow-reorder");
  if (btnReorder){
    btnReorder.hidden = !hasSlides || slideshowOrder.length <= 1;
    btnReorder.textContent = slideshowReorderMode ? "Done" : "Reorder";
    btnReorder.classList.toggle("primary", !!slideshowReorderMode);
    btnReorder.disabled = !!(slideshowDividerInsertMode || slideshowTitleInsertMode || slideshowEditingTitleBeforeId);
  }

  const btnAddTitle = $("slideshow-add-title");
  const btnAddDivider = $("slideshow-add-divider");
  if (btnAddTitle){
    btnAddTitle.hidden = !hasSlides;
    btnAddTitle.disabled = !!(slideshowReorderMode || !hasSlides);
    btnAddTitle.title = "Add or edit a section title above the selected slide.";
  }
  if (btnAddDivider){
    btnAddDivider.hidden = !hasSlides;
    btnAddDivider.disabled = !!(slideshowReorderMode || !hasSlides || slideshowOrder.length <= 1 || !slideshowFindOpenDividerBeforeId());
    btnAddDivider.title = "Add a section divider near the selected slide.";
  }

  // If we just cancelled Reorder Mode, restore Title/Divider buttons to their prior disabled state.
  if (slideshowReorderRestoreButtonsOnce){
    if (btnAddTitle) btnAddTitle.disabled = !!slideshowReorderPrevTitleDisabled;
    if (btnAddDivider) btnAddDivider.disabled = !!slideshowReorderPrevDividerDisabled;
    slideshowReorderRestoreButtonsOnce = false;
  }

  const btnDel = $("slideshow-del");
  if (btnDel) btnDel.disabled = !hasSlides;

  // Inspector overlay sizing (so it covers picker/actions but not the Back button)
  try{
    const side = $("slideshow-side");
    const head = $("slideshow-side-head");
    if (side && head){
      side.style.setProperty("--ss-head-h", `${Math.ceil(head.getBoundingClientRect().height)}px`);
    }
  }catch{}

  // Thumbs: only rebuild when something that affects them changes
  const thumbsEl = $("slideshow-thumbs");
  if (thumbsEl){
    thumbsEl.dataset.reorder = slideshowReorderMode ? "1" : "0";

    const orderKey = hasSlides ? slideshowOrder.join("|") : "";

    const titlesKey = (hasAnyTitles && hasSlides)
      ? slideshowOrder.map(id => {
          const rec = slideshowTitlesMap.get(id);
          return rec ? `${id}:${String(rec.text ?? "")}` : `${id}:`;
        }).join("|")
      : "";

    const divKey = (hasAnyDividers && hasSlides)
      ? slideshowOrder.map(id => (slideshowDividersSet.has(id) ? `${id}:1` : `${id}:0`)).join("|")
      : "";

    const sig =
      `${isLoadingSlides ? 1 : 0}|${hasSlides ? 1 : 0}|${selected}|${orderKey}|${slideshowReorderMode ? 1 : 0}|` +
      `${slideshowDividerInsertMode ? 1 : 0}|${slideshowTitleInsertMode ? 1 : 0}|` +
      `${String(slideshowSelectedDividerBeforeId || "")}|${String(slideshowSelectedTitleBeforeId || "")}|${String(slideshowEditingTitleBeforeId || "")}|` +
      `${titlesKey}|${divKey}`;

    if (sig !== slideshowThumbsSig){
      slideshowThumbsSig = sig;
      renderSlideshowThumbsInto(thumbsEl, { hasSlides, selected });
      thumbsEl.scrollTop = slideshowThumbsScrollTop;
      if (!slideshowReorderMode) thumbsEl.querySelector(".slideshow-thumb.is-active")?.scrollIntoView({ block:"nearest" });
    } else {
      thumbsEl.scrollTop = slideshowThumbsScrollTop;
    }
  }

  // Slide previews in the picker (live thumbnails)
  if (hasSlides){
    syncSlideshowThumbDocs(slideshowOrder);
    for (const id of slideshowOrder){
      const doc = slideshowDocCache.get(id);
      if (doc) scheduleSlideshowThumbRender(id, doc);
    }
  } else {
    detachSlideshowThumbDocs();
  }

  // Slide-specific locations in the picker (who is on which slide)
  renderSlideshowThumbLocations();

  // Attach / render doc
  if (hasSlides && selected){
    attachSlideshowDoc(selected);
    const doc = slideshowDocCache.get(selected);
    if (doc) renderSlideshowStage(selected, doc);
  } else {
    detachSlideshowDoc();
  }

  applySlideshowComposerRules();
  try{ renderOnlineIndicator(); }catch{}
}

/* -------------------- Rooms list rendering -------------------- */
const roomsBlockEl = $("rooms-list-card") || document.querySelector(".rooms-block.side-section");
const roomsHeadEl = $("rooms-head");
const roomsTitleEl = $("rooms-title");
let sidebarRoomsMode = "public";
let sidebarRoomsHadPublic = false;

function setRoomsCount(n){
  const count = Number(n) || 0;
  const mini = $("rooms-mini");
  if (mini) mini.textContent = String(count);
  if (roomsBlockEl) roomsBlockEl.hidden = count <= 0;
}

function getSidebarRoomVisibilityState(allRooms = getSortedRoomEntries()){
  const publicRooms = [];
  const privateRooms = [];

  for (const room of allRooms){
    const meta = roomsMetaCache.get(room.roomId) || null;
    if (isPrivateRoomMeta(meta)) privateRooms.push(room);
    else publicRooms.push(room);
  }

  const hasPublic = publicRooms.length > 0;
  const hasPrivate = privateRooms.length > 0;
  const canToggle = hasPublic && hasPrivate;

  if (hasPublic && !sidebarRoomsHadPublic){
    sidebarRoomsMode = "public";
  } else if (!hasPublic && hasPrivate){
    sidebarRoomsMode = "all";
  } else if (!hasPrivate){
    sidebarRoomsMode = "public";
  }

  sidebarRoomsHadPublic = hasPublic;

  const showAll = canToggle ? sidebarRoomsMode === "all" : (!hasPublic && hasPrivate);
  return {
    allRooms,
    visibleRooms: showAll ? allRooms : publicRooms,
    hasPublic,
    hasPrivate,
    canToggle,
    showAll
  };
}

function syncRoomsListToggleUI(state){
  if (!roomsBlockEl) return;

  const title = state.showAll ? "All Rooms" : "Rooms List";
  if (roomsTitleEl) roomsTitleEl.textContent = title;

  roomsBlockEl.classList.toggle("rooms-toggleable", !!state.canToggle);
  roomsBlockEl.classList.toggle("rooms-showing-all", !!state.showAll);
  roomsBlockEl.setAttribute("aria-label", title);
  roomsBlockEl.removeAttribute("title");

  if (state.canToggle){
    roomsBlockEl.setAttribute("role", "button");
    roomsBlockEl.tabIndex = 0;
    roomsBlockEl.setAttribute("aria-pressed", state.showAll ? "true" : "false");
  } else {
    roomsBlockEl.removeAttribute("role");
    roomsBlockEl.removeAttribute("tabindex");
    roomsBlockEl.removeAttribute("aria-pressed");
  }
}

function toggleSidebarRoomsMode(){
  const state = getSidebarRoomVisibilityState();
  if (!state.canToggle) return;
  sidebarRoomsMode = state.showAll ? "public" : "all";
  roomsListLastSig = "";
  renderRoomsList();
}

function isRoomsListChromeTarget(target){
  return !!(
    target &&
    roomsBlockEl?.contains?.(target) &&
    !target.closest?.(".room-row, button, a, input, textarea, select, [contenteditable='true']")
  );
}

if (roomsBlockEl){
  roomsBlockEl.addEventListener("click", (e) => {
    if (!isRoomsListChromeTarget(e.target)) return;
    toggleSidebarRoomsMode();
  });
  roomsBlockEl.addEventListener("keydown", (e) => {
    if (e.key !== "Enter" && e.key !== " ") return;
    if (!roomsBlockEl.classList.contains("rooms-toggleable")) return;
    e.preventDefault();
    toggleSidebarRoomsMode();
  });
}

function stopRoomMetaListeners(){
  for (const { ref, cb } of roomMetaListeners.values()){
    try{ ref.off("value", cb); }catch{}
  }
  roomMetaListeners.clear();
}

function ensureRoomMetaListener(roomId){
  if (roomMetaListeners.has(roomId)) return;
  const ref = db.ref(`rooms/${roomId}`);
  const cb = async (snap) => {
    const meta = snap.exists() ? snap.val() : null;
    const prevMeta = roomsMetaCache.get(roomId) || null;
    const displayName = roomDisplayName(roomId, meta || prevMeta);

    // Room deleted: force everyone out and reset UI.
    if (!meta){
      roomsMetaCache.delete(roomId);

      // Prevent “ghost rooms” (don’t wait for the membership listener to eventually catch up).
      membershipMap.delete(roomId);
      scheduleRoomsListCacheSave();
      renderRoomsList();

      // Best-effort: remove membership in DB too (cleans up other devices).
      try{ if (currentUser?.code) await db.ref(`memberships/${currentUser.code}/${roomId}`).remove(); }catch{}

      // Stop listening to meta for a room that no longer exists.
      const rec = roomMetaListeners.get(roomId);
      if (rec){ try{ rec.ref.off("value", rec.cb); }catch{} }
      roomMetaListeners.delete(roomId);

      if (currentRoomId === roomId){
        clearReplyState({ quiet:true });
        clearPendingFiles({ quiet:true });
        $("msg-input").value = "";
        showLoggedInHome();
        showToast({ title:"Room deleted", body:`${displayName} was deleted.`, duration: 2400 });
      } else {
        // If we’re on Home overview, refresh it live (but never interrupt Schedules)
        const place = localStorage.getItem(LS.PLACE) || "home";
        if (!currentRoomId && views.chat.dataset.active === "true" && place === "home"){
          setHeaderHome();
          clearMessagesToHome();
        }
      }

      return;
    }

    roomsMetaCache.set(roomId, meta);
    scheduleRoomsListCacheSave();
    renderRoomsList();
    if (currentRoomId === roomId){
      setHeaderRoom(roomId);
      renderRoomSidebarHeader(roomId);
    }
    if (isRoomActivelyRead(roomId)) scheduleLastSeenBump(roomId);
    // If we’re on Home overview, refresh it live (but never interrupt Schedules)
    const place = localStorage.getItem(LS.PLACE) || "home";
    if (!currentRoomId && views.chat.dataset.active === "true" && place === "home"){
      setHeaderHome();
      clearMessagesToHome();
    }
  };
  ref.on("value", cb);
  roomMetaListeners.set(roomId, { ref, cb });
}

function roomSidebarLeaveIconSVG(){
  return `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M10 7.5H7.75A2.75 2.75 0 0 0 5 10.25v3.5A2.75 2.75 0 0 0 7.75 16.5H10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>
      <path d="M13 8l5 4-5 4" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>
      <path d="M18 12H9" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>
    </svg>
  `;
}

function applySidebarRoomAvatar(row, meta){
  const avatarEl = row?._avatarEl || row?.querySelector(".room-avatar-image");
  if (!avatarEl) return;

  const frameEl = avatarEl.parentElement || row?._avatarWrap || row;

  applyCroppedImage(
    avatarEl,
    String(meta?.photoDataURL || defaultStickmanDataURL()),
    meta?.photoTransform,
    getMediaFrameSize(frameEl, 42),
    132
  );
}

function refreshRoomIconSurfaces(roomId){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  scheduleRoomsListCacheSave();
  updateRoomListItem(id);

  if (currentRoomId === id){
    renderRoomSidebarHeader(id);
  }

  const place = localStorage.getItem(LS.PLACE) || "home";
  if (!currentRoomId && views.chat.dataset.active === "true" && place === "home"){
    setHeaderHome();
    clearMessagesToHome();
  }
}

function getSidebarRoomPreview(meta){
  return String(meta?.lastMessagePreview || "No messages yet.");
}

function syncSidebarRoomActiveStates(){
  const activeRoomId = sanitizeRoomCode(currentRoomId);
  const shouldShowActive = !!activeRoomId && views.chat.dataset.active === "true";
  const rows = roomsListEl ? roomsListEl.querySelectorAll(".room-row") : [];

  rows.forEach((row) => {
    const rowRoomId = sanitizeRoomCode(row.getAttribute("data-room-row"));
    row.classList.toggle("active", shouldShowActive && rowRoomId === activeRoomId);
  });
}

function updateRoomListItem(roomId){
  const row = roomRowCache.get(roomId) || document.querySelector(`[data-room-row="${CSS.escape(roomId)}"]`);
  if (!row) return;

  const meta = roomsMetaCache.get(roomId) || null;
  const titleEl = row._titleEl || row.querySelector(".room-name");
  const previewEl = row._previewEl || row.querySelector(".room-preview");
  const unreadBadgeEl = row._unreadBadgeEl || row.querySelector(".room-unread-badge");
  const pinHostEl = row._pinHostEl || row.querySelector(".room-markers");
  const displayName = roomDisplayName(roomId, meta);

  if (titleEl) titleEl.textContent = displayName;
  row.setAttribute("aria-label", `Open room ${displayName}`);
  const avatarImg = row._avatarEl || row.querySelector(".room-avatar-image");
  if (avatarImg) avatarImg.alt = `Room ${displayName} icon`;
  if (previewEl) previewEl.textContent = getSidebarRoomPreview(meta);
  if (unreadBadgeEl){
    const missedCount = getRoomMissedCount(roomId);
    unreadBadgeEl.hidden = !missedCount;
    unreadBadgeEl.textContent = formatUnreadBadgeCount(missedCount);
    unreadBadgeEl.setAttribute("aria-label", `${formatUnreadBadgeCount(missedCount)} unread messages`);
  }
  if (pinHostEl){
    const pinMark = getPinnedRoomSet().has(roomId)
      ? `<span class="room-pin-mark" aria-label="Pinned Room" title="Pinned">${roomPinBadgeSVG()}</span>`
      : "";
    pinHostEl.innerHTML = `${privateRoomMarkHTML(meta)}${pinMark}`;
  }
  applySidebarRoomAvatar(row, meta);
  row.classList.toggle("active", sanitizeRoomCode(currentRoomId) === roomId && views.chat.dataset.active === "true");
}

let roomsListLastSig = "";
function renderRoomsList(){
  if (!roomsListEl) return;

  const allRooms = getSortedRoomEntries();
  for (const room of allRooms){
    ensureRoomMetaListener(room.roomId);
  }

  const state = getSidebarRoomVisibilityState(allRooms);
  const rooms = state.visibleRooms;
  const allIds = allRooms.map((item) => item.roomId);
  const ids = rooms.map((item) => item.roomId);

  const keep = new Set(allIds);
  for (const rid of Array.from(roomMetaListeners.keys())){
    if (keep.has(rid)) continue;
    const rec = roomMetaListeners.get(rid);
    if (rec){ try{ rec.ref.off("value", rec.cb); }catch{} }
    roomMetaListeners.delete(rid);
    roomsMetaCache.delete(rid);
  }

  setRoomsCount(ids.length);
  syncRoomsListToggleUI(state);

  const sig = [state.showAll ? "all" : "public", state.canToggle ? 1 : 0, ...rooms.map((item) => {
    const meta = roomsMetaCache.get(item.roomId) || null;
    return `${item.roomId}:${item.displayName}:${isPrivateRoomMeta(meta) ? 1 : 0}:${item.pinned ? 1 : 0}:${item.missedCount}:${item.lastAt}`;
  })].join("|");
  if (sig === roomsListLastSig){
    for (const room of rooms){
      ensureRoomMetaListener(room.roomId);
      updateRoomListItem(room.roomId);
    }
    return;
  }
  roomsListLastSig = sig;

  const keepRows = new Set(ids);
  for (const rid of Array.from(roomRowCache.keys())){
    if (keepRows.has(rid)) continue;
    const row = roomRowCache.get(rid);
    if (row) row.remove();
    roomRowCache.delete(rid);
  }

  let cursor = roomsListEl.firstElementChild;

  for (const room of rooms){
    const roomId = room.roomId;
    ensureRoomMetaListener(roomId);
    const meta = roomsMetaCache.get(roomId) || null;

    let row = roomRowCache.get(roomId);
    if (!row){
      row = document.createElement("div");
      row.className = "room-row";
      row.setAttribute("data-room-row", roomId);
      row.tabIndex = 0;
      row.setAttribute("role", "button");
      row.setAttribute("aria-label", `Open room ${roomDisplayName(roomId, meta)}`);

      const left = document.createElement("div");
      left.className = "room-left";

      const avatar = document.createElement("div");
      avatar.className = "room-avatar";

      const avatarImg = document.createElement("img");
      avatarImg.className = "room-avatar-image";
      avatarImg.alt = `Room ${roomDisplayName(roomId, meta)} icon`;
      avatarImg.draggable = false;

      const unreadBadge = document.createElement("span");
      unreadBadge.className = "room-unread-badge";
      unreadBadge.hidden = true;

      avatar.appendChild(avatarImg);
      avatar.appendChild(unreadBadge);

      const content = document.createElement("div");
      content.className = "room-content";

      const nameRow = document.createElement("div");
      nameRow.className = "room-name-row";

      const title = document.createElement("div");
      title.className = "room-name";
      title.textContent = roomDisplayName(roomId, meta);

      const markers = document.createElement("div");
      markers.className = "room-markers";

      const metaRow = document.createElement("div");
      metaRow.className = "room-meta";

      const preview = document.createElement("div");
      preview.className = "room-preview";

      row._avatarEl = avatarImg;
      row._previewEl = preview;
      row._unreadBadgeEl = unreadBadge;
      row._pinHostEl = markers;

      nameRow.appendChild(title);
      nameRow.appendChild(markers);
      metaRow.appendChild(preview);
      content.appendChild(nameRow);
      content.appendChild(metaRow);

      left.appendChild(avatar);
      left.appendChild(content);

      const openThisRoom = () => openRoom(roomId);

      row.addEventListener("contextmenu", (e) => {
        e.preventDefault();
        e.stopPropagation();
        openRoomButtonContextMenu(e, roomId, row);
      });
      row.addEventListener("click", () => {
        openThisRoom();
      });
      row.addEventListener("keydown", (e) => {
        if (e.key !== "Enter" && e.key !== " ") return;
        e.preventDefault();
        openThisRoom();
      });

      row.appendChild(left);

      roomRowCache.set(roomId, row);
    }

    const previewEl = row._previewEl || row.querySelector(".room-preview");
    if (previewEl) previewEl.textContent = getSidebarRoomPreview(meta);
    applySidebarRoomAvatar(row, meta);
    updateRoomListItem(roomId);

    if (row !== cursor){
      roomsListEl.insertBefore(row, cursor);
    } else {
      cursor = cursor.nextElementSibling;
    }
  }
}

/* -------------------- Memberships -------------------- */
function attachMemberships(){
  if (!currentUser) return;

  if (membershipsRef) membershipsRef.off();
  attachPinnedRoomsSync();
  stopRoomMetaListeners();
  roomsMetaCache.clear();
  membershipMap.clear();
  restoreDone = false;

  // Fast first paint: reuse last-known rooms list immediately (then reconcile from Firebase)
  try{ hydrateRoomsListFromCache(); }catch{}

  membershipsRef = db.ref(`memberships/${currentUser.code}`);
  membershipsRef.on("value", (snap) => {
    const prevSelected = slideshowSelectedId;
    const v = snap.exists() ? (snap.val() || {}) : {};
    const next = new Map();

    for (const [roomId, entry] of Object.entries(v)){
      if (!roomId) continue;
      if (entry === true){
        next.set(roomId, { joinedAt: 0, lastSeenAt: 0, lastSeenCount: 0 });
      } else if (typeof entry === "object" && entry){
        next.set(roomId, {
          joinedAt: Number(entry.joinedAt) || 0,
          lastSeenAt: Number(entry.lastSeenAt) || 0,
          lastSeenCount: Number(entry.lastSeenCount) || 0
        });
      }
    }

    membershipMap = next;
    renderRoomsList();
    scheduleRoomsListCacheSave();

    // If a ping toast is showing for a room you just left, close it immediately.
    if (activePingToastRoomId && !membershipMap.has(activePingToastRoomId)){
      closeToast();
    }

    // Restore place (once). If the cached startup path already opened the room, do not reopen it.
    if (!restoreDone){
      restoreDone = true;
      const place = localStorage.getItem(LS.PLACE) || "home";
      if (place.startsWith("room:")){
        const roomId = sanitizeRoomCode(place.slice(5));
        if (roomId && membershipMap.has(roomId)){
          if (sanitizeRoomCode(currentRoomId) !== roomId) openRoom(roomId, { quiet: true });
          return;
        }
      }
      if (!currentRoomId) showLoggedInHome();
    }

    // If current room removed, go home
    if (currentRoomId && !membershipMap.has(currentRoomId)){
      const displayName = roomDisplayName(currentRoomId, roomsMetaCache.get(currentRoomId) || null);
      showLoggedInHome();
      showToast({ title:"Left room", body:`You left ${displayName}.`, duration: 2200 });
    }

    // If we’re on Home overview, refresh it live when memberships change (join/leave/delete)
    const placeNow = localStorage.getItem(LS.PLACE) || "home";
    if (restoreDone && !currentRoomId && views.chat.dataset.active === "true" && placeNow === "home"){
      setHeaderHome();
      clearMessagesToHome();
    }
  });
}

/* -------------------- Pings -------------------- */
function detachPingsInbox(){
  if (pingsInboxRef && pingsInboxCb){
    try{ pingsInboxRef.off("value", pingsInboxCb); }catch{}
  }
  pingsInboxRef = null;
  pingsInboxCb = null;
  pingsInboxFirstSnapshot = true;
  seenPingKeys.clear();
  activePingToastRoomId = null;
}

// Desktop notification for pings (runs only while the site is open)
let lastDesktopPingAt = 0;
let lastDesktopPingKey = "";

function supportsDesktopNotifications(){
  try{ return typeof Notification !== "undefined"; }catch{ return false; }
}

async function ensureDesktopNotificationPermission(){
  if (!supportsDesktopNotifications()) return false;
  if (Notification.permission === "granted") return true;
  if (Notification.permission === "denied") return false;
  try{
    const p = await Notification.requestPermission();
    return p === "granted";
  }catch{ return false; }
}

function showDesktopPingNotification({ roomId, fromUsername } = {}){
  if (!pushNotifsEnabled) return;
  if (!supportsDesktopNotifications()) return;
  if (Notification.permission !== "granted") return;

  const rid = String(roomId || "").trim();
  const from = String(fromUsername || "Someone").trim() || "Someone";
  const key = `${from}::${rid}`;

  // De-dupe and throttle (avoids multi-event spam for the same snapshot)
  const t = Date.now();
  if (key === lastDesktopPingKey && (t - lastDesktopPingAt) < 1200) return;
  lastDesktopPingKey = key;
  lastDesktopPingAt = t;

  try{
    const title = `Your Christian Bible tutor, ${from}, has notified you in Room ${rid}.`;
    const n = new Notification(title, { silent:true, tag:`ping:${key}` });
    n.onclick = () => {
      try{ window.focus(); }catch{}
      try{ if (rid) openRoom(rid); }catch{}
      try{ n.close(); }catch{}
    };
  }catch{}
}

function showPingSummaryToast(countsByRoom, { onClose=null } = {}){
  const rooms = Object.keys(countsByRoom || {});
  if (!rooms.length) return;

  const total = rooms.reduce((sum, r) => sum + (Number(countsByRoom[r]) || 0), 0);

  const btnId = `toast_open_room_${Math.random().toString(36).slice(2)}`;
  const canOpen = rooms.length === 1;

  const listHtml = rooms
    .sort((a,b) => a.localeCompare(b))
    .map((r) => `<div><span class="strong">${escapeHtml(r)}</span>: ${Number(countsByRoom[r])||0}</div>`)
    .join("");

  showToast({
    title: `Pinged ${total} time${total === 1 ? "" : "s"}`,
    bodyHTML: `
      <div class="muted small" style="margin-top:2px">Rooms:</div>
      <div class="small" style="margin-top:6px">${listHtml}</div>
      ${canOpen ? `<div style="margin-top:10px"><button class="btn tiny" id="${btnId}" type="button">Open Room</button></div>` : ``}
    `,
    duration: 9000,
    onClose
  });

  if (canOpen){
    activePingToastRoomId = rooms[0];
    setTimeout(() => {
      const btn = document.getElementById(btnId);
      btn?.addEventListener("click", () => {
        closeToast("manual");
        openRoom(rooms[0]);
      }, { once:true });
    }, 0);
  } else {
    activePingToastRoomId = null;
  }
}

function showPingToast({ roomId, fromUsername, onClose=null }){
  const btnId = `toast_open_room_${Math.random().toString(36).slice(2)}`;
  activePingToastRoomId = roomId;

  showToast({
    title: "Pinged",
    bodyHTML: `
      <div class="small" style="margin-top:2px">
        <span class="strong">${escapeHtml(fromUsername || "Someone")}</span> pinged you in
        <span class="strong">${escapeHtml(roomId)}</span>.
      </div>
      <div style="margin-top:10px">
        <button class="btn tiny" id="${btnId}" type="button">Open Room</button>
      </div>
    `,
    duration: 9000,
    onClose
  });

  setTimeout(() => {
    const btn = document.getElementById(btnId);
    btn?.addEventListener("click", () => {
      closeToast("manual");
      openRoom(roomId);
    }, { once:true });
  }, 0);
}

function handlePingsSnapshot(v, { isInitial=false } = {}){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const isHome = !currentRoomId && views.chat.dataset.active === "true" && placeNow === "home";

  const newEvents = [];

  for (const [roomId, byId] of Object.entries(v || {})){
    if (!byId || typeof byId !== "object") continue;
    for (const [pingId, rec] of Object.entries(byId || {})){
      const key = `${roomId}/${pingId}`;
      if (seenPingKeys.has(key)) continue;
      seenPingKeys.add(key);
      newEvents.push({ roomId, pingId, rec: rec || {} });
    }
  }

  if (!newEvents.length) return;

  // Desktop push notification + ping sound (only for new pings, not the initial snapshot)
  if (!isInitial){
    const first = newEvents[0];
    showDesktopPingNotification({ roomId: first.roomId, fromUsername: first.rec?.fromUsername });
    playSfx("notif");
  }

  // Keep pings in Firebase until the toast closes/expires.
  // If the tab disconnects while the toast is visible, onDisconnect() removes them automatically.
  const handles = [];
  for (const ev of newEvents){
    try{
      const ref = db.ref(`pings/${currentUser.code}/${ev.roomId}/${ev.pingId}`);
      const od = ref.onDisconnect();
      od.remove();
      handles.push({ ref, od });
    }catch{}
  }

  const cleanup = () => {
    for (const h of handles){
      try{ h.od.cancel(); }catch{}
      try{ h.ref.remove(); }catch{}
    }
  };

  let shown = false;

  if (isHome && isInitial){
    const counts = {};
    for (const ev of newEvents){
      counts[ev.roomId] = (counts[ev.roomId] || 0) + 1;
    }
    showPingSummaryToast(counts, { onClose: cleanup });
    shown = true;
  } else {
    for (const ev of newEvents){
      if (currentRoomId && currentRoomId === ev.roomId){
        showToast({
          title: "Pinged",
          bodyHTML: `
            <div class="small" style="margin-top:2px">
              <span class="strong">${escapeHtml(ev.rec?.fromUsername || "Someone")}</span> pinged you in this room.
            </div>
          `,
          duration: 2000,
          onClose: cleanup
        });
        shown = true;
        break;
      }

      showPingToast({ roomId: ev.roomId, fromUsername: ev.rec?.fromUsername, onClose: cleanup });
      shown = true;
      break;
    }
  }

  // If we decided not to show a toast for any reason, delete immediately.
  if (!shown) cleanup();
}

function attachPingsInbox(){
  if (!currentUser) return;
  detachPingsInbox();

  pingsInboxRef = db.ref(`pings/${currentUser.code}`);
  pingsInboxFirstSnapshot = true;
  pingsInboxCb = (snap) => {
    const v = snap.exists() ? (snap.val() || {}) : {};
    const isInitial = pingsInboxFirstSnapshot;
    pingsInboxFirstSnapshot = false;
    handlePingsSnapshot(v, { isInitial });
  };
  pingsInboxRef.on("value", pingsInboxCb);
}

/* -------------------- Chat header + composer -------------------- */
function syncComposerPrimaryAction(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const send = $("btn-send");
  if (!send) return;

  const setAction = (action, label, svg) => {
    send.dataset.action = action;
    send.setAttribute("aria-label", label);
    send.setAttribute("title", label);
    send.innerHTML = `<span class="composer-send-icon" aria-hidden="true">${svg}</span>`;
  };

  const sendSvg = `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M21.25 3.75 10.4 14.6" stroke="currentColor" stroke-width="2.05" stroke-linecap="round" stroke-linejoin="round"/>
      <path d="M21.25 3.75 14.3 20.25l-3.9-5.75-5.65-3.9 16.5-6.85Z" fill="currentColor"/>
    </svg>
  `;

  const changeSvg = `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M4.75 5.5A2.75 2.75 0 0 1 7.5 2.75h6A2.75 2.75 0 0 1 16.25 5.5v3.25" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"/>
      <path d="M7.75 8.5h5M7.75 11.5h3.25" stroke="currentColor" stroke-width="1.9" stroke-linecap="round"/>
      <path d="m13.9 17.55 4.9-4.9a1.8 1.8 0 1 1 2.55 2.55l-4.9 4.9-3.2.85.65-3.4Z" stroke="currentColor" stroke-width="1.9" stroke-linejoin="round"/>
      <path d="M6.75 18.5h4" stroke="currentColor" stroke-width="1.9" stroke-linecap="round"/>
    </svg>
  `;

  const cancelSvg = `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M4.75 5.5A2.75 2.75 0 0 1 7.5 2.75h6A2.75 2.75 0 0 1 16.25 5.5v3.25" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"/>
      <path d="M7.75 8.5h5M7.75 11.5h3.25" stroke="currentColor" stroke-width="1.9" stroke-linecap="round"/>
      <path d="m15.85 13.85 5.4 5.4M21.25 13.85l-5.4 5.4" stroke="currentColor" stroke-width="2.15" stroke-linecap="round"/>
      <path d="M6.75 18.5h4" stroke="currentColor" stroke-width="1.9" stroke-linecap="round"/>
    </svg>
  `;

  if (placeNow === "slideshow"){
    setAction("change", "Change text", changeSvg);
    return;
  }

  const roomId = sanitizeRoomCode(currentRoomId);
  const editingThisRoom = !!(editState && roomId && editState.roomId === roomId && placeNow === `room:${roomId}`);
  setAction(
    editingThisRoom ? "cancel" : "send",
    editingThisRoom ? "Cancel editing" : "Send message",
    editingThisRoom ? cancelSvg : sendSvg
  );
}

function setComposerEnabled(enabled){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const isRoom = placeNow.startsWith("room:");
  const isSlideshow = placeNow === "slideshow";

  const input = $("msg-input");
  const send = $("btn-send");
  const up = $("btn-upload");

  if (input){
    input.disabled = !enabled;
    input.setAttribute("aria-label", "Message");
  }
  if (send) send.disabled = !enabled;

  if (up){
    if (!enabled){
      up.hidden = true;
      up.disabled = true;
    } else if (isRoom){
      up.hidden = false;
      up.disabled = false;
    } else if (isSlideshow){
      up.hidden = false;
      const hasSlides = Array.isArray(slideshowOrder) && slideshowOrder.length > 0;
      const hasSelected = !!slideshowSelectedId && hasSlides && slideshowOrder.includes(slideshowSelectedId);
      up.disabled = !(hasSlides && hasSelected);
    } else {
      up.hidden = true;
      up.disabled = true;
    }
  }

  if (input){
    const editingThisRoom = !!(editState && currentRoomId && editState.roomId === sanitizeRoomCode(currentRoomId) && isRoom);
    input.placeholder = !enabled
      ? "Select a room to chat…"
      : (isSlideshow ? "Select text on the slide to edit…" : (editingThisRoom ? "Edit your message…" : "Type a message…"));
  }

  syncComposerPrimaryAction();
}

// Slideshow: prevent typing into the composer unless text is intentionally selected on the slide
let slideshowComposerUnlocked = false;

function updateSlideshowSelectionState(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  if (placeNow !== "slideshow") return;

  const canvas = $("slideshow-canvas");
  let ok = false;
  try{
    const sel = document.getSelection();
    if (canvas && sel && sel.rangeCount > 0 && !sel.isCollapsed){
      let node = sel.anchorNode || sel.focusNode;
      if (node && node.nodeType === 3) node = node.parentNode;
      if (node && canvas.contains(node)) ok = true;
    }
  }catch{}

  slideshowComposerUnlocked = ok;
}

/* -------------------- Slideshow composer gating -------------------- */
function applySlideshowComposerRules(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";

  const top = $("slideshow-composer-top");
  const btnCopy = $("btn-slide-copy");
  const btnPaste = $("btn-slide-paste");
  const btnCopyPaste = $("btn-slide-copy-paste");
  const btnText = $("btn-slide-text");
  const btnShape = $("btn-slide-shape");
  const btnBg = $("btn-slide-bg");
  const btnDuplicate = $("btn-slide-duplicate");
  const btnDeleteObj = $("btn-slide-delete-object");
  const btnForward = $("btn-slide-forward");
  const btnBackward = $("btn-slide-backward");
  const btnCenterX = $("btn-slide-center-x");
  const btnCenterY = $("btn-slide-center-y");
  const btnCenterBoth = $("btn-slide-center-both");
  const btnFront = $("btn-slide-front");
  const btnBack = $("btn-slide-back");

  if (placeNow !== "slideshow"){
    if (top) top.hidden = true;
    syncComposerPrimaryAction();
    return;
  }

  if (top) top.hidden = false;

  const hasSlides = Array.isArray(slideshowOrder) && slideshowOrder.length > 0;
  const hasSelected = !!slideshowSelectedId && hasSlides && slideshowOrder.includes(slideshowSelectedId);
  const hasObjSelected = !!(hasSlides && hasSelected && slideshowSelectedObjId);

  // Copy/Paste controls stay visible; availability is controlled only by disabled state.
  if (btnCopy){
    btnCopy.hidden = false;
    btnCopy.disabled = !hasObjSelected;
  }
  if (btnPaste){
    const hasCopy = !!slideshowClipboard;
    btnPaste.hidden = false;
    // Paste works with or without an object selected (but you must have a slide selected)
    btnPaste.disabled = !(hasCopy && hasSlides && hasSelected);
  }
  if (btnCopyPaste){
    btnCopyPaste.hidden = false;
    btnCopyPaste.disabled = !hasObjSelected;
  }

  [
    btnDuplicate,
    btnDeleteObj,
    btnForward,
    btnBackward,
    btnCenterX,
    btnCenterY,
    btnCenterBoth,
    btnFront,
    btnBack
  ].forEach((btn) => {
    if (btn) btn.disabled = !hasObjSelected;
  });

  if (btnText) btnText.disabled = !(hasSlides && hasSelected);
  if (btnShape) btnShape.disabled = !(hasSlides && hasSelected);
  if (btnBg) btnBg.disabled = !(hasSlides && hasSelected);

  const input = $("msg-input");
  const send = $("btn-send");
  const up = $("btn-upload");
  const fi = $("file-input");

  if (up){
    up.hidden = false;
    up.disabled = !(hasSlides && hasSelected);
  }

  if (fi){
    fi.accept = (hasSlides && hasSelected) ? "image/*,image/gif,video/*,audio/*" : "";
  }

  const canEditText = !!(hasSlides && hasSelected && slideshowSelectedObjId && slideshowSelectedObjType === "text");
  if (input){
    input.disabled = !canEditText;
    input.placeholder = canEditText ? "Edit selected text…" : "Select a text object on the slide to edit…";
  }
  if (send){
    send.disabled = !canEditText;
    syncComposerPrimaryAction();
  }
}

document.addEventListener("selectionchange", () => {
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  if (placeNow !== "slideshow") return;
  updateSlideshowSelectionState();
  applySlideshowComposerRules();
});

/* -------------------- Room Online Indicator (presence + typing) -------------------- */
function detachOnlineIndicator(){
  if (roomOnlineRef && roomOnlineCb){
    try{ roomOnlineRef.off("value", roomOnlineCb); }catch{}
  }
  roomOnlineRef = null;
  roomOnlineCb = null;

  if (slideshowOnlineRef && slideshowOnlineCb){
    try{ slideshowOnlineRef.off("value", slideshowOnlineCb); }catch{}
  }
  slideshowOnlineRef = null;
  slideshowOnlineCb = null;

  // NEW: memberships listener
  if (roomMembersRef && roomMembersCb){
    try{ roomMembersRef.off("value", roomMembersCb); }catch{}
  }
  roomMembersRef = null;
  roomMembersCb = null;

  // NEW: call-members listener
  if (roomCallMembersRef && roomCallMembersCb){
    try{ roomCallMembersRef.off("value", roomCallMembersCb); }catch{}
  }
  roomCallMembersRef = null;
  roomCallMembersCb = null;

  onlineIndicatorMode = "room";
  onlinePresenceCache.clear();
  roomMembersCache.clear();
  roomCallMembersCache.clear();

  if (onlineListEl) onlineListEl.innerHTML = "";
  onlineTiles.clear();

  // Default back to room label
  if (onlineLabelEl) onlineLabelEl.textContent = "Members - 0";
  renderRoomSidebarHeader(null);
  if (onlinePill) onlinePill.hidden = true;
}

function setSlideshowEditorsShown(next){
  slideshowEditorsShown = !!next;
  const side = $("slideshow-side");
  if (side) side.classList.toggle("editors-open", slideshowEditorsShown);

  const toggle = $("slideshow-editors-toggle");
  if (toggle){
    toggle.textContent = slideshowEditorsShown ? "Hide" : "Show";
    toggle.setAttribute("aria-expanded", slideshowEditorsShown ? "true" : "false");
  }

  if (onlineListEl){
    const placeNow = localStorage.getItem(LS.PLACE) || "home";
    onlineListEl.hidden = placeNow === "slideshow" && !slideshowEditorsShown;
  }
}

function syncSlideshowEditorsToggle(count = 0){
  if (!onlinePill || !onlineLabelEl) return;

  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const isSlideshow = placeNow === "slideshow" && document.body.classList.contains("slideshow-full");
  let toggle = $("slideshow-editors-toggle");

  if (!isSlideshow){
    if (toggle) toggle.remove();
    const side = $("slideshow-side");
    if (side) side.classList.remove("editors-open");
    if (onlineListEl) onlineListEl.hidden = false;
    return;
  }

  if (!toggle){
    toggle = document.createElement("button");
    toggle.id = "slideshow-editors-toggle";
    toggle.className = "slideshow-editors-toggle";
    toggle.type = "button";
    toggle.addEventListener("click", () => setSlideshowEditorsShown(!slideshowEditorsShown));
    onlineLabelEl.insertAdjacentElement("afterend", toggle);
  }

  toggle.setAttribute("aria-label", `${slideshowEditorsShown ? "Hide" : "Show"} slideshow editors`);
  toggle.dataset.count = String(Math.max(0, Number(count) || 0));
  setSlideshowEditorsShown(slideshowEditorsShown);
}

function ensureOnlinePillMount(isSlideshow){
  if (!onlinePill) return;
  const slideshowHost = $("slideshow-side-topbar");
  const defaultHost = $("members-sidebar-mount");
  if (isSlideshow && slideshowHost){
    if (onlinePill.parentElement !== slideshowHost) slideshowHost.appendChild(onlinePill);
  } else if (defaultHost){
    if (onlinePill.parentElement !== defaultHost) defaultHost.appendChild(onlinePill);
  }
  syncSlideshowEditorsToggle();
}

function renderRoomSidebarHeader(roomId = currentRoomId){
  const id = sanitizeRoomCode(roomId);
  const meta = id ? (roomsMetaCache.get(id) || null) : null;
  const rawPhotoDataURL = String(meta?.photoDataURL || "");
  const photoDataURL = rawPhotoDataURL || defaultStickmanDataURL();
  const hasCustomPhoto = !!rawPhotoDataURL && rawPhotoDataURL !== defaultStickmanDataURL();
  const displayName = id ? roomDisplayName(id, meta) : "";
  if (roomSummaryEl) roomSummaryEl.hidden = !id;
  if (roomLabelEl){
    roomLabelEl.innerHTML = id ? `${privateRoomMarkHTML(meta)}<span>Room ${escapeHtml(displayName)}</span>` : "Room —";
  }

  if (roomIconImageEl){
    applyCroppedImage(
      roomIconImageEl,
      photoDataURL,
      meta?.photoTransform,
      132,
      132
    );
    roomIconImageEl.alt = id ? `Room ${displayName} Icon` : "Room icon";
  }

  if (roomIconButtonEl){
    roomIconButtonEl.disabled = !id;
    roomIconButtonEl.setAttribute("aria-label", id ? `Change icon for Room ${displayName}` : "Change Room Icon");
  }
}

function attachOnlineIndicator(roomId){
  if (!onlinePill || !onlineListEl) return;
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  detachOnlineIndicator();
  onlineIndicatorMode = "room";

  // Chat rooms: "Members:" label
  if (onlineLabelEl) onlineLabelEl.textContent = "Members - 0";
  onlinePill.hidden = (!currentRoomId || currentRoomId !== id || views.chat.dataset.active !== "true");
  ensureOnlinePillMount(false);
  renderRoomSidebarHeader(id);

  // 1) Room-open presence (online + typing)
  roomOnlineRef = db.ref(`rooms/${id}/online`);
  roomOnlineCb = (snap) => {
    onlinePresenceCache.clear();
    const v = snap.exists() ? (snap.val() || {}) : {};
    for (const [code, rec] of Object.entries(v)){
      if (!code) continue;
      const username = (rec && rec.username) ? String(rec.username) : (liveUserCache.get(code)?.username || "User");
      const usernameLower = (rec && rec.usernameLower) ? String(rec.usernameLower) : username.toLowerCase();
      const typing = !!(rec && rec.typing);
      const idle = !!(rec && rec.idle);
      onlinePresenceCache.set(code, { code, username, usernameLower, typing, idle });
      ensureLiveUserListener(code);
    }
    renderOnlineIndicator();
  };
  roomOnlineRef.on("value", roomOnlineCb);

  // 2) Room memberships (ALL joined users)
  roomMembersRef = db.ref("memberships");
  roomMembersCb = (snap) => {
    roomMembersCache.clear();
    const all = snap.exists() ? (snap.val() || {}) : {};
    for (const [code, rooms] of Object.entries(all)){
      if (!code || !rooms) continue;
      if (Object.prototype.hasOwnProperty.call(rooms, id)){
        roomMembersCache.set(code, true);
        ensureLiveUserListener(code);
      }
    }
    renderOnlineIndicator();
    refreshMentionFormattingForRenderedMessages();
  };
  roomMembersRef.on("value", roomMembersCb);

  // 3) In-call members for this room (treated as online even if room is closed)
  roomCallMembersRef = db.ref(`calls/${id}/members`);
  roomCallMembersCb = (snap) => {
    roomCallMembersCache.clear();
    const v = snap.exists() ? (snap.val() || {}) : {};
    const now = Date.now();
    for (const [code, rec] of Object.entries(v)){
      if (!code || !rec) continue;
      const connected = !!rec.connected;

      // Robust freshness: some clients may not have lastSeenAt immediately, so fall back safely.
      const lastSeenAt = Number(rec.lastSeenAt || rec.updatedAt || rec.joinedAt || 0);

      // If connected is true, consider them in-call unless their timestamp is clearly stale.
      const fresh = connected && (lastSeenAt <= 0 || ((now - lastSeenAt) <= CALL_STALE_MEMBER_MS));
      if (!fresh) continue;
      roomCallMembersCache.set(code, true);
      ensureLiveUserListener(code);
    }
    renderOnlineIndicator();
  };
  roomCallMembersRef.on("value", roomCallMembersCb);
}

function attachSlideshowIndicator(){
  if (!onlinePill || !onlineListEl) return;
  if (!currentUser) return;

  detachOnlineIndicator();
  onlineIndicatorMode = "slideshow";
  if (onlineLabelEl) onlineLabelEl.textContent = "Editing:";
  onlinePill.hidden = (localStorage.getItem(LS.PLACE) !== "slideshow");
  ensureOnlinePillMount(true);

  slideshowOnlineRef = db.ref("slideshow/online");
  slideshowOnlineCb = (snap) => {
    onlinePresenceCache.clear();
    const v = snap.exists() ? (snap.val() || {}) : {};
    for (const [code, rec] of Object.entries(v)){
      if (!code) continue;
      const username = (rec && rec.username) ? String(rec.username) : (liveUserCache.get(code)?.username || "User");
      const usernameLower = (rec && rec.usernameLower) ? String(rec.usernameLower) : username.toLowerCase();
      const displayName = (rec && rec.displayName) ? String(rec.displayName) : (liveUserCache.get(code)?.displayName || username);
      const displayNameLower = (rec && rec.displayNameLower) ? String(rec.displayNameLower) : displayName.toLowerCase();
      const idle = !!(rec && rec.idle);
      onlinePresenceCache.set(code, { code, username, usernameLower, displayName, displayNameLower, typing:false, idle });
      ensureLiveUserListener(code);
    }
    renderOnlineIndicator();
  };

  slideshowOnlineRef.on("value", slideshowOnlineCb);
}

function renderOnlineIndicator(){
  if (!onlinePill || !onlineListEl) return;

  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const isRoom = placeNow.startsWith("room:") && !!currentRoomId;
  const isSlideshow = placeNow === "slideshow";
  const typingMode = getSavedTypingIndicatorMode();

  const hideTypingBar = () => {
    if (typingBarEl){
      clearTimeout(typingBarHideTimer);

      if (typingBarEl.hidden){
        typingBarEl.classList.remove("is-visible", "is-hiding");
        if (typingBarUsersEl){
          typingBarUsersEl.dataset.textKey = "";
          typingBarUsersEl.innerHTML = "";
        }
        return;
      }

      typingBarEl.classList.remove("is-visible");
      typingBarEl.classList.add("is-hiding");

      typingBarHideTimer = setTimeout(() => {
        typingBarEl.hidden = true;
        typingBarEl.classList.remove("is-hiding");
        if (typingBarUsersEl){
          typingBarUsersEl.dataset.textKey = "";
          typingBarUsersEl.innerHTML = "";
        }
      }, 180);
    } else if (typingBarUsersEl){
      typingBarUsersEl.dataset.textKey = "";
      typingBarUsersEl.innerHTML = "";
    }
  };

  ensureOnlinePillMount(isSlideshow);

  const chatActive = (views.chat?.dataset?.active === "true");
  if ((!isRoom && !isSlideshow) || (!chatActive && !document.body.classList.contains("slideshow-full"))){
    onlinePill.hidden = true;
    onlineListEl.innerHTML = "";
    onlineTiles.clear();
    slideshowEditorsShown = false;
    syncSlideshowEditorsToggle();
    hideTypingBar();
    return;
  }

  onlinePill.hidden = false;

  let entries = [];

  if (isSlideshow){
    entries = Array.from(onlinePresenceCache.values()).map((p) => {
      const live = liveUserCache.get(p.code) || null;
      const uname = (p.username || live?.username || "User");
      const dname = (live?.displayName || p.displayName || uname);
      return {
        code: p.code,
        username: uname,
        usernameLower: p.usernameLower || String(uname).toLowerCase(),
        displayName: dname,
        displayNameLower: live?.displayNameLower || p.displayNameLower || String(dname).toLowerCase(),
        typing: false,
        idle: !!p.idle,
        status: p.idle ? "idle" : "online"
      };
    });
  } else {
    const memberCodes = Array.from(roomMembersCache.keys());

    for (const code of onlinePresenceCache.keys()){
      if (!roomMembersCache.has(code) && !memberCodes.includes(code)) memberCodes.push(code);
    }
    for (const code of roomCallMembersCache.keys()){
      if (!roomMembersCache.has(code) && !memberCodes.includes(code)) memberCodes.push(code);
    }

    entries = memberCodes.filter((code) => !isGhostModeEnabledForRoom(currentRoomId, code)).map((code) => {
      const p = onlinePresenceCache.get(code) || null;
      const live = liveUserCache.get(code) || null;

      const uname = (p?.username || live?.username || "User");
      const unameLower = (p?.usernameLower || String(live?.username || uname).toLowerCase());
      const dname = (live?.displayName || p?.displayName || uname);
      const dnameLower = (live?.displayNameLower || p?.displayNameLower || String(dname).toLowerCase());

      const inCall = roomCallMembersCache.has(code);
      const hasRoomOpen = !!p;

      let status = "offline";
      if (hasRoomOpen || inCall) status = (hasRoomOpen && p?.idle) ? "idle" : "online";

      return {
        code,
        username: uname,
        usernameLower: unameLower,
        displayName: dname,
        displayNameLower: dnameLower,
        typing: !!(hasRoomOpen && p?.typing),
        idle: !!(hasRoomOpen && p?.idle),
        status
      };
    });
  }

  const nameKey = (x) => String((liveUserCache.get(x.code)?.displayNameLower || liveUserCache.get(x.code)?.usernameLower || x.displayNameLower || x.usernameLower || x.code)).toLowerCase();
  const stableSort = (arr) => arr.sort((a,b) => {
    const c = nameKey(a).localeCompare(nameKey(b));
    return c !== 0 ? c : String(a.code).localeCompare(String(b.code));
  });

  if (isSlideshow){
    const activeGroup = entries.filter(x => x.status !== "idle");
    const idleGroup = entries.filter(x => x.status === "idle");
    stableSort(activeGroup);
    stableSort(idleGroup);
    entries = [...activeGroup, ...idleGroup];
    if (onlineLabelEl) onlineLabelEl.textContent = `Editing - ${entries.length}`;
    syncSlideshowEditorsToggle(entries.length);
    hideTypingBar();
  } else {
    const activeGroup = entries.filter(x => x.status !== "offline");
    const offlineGroup = entries.filter(x => x.status === "offline");
    stableSort(activeGroup);
    stableSort(offlineGroup);
    entries = [...activeGroup, ...offlineGroup];
    syncSlideshowEditorsToggle(0);
    if (onlineLabelEl) onlineLabelEl.textContent = `Members - ${entries.length}`;

    const typingUsers = activeGroup.filter((x) => x.typing && x.code !== currentUser?.code);

    if (typingBarEl){
      const showTypingBar = typingMode === "bar" && typingUsers.length > 0;

      clearTimeout(typingBarHideTimer);

      if (showTypingBar){
        typingBarEl.hidden = false;
        typingBarEl.classList.remove("is-hiding");
        typingBarEl.classList.add("is-visible");
      } else {
        hideTypingBar();
      }

      if (typingBarUsersEl){
        if (showTypingBar) {
          let text = "";
          let textKey = "";

          if (typingUsers.length >= 5){
            text = "Several people are typing";
            textKey = text;
          } else {
            const names = typingUsers.map((user) => {
              const live = liveUserCache.get(user.code) || null;
              const uname = String(live?.displayName || user.displayName || live?.username || user.username || "User");
              return {
                html: `<strong>${escapeHtml(uname)}</strong>`,
                text: uname
              };
            });

            if (names.length === 1){
              text = `${names[0].html} is typing`;
              textKey = `${names[0].text}|1`;
            } else if (names.length === 2){
              text = `${names[0].html} and ${names[1].html} are typing`;
              textKey = `${names[0].text}|${names[1].text}|2`;
            } else {
              const last = names.pop();
              text = `${names.map((x) => x.html).join(", ")}, and ${last.html} are typing`;
              textKey = `${names.map((x) => x.text).join("|")}|${last.text}|${typingUsers.length}`;
            }
          }

          if (typingBarUsersEl.dataset.textKey !== textKey){
            typingBarUsersEl.dataset.textKey = textKey;
            typingBarUsersEl.innerHTML = `<span class="typing-bar-users-inner">${text}</span>`;
          }
        }
      }
    }
  }

  const frag = document.createDocumentFragment();
  const keep = new Set();

  for (const p of entries){
    const code = p.code;
    keep.add(code);

    ensureLiveUserListener(code);

    let tile = onlineTiles.get(code);
    if (!tile){
      const wrap = document.createElement("div");
      wrap.dataset.usercode = code;

      const ava = document.createElement("div");
      ava.className = "mini-avatar online-ava-img";

      const typing = document.createElement("div");
      typing.className = "online-typing";
      typing.innerHTML = '<span class="dot"></span><span class="dot"></span><span class="dot"></span>';

      const tip = document.createElement("div");
      tip.className = "online-tooltip";

      wrap.className = isSlideshow
        ? "online-ava member-row slideshow-editor-row"
        : "online-ava member-row";

      const avatarWrap = document.createElement("div");
      avatarWrap.className = "member-avatar-wrap";

      const status = document.createElement("div");
      status.className = "member-status-dot";

      const meta = document.createElement("div");
      meta.className = "member-meta";

      const nameRow = document.createElement("div");
      nameRow.className = "member-name-row";

      const name = document.createElement("div");
      name.className = "member-name";
      name.dataset.displayNameUsercode = code;

      const activity = document.createElement("span");
      activity.className = "member-activity-indicator";
      activity.setAttribute("aria-hidden", "true");

      const sub = document.createElement("div");
      sub.className = "member-sub";

      avatarWrap.appendChild(ava);
      avatarWrap.appendChild(status);
      avatarWrap.appendChild(typing);

      nameRow.appendChild(name);
      if (!isSlideshow) nameRow.appendChild(activity);

      meta.appendChild(nameRow);
      meta.appendChild(sub);

      wrap.appendChild(avatarWrap);
      wrap.appendChild(meta);
      wrap.appendChild(tip);

      tile = { wrap, ava, tip, typing, status, meta, nameRow, name, activity, sub };

      onlineTiles.set(code, tile);
    }

    const isOffline = p.status === "offline";
    const isIdle = p.status === "idle";
    tile.wrap.classList.toggle("typing", ((p.status === "online" || p.status === "idle") && !!p.typing));
    tile.wrap.classList.toggle("offline", isOffline);
    tile.wrap.classList.toggle("idle", isIdle);

    const live = liveUserCache.get(code) || null;
    const uname = String(live?.displayName || p.displayName || live?.username || p.username || "User");

    const classNameNow = isSlideshow ? "" : getClassNameAtTimestamp(accurateNowMs(), { username: live?.username || p.username || uname, dayType: scheduleType || "full" });
    const memberStatusText = classNameNow || "";
    const presenceText = isOffline ? "Offline" : (isIdle ? "Idle" : "Online");
    const activityItems = isSlideshow ? [] : getUserActivityItems(live || p);
    const activityLabel = isSlideshow ? "" : getUserActivityLabel(live || p);
    const tipParts = [uname, presenceText];
    if (memberStatusText) tipParts.push(memberStatusText);
    if (activityLabel) tipParts.push(activityLabel);
    tile.tip.textContent = tipParts.join(" · ");

    if (tile.status) tile.status.dataset.state = isOffline ? "offline" : (isIdle ? "idle" : "online");
    if (tile.name) tile.name.textContent = uname;
    if (tile.activity){
      tile.activity.hidden = !activityItems.length;
      tile.activity.title = activityLabel || "";
      tile.activity.innerHTML = userActivityIconsMarkup(activityItems, "member-activity-icon");
    }
    if (tile.sub){
      tile.sub.hidden = !memberStatusText;
      tile.sub.textContent = memberStatusText;
    }

    if (code === currentUser?.code){
      applyAvatar(tile.ava, live || currentUser);
    } else if (live){
      applyAvatar(tile.ava, live);
    } else {
      applyAvatar(tile.ava, { code, username: uname, photoDataURL: defaultStickmanDataURL(), photoTransform: null });
    }

    if (isSlideshow){
      const sid = String(slideshowLocationsCache.get(code)?.slideId || "");
      const canJump = !!(sid && Array.isArray(slideshowOrder) && slideshowOrder.includes(sid));
      tile.wrap.classList.toggle("can-jump", canJump);
      tile.wrap.classList.toggle("no-jump", !canJump);
      tile.wrap.onclick = canJump ? (() => slideshowJumpToSlide(sid)) : null;
      if (canJump) tile.wrap.removeAttribute("aria-disabled");
      else tile.wrap.setAttribute("aria-disabled", "true");
    } else {
      tile.wrap.classList.remove("can-jump", "no-jump");
      tile.wrap.onclick = null;
      tile.wrap.removeAttribute("aria-disabled");
    }

    frag.appendChild(tile.wrap);
  }

  for (const [code, tile] of onlineTiles){
    if (!keep.has(code)){
      tile.wrap.remove();
      onlineTiles.delete(code);
    }
  }

  const orderedNodes = Array.from(frag.childNodes);
  orderedNodes.forEach((node, index) => {
    const current = onlineListEl.childNodes[index] || null;
    if (current !== node) onlineListEl.insertBefore(node, current);
  });
  while (onlineListEl.childNodes.length > orderedNodes.length){
    onlineListEl.removeChild(onlineListEl.lastChild);
  }
}

function refreshOnlineIndicatorStatusTexts(){
  if (!onlineListEl) return;

  onlineListEl.querySelectorAll(".online-ava.member-row:not(.slideshow-editor-row)[data-usercode]").forEach((row) => {
    const code = String(row.dataset.usercode || "");
    if (!code) return;

    const live = liveUserCache.get(code) || (String(currentUser?.code || "") === code ? currentUser : null);
    if (!live) return;

    const nameEl = row.querySelector(".member-name");
    const subEl = row.querySelector(".member-sub");
    const tipEl = row.querySelector(".online-tooltip");
    const activityEl = row.querySelector(".member-activity-indicator");
    const isOffline = row.classList.contains("offline");
    const isIdle = row.classList.contains("idle");

    const uname = String(live.displayName || live.username || "User");
    const classNameNow = getClassNameAtTimestamp(accurateNowMs(), {
      username: live.username || uname,
      dayType: scheduleType || "full"
    });
    const memberStatusText = classNameNow || "";
    const presenceText = isOffline ? "Offline" : (isIdle ? "Idle" : "Online");
    const activityItems = getUserActivityItems(live);
    const activityLabel = getUserActivityLabel(live);
    const tipParts = [uname, presenceText];
    if (memberStatusText) tipParts.push(memberStatusText);
    if (activityLabel) tipParts.push(activityLabel);
    const tipText = tipParts.join(" · ");

    if (nameEl && nameEl.textContent !== uname) nameEl.textContent = uname;
    if (activityEl){
      activityEl.hidden = !activityItems.length;
      activityEl.title = activityLabel || "";
      activityEl.innerHTML = userActivityIconsMarkup(activityItems, "member-activity-icon");
    }
    if (subEl){
      subEl.hidden = !memberStatusText;
      if (subEl.textContent !== memberStatusText) subEl.textContent = memberStatusText;
    }
    if (tipEl && tipEl.textContent !== tipText) tipEl.textContent = tipText;
  });
}

function startRoomPresence(roomId){
  if (!currentUser) return;
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  stopRoomPresence();

  myPresenceRef = db.ref(`rooms/${id}/online/${currentUser.code}`);

  const writePresence = async () => {
    if (!myPresenceRef || !currentUser) return;

    if (isGhostModeEnabledForRoom(id, currentUser.code)){
      try{ await myPresenceRef.onDisconnect().cancel(); }catch{}
      try{ await myPresenceRef.remove(); }catch{}
      return;
    }

    const uname = currentUser.username || "User";
    const dname = currentUser.displayName || uname;
    const payload = {
      code: currentUser.code,
      username: uname,
      usernameLower: uname.toLowerCase(),
      displayName: dname,
      displayNameLower: dname.toLowerCase(),
      typing: false,
      idle: !!document.hidden || !!myRoomIdle,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    };

    try{ await myPresenceRef.onDisconnect().remove(); }catch{}
    try{ await myPresenceRef.set(payload); }catch{}
  };

  writePresence();
  startRoomIdleTracking();

  presenceConnRef = db.ref(".info/connected");
  presenceConnCb = (snap) => {
    if (snap.val() === true){
      writePresence();
      scheduleRoomIdleCheck();
    }
  };
  presenceConnRef.on("value", presenceConnCb);
}

function stopRoomPresence(){
  stopRoomIdleTracking();
  try{ if (typingIdleTimer) clearTimeout(typingIdleTimer); }catch{}
  typingIdleTimer = null;
  myTyping = false;

  if (presenceConnRef && presenceConnCb){
    try{ presenceConnRef.off("value", presenceConnCb); }catch{}
  }
  presenceConnRef = null;
  presenceConnCb = null;

  if (myPresenceRef){
    try{ myPresenceRef.onDisconnect().cancel(); }catch{}
    try{ myPresenceRef.remove(); }catch{}
  }
  myPresenceRef = null;
}

function startSlideshowPresence(){
  if (!currentUser) return;

  stopSlideshowPresence();

  mySlideshowPresenceRef = db.ref(`slideshow/online/${currentUser.code}`);
  mySlideshowActivityRef = db.ref(`users/${currentUser.code}/slideshowActivity`);

  const writePresence = async () => {
    if (!mySlideshowPresenceRef || !mySlideshowActivityRef || !currentUser) return;
    const uname = currentUser.username || "User";
    const dname = currentUser.displayName || uname;
    const payload = {
      code: currentUser.code,
      username: uname,
      usernameLower: uname.toLowerCase(),
      displayName: dname,
      displayNameLower: dname.toLowerCase(),
      idle: !!document.hidden || !!mySlideshowIdle,
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    };
    const activityPayload = {
      active: true,
      label: "Editing Slideshow",
      updatedAt: firebase.database.ServerValue.TIMESTAMP
    };

    try{ await mySlideshowPresenceRef.onDisconnect().remove(); }catch{}
    try{ await mySlideshowActivityRef.onDisconnect().remove(); }catch{}
    try{ await mySlideshowPresenceRef.set(payload); }catch{}
    try{ await mySlideshowActivityRef.set(activityPayload); }catch{}
  };

  writePresence();
  startSlideshowIdleTracking();

  slideshowConnRef = db.ref(".info/connected");
  slideshowConnCb = (snap) => {
    if (snap.val() === true){
      writePresence();
      scheduleSlideshowIdleCheck();
    }
  };
  slideshowConnRef.on("value", slideshowConnCb);
}

function stopSlideshowPresence(){
  detachSlideshowLocations();
  stopSlideshowIdleTracking();

  if (slideshowConnRef && slideshowConnCb){
    try{ slideshowConnRef.off("value", slideshowConnCb); }catch{}
  }
  slideshowConnRef = null;
  slideshowConnCb = null;

  if (mySlideshowPresenceRef){
    try{ mySlideshowPresenceRef.onDisconnect().cancel(); }catch{}
    try{ mySlideshowPresenceRef.remove(); }catch{}
  }
  mySlideshowPresenceRef = null;

  if (mySlideshowActivityRef){
    try{ mySlideshowActivityRef.onDisconnect().cancel(); }catch{}
    try{ mySlideshowActivityRef.remove(); }catch{}
  }
  mySlideshowActivityRef = null;

  if (mySlideshowLocationRef){
    try{ mySlideshowLocationRef.onDisconnect().cancel(); }catch{}
    try{ mySlideshowLocationRef.remove(); }catch{}
  }
  mySlideshowLocationRef = null;
  mySlideshowLocationSlideId = null;
}

function setMyTyping(val){
  const next = !!val;
  if (next === myTyping) return;
  myTyping = next;

  if (!myPresenceRef) return;
  try{
    myPresenceRef.update({ typing: next, updatedAt: firebase.database.ServerValue.TIMESTAMP });
  }catch{}
}

function bumpMyTyping(){
  if (!myPresenceRef) return;
  setMyTyping(true);
  if (typingIdleTimer) clearTimeout(typingIdleTimer);
  typingIdleTimer = setTimeout(() => setMyTyping(false), 900);
}

function isChatRoomPresenceActive(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  return !!(currentUser && myPresenceRef && currentRoomId && placeNow.startsWith("room:") && views.chat?.dataset?.active === "true");
}

function isRoomIdleNow(){
  if (document.hidden) return true;
  if (!lastRoomInputAtMs) return false;
  return (accurateNowMs() - lastRoomInputAtMs) >= ROOM_IDLE_MS;
}

function writeMyRoomIdle(next, opts = {}){
  const idle = !!next;
  const force = !!opts.force;
  if (!force && idle === myRoomIdle) return;

  myRoomIdle = idle;

  const selfCode = String(currentUser?.code || "");
  if (selfCode && onlinePresenceCache.has(selfCode)){
    onlinePresenceCache.set(selfCode, {
      ...(onlinePresenceCache.get(selfCode) || {}),
      idle
    });
    try{ renderOnlineIndicator(); }catch{}
  }

  if (!myPresenceRef) return;
  try{
    myPresenceRef.update({ idle, updatedAt: firebase.database.ServerValue.TIMESTAMP });
  }catch{}
}

function scheduleRoomIdleCheck(){
  try{ if (roomIdleTimer) clearTimeout(roomIdleTimer); }catch{}
  roomIdleTimer = null;

  if (!isChatRoomPresenceActive()) return;

  if (document.hidden){
    writeMyRoomIdle(true);
    return;
  }

  const elapsed = Math.max(0, accurateNowMs() - (lastRoomInputAtMs || accurateNowMs()));
  const delay = Math.max(250, ROOM_IDLE_MS - elapsed);

  roomIdleTimer = setTimeout(() => {
    if (!isChatRoomPresenceActive()) return;
    writeMyRoomIdle(isRoomIdleNow());
    scheduleRoomIdleCheck();
  }, delay);
}

function markRoomInputActive(){
  if (!isChatRoomPresenceActive()) return;
  lastRoomInputAtMs = accurateNowMs();
  if (!document.hidden) writeMyRoomIdle(false);
  scheduleRoomIdleCheck();
}

function handleRoomIdleVisibilityChange(){
  if (!isChatRoomPresenceActive()) return;

  if (document.hidden){
    writeMyRoomIdle(true);
    scheduleRoomIdleCheck();
    return;
  }

  lastRoomInputAtMs = accurateNowMs();
  writeMyRoomIdle(false);
  scheduleRoomIdleCheck();
}

function handleRoomIdleBlur(){
  if (!isChatRoomPresenceActive()) return;
  writeMyRoomIdle(true);
}

function startRoomIdleTracking(){
  lastRoomInputAtMs = accurateNowMs();
  myRoomIdle = !!document.hidden;

  if (!roomIdleEventBound){
    roomIdleEventBound = true;
    document.addEventListener("visibilitychange", handleRoomIdleVisibilityChange);
    window.addEventListener("focus", handleRoomIdleVisibilityChange);
    window.addEventListener("blur", handleRoomIdleBlur);
    document.addEventListener("keydown", markRoomInputActive, true);
    document.addEventListener("pointerdown", markRoomInputActive, true);
    document.addEventListener("pointermove", markRoomInputActive, { passive:true, capture:true });
    document.addEventListener("wheel", markRoomInputActive, { passive:true, capture:true });
  }

  writeMyRoomIdle(isRoomIdleNow(), { force:true });
  scheduleRoomIdleCheck();
}

function stopRoomIdleTracking(){
  try{ if (roomIdleTimer) clearTimeout(roomIdleTimer); }catch{}
  roomIdleTimer = null;

  if (roomIdleEventBound){
    roomIdleEventBound = false;
    document.removeEventListener("visibilitychange", handleRoomIdleVisibilityChange);
    window.removeEventListener("focus", handleRoomIdleVisibilityChange);
    window.removeEventListener("blur", handleRoomIdleBlur);
    document.removeEventListener("keydown", markRoomInputActive, true);
    document.removeEventListener("pointerdown", markRoomInputActive, true);
    document.removeEventListener("pointermove", markRoomInputActive, { capture:true });
    document.removeEventListener("wheel", markRoomInputActive, { capture:true });
  }

  myRoomIdle = false;
  lastRoomInputAtMs = 0;
}

function isSlideshowPresenceActive(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  return !!(currentUser && mySlideshowPresenceRef && placeNow === "slideshow" && document.body.classList.contains("slideshow-full"));
}

function isSlideshowIdleNow(){
  if (document.hidden) return true;
  if (!lastSlideshowInputAtMs) return false;
  return (accurateNowMs() - lastSlideshowInputAtMs) >= ROOM_IDLE_MS;
}

function writeMySlideshowIdle(next, opts = {}){
  const idle = !!next;
  const force = !!opts.force;
  if (!force && idle === mySlideshowIdle) return;

  mySlideshowIdle = idle;

  const selfCode = String(currentUser?.code || "");
  if (selfCode && onlinePresenceCache.has(selfCode)){
    onlinePresenceCache.set(selfCode, {
      ...(onlinePresenceCache.get(selfCode) || {}),
      idle
    });
    try{ renderOnlineIndicator(); }catch{}
  }

  if (!mySlideshowPresenceRef) return;
  try{
    mySlideshowPresenceRef.update({ idle, updatedAt: firebase.database.ServerValue.TIMESTAMP });
  }catch{}
}

function scheduleSlideshowIdleCheck(){
  try{ if (slideshowIdleTimer) clearTimeout(slideshowIdleTimer); }catch{}
  slideshowIdleTimer = null;

  if (!isSlideshowPresenceActive()) return;

  if (document.hidden){
    writeMySlideshowIdle(true);
    return;
  }

  const elapsed = Math.max(0, accurateNowMs() - (lastSlideshowInputAtMs || accurateNowMs()));
  const delay = Math.max(250, ROOM_IDLE_MS - elapsed);

  slideshowIdleTimer = setTimeout(() => {
    if (!isSlideshowPresenceActive()) return;
    writeMySlideshowIdle(isSlideshowIdleNow());
    scheduleSlideshowIdleCheck();
  }, delay);
}

function markSlideshowInputActive(){
  if (!isSlideshowPresenceActive()) return;
  lastSlideshowInputAtMs = accurateNowMs();
  if (!document.hidden) writeMySlideshowIdle(false);
  scheduleSlideshowIdleCheck();
}

function handleSlideshowIdleVisibilityChange(){
  if (!isSlideshowPresenceActive()) return;

  if (document.hidden){
    writeMySlideshowIdle(true);
    scheduleSlideshowIdleCheck();
    return;
  }

  lastSlideshowInputAtMs = accurateNowMs();
  writeMySlideshowIdle(false);
  scheduleSlideshowIdleCheck();
}

function handleSlideshowIdleBlur(){
  if (!isSlideshowPresenceActive()) return;
  writeMySlideshowIdle(true);
}

function startSlideshowIdleTracking(){
  lastSlideshowInputAtMs = accurateNowMs();
  mySlideshowIdle = !!document.hidden;

  if (!slideshowIdleEventBound){
    slideshowIdleEventBound = true;
    document.addEventListener("visibilitychange", handleSlideshowIdleVisibilityChange);
    window.addEventListener("focus", handleSlideshowIdleVisibilityChange);
    window.addEventListener("blur", handleSlideshowIdleBlur);
    document.addEventListener("keydown", markSlideshowInputActive, true);
    document.addEventListener("pointerdown", markSlideshowInputActive, true);
    document.addEventListener("pointermove", markSlideshowInputActive, { passive:true, capture:true });
    document.addEventListener("wheel", markSlideshowInputActive, { passive:true, capture:true });
  }

  writeMySlideshowIdle(isSlideshowIdleNow(), { force:true });
  scheduleSlideshowIdleCheck();
}

function stopSlideshowIdleTracking(){
  try{ if (slideshowIdleTimer) clearTimeout(slideshowIdleTimer); }catch{}
  slideshowIdleTimer = null;

  if (slideshowIdleEventBound){
    slideshowIdleEventBound = false;
    document.removeEventListener("visibilitychange", handleSlideshowIdleVisibilityChange);
    window.removeEventListener("focus", handleSlideshowIdleVisibilityChange);
    window.removeEventListener("blur", handleSlideshowIdleBlur);
    document.removeEventListener("keydown", markSlideshowInputActive, true);
    document.removeEventListener("pointerdown", markSlideshowInputActive, true);
    document.removeEventListener("pointermove", markSlideshowInputActive, { capture:true });
    document.removeEventListener("wheel", markSlideshowInputActive, { capture:true });
  }

  mySlideshowIdle = false;
  lastSlideshowInputAtMs = 0;
}

let msgElByKey = new Map(); // messageKey -> row element
let msgDataByKey = new Map(); // messageKey -> message payload (for reply previews)

let replyState = null; // { key, userCode, username }
let replyBarEl = null;
let replyBarTextEl = null;
let replyBarMessageEl = null;
let replyBarAvatarEl = null;
