window.addEventListener("resize", rafThrottle(() => {
  if (!document.body.classList.contains("slideshow-full")) return;
  fitSlideshowStage();
  slideshowThumbsSig = "";
  scheduleRenderSlideshowUI();
  try{
    if (Array.isArray(slideshowOrder)){
      for (const id of slideshowOrder){
        const doc = slideshowDocCache.get(id);
        if (doc) scheduleSlideshowThumbRender(id, doc);
      }
    }
  }catch{}
}), { passive:true });

let chatOverlaysEl = null;

let pingBarEl = null;
let pingListEl = null;
let pingBarQueryEl = null;
let pingBarCountEl = null;
let pingBarCloseEl = null;
let pingTokenStart = -1;
let pingRosterRef = null;
let pingRosterCb = null;
let pingRosterValCache = null;

let filesBarEl = null;
let filesListEl = null;
let filesBarCountEl = null;
let filesBarLimitEl = null;
let filesBarCloseEl = null;

let pendingFiles = []; // regular files + voice messages
let pendingGifs  = []; // up to 2
let overlaysInited = false;

function isVoicePendingFile(item){
  return !!item?.isVoiceMessage;
}
function countPendingVoiceMessages(){
  return pendingFiles.filter(isVoicePendingFile).length;
}
function countPendingStandardFiles(){
  return pendingFiles.filter((item) => !isVoicePendingFile(item)).length;
}
function getTotalPendingAttachmentCount(){
  return pendingFiles.length + pendingGifs.length;
}

let msgMenuEl = null;
let msgMenuUserEl = null;
let msgMenuBtns = null;
let msgMenuCtx = null; // { key, userCode, username, displayName, text }
let msgMenuCloseSeq = 0;
let msgMenuCloseOnEnd = null;
let msgMenuAnchorEl = null;
let msgMenuAnchorBubble = null;
let editState = null; // { key, roomId, originalText }

function beginEditMessage(msg){
  const roomId = sanitizeRoomCode(currentRoomId);
  if (!currentUser || !roomId || !msg?._key) return;
  if (String(msg.userCode || "") !== String(currentUser.code || "")) return;

  initOverlaysUI();

  try{ clearReplyState({ quiet:true }); }catch{}
  try{ clearPendingFiles({ quiet:true }); }catch{}
  try{ closePingBar({ quiet:true }); }catch{}

  editState = {
    key: String(msg._key),
    roomId,
    originalText: String(msg.text || "")
  };

  const input = $("msg-input");
  if (input){
    input.value = String(msg.text || "");
    lastMsgInputVal = input.value;
    input.placeholder = "Edit your message…";
    try{
      input.focus();
      input.setSelectionRange(input.value.length, input.value.length);
    }catch{}
  }

  try{ syncComposerPreviewHeight(); }catch{}
  try{ syncChatOverlayMetrics(); }catch{}
  syncComposerPrimaryAction();
}

function cancelEditMessage({ keepText=false, quiet=false } = {}){
  if (!editState){
    if (!quiet) syncComposerPrimaryAction();
    return;
  }

  editState = null;

  const input = $("msg-input");
  if (input){
    if (!keepText){
      input.value = "";
      lastMsgInputVal = "";
    }
    input.placeholder = "Type a message…";
  }

  try{ syncComposerPreviewHeight(); }catch{}
  try{ syncChatOverlayMetrics(); }catch{}
  syncComposerPrimaryAction();
}

let _scrollLocked = false;
const _preventScroll = (e) => { e.preventDefault(); };

function initOverlaysUI(){
  if (overlaysInited) return;
  overlaysInited = true;

  // Reply UI
  replyBarEl = $("reply-bar");
  replyBarTextEl = $("reply-bar-text");
  replyBarMessageEl = $("reply-bar-message");
  replyBarAvatarEl = $("reply-bar-avatar");
  replyBarCloseEl = $("reply-bar-close");
  replyBarCloseEl?.addEventListener("click", () => clearReplyState());

  // Ping UI
  pingBarEl = $("ping-bar");
  pingListEl = $("ping-list");
  pingBarQueryEl = $("ping-bar-query");
  pingBarCountEl = $("ping-bar-count");
  pingBarCloseEl = $("ping-bar-close");
  pingBarCloseEl?.addEventListener("click", () => closePingBar());

  // Files UI
  chatOverlaysEl = $("chat-overlays");
  filesBarEl = $("files-bar");
  filesListEl = $("files-list");
  filesBarCountEl = $("files-bar-count");
  filesBarLimitEl = $("files-bar-limit");
  filesBarCloseEl = $("files-bar-close");
  filesBarCloseEl?.addEventListener("click", () => clearPendingFiles());

  window.addEventListener("resize", () => syncChatOverlayMetrics(), { passive:true });
  requestAnimationFrame(syncChatOverlayMetrics);
}

function syncChatOverlayMetrics(){
  const main = document.querySelector(".chat-main");
  const composer = $("composer") || document.querySelector(".composer");
  if (!main || !composer) return;

  const composerH = Math.round(composer.getBoundingClientRect().height || 0);
  main.style.setProperty("--composer-h", `${composerH}px`);

  const overlays = chatOverlaysEl || $("chat-overlays");
  const anyOpen =
    (!!replyBarEl && !replyBarEl.hidden) ||
    (!!pingBarEl && !pingBarEl.hidden) ||
    (!!filesBarEl && !filesBarEl.hidden);

  const overlaysH = (overlays && anyOpen)
    ? Math.round(overlays.getBoundingClientRect().height || 0)
    : 0;

  main.style.setProperty("--overlays-h", `${overlaysH}px`);

  // boxes are true overlays; do not shift chat content/scroll
  scheduleOverlayShiftUpdate(true);
}

// ===== Overlay Shift (Option B: shift whenever user is near bottom) =====
let _overlayShift = 0;
let _overlayShiftRAF = 0;

function isNearChatBottom(th = 28){
  if (!messagesEl) return true;
  const dist = messagesEl.scrollHeight - (messagesEl.scrollTop + messagesEl.clientHeight);
  return dist <= th;
}

function applyOverlayShift(force = false){
  // Per requirement: reply/files boxes must NOT affect chat length or scroll.
  const main = document.querySelector(".chat-main");
  if (!main) return;

  if (!force && _overlayShift === 0) return;
  _overlayShift = 0;

  main.style.setProperty("--overlays-shift", "0px");
  if (messagesListEl && messagesListEl !== messagesEl){
    messagesListEl.style.transform = "translateY(0px)";
  }
}

function scheduleOverlayShiftUpdate(force = false){
  if (_overlayShiftRAF) return;
  _overlayShiftRAF = requestAnimationFrame(() => {
    _overlayShiftRAF = 0;
    applyOverlayShift(force);
  });
}

function readFileAsDataURL(file){
  return new Promise((resolve, reject) => {
    const fr = new FileReader();
    fr.onload = () => resolve(String(fr.result || ""));
    fr.onerror = () => reject(fr.error || new Error("read failed"));
    fr.readAsDataURL(file);
  });
}

function getRoomIconMenuPayload(roomId){
  const id = sanitizeRoomCode(roomId);
  const meta = id ? (roomsMetaCache.get(id) || null) : null;
  const dataURL = String(meta?.photoDataURL || defaultStickmanDataURL());
  return {
    id,
    dataURL,
    fileName: id ? `room-${id}-icon.${inferImageExt(dataURL)}` : `room-icon.${inferImageExt(dataURL)}`
  };
}

function openRoomIconContextMenu(e, roomId, anchorEl){
  e.preventDefault();
  e.stopPropagation();

  const payload = getRoomIconMenuPayload(roomId);
  if (!payload.id || !payload.dataURL) return;

  closeMsgMenu(true);
  openMsgMenuFor(anchorEl || e.currentTarget || document.body, {
    menu: "roomIcon",
    username: "Room Icon",
    roomId: payload.id,
    imageDataURL: payload.dataURL,
    imageFileName: payload.fileName,
    pointerX: e.clientX,
    pointerY: e.clientY
  });
}

function openRoomButtonContextMenu(e, roomId, anchorEl){
  e.preventDefault();
  e.stopPropagation();

  const payload = getRoomIconMenuPayload(roomId);
  if (!payload.id || !payload.dataURL) return;

  closeMsgMenu(true);
  const meta = roomsMetaCache.get(payload.id) || null;
  openMsgMenuFor(anchorEl || e.currentTarget || document.body, {
    menu: "roomButton",
    username: isPrivateRoomMeta(meta) ? "Private" : "Public",
    roomId: payload.id,
    imageDataURL: payload.dataURL,
    imageFileName: payload.fileName,
    pointerX: e.clientX,
    pointerY: e.clientY
  });
}

function bindRoomIconContextMenu(el, roomId){
  if (!el || el.dataset.roomIconContextBound === "1") return;
  el.dataset.roomIconContextBound = "1";
  el.addEventListener("contextmenu", (e) => openRoomIconContextMenu(e, roomId, el));
}

function openRoomIconEditor(roomIdOverride = currentRoomId){
  const id = sanitizeRoomCode(roomIdOverride);
  if (!id || !currentUser){
    showToast({ title:"Pick a room", body:"Open a room first.", duration: 2200 });
    return;
  }

  const meta = roomsMetaCache.get(id) || null;
  const initialDataURL = String(meta?.photoDataURL || defaultStickmanDataURL());
  const initialTransform = normalizeTransformToRel(meta?.photoTransform, 132);

  openModal({
    title: `Edit Room ${id} Icon`,
    bodyHTML: `
      <input id="room-icon-editor-file" type="file" accept="image/png,image/jpeg,image/jpg,image/gif" hidden />

      <div class="upload" style="margin-top:8px">
        <div class="upload-ui">
          <div class="upload-left">
            <div class="avatar-wrap">
              <div class="avatar-ring" style="width:132px; height:132px">
                <div class="avatar-clip" id="room-icon-editor-clip">
                  <img id="room-icon-editor-img" alt="Room Icon" draggable="false" />
                </div>
              </div>
            </div>
            <div class="upload-text">
              <div class="strong">Upload PNG / JPG / GIF</div>
              <div class="muted small">Drag + zoom for more customization.</div>
            </div>
          </div>

          <div class="upload-actions-stack">
            <div class="upload-actions-row">
              <button class="btn tiny" id="btn-room-icon-choose" type="button">Choose</button>
              <button class="btn tiny" id="btn-room-icon-use-default" type="button">Use Default</button>
            </div>
            <div class="upload-actions-row">
              <button class="btn tiny" id="btn-room-icon-download" type="button">Download Icon</button>
              <button class="btn tiny" id="btn-room-icon-copy-address" type="button">Copy Icon Address</button>
            </div>
          </div>
        </div>
      </div>

      <div class="crop-controls" id="room-icon-editor-controls">
        <div class="row">
          <div class="muted small">Drag the picture in the circle.</div>
        </div>
        <div class="row">
          <label class="label small" for="room-icon-editor-zoom">Zoom</label>
          <input id="room-icon-editor-zoom" type="range" min="1.0" max="3.0" step="0.01" value="1.0" style="width:100%" />
        </div>
        <div class="row">
          <button class="btn tiny" id="btn-room-icon-center" type="button">Center</button>
          <button class="btn tiny" id="btn-room-icon-reset" type="button">Reset</button>
        </div>
      </div>
    `,
    actionsHTML: `
      <button class="btn tiny primary" id="btn-room-icon-save" type="button">Save</button>
    `
  });

  const clip = $("room-icon-editor-clip");
  const img = $("room-icon-editor-img");
  const input = $("room-icon-editor-file");
  const zoom = $("room-icon-editor-zoom");
  const btnChoose = $("btn-room-icon-choose");
  const btnUseDefault = $("btn-room-icon-use-default");
  const btnDownloadIcon = $("btn-room-icon-download");
  const btnCopyIconAddress = $("btn-room-icon-copy-address");
  const btnCenter = $("btn-room-icon-center");
  const btnReset = $("btn-room-icon-reset");
  const btnSave = $("btn-room-icon-save");

  if (!clip || !img || !input || !zoom || !btnChoose || !btnUseDefault || !btnDownloadIcon || !btnCopyIconAddress || !btnCenter || !btnReset || !btnSave){
    return;
  }

  img.addEventListener("dragstart", (e) => e.preventDefault());

  const clamp = (n, a, b) => Math.min(b, Math.max(a, n));
  const state = {
    dataURL: initialDataURL,
    scale: 1,
    x: 0,
    y: 0,
    dragging: false,
    dragStartX: 0,
    dragStartY: 0,
    startX: 0,
    startY: 0,
    pointerId: null
  };

  function clipSize(){
    const r = clip.getBoundingClientRect();
    const w = Math.round(r.width || 0);
    return Math.max(1, w || 132);
  }

  function applyPreview(){
    img.style.transform = `translate(calc(-50% + ${state.x}px), calc(-50% + ${state.y}px)) scale(${state.scale})`;
  }

  function packTransform(){
    const size = clipSize();
    return {
      unit: "rel",
      scale: state.scale,
      x: (state.x || 0) / size,
      y: (state.y || 0) / size
    };
  }

  function loadFromCurrent(){
    img.src = state.dataURL;
    const px = transformToPixels(initialTransform, clipSize(), 132);
    state.scale = clamp(Number(px.scale) || 1, 0.2, 3.0);
    state.x = Number(px.x) || 0;
    state.y = Number(px.y) || 0;
    zoom.value = String(state.scale);
    applyPreview();
  }

  loadFromCurrent();
  requestAnimationFrame(() => requestAnimationFrame(loadFromCurrent));

  btnChoose.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    closeMsgMenu(true);
    try{ input.value = ""; }catch{}
    setTimeout(() => {
      try{ input.click(); }catch{}
    }, 0);
  });

  btnDownloadIcon.addEventListener("click", async () => {
    if (!state.dataURL) return;
    await downloadFileViaObjectURL(state.dataURL, `room-${id}-icon.${inferImageExt(state.dataURL)}`);
  });

  btnCopyIconAddress.addEventListener("click", async () => {
    if (!state.dataURL) return;
    await copyImageAddress(state.dataURL);
  });
  btnUseDefault.addEventListener("click", async () => {
    btnUseDefault.disabled = true;
    try{
      const patch = {
        photoDataURL: null,
        photoTransform: null
      };
      roomsMetaCache.set(id, {
        ...(roomsMetaCache.get(id) || {}),
        ...patch
      });
      refreshRoomIconSurfaces(id);
      await db.ref(`rooms/${id}`).update(patch);
      closeModal();
      showToast({ title:"Room icon reset", body:`Room ${id} is using the default icon again.`, duration: 2200 });
    }catch{
      btnUseDefault.disabled = false;
      showToast({ title:"Reset failed", body:"Could not restore the default room icon.", duration: 2600 });
    }
  });

  btnCenter.addEventListener("click", () => {
    state.x = 0;
    state.y = 0;
    applyPreview();
  });

  btnReset.addEventListener("click", () => {
    state.scale = 1;
    state.x = 0;
    state.y = 0;
    zoom.value = "1";
    applyPreview();
  });

  function endDrag(){
    if (!state.dragging) return;
    state.dragging = false;
    state.pointerId = null;
  }

  clip.addEventListener("pointerdown", (e) => {
    state.dragging = true;
    state.pointerId = e.pointerId;
    state.dragStartX = e.clientX;
    state.dragStartY = e.clientY;
    state.startX = state.x;
    state.startY = state.y;
    try{ clip.setPointerCapture(e.pointerId); }catch{}
  });

  clip.addEventListener("pointermove", (e) => {
    if (!state.dragging) return;
    if (state.pointerId !== null && e.pointerId !== state.pointerId) return;

    const dx = e.clientX - state.dragStartX;
    const dy = e.clientY - state.dragStartY;
    state.x = state.startX + dx;
    state.y = state.startY + dy;
    applyPreview();
  });

  clip.addEventListener("pointerup", () => endDrag());
  clip.addEventListener("pointercancel", () => endDrag());

  zoom.addEventListener("input", () => {
    state.scale = clamp(Number(zoom.value) || 1, 0.2, 3.0);
    applyPreview();
  });

  input.addEventListener("change", async () => {
    const file = (input.files && input.files[0]) ? input.files[0] : null;
    input.value = "";
    if (!file) return;

    if (!fileTypeOk(file)){
      showToast({ title:"Invalid file", body:"Room icons must be PNG, JPG/JPEG, or GIF.", duration: 2600 });
      return;
    }

    try{
      state.dataURL = await readFileAsDataURL(file);
      state.scale = 1;
      state.x = 0;
      state.y = 0;
      zoom.value = "1";
      img.src = state.dataURL;
      applyPreview();
    }catch{
      showToast({ title:"Read failed", body:"Could not read that file.", duration: 2600 });
    }
  });

  btnSave.addEventListener("click", async () => {
    btnSave.disabled = true;
    try{
      const patch = {
        photoDataURL: state.dataURL,
        photoTransform: packTransform()
      };
      roomsMetaCache.set(id, {
        ...(roomsMetaCache.get(id) || {}),
        ...patch
      });
      refreshRoomIconSurfaces(id);
      await db.ref(`rooms/${id}`).update(patch);
      closeModal();
      showToast({ title:"Room icon updated", body:`Updated the icon for room ${roomDisplayName(id, roomsMetaCache.get(id) || null)}.`, duration: 2200 });
    }catch{
      btnSave.disabled = false;
      showToast({ title:"Upload failed", body:"Could not update the room icon.", duration: 2600 });
    }
  });
}

if (roomIconButtonEl){
  roomIconButtonEl.addEventListener("click", () => {
    openRoomIconEditor();
  });
  roomIconButtonEl.addEventListener("contextmenu", (e) => {
    openRoomIconContextMenu(e, currentRoomId, roomIconButtonEl);
  });
}

function canUsePingBox(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  return !!(currentUser && currentRoomId && placeNow.startsWith("room:") && views.chat.dataset.active === "true");
}

function attachPingRoster(){
  if (pingRosterRef || !canUsePingBox()) return;
  pingRosterRef = db.ref("memberships");
  pingRosterCb = (snap) => {
    pingRosterValCache = snap.exists() ? (snap.val() || {}) : {};
    if (pingBarEl && !pingBarEl.hidden) renderPingList();
  };
  pingRosterRef.on("value", pingRosterCb);
}

function detachPingRoster(){
  if (pingRosterRef && pingRosterCb){
    try{ pingRosterRef.off("value", pingRosterCb); }catch{}
  }
  pingRosterRef = null;
  pingRosterCb = null;
  pingRosterValCache = null;
}

function openPingBar({ tokenStart=null } = {}){
  if (!canUsePingBox()) return;
  initOverlaysUI();
  if (!pingBarEl) return;

  if (typeof tokenStart === "number") pingTokenStart = tokenStart;

  pingBarEl.hidden = false;
  pingBarEl.classList.remove("closing");
  pingBarEl.classList.add("open");
  attachPingRoster();
  renderPingList();
  syncChatOverlayMetrics();
}

function closePingBar({ quiet=false } = {}){
  if (!pingBarEl) return;
  if (pingBarEl.hidden) { syncChatOverlayMetrics(); return; }

  if (quiet){
    pingBarEl.hidden = true;
    pingBarEl.classList.remove("open","closing");
    if (pingListEl) pingListEl.innerHTML = "";
    pingTokenStart = -1;
    detachPingRoster();
    syncChatOverlayMetrics();
    return;
  }

  pingBarEl.classList.remove("open");
  pingBarEl.classList.add("closing");
  const onEnd = () => {
    pingBarEl?.removeEventListener("animationend", onEnd);
    if (pingBarEl){
      pingBarEl.hidden = true;
      pingBarEl.classList.remove("closing");
    }
    if (pingListEl) pingListEl.innerHTML = "";
    pingTokenStart = -1;
    detachPingRoster();
    syncChatOverlayMetrics();
  };
  pingBarEl.addEventListener("animationend", onEnd);
}

function getPingFilter(){
  const input = $("msg-input");
  const val = String(input?.value || "");
  if (!input || pingTokenStart < 0 || pingTokenStart >= val.length) return { query:"", done:true };

  const after = val.slice(pingTokenStart);
  const m = after.match(/^@([A-Za-z0-9_]*)/);
  if (!m) return { query:"", done:true };
  const q = String(m[1] || "");

  // If the next char after the username token is punctuation (not whitespace), stop ping mode.
  const consumedLen = 1 + q.length;
  const nextCh = after[consumedLen] || "";
  if (nextCh && !/\s/.test(nextCh)) return { query:q, done:true };

  const nextSpaceAt = after.search(/\s/);
  if (nextSpaceAt !== -1 && nextSpaceAt <= (input.selectionStart - pingTokenStart)) return { query:q, done:true };

  return { query:q, done:false };
}

function computePingUserList(){
  const root = pingRosterValCache || {};
  const roomId = currentRoomId;
  if (!roomId) return [];

  const out = [];
  for (const [userCode, rooms] of Object.entries(root)){
    if (!userCode) continue;
    if (String(userCode) === String(currentUser?.code || "")) continue;
    if (!rooms || typeof rooms !== "object") continue;
    if (!rooms[roomId]) continue;
    out.push(String(userCode));
  }
  return out;
}

function applyPingSuggestion(name){
  const input = $("msg-input");
  if (!input) return;

  const cleanName = String(name || "").trim();
  if (!cleanName) return;

  const val = String(input.value || "");
  const caret = (typeof input.selectionStart === "number") ? input.selectionStart : val.length;

  const start = Math.max(0, Math.min(pingTokenStart, val.length));
  const end = Math.max(start + 1, caret);

  const mention = `@${cleanName} `;
  const next = val.slice(0, start) + mention + val.slice(end);
  input.value = next;
  lastMsgInputVal = next;

  const newCaret = start + mention.length;
  try{ input.setSelectionRange(newCaret, newCaret); }catch{}
  closePingBar({ quiet:true });
  input.focus();
}

function renderPingList(){
  initOverlaysUI();
  if (!pingListEl || !pingBarEl) return;
  if (pingBarEl.hidden) return;

  const { query, done } = getPingFilter();
  if (done){
    closePingBar({ quiet:true });
    return;
  }

  const q = query.toLowerCase();
  const codes = computePingUserList();

  codes.sort((a, b) => {
    const au = String(liveUserCache.get(a)?.displayName || liveUserCache.get(a)?.username || "").toLowerCase();
    const bu = String(liveUserCache.get(b)?.displayName || liveUserCache.get(b)?.username || "").toLowerCase();
    if (au && bu) return au.localeCompare(bu);
    if (au) return -1;
    if (bu) return 1;
    return a.localeCompare(b);
  });

  // If user fully typed an exact username, auto-close. If they typed an exact display name, rewrite it to the username.
  if (q){
    for (const code of codes){
      const u = liveUserCache.get(code);
      const username = String(u?.username || "").trim();
      const uname = username.toLowerCase();
      const dname = String(u?.displayName || u?.username || "").toLowerCase();
      if (uname && uname === q){
        closePingBar({ quiet:true });
        syncChatOverlayMetrics();
        return;
      }
      if (username && dname && dname === q && dname !== uname){
        applyPingSuggestion(username);
        return;
      }
    }
  }

  pingListEl.innerHTML = "";

  let rendered = 0;
  let activeAssigned = false;

  for (const code of codes){
    ensureLiveUserListener(code);

    const u = liveUserCache.get(code);
    const displayName = String(u?.displayName || u?.username || "").trim();
    const username = String(u?.username || "").trim();

    if (!displayName || !username) continue;

    const qMatch = !q
      || displayName.toLowerCase().startsWith(q)
      || username.toLowerCase().startsWith(q);

    if (!qMatch) continue;

    const item = document.createElement("button");
    item.type = "button";
    item.className = "file-item ping-item";
    item.setAttribute("data-ping-name", username);
    item.setAttribute("aria-label", `Ping ${displayName}`);

    const ava = document.createElement("div");
    ava.className = "mini-avatar ping-item-avatar";
    ava.dataset.usercode = code;
    applyAvatar(ava, u);

    const meta = document.createElement("div");
    meta.className = "ping-item-meta";

    const nameEl = document.createElement("div");
    nameEl.className = "ping-item-name";
    nameEl.textContent = displayName;

    const userEl = document.createElement("div");
    userEl.className = "ping-item-username";
    userEl.textContent = `@${username}`;

    meta.appendChild(nameEl);
    meta.appendChild(userEl);

    item.appendChild(ava);
    item.appendChild(meta);

    if (!activeAssigned){
      item.classList.add("is-active");
      activeAssigned = true;
    }

    item.addEventListener("click", () => applyPingSuggestion(username));

    pingListEl.appendChild(item);
    rendered++;
  }

  if (!rendered){
    const empty = document.createElement("div");
    empty.className = "overlay-empty";
    empty.textContent = q ? `No room members match @${q}.` : "No other room members are available.";
    pingListEl.appendChild(empty);
  }

  if (pingBarQueryEl) pingBarQueryEl.textContent = q ? `Filtering @${q}` : "Type after @ to filter";
  if (pingBarCountEl) pingBarCountEl.textContent = `${rendered} ${rendered === 1 ? "match" : "matches"}`;

  // Show max 6 without scroll; become scrollable when there are 7+ results
  pingListEl.classList.toggle("ping-scroll", rendered >= 7);

  syncChatOverlayMetrics();
}

function openFilesBar(){
  initOverlaysUI();
  if (!filesBarEl) return;
  filesBarEl.hidden = false;
  filesBarEl.classList.remove("closing");
  filesBarEl.classList.add("open");
  syncChatOverlayMetrics();
}

function closeFilesBar({ quiet=false } = {}){
  if (!filesBarEl) return;
  if (filesBarEl.hidden) { syncChatOverlayMetrics(); return; }

  if (quiet){
    filesBarEl.hidden = true;
    filesBarEl.classList.remove("open","closing");
    if (filesListEl) filesListEl.innerHTML = "";
    syncChatOverlayMetrics();
    return;
  }

  filesBarEl.classList.remove("open");
  filesBarEl.classList.add("closing");
  const onEnd = () => {
    filesBarEl?.removeEventListener("animationend", onEnd);
    if (filesBarEl){
      filesBarEl.hidden = true;
      filesBarEl.classList.remove("closing");
    }
    if (filesListEl) filesListEl.innerHTML = "";
    syncChatOverlayMetrics();
  };
  filesBarEl.addEventListener("animationend", onEnd);
}

function clearPendingFiles({ quiet=false } = {}){
  if (!quiet){
    for (const f of [...pendingFiles, ...pendingGifs]){
      try{
        if (String(f?.previewURL || "").startsWith("blob:")) URL.revokeObjectURL(f.previewURL);
      }catch{}
    }
  }
  pendingFiles = [];
  pendingGifs = [];
  closeFilesBar({ quiet });
}

function removePendingFile(idx){
  if (idx < 0 || idx >= pendingFiles.length) return;
  const [removed] = pendingFiles.splice(idx, 1);
  try{
    if (String(removed?.previewURL || "").startsWith("blob:")) URL.revokeObjectURL(removed.previewURL);
  }catch{}
  renderFilesBar();
}

function removePendingGif(idx){
  if (idx < 0 || idx >= pendingGifs.length) return;
  const [removed] = pendingGifs.splice(idx, 1);
  try{
    if (String(removed?.previewURL || "").startsWith("blob:")) URL.revokeObjectURL(removed.previewURL);
  }catch{}
  renderFilesBar();
}

function renderFilesBar(){
  initOverlaysUI();
  if (!filesBarEl || !filesListEl) return;

  const any = getTotalPendingAttachmentCount() > 0;
  if (!any){
    closeFilesBar({ quiet:true });
    return;
  }

  const total = getTotalPendingAttachmentCount();
  const fileCount = countPendingStandardFiles();
  const voiceCount = countPendingVoiceMessages();
  const gifCount = pendingGifs.length;

  if (filesBarCountEl){
    filesBarCountEl.textContent = `${total} selected`;
  }
  if (filesBarLimitEl){
    filesBarLimitEl.textContent = `${fileCount}/3 files · ${voiceCount}/3 voice · ${gifCount}/2 GIFs`;
  }

  filesListEl.innerHTML = "";

  const renderAttachmentItem = (f, idx, type) => {
    const item = document.createElement("div");
    item.className = "file-item attachment-item";
    if (f?.isVoiceMessage) item.dataset.voice = "1";

    const kind = f?.isVoiceMessage ? "voice" : String(f?.kind || type || "file").toLowerCase();
    item.dataset.kind = kind;

    const thumb = document.createElement("div");
    thumb.className = "file-thumb";
    const thumbSrc = readChunkedField(f, "dataURL") || String(f?.previewURL || f?.dataURL || "");
    if ((kind === "image" || kind === "gif") && thumbSrc){
      const img = document.createElement("img");
      img.alt = "";
      img.draggable = false;
      img.src = thumbSrc;
      thumb.appendChild(img);
    } else {
      thumb.textContent =
        kind === "voice" ? "🎙" :
        kind === "audio" ? "♪" :
        kind === "video" ? "▶" :
        kind === "html" ? "</>" :
        kind === "gif" ? "GIF" :
        "FILE";
    }

    const meta = document.createElement("div");
    meta.className = "file-meta";

    const name = document.createElement("div");
    name.className = "file-name";
    name.textContent = kind === "voice" ? "Voice Message" : String(f.fileName || f.name || (kind === "gif" ? "tenor.gif" : "file"));

    const sub = document.createElement("div");
    sub.className = "file-sub";
    const size = f?.size ? ` • ${Math.max(1, Math.round(f.size / 1024))} KB` : "";
    sub.textContent = kind === "voice"
      ? `AUDIO${size} • Voice ${idx + 1}/${Math.max(1, voiceCount)}`
      : `${kind.toUpperCase()}${size}${kind === "gif" ? " • TENOR" : ""}`;

    meta.appendChild(name);
    meta.appendChild(sub);

    const rm = document.createElement("button");
    rm.className = "file-remove";
    rm.type = "button";
    rm.setAttribute("aria-label", `Remove ${name.textContent}`);
    rm.textContent = "✕";
    rm.addEventListener("click", () => {
      if (type === "gif") removePendingGif(idx);
      else removePendingFile(idx);
    });

    item.appendChild(thumb);
    item.appendChild(meta);
    item.appendChild(rm);
    filesListEl.appendChild(item);
  };

  pendingFiles.forEach((f, idx) => renderAttachmentItem(f, idx, "file"));
  pendingGifs.forEach((g, idx) => renderAttachmentItem(g, idx, "gif"));

  openFilesBar();
}

function getReplyTargetAttachmentCount(msg){
  if (!msg || typeof msg !== "object") return 0;

  let files = Array.isArray(msg.files) ? msg.files : [];
  const gifs = Array.isArray(msg.gifs) ? msg.gifs : [];
  if (!files.length && (msg.t === "image" || msg.t === "video" || msg.t === "html" || msg.t === "audio") && msg.dataURL){
    files = [{ kind: msg.t, dataURL: msg.dataURL }];
  }
  return files.length + gifs.length;
}

function getReplyTargetPreviewText(msg){
  if (!msg) return "Original message is still loading.";

  const text = String(msg.text || "").trim().replace(/\s+/g, " ");
  const attCount = getReplyTargetAttachmentCount(msg);
  if (text) return text.length > 240 ? `${text.slice(0, 237)}...` : text;
  if (attCount === 1) return "1 attachment";
  if (attCount > 1) return `${attCount} attachments`;
  return "Original message";
}

function updateReplyBarPreview(){
  if (!replyState) return;

  const key = String(replyState.key || "");
  const targetMsg = key ? getReplyTargetMessage(key) : null;
  if (key && !targetMsg) scheduleReplyTargetPreviewHydrate(currentRoomId, key);
  const userCode = String(targetMsg?.userCode || replyState.userCode || "");

  if (userCode) ensureLiveUserListener(userCode);
  const live = userCode ? liveUserCache.get(userCode) : null;

  const username = String(live?.username || targetMsg?.username || replyState.username || "User");
  const displayName = String(live?.displayName || targetMsg?.displayName || replyState.displayName || username || "User");

  replyState.displayName = displayName;
  replyState.username = username;
  if (userCode) replyState.userCode = userCode;

  if (replyBarTextEl) {
    replyBarTextEl.innerHTML = `${escapeHtml(displayName)} <span class="reply-bar-username">${escapeHtml(username)}</span>`;
  }
  if (replyBarMessageEl) replyBarMessageEl.textContent = getReplyTargetPreviewText(targetMsg);
  if (replyBarAvatarEl){
    if (userCode) replyBarAvatarEl.dataset.usercode = userCode;
    else delete replyBarAvatarEl.dataset.usercode;
    applyAvatar(replyBarAvatarEl, live || targetMsg || { ...replyState, username, displayName });
  }
}

function setReplyState(next){
  if (!next?.key) return;
  initOverlaysUI();

  replyState = {
    key: String(next.key || ""),
    userCode: next.userCode || "",
    username: next.username || "User",
    displayName: next.displayName || next.username || "User"
  };

  updateReplyBarPreview();
  if (replyBarEl){
    replyBarEl.hidden = false;
    replyBarEl.classList.remove("closing");
    replyBarEl.classList.add("open");
  }
  syncChatOverlayMetrics();
  $("msg-input")?.focus();
}

function clearReplyState({ quiet=false } = {}){
  replyState = null;
  initOverlaysUI();
  if (!replyBarEl) return;

  if (replyBarEl.hidden) { syncChatOverlayMetrics(); return; }

  if (quiet){
    replyBarEl.hidden = true;
    replyBarEl.classList.remove("open","closing");
    syncChatOverlayMetrics();
    return;
  }

  replyBarEl.classList.remove("open");
  replyBarEl.classList.add("closing");

  const onEnd = () => {
    replyBarEl?.removeEventListener("animationend", onEnd);
    if (replyBarEl){
      replyBarEl.hidden = true;
      replyBarEl.classList.remove("closing");
    }
    syncChatOverlayMetrics();
  };
  replyBarEl.addEventListener("animationend", onEnd);
}

