function roomJoinBodyHTML(){
  return `
    <div>
      <div class="label">Room Name</div>
      <input class="input" id="room-modal-code" maxlength="20" placeholder="e.g. 1 or ABC123" />
      <div class="label">Room Password</div>
      <input class="input" id="room-modal-password" maxlength="64" autocomplete="off" placeholder="Leave blank for public rooms" />
    </div>
  `;
}

function bindCreateRoomIconPicker(){
  const clip = $("room-create-icon-clip");
  const img = $("room-create-icon-img");
  const input = $("room-create-icon-file");
  const zoom = $("room-create-icon-zoom");
  const btnChoose = $("btn-room-create-icon-choose");
  const btnUseDefault = $("btn-room-create-icon-use-default");
  const btnCenter = $("btn-room-create-icon-center");
  const btnReset = $("btn-room-create-icon-reset");

  if (!clip || !img || !input || !zoom || !btnChoose || !btnUseDefault || !btnCenter || !btnReset){
    return {
      getPayload(){
        return { photoDataURL: null, photoTransform: null };
      }
    };
  }

  img.addEventListener("dragstart", (e) => e.preventDefault());

  const clamp = (n, a, b) => Math.min(b, Math.max(a, n));
  const state = {
    dataURL: defaultStickmanDataURL(),
    scale: 1,
    x: 0,
    y: 0,
    dragging: false,
    dragStartX: 0,
    dragStartY: 0,
    startX: 0,
    startY: 0,
    pointerId: null,
    useDefault: true
  };

  function clipSize(){
    const r = clip.getBoundingClientRect();
    const w = Math.round(r.width || 0);
    return Math.max(1, w || 132);
  }

  function applyPreview(){
    img.src = state.dataURL;
    img.style.transform = `translate(calc(-50% + ${state.x}px), calc(-50% + ${state.y}px)) scale(${state.scale})`;
  }

  function packTransform(){
    const size = clipSize();
    return {
      unit: "rel",
      scale: state.scale,
      x: (state.x || 0) / size,
      y: (state.y || 0) / size
    };
  }

  function resetToDefault(){
    state.dataURL = defaultStickmanDataURL();
    state.scale = 1;
    state.x = 0;
    state.y = 0;
    state.useDefault = true;
    zoom.value = "1";
    applyPreview();
  }

  resetToDefault();
  requestAnimationFrame(() => requestAnimationFrame(applyPreview));

  btnChoose.addEventListener("click", () => input.click());
  btnUseDefault.addEventListener("click", () => resetToDefault());

  btnCenter.addEventListener("click", () => {
    state.x = 0;
    state.y = 0;
    applyPreview();
  });

  btnReset.addEventListener("click", () => {
    state.scale = 1;
    state.x = 0;
    state.y = 0;
    zoom.value = "1";
    applyPreview();
  });

  function endDrag(){
    if (!state.dragging) return;
    state.dragging = false;
    state.pointerId = null;
  }

  clip.addEventListener("pointerdown", (e) => {
    if (e.button !== 0) return;
    state.dragging = true;
    state.pointerId = e.pointerId;
    state.dragStartX = e.clientX;
    state.dragStartY = e.clientY;
    state.startX = state.x;
    state.startY = state.y;
    try{ clip.setPointerCapture(e.pointerId); }catch{}
  });

  clip.addEventListener("pointermove", (e) => {
    if (!state.dragging) return;
    if (state.pointerId !== null && e.pointerId !== state.pointerId) return;

    state.x = state.startX + (e.clientX - state.dragStartX);
    state.y = state.startY + (e.clientY - state.dragStartY);
    applyPreview();
  });

  clip.addEventListener("pointerup", () => endDrag());
  clip.addEventListener("pointercancel", () => endDrag());

  zoom.addEventListener("input", () => {
    state.scale = clamp(Number(zoom.value) || 1, 0.2, 3.0);
    applyPreview();
  });

  input.addEventListener("change", async () => {
    const file = (input.files && input.files[0]) ? input.files[0] : null;
    input.value = "";
    if (!file) return;

    if (!fileTypeOk(file)){
      showToast({ title:"Invalid file", body:"Room icons must be PNG, JPG/JPEG, or GIF.", duration: 2600 });
      return;
    }

    try{
      state.dataURL = await readFileAsDataURL(file);
      state.scale = 1;
      state.x = 0;
      state.y = 0;
      state.useDefault = false;
      zoom.value = "1";
      applyPreview();
    }catch{
      showToast({ title:"Read failed", body:"Could not read that file.", duration: 2600 });
    }
  });

  return {
    getPayload(){
      if (state.useDefault){
        return { photoDataURL: null, photoTransform: null };
      }
      return {
        photoDataURL: state.dataURL,
        photoTransform: packTransform()
      };
    }
  };
}

function openRoomPasswordModal(roomId){
  const id = sanitizeRoomCode(roomId);
  const meta = id ? (roomsMetaCache.get(id) || null) : null;
  if (!id || !currentUser || !membershipMap.has(id) || !isPrivateRoomMeta(meta)) return;

  const password = String(meta?.password || "").trim();
  const legacyOnly = !password && String(meta?.passwordHash || "").trim();
  const displayPassword = password || (legacyOnly ? "Legacy password unavailable until migrated" : "No password set");

  openModal({
    title: "Room Password",
    bodyHTML: `
      <div class="label">Room Password</div>
      <input class="input mono-input" id="room-password-display" type="text" value="${escapeAttr(displayPassword)}" readonly />
      ${legacyOnly ? `<p class="muted small" style="margin-top:10px">This room still has a legacy hashed password. It will migrate to the password field after the next successful password join.</p>` : ""}
    `,
    actionsHTML: `<button class="btn primary" id="btn-copy-room-password" type="button"${password ? "" : " disabled"}>Copy</button>`
  });

  const input = $("room-password-display");
  $("btn-copy-room-password")?.addEventListener("click", async () => {
    if (!password) return;
    await copyTextToClipboard(password);
    try{ input?.select?.(); }catch{}
    showToast({ title:"Copied", body:"Room password copied.", duration: 1800 });
  });
}

function openToggleRoomAccessModal(roomId){
  const id = sanitizeRoomCode(roomId);
  const meta = id ? (roomsMetaCache.get(id) || null) : null;
  if (!id || !currentUser || meta?.createdBy !== currentUser.code) return;

  if (isPrivateRoomMeta(meta)){
    db.ref(`rooms/${id}`).update({ private:false, password:null, passwordHash:null }).then(() => {
      roomsMetaCache.set(id, { ...(roomsMetaCache.get(id) || {}), private:false, password:null, passwordHash:null });
      refreshRoomIconSurfaces(id);
      showToast({ title:"Room is public", body:`${roomDisplayName(id)} is now public.`, duration: 2200 });
    }).catch(() => showToast({ title:"Update failed", body:"Could not toggle room access.", duration: 2600 }));
    return;
  }

  openModal({
    title: "Private Room Password",
    bodyHTML: `
      <div class="label">Room Password</div>
      <input class="input" id="toggle-room-password" maxlength="64" autocomplete="off" placeholder="Password" />
    `,
    actionsHTML: `<button class="btn primary" id="btn-toggle-room-access-save" type="button">Make Private</button>`
  });
  $("btn-toggle-room-access-save")?.addEventListener("click", async () => {
    const password = sanitizeRoomPassword($("toggle-room-password")?.value || "");
    if (!password){
      showToast({ title:"Invalid password", body:"Enter a password that is not empty spaces.", duration: 2600 });
      return;
    }
    try{
      await db.ref(`rooms/${id}`).update({ private:true, password, passwordHash:null });
      roomsMetaCache.set(id, { ...(roomsMetaCache.get(id) || {}), private:true, password, passwordHash:null });
      refreshRoomIconSurfaces(id);
      closeModal();
      showToast({ title:"Room is private", body:`${roomDisplayName(id)} now requires a password.`, duration: 2200 });
    }catch{
      showToast({ title:"Update failed", body:"Could not toggle room access.", duration: 2600 });
    }
  });
}

function openRoomComposerModal(mode = "create"){
  if (!currentUser) return;

  openModal({
    title: " ",
    bodyHTML: mode === "create" ? roomCreateBodyHTML() : roomJoinBodyHTML(),
    actionsHTML: `
      <button class="btn primary" id="btn-room-modal-confirm" type="button">${mode === "create" ? "Create" : "Join"}</button>
    `
  });

  $("modal-title").innerHTML = roomModalTabsHTML(mode);

  $("room-mode-create")?.addEventListener("click", () => openRoomComposerModal("create"));
  $("room-mode-join")?.addEventListener("click", () => openRoomComposerModal("join"));

  if (mode === "create"){
    const iconPicker = bindCreateRoomIconPicker();

    $("btn-room-modal-confirm").addEventListener("click", async () => {
      const roomName = sanitizeRoomName($("room-modal-code")?.value || "");
      const roomId = sanitizeRoomCode(roomName);
      const passwordRaw = $("room-modal-password")?.value || "";
      const password = passwordRaw.trim() ? sanitizeRoomPassword(passwordRaw) : null;
      if (!roomId || !roomName){
        showToast({ title:"Invalid name", body:"Room name must be 1–20 printable characters and cannot include . # $ [ ] or /.", duration: 2600 });
        return;
      }
      if (passwordRaw.trim() && !password){
        showToast({ title:"Invalid password", body:"Room password must use printable keyboard characters and cannot be only spaces.", duration: 2600 });
        return;
      }

      const iconPayload = iconPicker.getPayload();

      try{
        const tx = await db.ref(`rooms/${roomId}`).transaction((cur) => {
          if (cur === null){
            return {
              name: roomName,
              private: !!password,
              password,
              passwordHash: null,
              createdAt: firebase.database.ServerValue.TIMESTAMP,
              createdBy: currentUser.code,
              lastMessageAt: 0,
              lastMessagePreview: "",
              messageCount: 0,
              photoDataURL: iconPayload.photoDataURL,
              photoTransform: iconPayload.photoTransform
            };
          }
          return undefined;
        });
        if (!tx.committed){
          showToast({ title:"Room exists", body:"A room with that name already exists.", duration: 2600 });
          return;
        }

        try{
          await db.ref(`memberships/${currentUser.code}/${roomId}`).update({
            joinedAt: firebase.database.ServerValue.TIMESTAMP,
            lastSeenAt: 0,
            lastSeenCount: 0
          });
        }catch{}

        membershipMap.set(roomId, {
          joinedAt: Date.now(),
          lastSeenAt: 0,
          lastSeenCount: 0
        });

        closeModal();
        showToast({ title:"Room created", body:`Room ${roomName} is ready.`, duration: 2200 });
        openRoom(roomId);

      }catch(e){
        console.error("create room failed:", e);
        showToast({ title:"Create failed", body:"Check console / rules.", duration: 2800 });
      }
    });

    return;
  }

  $("btn-room-modal-confirm").addEventListener("click", async () => {
    const roomName = sanitizeRoomName($("room-modal-code")?.value || "");
    const roomId = sanitizeRoomCode(roomName);
    const passwordRaw = $("room-modal-password")?.value || "";
    const password = passwordRaw.trim() ? sanitizeRoomPassword(passwordRaw) : null;
    if (!roomId || !roomName){
      showToast({ title:"Invalid name", body:"Enter a valid room name.", duration: 2400 });
      return;
    }
    if (passwordRaw.trim() && !password){
      showToast({ title:"Invalid password", body:"Room password must use printable keyboard characters and cannot be only spaces.", duration: 2600 });
      return;
    }

    try{
      const roomSnap = await db.ref(`rooms/${roomId}`).once("value");
      if (!roomSnap.exists()){
        showToast({ title:"Not found", body:"That room doesn’t exist. Create it first.", duration: 2800 });
        return;
      }
      const roomMeta = roomSnap.val() || {};
      if (isPrivateRoomMeta(roomMeta) && !password){
        showToast({ title:"Password required", body:"Password required", duration: 2600 });
        return;
      }
      if (isPrivateRoomMeta(roomMeta)){
        const ok = await verifyRoomPassword(roomMeta, password, roomId);
        if (!ok){
          showToast({ title:"Incorrect password", body:"That password is incorrect.", duration: 2600 });
          return;
        }
      }

      try{
        await db.ref(`memberships/${currentUser.code}/${roomId}`).update({
          joinedAt: firebase.database.ServerValue.TIMESTAMP,
          lastSeenAt: 0,
          lastSeenCount: 0
        });
      }catch{}

      membershipMap.set(roomId, {
        joinedAt: Date.now(),
        lastSeenAt: 0,
        lastSeenCount: 0
      });

      closeModal();
      showToast({ title:"Joined", body:`Room ${roomDisplayName(roomId, roomSnap.val() || null)}.`, duration: 1800 });
      openRoom(roomId);

    }catch(e){
      console.error("join room failed:", e);
      showToast({ title:"Join failed", body:"Check console / rules.", duration: 2800 });
    }
  });
}

$("btn-room-plus")?.addEventListener("click", () => openRoomComposerModal("create"));

/* -------------------- Chat: send / upload -------------------- */
$("btn-send").addEventListener("click", () => {
  if (editState){
    cancelEditMessage();
    return;
  }
  sendTextMessage();
});
$("msg-input").addEventListener("keydown", (e) => {
  if (e.key === "Tab" && pingBarEl && !pingBarEl.hidden){
    const activeItem = pingListEl?.querySelector(".ping-item.is-active") || pingListEl?.querySelector(".ping-item");
    const pingName = String(activeItem?.getAttribute("data-ping-name") || "").trim();
    if (pingName){
      e.preventDefault();
      applyPingSuggestion(pingName);
      return;
    }
  }

  if (e.key !== "Enter") return;
  if (e.shiftKey) return;
  e.preventDefault();
  sendTextMessage();
});

$("composer-row")?.addEventListener("pointerdown", (e) => {
  const input = $("msg-input");
  if (!input || input.disabled) return;
  if (e.target.closest("button, a, textarea, input, .emoji-popover, .gif-popover, .voice-popover")) return;

  e.preventDefault();
  input.focus();

  try{
    const end = String(input.value || "").length;
    input.setSelectionRange(end, end);
  }catch{}
});

document.addEventListener("keydown", (e) => {
  if (e.defaultPrevented) return;
  if (e.repeat) return;
  if (e.key !== "/") return;
  if (!currentUser || !currentRoomId) return;

  const input = $("msg-input");
  if (!input || input.disabled) return;

  const active = document.activeElement;
  const tag = String(active?.tagName || "").toUpperCase();
  if (active === input) return;
  if (tag === "INPUT" || tag === "TEXTAREA" || active?.isContentEditable) return;

  let hasSelection = false;
  try{
    const sel = window.getSelection ? window.getSelection() : null;
    hasSelection = !!(sel && !sel.isCollapsed);
  }catch{}

  if (hasSelection) return;

  e.preventDefault();
  input.focus();

  try{
    const end = String(input.value || "").length;
    input.setSelectionRange(end, end);
  }catch{}
});

/* -------------------- Emoji picker (composer only) -------------------- */
let emojiPopoverOpen = false;
let emojiCtxMenu = null;
let emojiCtxMenuClosing = false;
let emojiCtxMenuCloseTimer = null;

function copyTextToClipboard(text){
  const t = String(text ?? "");
  if (!t) return Promise.resolve();
  return (async () => {
    try{ await navigator.clipboard.writeText(t); return; }catch{}
    // Fallback
    const ta = document.createElement("textarea");
    ta.value = t;
    ta.setAttribute("readonly", "true");
    ta.style.position = "fixed";
    ta.style.left = "-9999px";
    document.body.appendChild(ta);
    ta.select();
    try{ document.execCommand("copy"); }catch{}
    ta.remove();
  })();
}

function ensureEmojiCtxMenu(){
  if (emojiCtxMenu) return emojiCtxMenu;

  const el = document.createElement("div");
  el.className = "msg-menu";
  el.id = "emoji-ctx-menu";
  el.style.display = "none";
  el.innerHTML = `
    <button class="msg-menu-btn" id="emoji-ctx-copy" type="button">
      <span class="msg-menu-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none">
          <path d="M8 8h10v12H8V8Z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
          <path d="M6 16H5a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
        </svg>
      </span>
      <span class="msg-menu-label">Copy</span>
    </button>
  `;
  document.body.appendChild(el);

  $("emoji-ctx-copy").addEventListener("click", async () => {
    const emoji = el.dataset.emoji || "";
    await copyTextToClipboard(emoji);
    closeEmojiCtxMenu();
  });

  emojiCtxMenu = el;
  return el;
}

function closeEmojiCtxMenu(immediate=false){
  const el = emojiCtxMenu;
  if (!el || el.style.display === "none") return;

  if (emojiCtxMenuCloseTimer){
    clearTimeout(emojiCtxMenuCloseTimer);
    emojiCtxMenuCloseTimer = null;
  }

  const reduce = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  if (immediate || reduce){
    el.style.display = "none";
    el.classList.remove("open");
    el.classList.remove("closing");
    emojiCtxMenuClosing = false;
    return;
  }

  if (emojiCtxMenuClosing) return;
  emojiCtxMenuClosing = true;

  el.classList.remove("open");
  el.classList.add("closing");

  const finish = () => {
    emojiCtxMenuCloseTimer = null;
    el.style.display = "none";
    el.classList.remove("closing");
    emojiCtxMenuClosing = false;
  };

  emojiCtxMenuCloseTimer = setTimeout(finish, 140);
}

function openEmojiCtxMenu({ x, y, emoji }){
  const el = ensureEmojiCtxMenu();

  if (emojiCtxMenuCloseTimer){
    clearTimeout(emojiCtxMenuCloseTimer);
    emojiCtxMenuCloseTimer = null;
  }
  emojiCtxMenuClosing = false;

  el.dataset.emoji = String(emoji || "");

  el.style.left = `${Math.max(8, x)}px`;
  el.style.top  = `${Math.max(8, y)}px`;
  el.style.display = "";
  el.classList.remove("closing");
  el.classList.add("open");
}

function insertEmojiToComposer(emoji){
  const input = $("msg-input");
  if (!input) return;

  // Always focus + append at end (matches your spec whether focused or not)
  input.focus();
  input.value = String(input.value || "") + String(emoji || "");

  // Trigger existing typing/ping logic
  input.dispatchEvent(new Event("input", { bubbles:true }));
}

function closeEmojiPopover(){
  const pop = $("emoji-popover");
  if (!pop || pop.hidden) return;

  pop.classList.remove("open");
  pop.classList.add("closing");

  const reduce = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const finish = () => {
    pop.hidden = true;
    pop.classList.remove("closing");
    emojiPopoverOpen = false;
  };

  if (reduce){ finish(); return; }
  setTimeout(finish, 200);
}

function openEmojiPopover(){
  const pop = $("emoji-popover");
  if (!pop) return;

  pop.hidden = false;
  pop.classList.remove("closing");
  // next frame so transition runs
  requestAnimationFrame(() => pop.classList.add("open"));
  emojiPopoverOpen = true;

  // Lazy-bind picker events once
  const picker = $("emoji-picker");
  if (picker && picker.dataset.bound !== "1"){
    picker.dataset.bound = "1";

    // Left-click select -> insert
    picker.addEventListener("emoji-click", (e) => {
      const emoji = e?.detail?.unicode;
      if (!emoji) return;
      insertEmojiToComposer(emoji);
      // Keep picker open (your spec implies it stays open unless clicking off)
    });

    // Right-click any emoji -> custom menu with Copy only (styled like msg menu)
    // NOTE: emoji-picker-element uses shadow DOM; we bind to its shadow root.
    const tryBindShadow = () => {
      const sr = picker.shadowRoot;
      if (!sr) return false;

      sr.addEventListener("contextmenu", (ev) => {
        const t = ev.target;
        const btn = (t && t.closest) ? t.closest("button") : null;
        if (!btn) return;

        // Heuristic: emoji buttons usually contain the emoji as textContent.
        const emoji = (btn.textContent || "").trim();
        if (!emoji) return;

        ev.preventDefault();
        ev.stopPropagation();

        openEmojiCtxMenu({ x: ev.clientX, y: ev.clientY, emoji });
      });

      return true;
    };

    // Shadow root can appear after component upgrades
    if (!tryBindShadow()){
      setTimeout(() => { try{ tryBindShadow(); }catch{} }, 60);
      setTimeout(() => { try{ tryBindShadow(); }catch{} }, 220);
      setTimeout(() => { try{ tryBindShadow(); }catch{} }, 600);
    }
  }
}

function toggleEmojiPopover(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";

  // Composer emoji picker only inside rooms (chat rooms)
  if (!currentRoomId || !placeNow.startsWith("room:") || views.chat.dataset.active !== "true"){
    showToast({ title:"Pick a room", body:"Create or join a room first.", duration: 2200 });
    return;
  }

  if (emojiPopoverOpen) closeEmojiPopover();
  else openEmojiPopover();
}

let membersListVisible = true;

function isActiveChatRoomForMembersToggle(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  return !!currentRoomId && placeNow.startsWith("room:") && views.chat.dataset.active === "true";
}

function toggleMembersListVisibility(){
  if (!isActiveChatRoomForMembersToggle()) return false;
  closeEmojiCtxMenu();
  membersListVisible = !membersListVisible;
  syncEmojiButtonVisibility();
  return true;
}

function syncEmojiButtonVisibility(){
  const eBtn = $("btn-emoji");
  const gBtn = $("btn-gif");
  const vBtn = $("btn-voice");
  const mBtn = $("btn-members");
  const membersSidebar = $("members-sidebar");
  if (!eBtn && !gBtn && !vBtn && !mBtn && !membersSidebar) return;

  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const inRoom = !!currentRoomId && placeNow.startsWith("room:") && views.chat.dataset.active === "true";
  const showMembersSidebar = inRoom && membersListVisible;

  document.body.dataset.roomView = inRoom ? "1" : "0";
  document.body.dataset.membersSidebar = showMembersSidebar ? "1" : "0";

  if (eBtn) eBtn.hidden = !inRoom;
  if (gBtn) gBtn.hidden = !inRoom;
  if (vBtn) vBtn.hidden = !inRoom;
  if (mBtn) mBtn.hidden = !inRoom;
  if (membersSidebar) membersSidebar.hidden = !showMembersSidebar;

  if (!inRoom){
    membersListVisible = true;
    closeEmojiCtxMenu(true);
    closeEmojiPopover();
    closeGifPopover();
    closeVoicePopover();
  }
}

// Run once on load/bind
syncEmojiButtonVisibility();

$("btn-emoji")?.addEventListener("click", (e) => {
  e.preventDefault();
  e.stopPropagation();
  closeEmojiCtxMenu();
  toggleEmojiPopover();
});

$("btn-gif")?.addEventListener("click", (e) => {
  e.preventDefault();
  e.stopPropagation();
  closeEmojiCtxMenu();
  toggleGifPopover();
});

$("btn-voice")?.addEventListener("click", (e) => {
  e.preventDefault();
  e.stopPropagation();
  closeEmojiCtxMenu();
  toggleVoicePopover();
});

$("btn-members")?.addEventListener("click", (e) => {
  e.preventDefault();
  e.stopPropagation();
  toggleMembersListVisibility();
});

document.addEventListener("keydown", (e) => {
  if (e.repeat) return;
  if (!e.ctrlKey || e.shiftKey || e.altKey || e.metaKey) return;
  if (String(e.key || "").toLowerCase() !== "u") return;
  if (!isActiveChatRoomForMembersToggle()) return;

  e.preventDefault();
  e.stopPropagation();
  toggleMembersListVisibility();
});

// click-off closes picker (and ctx menu), but clicking inside picker keeps it open
document.addEventListener("pointerdown", (e) => {
  const ePop = $("emoji-popover");
  const eBtn = $("btn-emoji");

  const gPop = $("gif-popover");
  const gBtn = $("btn-gif");

  const vPop = $("voice-popover");
  const vBtn = $("btn-voice");

  if (emojiCtxMenu && emojiCtxMenu.style.display !== "none"){
    const inside = emojiCtxMenu.contains(e.target);
    if (!inside) closeEmojiCtxMenu();
  }

  if (emojiPopoverOpen && ePop && !ePop.hidden){
    const target = e.target;
    const insideEmoji = ePop.contains(target);
    const onEmojiBtn = eBtn && eBtn.contains(target);
    const insideCtx = emojiCtxMenu && emojiCtxMenu.style.display !== "none" && emojiCtxMenu.contains(target);
    if (!insideEmoji && !onEmojiBtn && !insideCtx) closeEmojiPopover();
  }

  if (gifPopoverOpen && gPop && !gPop.hidden){
    const target = e.target;
    const insideGif = gPop.contains(target);
    const onGifBtn = gBtn && gBtn.contains(target);
    if (!insideGif && !onGifBtn) closeGifPopover();
  }

  if (voicePopoverOpen && vPop && !vPop.hidden){
    const target = e.target;
    const insideVoice = vPop.contains(target);
    const onVoiceBtn = vBtn && vBtn.contains(target);
    if (!insideVoice && !onVoiceBtn) closeVoicePopover();
  }
});

// Esc closes picker/menu
document.addEventListener("keydown", (e) => {
  if (e.key !== "Escape") return;
  if (emojiPopoverOpen) closeEmojiPopover();
  if (gifPopoverOpen) closeGifPopover();
  if (voicePopoverOpen) closeVoicePopover();
  closeEmojiCtxMenu();
});

/* -------------------- Tenor GIF picker (composer; rooms only) -------------------- */
let gifPopoverOpen = false;
let gifBound = false;

const TENOR_KEY = "LIVDSRZULELA"; // Tenor demo key
const TENOR_LIMIT = 24;

let tenorMode = "featured"; // "featured" | "search"
let tenorQuery = "";
let tenorNextPos = "";
let tenorHasMore = true;
let tenorLoading = false;
let tenorItems = [];

function canUseGifPicker(){
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  return !!(currentUser && currentRoomId && placeNow.startsWith("room:") && views.chat.dataset.active === "true");
}

function closeGifPopover(){
  const pop = $("gif-popover");
  if (!pop || pop.hidden) return;

  pop.classList.remove("open");
  pop.classList.add("closing");

  const reduce = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const finish = () => {
    pop.hidden = true;
    pop.classList.remove("closing");
    gifPopoverOpen = false;
  };

  if (reduce){ finish(); return; }
  setTimeout(finish, 200);
}

async function tenorFetch({ mode, q, pos }){
  // Use Tenor classic endpoint so the public demo key works client-side.
  const base = "https://g.tenor.com/v1/";
  const endpoint = (mode === "search") ? "search" : "trending";

  const params = new URLSearchParams();
  params.set("key", TENOR_KEY);
  params.set("limit", String(TENOR_LIMIT));
  params.set("media_filter", "basic");     // includes gif + tinygif
  params.set("contentfilter", "high");
  if (pos) params.set("pos", String(pos));
  if (mode === "search" && q) params.set("q", String(q));

  const url = base + endpoint + "?" + params.toString();

  const resp = await fetch(url);
  if (!resp.ok) throw new Error(`Tenor request failed (${resp.status})`);
  return await resp.json();
}

function pickTenorPreviewUrl(item){
  const m0 = item?.media?.[0] || {};
  return m0?.tinygif?.url || m0?.gif?.url || "";
}

function pickTenorGifUrl(item){
  const m0 = item?.media?.[0] || {};
  return m0?.mediumgif?.url || m0?.tinygif?.url || m0?.gif?.url || "";
}

function renderGifGrid(){
  const grid = $("gif-grid");
  if (!grid) return;

  if (!tenorItems.length){
    grid.innerHTML = `<div class="gif-empty">No GIFs found.</div>`;
    return;
  }

  grid.innerHTML = "";
  for (const it of tenorItems){
    const prev = pickTenorPreviewUrl(it);
    const full = pickTenorGifUrl(it);
    if (!prev || !full) continue;

    const b = document.createElement("button");
    b.type = "button";
    b.className = "gif-tile";
    b.title = "Add GIF";

    const img = document.createElement("img");
    img.src = prev;
    img.alt = "GIF";
    img.loading = "lazy";

    b.appendChild(img);

    b.addEventListener("click", async (e) => {
      e.preventDefault();
      e.stopPropagation();
      await addTenorGifToPending(it);
    });

    grid.appendChild(b);
  }
}

async function loadTenorPage({ reset=false } = {}){
  if (tenorLoading) return;
  if (!reset && !tenorHasMore) return;

  tenorLoading = true;

  try{
    const data = await tenorFetch({
      mode: tenorMode,
      q: tenorQuery,
      pos: reset ? "" : tenorNextPos
    });

    const results = Array.isArray(data?.results) ? data.results : [];
    tenorNextPos = String(data?.next || "");
    tenorHasMore = !!(tenorNextPos && tenorNextPos !== "0");

    if (reset) tenorItems = results;
    else tenorItems = tenorItems.concat(results);

    renderGifGrid();
  }catch(e){
    console.error("tenor load failed:", e);
    showToast({ title:"Tenor error", body:"Couldn’t load GIFs right now.", duration: 2400 });
  }finally{
    tenorLoading = false;
  }
}

function openGifPopover(){
  const pop = $("gif-popover");
  if (!pop) return;

  pop.hidden = false;
  pop.classList.remove("closing");
  requestAnimationFrame(() => pop.classList.add("open"));
  gifPopoverOpen = true;

  if (!gifBound){
    gifBound = true;

    const search = $("gif-search");
    const grid = $("gif-grid");

    let t = null;
    search?.addEventListener("input", () => {
      clearTimeout(t);
      t = setTimeout(() => {
        const q = String(search.value || "").trim();
        tenorQuery = q;
        tenorMode = q ? "search" : "featured";
        tenorNextPos = "";
        tenorHasMore = true;

        if (grid) grid.scrollTop = 0;
        loadTenorPage({ reset:true });
      }, 180);
    });

    // Infinite scroll: load more as you scroll near the bottom
    grid?.addEventListener("scroll", () => {
      if (tenorLoading || !tenorHasMore) return;
      const nearBottom = (grid.scrollTop + grid.clientHeight) >= (grid.scrollHeight - 180);
      if (nearBottom) loadTenorPage({ reset:false });
    }, { passive:true });
  }

  // initial load (featured) if nothing yet
  if (!tenorItems.length){
    tenorMode = "featured";
    tenorQuery = "";
    tenorNextPos = "";
    tenorHasMore = true;

    const search = $("gif-search");
    if (search) search.value = "";

    const grid = $("gif-grid");
    if (grid) grid.scrollTop = 0;

    loadTenorPage({ reset:true });
  }
}

function toggleGifPopover(){
  // Composer gif picker only inside rooms (chat rooms)
  if (!canUseGifPicker()){
    showToast({ title:"Pick a room", body:"Create or join a room first.", duration: 2200 });
    return;
  }

  if (gifPopoverOpen) closeGifPopover();
  else openGifPopover();
}

async function addTenorGifToPending(item){
  if (!canUseGifPicker()) return;

  if (pendingGifs.length >= 2){
    showToast({ title:"Max GIFs", body:"You can attach up to 2 GIFs per message.", duration: 2400 });
    return;
  }

  const gifUrl = pickTenorGifUrl(item);
  if (!gifUrl){
    showToast({ title:"GIF unavailable", body:"That GIF could not be loaded.", duration: 2200 });
    return;
  }

  try{
    const resp = await fetch(gifUrl);
    const blobRaw = await resp.blob();
    const blob = blobRaw.type ? blobRaw : blobRaw.slice(0, blobRaw.size, "image/gif");

    const tenorId = String(item?.id || "");
    const fileName = `tenor-${tenorId || "gif"}.gif`;

    const file = new File([blob], fileName, { type:"image/gif" });
    const previewURL = URL.createObjectURL(file);

    pendingGifs.push({
      kind: "gif",
      dataURL: "",
      previewURL,
      fileObject:file,
      fileName,
      name: String(item?.title || "Tenor GIF"),
      size: blob.size || 0,
      mimeType: "image/gif",
      tenorId: tenorId || null,
      tenorUrl: gifUrl
    });

    closeGifPopover();
    renderFilesBar();
  }catch(e){
    console.error("add tenor gif failed:", e);
    showToast({ title:"GIF failed", body:"Couldn’t add that GIF.", duration: 2400 });
  }
}

/* -------------------- Voice message composer (rooms only) -------------------- */
let voicePopoverOpen = false;
let voiceRecorderBound = false;
let voiceRecorder = null;
let voiceRecorderStream = null;
let voiceRecorderChunks = [];
let voiceRecordingStartAt = 0;
let voiceRecordingElapsedBeforePause = 0;
let voiceMessageTrimStartSec = 0;
let voiceRecordingTimer = 0;
let voiceRecordingPaused = false;
let voiceUploadInputEl = null;
let voicePreviewBlob = null;
let voicePreviewMimeType = "";
let voicePreviewFile = null;
let voicePreviewUrl = "";
let voiceRecorderStopMode = "preview";

function canUseVoiceComposer(){
  return canUseGifPicker();
}

function getBestVoiceMimeType(){
  const candidates = [
    "audio/webm;codecs=opus",
    "audio/ogg;codecs=opus",
    "audio/webm",
    "audio/ogg",
    "audio/mp4"
  ];
  for (const mime of candidates){
    try{
      if (globalThis.MediaRecorder?.isTypeSupported?.(mime)) return mime;
    }catch{}
  }
  return "";
}

function getVoiceFileExtension(mime){
  const m = String(mime || "").toLowerCase();
  if (m.includes("ogg")) return "ogg";
  if (m.includes("mp4")) return "m4a";
  return "webm";
}

function formatVoiceComposerTime(totalMs){
  const totalSec = Math.max(0, Math.floor((Number(totalMs) || 0) / 1000));
  const min = Math.floor(totalSec / 60);
  const sec = totalSec % 60;
  return `${min}:${String(sec).padStart(2, "0")}`;
}

function getVoiceRecordingElapsedMs(){
  if (!voiceRecordingStartAt) return voiceRecordingElapsedBeforePause;
  if (voiceRecordingPaused) return voiceRecordingElapsedBeforePause;
  return voiceRecordingElapsedBeforePause + Math.max(0, Date.now() - voiceRecordingStartAt);
}

function getVoicePreviewAudio(){
  return $("voice-preview-audio");
}

function stopVoicePreviewPlayback({ resetTime = false } = {}){
  const audio = getVoicePreviewAudio();
  if (!audio) return;
  try{ audio.pause(); }catch{}
  if (resetTime){
    try{ audio.currentTime = 0; }catch{}
  }
}

function revokeVoicePreviewUrl(){
  if (!voicePreviewUrl) return;
  try{ URL.revokeObjectURL(voicePreviewUrl); }catch{}
  voicePreviewUrl = "";
}

function syncVoicePreviewMedia(){
  const audio = getVoicePreviewAudio();
  if (!audio) return;
  if (voicePreviewUrl){
    if (audio.src !== voicePreviewUrl) audio.src = voicePreviewUrl;
    audio.hidden = false;
  } else {
    stopVoicePreviewPlayback({ resetTime:true });
    audio.removeAttribute("src");
    try{ audio.load(); }catch{}
    audio.hidden = true;
  }
}

function clearVoicePreview({ keepUi = false } = {}){
  stopVoicePreviewPlayback({ resetTime:true });
  voicePreviewBlob = null;
  voicePreviewMimeType = "";
  voicePreviewFile = null;
  revokeVoicePreviewUrl();
  syncVoicePreviewMedia();
  if (!keepUi) syncVoicePopoverUI();
}

function getVoicePreviewFile(){
  if (voicePreviewFile instanceof File) return voicePreviewFile;
  if (!(voicePreviewBlob instanceof Blob)) return null;
  const mime = String(voicePreviewMimeType || voicePreviewBlob.type || "audio/webm");
  const ext = getVoiceFileExtension(mime);
  voicePreviewFile = new File([voicePreviewBlob], `voice-message-${Date.now()}.${ext}`, { type: mime });
  return voicePreviewFile;
}

function stopVoiceRecordingTimer(){
  if (voiceRecordingTimer){
    clearInterval(voiceRecordingTimer);
    voiceRecordingTimer = 0;
  }
}

function startVoiceRecordingTimer(){
  stopVoiceRecordingTimer();
  voiceRecordingTimer = setInterval(() => {
    syncVoicePopoverUI();
  }, 120);
}

function resetVoiceRecorderState({ keepStream = false } = {}){
  stopVoiceRecordingTimer();
  voiceRecorder = null;
  voiceRecorderChunks = [];
  voiceRecordingStartAt = 0;
  voiceRecordingElapsedBeforePause = 0;
  voiceMessageTrimStartSec = 0;
  voiceRecordingPaused = false;
  voiceRecorderStopMode = "preview";

  if (!keepStream && voiceRecorderStream){
    try{ voiceRecorderStream.getTracks().forEach((track) => track.stop()); }catch{}
    voiceRecorderStream = null;
  }
}

async function ensureVoiceRecorderStream(){
  if (voiceRecorderStream) return voiceRecorderStream;
  if (!navigator.mediaDevices?.getUserMedia){
    throw new Error("Microphone access is not supported in this browser.");
  }
  voiceRecorderStream = await navigator.mediaDevices.getUserMedia({ audio:true });
  return voiceRecorderStream;
}

function syncVoicePopoverUI(){
  const pop = $("voice-popover");
  const preview = $("voice-preview-time");
  const state = $("voice-state-text");
  const pauseBtn = $("btn-voice-pause");
  const stopBtn = $("btn-voice-stop");
  const startBtn = $("btn-voice-start");
  const uploadBtn = $("btn-voice-upload");
  const clearBtn = $("btn-voice-clear");
  const previewAudio = getVoicePreviewAudio();

  const hasRecorder = !!voiceRecorder;
  const hasPreview = !!voicePreviewBlob;
  const overLimit = countPendingVoiceMessages() >= 3;
  const previewMs = (() => {
    if (hasRecorder) return getVoiceRecordingElapsedMs();
    if (previewAudio){
      const dur = Number(previewAudio.duration);
      if (Number.isFinite(dur) && dur > 0) return dur * 1000;
    }
    return 0;
  })();

  if (pop){
    pop.dataset.recording = hasRecorder && !voiceRecordingPaused ? "1" : "0";
    pop.dataset.paused = hasRecorder && voiceRecordingPaused ? "1" : "0";
    pop.dataset.hasPreview = hasPreview ? "1" : "0";
  }

  if (preview) preview.textContent = formatVoiceComposerTime(previewMs);
  if (state){
    state.textContent = hasRecorder
      ? (voiceRecordingPaused ? "Paused" : "Recording…")
      : (hasPreview ? "Preview ready" : "Ready to record");
  }

  if (startBtn){
    startBtn.hidden = hasRecorder;
    startBtn.disabled = overLimit;
    startBtn.textContent = hasPreview ? "Re-record" : "Start recording";
  }

  if (uploadBtn){
    uploadBtn.disabled = overLimit || hasRecorder;
  }

  if (pauseBtn){
    pauseBtn.hidden = !hasRecorder;
    pauseBtn.disabled = !hasRecorder;
    pauseBtn.textContent = voiceRecordingPaused ? "Resume" : "Pause";
  }

  if (stopBtn){
    stopBtn.hidden = !hasRecorder && !hasPreview;
    stopBtn.disabled = hasRecorder ? false : (!hasPreview || overLimit);
    stopBtn.textContent = hasRecorder ? "Stop" : "Send";
  }

  if (clearBtn){
    clearBtn.hidden = !hasRecorder && !hasPreview;
    clearBtn.disabled = false;
    clearBtn.textContent = hasRecorder ? "Cancel" : "Clear";
  }

  if (previewAudio){
    previewAudio.hidden = !hasPreview;
  }
}

async function addVoiceMessageFile(file){
  if (!file) return false;
  if (countPendingVoiceMessages() >= 3){
    showToast({ title:"Max voice messages", body:"You can attach up to 3 voice messages per message.", duration: 2400 });
    return false;
  }
  await addPendingFile(file, {
    isVoiceMessage: true,
    displayName: "Voice Message",
    voiceTrimStartSec: 0
  });
  renderFilesBar();
  syncChatOverlayMetrics();
  return true;
}

async function sendVoicePreviewToComposer(){
  const file = getVoicePreviewFile();
  if (!file) return;
  stopVoicePreviewPlayback({ resetTime:true });
  const added = await addVoiceMessageFile(file);
  if (!added) return;
  clearVoicePreview({ keepUi:true });
  syncVoicePopoverUI();
  closeVoicePopover({ keepRecorder:false });
}

async function startVoiceRecording(){
  if (!canUseVoiceComposer()) return;
  if (voiceRecorder) return;
  if (countPendingVoiceMessages() >= 3){
    showToast({ title:"Max voice messages", body:"You can attach up to 3 voice messages per message.", duration: 2400 });
    return;
  }

  try{
    stopVoicePreviewPlayback({ resetTime:true });
    clearVoicePreview({ keepUi:true });

    const stream = await ensureVoiceRecorderStream();
    const mimeType = getBestVoiceMimeType();
    voiceRecorderChunks = [];
    voiceRecordingElapsedBeforePause = 0;
    voiceMessageTrimStartSec = 0;
    voiceRecordingStartAt = Date.now();
    voiceRecordingPaused = false;
    voiceRecorderStopMode = "preview";

    const recorder = mimeType ? new MediaRecorder(stream, { mimeType }) : new MediaRecorder(stream);
    voiceRecorder = recorder;

    recorder.addEventListener("dataavailable", (e) => {
      if (e.data && e.data.size > 0) voiceRecorderChunks.push(e.data);
    });

    recorder.addEventListener("stop", () => {
      const shouldSavePreview = voiceRecorderStopMode !== "discard";
      const mime = String(recorder.mimeType || mimeType || "audio/webm");
      const chunks = voiceRecorderChunks.slice();

      resetVoiceRecorderState({ keepStream:false });

      if (shouldSavePreview && chunks.length){
        try{
          voicePreviewBlob = new Blob(chunks, { type: mime });
          voicePreviewMimeType = mime;
          voicePreviewFile = null;
          revokeVoicePreviewUrl();
          voicePreviewUrl = URL.createObjectURL(voicePreviewBlob);
          syncVoicePreviewMedia();
        }catch(e){
          console.error("voice preview build failed:", e);
          clearVoicePreview({ keepUi:true });
          showToast({ title:"Voice message failed", body:"Couldn’t prepare the preview.", duration: 2400 });
        }
      } else {
        clearVoicePreview({ keepUi:true });
      }

      syncVoicePopoverUI();
    });

    recorder.start(250);
    syncVoicePreviewMedia();
    startVoiceRecordingTimer();
    syncVoicePopoverUI();
  }catch(e){
    console.error("voice recording start failed:", e);
    resetVoiceRecorderState({ keepStream:false });
    clearVoicePreview({ keepUi:true });
    syncVoicePopoverUI();
    showToast({ title:"Microphone unavailable", body:"Allow microphone access and try again.", duration: 2800 });
  }
}

function toggleVoiceRecordingPause(){
  if (!voiceRecorder) return;

  try{
    if (voiceRecorder.state === "recording"){
      voiceRecordingElapsedBeforePause = getVoiceRecordingElapsedMs();
      try{ voiceRecorder.requestData?.(); }catch{}
      voiceRecordingPaused = true;
      voiceRecorder.pause();
    } else if (voiceRecorder.state === "paused"){
      voiceRecordingStartAt = Date.now();
      voiceRecordingPaused = false;
      voiceRecorder.resume();
    }
  }catch{}

  syncVoicePopoverUI();
}

function finishVoiceRecording({ savePreview = true } = {}){
  if (!voiceRecorder) return;
  voiceRecorderStopMode = savePreview ? "preview" : "discard";
  try{
    if (voiceRecorder.state !== "inactive") voiceRecorder.stop();
  }catch(e){
    console.error("voice recording stop failed:", e);
    resetVoiceRecorderState({ keepStream:false });
    if (!savePreview) clearVoicePreview({ keepUi:true });
    syncVoicePopoverUI();
    showToast({ title:"Voice message failed", body:"Couldn’t finish the recording.", duration: 2400 });
  }
}

function clearVoiceRecordingDraft(){
  if (voiceRecorder){
    finishVoiceRecording({ savePreview:false });
    return;
  }
  clearVoicePreview();
}

function closeVoicePopover({ keepRecorder = true } = {}){
  const pop = $("voice-popover");
  if (!pop || pop.hidden) return;

  stopVoicePreviewPlayback({ resetTime:false });

  pop.classList.remove("open");
  pop.classList.add("closing");

  const finish = () => {
    pop.hidden = true;
    pop.classList.remove("closing");
    voicePopoverOpen = false;
  };

  setTimeout(finish, 200);

  if (!keepRecorder && voiceRecorder){
    finishVoiceRecording({ savePreview:false });
  }
}

function bindVoicePopoverOnce(){
  if (voiceRecorderBound) return;
  voiceRecorderBound = true;

  voiceUploadInputEl = document.createElement("input");
  voiceUploadInputEl.type = "file";
  voiceUploadInputEl.accept = "audio/*";
  voiceUploadInputEl.hidden = true;
  document.body.appendChild(voiceUploadInputEl);

  voiceUploadInputEl.addEventListener("change", async () => {
    const file = voiceUploadInputEl.files?.[0];
    voiceUploadInputEl.value = "";
    if (!file) return;
    await addVoiceMessageFile(file);
    closeVoicePopover();
  });

  const previewAudio = getVoicePreviewAudio();
  if (previewAudio && previewAudio.dataset.bound !== "1"){
    previewAudio.dataset.bound = "1";
    previewAudio.addEventListener("loadedmetadata", syncVoicePopoverUI);
    previewAudio.addEventListener("durationchange", syncVoicePopoverUI);
    previewAudio.addEventListener("play", syncVoicePopoverUI);
    previewAudio.addEventListener("pause", syncVoicePopoverUI);
    previewAudio.addEventListener("ended", syncVoicePopoverUI);
  }

  $("btn-voice-start")?.addEventListener("click", async (e) => {
    e.preventDefault();
    e.stopPropagation();
    await startVoiceRecording();
  });

  $("btn-voice-pause")?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    toggleVoiceRecordingPause();
  });

  $("btn-voice-stop")?.addEventListener("click", async (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (voiceRecorder){
      finishVoiceRecording({ savePreview:true });
      return;
    }
    await sendVoicePreviewToComposer();
  });

  $("btn-voice-clear")?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    clearVoiceRecordingDraft();
  });

  $("btn-voice-upload")?.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (countPendingVoiceMessages() >= 3){
      showToast({ title:"Max voice messages", body:"You can attach up to 3 voice messages per message.", duration: 2400 });
      return;
    }
    voiceUploadInputEl?.click();
  });
}

function openVoicePopover(){
  const pop = $("voice-popover");
  if (!pop) return;

  bindVoicePopoverOnce();
  syncVoicePreviewMedia();
  pop.hidden = false;
  pop.classList.remove("closing");
  requestAnimationFrame(() => pop.classList.add("open"));
  voicePopoverOpen = true;
  syncVoicePopoverUI();
}

function toggleVoicePopover(){
  if (!canUseVoiceComposer()){
    showToast({ title:"Pick a room", body:"Create or join a room first.", duration: 2200 });
    return;
  }

  if (voicePopoverOpen) closeVoicePopover();
  else openVoicePopover();
}

