// Slideshow keybinds
document.addEventListener("keydown", (e) => {
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  if (placeNow !== "slideshow") return;

  const t = e.target;
  if (t instanceof HTMLElement){
    const tag = t.tagName;
    if (tag === "INPUT" || tag === "TEXTAREA" || t.isContentEditable) return;
  }

  const rawKey = String(e.key || "");
  const key = rawKey.toLowerCase();

  if (slideshowSelectedObjId && ["ArrowLeft","ArrowRight","ArrowUp","ArrowDown"].includes(rawKey)){
    e.preventDefault();
    e.stopPropagation();
    const step = e.shiftKey ? SLIDESHOW_NUDGE_BIG_STEP_PCT : SLIDESHOW_NUDGE_STEP_PCT;
    if (rawKey === "ArrowLeft") slideshowNudgeSelectedObject(-step, 0);
    if (rawKey === "ArrowRight") slideshowNudgeSelectedObject(step, 0);
    if (rawKey === "ArrowUp") slideshowNudgeSelectedObject(0, -step);
    if (rawKey === "ArrowDown") slideshowNudgeSelectedObject(0, step);
    return;
  }

  if (!(e.ctrlKey || e.metaKey)) return;

  if (key === "x"){
    e.preventDefault();
    e.stopPropagation();
    slideshowAlignSelectedObject("x");
    return;
  }

  if (key === "y"){
    e.preventDefault();
    e.stopPropagation();
    slideshowAlignSelectedObject("y");
    return;
  }

  if (key === "e"){
    e.preventDefault();
    e.stopPropagation();
    slideshowAlignSelectedObject("both");
    return;
  }

  if (key === "]"){
    e.preventDefault();
    e.stopPropagation();
    slideshowSetSelectedObjectLayer("front");
    return;
  }

  if (key === "["){
    e.preventDefault();
    e.stopPropagation();
    slideshowSetSelectedObjectLayer("back");
    return;
  }

  // Ctrl/Cmd + C: copy selected object (200ms delay to allow selection click to settle)
  if (key === "c"){
    if (!slideshowSelectedObjId) return;
    e.preventDefault();
    e.stopPropagation();
    setTimeout(() => {
      if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
      if (!slideshowSelectedObjId) return;
      slideshowCopySelectedObject();
      applySlideshowComposerRules();
    }, 200);
    return;
  }

  // Ctrl/Cmd + V: paste (works with or without an object selected; requires something copied)
  if (key === "v"){
    if (!slideshowClipboard) return;
    e.preventDefault();
    e.stopPropagation();
    setTimeout(() => {
      if ((localStorage.getItem(LS.PLACE) || "") !== "slideshow") return;
      if (!slideshowClipboard) return;
      slideshowPasteClipboardObject();
      applySlideshowComposerRules();
    }, 200);
  }
});

let msgInputFocused = false;
const MSG_INPUT_MIN_HEIGHT = 38;
const MSG_INPUT_MAX_VIEWPORT_RATIO = 0.42;

function isRoomComposerPreviewActive(){
  return !!(views.chat?.dataset.active === "true");
}

function syncComposerPreviewHeight({ forceCollapsed=false } = {}){
  const composer = $("composer");
  const input = $("msg-input");
  if (!composer || !input) return;

  input.style.height = "auto";

  const viewportH = Math.max(window.innerHeight || 0, document.documentElement?.clientHeight || 0);
  const maxHeight = Math.max(MSG_INPUT_MIN_HEIGHT, Math.floor(viewportH * MSG_INPUT_MAX_VIEWPORT_RATIO));

  const cs = window.getComputedStyle(input);
  const probe = document.createElement("textarea");
  probe.className = input.className;
  probe.setAttribute("rows", "1");
  probe.setAttribute("tabindex", "-1");
  probe.style.position = "absolute";
  probe.style.visibility = "hidden";
  probe.style.pointerEvents = "none";
  probe.style.left = "-9999px";
  probe.style.top = "0";
  probe.style.height = "0px";
  probe.style.minHeight = "0";
  probe.style.maxHeight = "none";
  probe.style.overflowY = "hidden";
  probe.style.whiteSpace = cs.whiteSpace;
  probe.style.overflowWrap = cs.overflowWrap;
  probe.style.wordBreak = cs.wordBreak;
  probe.style.boxSizing = cs.boxSizing;
  probe.style.width = `${input.clientWidth || input.offsetWidth || 0}px`;
  document.body.appendChild(probe);

  const measureComposerHeight = (value) => {
    probe.value = value;
    probe.style.height = "0px";
    return Math.max(MSG_INPUT_MIN_HEIGHT, Math.min(probe.scrollHeight, maxHeight));
  };

  const singleRowHeight = measureComposerHeight("W");
  const contentHeight = measureComposerHeight(input.value || "");
  probe.remove();

  const needsExtraRows = /[\r\n]/.test(input.value || "") || contentHeight > singleRowHeight + 1;
  const shouldPreview = !!(msgInputFocused && isRoomComposerPreviewActive() && !forceCollapsed && needsExtraRows);

  composer.classList.toggle("composer-previewing", shouldPreview);

  if (!shouldPreview){
    input.style.overflowY = "hidden";
    input.style.height = `${MSG_INPUT_MIN_HEIGHT}px`;
    syncChatOverlayMetrics();
    return;
  }

  input.style.height = `${contentHeight}px`;
  input.style.overflowY = input.scrollHeight > maxHeight ? "auto" : "hidden";
  syncChatOverlayMetrics();
}

$("msg-input").addEventListener("focus", () => {
  msgInputFocused = true;
  requestAnimationFrame(() => syncComposerPreviewHeight());
});
$("msg-input").addEventListener("blur", () => {
  msgInputFocused = false;
  setMyTyping(false);
  syncComposerPreviewHeight({ forceCollapsed:true });
});

window.addEventListener("resize", () => syncComposerPreviewHeight(), { passive:true });
window.addEventListener("load", () => {
  requestAnimationFrame(() => syncComposerPreviewHeight({ forceCollapsed:true }));
}, { once:true });
requestAnimationFrame(() => syncComposerPreviewHeight({ forceCollapsed:true }));

let lastMsgInputVal = "";
$("msg-input").addEventListener("input", () => {
  const input = $("msg-input");
  if (!input) return;

  syncComposerPreviewHeight();

  let val = String(input.value || "");
  const placeNow = localStorage.getItem(LS.PLACE) || "home";

  if (msgInputFocused && currentRoomId) bumpMyTyping();

  const canPingHere = !!(msgInputFocused && currentRoomId && placeNow.startsWith("room:") && views.chat.dataset.active === "true");

  if (canPingHere && replaceDisplayNameMentionsInComposer(input)){
    val = String(input.value || "");
    syncComposerPreviewHeight();
  }

  if (!canPingHere){
    if (pingBarEl && !pingBarEl.hidden) closePingBar({ quiet:true });
    lastMsgInputVal = val;
    return;
  }

  const caret = (typeof input.selectionStart === "number") ? input.selectionStart : val.length;
  const atIdx = caret - 1;
  const justTypedAt = (atIdx >= 0 && val[atIdx] === "@" && val.length === lastMsgInputVal.length + 1);
  const okAtBoundary = (atIdx === 0 || /\s/.test(val[atIdx - 1] || ""));

  if (justTypedAt && okAtBoundary){
    openPingBar({ tokenStart: atIdx });
    lastMsgInputVal = val;
    return;
  }

  if (justTypedAt && !okAtBoundary){
    if (pingBarEl && !pingBarEl.hidden) closePingBar({ quiet:true });
  }

  if (pingBarEl && !pingBarEl.hidden){
    if (pingTokenStart < 0 || pingTokenStart >= val.length || val[pingTokenStart] !== "@"){
      closePingBar({ quiet:true });
    } else {
      renderPingList();
    }
  }

  lastMsgInputVal = val;
});

function canChat(){
  return !!(currentUser && currentRoomId);
}

function getMessagePreviewText(msg){
  const text = String(msg?.text || "").trim();
  if (text) return text;

  let files = Array.isArray(msg?.files) ? msg.files : [];
  const gifs = Array.isArray(msg?.gifs) ? msg.gifs : [];

  if (!files.length && (msg?.t === "image" || msg?.t === "video" || msg?.t === "html" || msg?.t === "audio") && msg?.dataURL){
    files = [{ kind: msg.t, dataURL: msg.dataURL }];
  }

  const all = [...files, ...gifs];
  if (!all.length) return "";

  const kinds = Array.from(new Set(all.map((f) => String(f?.kind || "file"))));

  if (all.length === 1){
    const k = kinds[0];
    return (k === "video") ? "[Video]" :
      (k === "image") ? "[Image]" :
      (k === "gif")   ? "[GIF]" :
      (k === "audio") ? "[Audio]" :
      (k === "html")  ? "[HTML]" :
      "[File]";
  }

  if (kinds.length === 1){
    const k = kinds[0];
    return (k === "video") ? `[${all.length} Videos]` :
      (k === "image") ? `[${all.length} Images]` :
      (k === "gif")   ? `[${all.length} GIFs]` :
      (k === "audio") ? `[${all.length} Audio Files]` :
      (k === "html")  ? `[${all.length} HTML]` :
      `[${all.length} Files]`;
  }

  return "[Attachments]";
}

function getLatestLoadedMessageKey(){
  let latestKey = "";
  let latestCreatedAt = -1;

  for (const [key, item] of msgDataByKey.entries()){
    const createdAt = Number(item?.createdAt) || 0;
    if (createdAt > latestCreatedAt || (createdAt === latestCreatedAt && String(key).localeCompare(latestKey) > 0)){
      latestKey = String(key);
      latestCreatedAt = createdAt;
    }
  }

  return latestKey;
}

function formatRoomLastMessagePreview(preview, username = currentUser?.username){
  const sender = sanitizeUsername(username || "") || "Unknown";
  const body = String(preview || "").trim();
  return (body ? `${sender}: ${body}` : sender).slice(0, 90);
}

async function syncRoomLastMessagePreview(roomId, preview){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  try{
    await db.ref(`rooms/${id}`).update({
      lastMessagePreview: formatRoomLastMessagePreview(preview)
    });
  }catch{}
}

async function updateRoomLastMessage(roomId, preview){
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  try{
    await db.ref(`rooms/${id}/messageCount`).transaction((cur) => (Number(cur) || 0) + 1);
    await db.ref(`rooms/${id}`).update({
      lastMessageAt: firebase.database.ServerValue.TIMESTAMP,
      lastMessagePreview: formatRoomLastMessagePreview(preview)
    });
  }catch{}
}

function getReplyTargetCacheKey(roomId, targetKey){
  const rid = sanitizeRoomCode(roomId || currentRoomId);
  const key = String(targetKey || "");
  return (rid && key) ? `${rid}:${key}` : "";
}

function getReplyTargetMessage(targetKey, roomId = currentRoomId){
  const key = String(targetKey || "");
  if (!key) return null;
  return msgDataByKey.get(key) || replyTargetPreviewCache.get(getReplyTargetCacheKey(roomId, key)) || null;
}

function scheduleReplyTargetPreviewHydrate(roomId, targetKey){
  const rid = sanitizeRoomCode(roomId || currentRoomId);
  const key = String(targetKey || "");
  const cacheKey = getReplyTargetCacheKey(rid, key);
  if (!rid || !key || !cacheKey) return;
  if (msgDataByKey.has(key) || replyTargetPreviewCache.has(cacheKey) || replyTargetHydratePending.has(cacheKey)) return;

  replyTargetHydratePending.add(cacheKey);
  db.ref(`messages/${rid}/${key}`).once("value").then((snap) => {
    const raw = snap.val();
    if (!raw) return;

    const targetMsg = normalizeMessageMedia({ _key:key, ...raw });
    replyTargetPreviewCache.set(cacheKey, targetMsg);
    refreshReplyPreviewDependents(key);
    if (replyState && String(replyState.key || "") === key) updateReplyBarPreview();
  }).catch(() => {}).finally(() => {
    replyTargetHydratePending.delete(cacheKey);
  });
}

function refreshReplyPreviewDependents(targetKey){
  const key = String(targetKey || "");
  if (!key) return;

  const dependents = [];
  for (const [msgKey, item] of msgDataByKey.entries()){
    if (msgKey === key) continue;
    if (String(item?.replyTo?.key || "") !== key) continue;
    dependents.push(item);
  }

  for (const item of dependents){
    replaceMessageRowByKey(item);
  }
}

function enqueueSendTask(taskFn){
  const task = Promise.resolve()
    .then(() => taskFn())
    .catch((e) => { console.error("send queue task failed:", e); });
  return task;
}

function extractMentionUsernames(text){
  const out = [];
  const me = String(currentUser?.username || "").toLowerCase();

  // Match @User where @ is not part of an email/word (prevents "test@email.com" hits)
  const re = /(^|\s)@([A-Za-z0-9_]{1,32})\b/g;
  let m;
  while ((m = re.exec(String(text || "")))){
    const raw = String(m[2] || "").trim();
    if (!raw) continue;
    const cleaned = sanitizeUsername(raw);
    if (!cleaned) continue;
    if (cleaned.toLowerCase() === me) continue; // cannot ping yourself
    out.push(cleaned);
  }

  const seen = new Set();
  const uniq = [];
  for (const name of out){
    const k = name.toLowerCase();
    if (seen.has(k)) continue;
    seen.add(k);
    uniq.push(name);
  }
  return uniq;
}

function findMentionNeedingSpace(text){
  const s = String(text || "");
  const known = new Map();

  const add = (name) => {
    const cleaned = sanitizeUsername(String(name || ""));
    if (!cleaned) return;
    const low = cleaned.toLowerCase();
    if (!known.has(low)) known.set(low, cleaned);
  };

  try{ (schedulesPeopleCache || []).forEach((u) => add(u?.username || u?.displayName || "")); }catch{}
  add(currentUser?.username || "");
  try{ for (const u of liveUserCache.values()) add(u?.username || ""); }catch{}

  const knownList = Array.from(known.entries())
    .map(([lower, display]) => ({ lower, display }))
    .sort((a,b) => b.lower.length - a.lower.length);

  // Roomwide aliases must also be followed by a literal space.
  const aliasRe = /(^|\s)@(everyone|all|a)(?=$|[^A-Za-z0-9_])/gi;
  let aliasMatch;
  while ((aliasMatch = aliasRe.exec(s))){
    const end = aliasRe.lastIndex;
    const nextCh = s[end] || "";
    if (nextCh !== " ") return aliasMatch[2];
  }

  if (!knownList.length) return null;

  // Find "@Username" tokens. If the token is a known username, it MUST be followed by a literal space.
  // If the token starts with a known username but has extra characters (e.g. "@TJhey"), block send.
  const re = /(^|\s)@([A-Za-z0-9_]{1,32})/g;
  let m;
  while ((m = re.exec(s))){
    const token = String(m[2] || "");
    const tokenLower = token.toLowerCase();
    const end = re.lastIndex;
    const nextCh = s[end] || "";

    for (const u of knownList){
      if (tokenLower === u.lower){
        if (nextCh !== " ") return u.display;
        break;
      }
      if (tokenLower.startsWith(u.lower)){
        return u.display;
      }
    }
  }

  return null;
}

async function resolveUserCodeByUsername(username){
  const cleaned = sanitizeUsername(username);
  if (!cleaned) return null;
  const hash = await sha256Hex(cleaned.toLowerCase());
  const snap = await db.ref(`usernames/${hash}`).once("value");
  if (!snap.exists()) return null;
  const v = snap.val();
  const code = (typeof v === "string")
    ? v
    : String((v && typeof v === "object" ? (v.code || v.c || "") : "") || "");
  return code ? code : null;
}

async function maybeSendPingsFromText({ roomId, text, msgKey }){
  if (!currentUser) return;
  const id = sanitizeRoomCode(roomId);
  if (!id) return;

  const rawText = String(text || "");
  const names = extractMentionUsernames(rawText);
  const wantsRoomwidePing = /(^|\s)@(everyone|all|a)(?=$|[^A-Za-z0-9_])/i.test(rawText);

  const codes = [];

  if (wantsRoomwidePing){
    try{
      const membershipsSnap = await db.ref("memberships").once("value");
      const memberships = membershipsSnap.val() || {};
      for (const [userCode, rooms] of Object.entries(memberships)){
        if (!userCode) continue;
        if (String(userCode) === String(currentUser.code || "")) continue;
        if (!rooms || typeof rooms !== "object") continue;
        if (!rooms[id]) continue;
        codes.push(String(userCode));
      }
    }catch{}
  }

  for (const name of names){
    try{
      const code = await resolveUserCodeByUsername(name);
      if (code) codes.push(code);
    }catch{}
  }

  const uniqueCodes = Array.from(new Set(codes)).filter((c) => c && c !== currentUser.code);

  for (const targetCode of uniqueCodes){
    try{
      const mem = await db.ref(`memberships/${targetCode}/${id}`).once("value");
      if (!mem.exists()) continue;

      const pingRef = db.ref(`pings/${targetCode}/${id}`).push();
      await pingRef.set({
        from: currentUser.code,
        fromUsername: currentUser.username,
        at: firebase.database.ServerValue.TIMESTAMP,
        msgKey: msgKey || null
      });
    }catch{}
  }
}

async function sendTextMessage(){
  // Slideshow: apply edits to selected text object
  if ((localStorage.getItem(LS.PLACE) || "") === "slideshow"){
    slideshowApplyTextFromComposer();
    return;
  }

  const roomId = sanitizeRoomCode(currentRoomId);
  if (!currentUser || !roomId){
    showToast({ title:"Not in a room", body:"Open a room first.", duration: 1800 });
    return;
  }

  initOverlaysUI();

  const input = $("msg-input");
  const raw = (input.value || "");
  const text = raw.trim();
  const hasFiles = Array.isArray(pendingFiles) && pendingFiles.length > 0;
  const hasGifs = Array.isArray(pendingGifs) && pendingGifs.length > 0;
  const editingThisRoom = !!(editState && editState.roomId === roomId);

  if (editingThisRoom){
    const editKey = String(editState?.key || "");
    const prevMsg = editKey ? (msgDataByKey.get(editKey) || null) : null;

    if (!editKey || !prevMsg){
      cancelEditMessage({ keepText:true, quiet:true });
      syncComposerPrimaryAction();
      showToast({ title:"Edit expired", body:"Open the message menu and try again.", duration: 2200 });
      return;
    }

    if (String(prevMsg.userCode || "") !== String(currentUser.code || "")){
      cancelEditMessage({ keepText:true, quiet:true });
      syncComposerPrimaryAction();
      showToast({ title:"Edit blocked", body:"You can only edit your own messages.", duration: 2200 });
      return;
    }

    const prevFiles = Array.isArray(prevMsg.files) ? prevMsg.files : [];
    const prevGifs = Array.isArray(prevMsg.gifs) ? prevMsg.gifs : [];
    if (!text && !prevFiles.length && !prevGifs.length){
      showToast({ title:"Message is empty", body:"Add text before saving this edit.", duration: 2200 });
      return;
    }

    const previousText = String(prevMsg.text || "");
    const optimistic = {
      ...prevMsg,
      text: text || "",
      editedPrevText: previousText,
      editedAt: Date.now()
    };

    replaceMessageRowByKey(optimistic);
    refreshReplyPreviewDependents(editKey);

    const restoreEditState = () => {
      editState = { key: editKey, roomId, originalText: previousText };
      if (input){
        input.value = raw;
        lastMsgInputVal = raw;
        input.placeholder = "Edit your message…";
        try{
          input.focus();
          input.setSelectionRange(input.value.length, input.value.length);
        }catch{}
      }
      try{ syncComposerPreviewHeight(); }catch{}
      syncComposerPrimaryAction();
    };

    editState = null;
    if (input){
      input.value = "";
      lastMsgInputVal = "";
      input.placeholder = "Type a message…";
    }
    setMyTyping(false);
    try{ syncComposerPreviewHeight(); }catch{}
    try{ input.focus(); }catch{}
    syncComposerPrimaryAction();

    try{
      await db.ref(`messages/${roomId}/${editKey}`).update({
        text: text || "",
        editedPrevText: previousText,
        editedAt: firebase.database.ServerValue.TIMESTAMP
      });

      if (getLatestLoadedMessageKey() === editKey){
        await syncRoomLastMessagePreview(roomId, getMessagePreviewText({
          ...prevMsg,
          text: text || "",
          editedPrevText: previousText,
          editedAt: Date.now()
        }));
      }
    }catch(e){
      console.error("edit message failed:", e);
      replaceMessageRowByKey(prevMsg);
      refreshReplyPreviewDependents(editKey);
      restoreEditState();
      showToast({ title:"Edit failed", body:"Check console / rules.", duration: 2600 });
    }
    return;
  }

  if (!text && !hasFiles && !hasGifs) return;

  const shouldPinAfterSend = autoScrollEnabled && isNearBottom(420);

  const badPing = findMentionNeedingSpace(raw);
  if (badPing){
    showToast({
      title:"Ping needs a space",
      body:`Add a space after @${badPing} before sending (example: "@${badPing} hey").`,
      duration: 4200
    });
    return;
  }

  const filesSnap = hasFiles ? pendingFiles.slice().map(f => ({ ...f })) : [];
  const gifsSnap  = hasGifs  ? pendingGifs.slice(0, 2).map(g => ({ ...g })) : [];
  const replySnap = (replyState && replyState.key) ? { ...replyState } : null;

  let lastPreview = text;
  if (!lastPreview && (filesSnap.length || gifsSnap.length)){
    const all = [...filesSnap, ...gifsSnap];
    const kinds = Array.from(new Set(all.map(f => {
      if (f?.isVoiceMessage) return "voice";
      return String(f.kind || "file");
    })));

    if (all.length === 1){
      const k = kinds[0];
      lastPreview =
        (k === "voice") ? "[Voice Message]" :
        (k === "video") ? "[Video]" :
        (k === "image") ? "[Image]" :
        (k === "gif")   ? "[GIF]" :
        (k === "audio") ? "[Audio]" :
        (k === "html")  ? "[HTML]" :
        "[File]";
    } else if (kinds.length === 1){
      const k = kinds[0];
      lastPreview =
        (k === "voice") ? `[${all.length} Voice Messages]` :
        (k === "video") ? `[${all.length} Videos]` :
        (k === "image") ? `[${all.length} Images]` :
        (k === "gif")   ? `[${all.length} GIFs]` :
        (k === "audio") ? `[${all.length} Audio Files]` :
        (k === "html")  ? `[${all.length} HTML]` :
        `[${all.length} Files]`;
    } else {
      lastPreview = "[Attachments]";
    }
  }

  const msg = {
    t: "text",
    text: text || "",
    userCode: currentUser.code,
    username: currentUser.username,
    displayName: currentUser.displayName || currentUser.username || "User",
    photoDataURL: currentUser.photoDataURL || defaultStickmanDataURL(),
    photoTransform: currentUser.photoTransform || null,
    createdAt: firebase.database.ServerValue.TIMESTAMP
  };

  if (filesSnap.length){
    msg.files = filesSnap.map(f => {
      const existingData = readChunkedField(f, "dataURL") || String(f.dataURL || "");
      return {
        kind: f.kind,
        dataURL: "",
        fileName: f.fileName || null,
        name: f.name || "",
        displayName: f.displayName || "",
        isVoiceMessage: !!f.isVoiceMessage,
        voiceTrimStartSec: Math.max(0, Number(f.voiceTrimStartSec) || 0),
        mimeType: f.mimeType || f.type || "",
        size: f.size || 0,
        dataChunkCount: f.fileObject instanceof Blob ? countDataURLChunksForBlob(f.fileObject) : countChunkedPartsForValue(existingData),
        uploadPending: 1,
        uploadProgress: 0
      };
    });
  }

  if (gifsSnap.length){
    msg.gifs = gifsSnap.map(g => {
      const existingData = readChunkedField(g, "dataURL") || String(g.dataURL || "");
      return {
        kind: "gif",
        dataURL: "",
        fileName: g.fileName || null,
        name: g.name || "",
        size: g.size || 0,
        source: "tenor",
        tenorId: g.tenorId || null,
        tenorUrl: g.tenorUrl || null,
        dataChunkCount: g.fileObject instanceof Blob ? countDataURLChunksForBlob(g.fileObject) : countChunkedPartsForValue(existingData),
        uploadPending: 1,
        uploadProgress: 0
      };
    });
  }

  if (replySnap?.key){
    const replyTargetMsg = getReplyTargetMessage(replySnap.key, roomId);
    const replyPreviewText = getReplyTargetPreviewText(replyTargetMsg);

    msg.replyTo = {
      key: replySnap.key,
      userCode: replySnap.userCode || String(replyTargetMsg?.userCode || ""),
      username: replySnap.username || replyTargetMsg?.username || "User",
      displayName: replySnap.displayName || replyTargetMsg?.displayName || replySnap.username || "User",
      previewText: replyPreviewText === "Original message is still loading." ? "" : replyPreviewText,
      attachmentCount: getReplyTargetAttachmentCount(replyTargetMsg)
    };
  }

  if (shouldPinAfterSend) forceScrollToBottomFor(1400, { reason:"send-before-clear" });

  // Clear UI instantly (no animations / no waiting for Firebase).
  input.value = "";
  lastMsgInputVal = "";
  try{ closePingBar({ quiet:true }); }catch{}
  try{ clearReplyState({ quiet:true }); }catch{}
  try{ clearPendingFiles({ quiet:true }); }catch{}
  setMyTyping(false);
  try{ syncComposerPreviewHeight(); }catch{}
  try{ input.focus(); }catch{}

  // Optimistic paint: show the message immediately (including attachments) as a stub.
  const newRef = db.ref(`messages/${roomId}`).push();
  const msgKey = newRef.key;
  if (msgKey){
    const stub = { ...msg, _key: msgKey, createdAt: Date.now(), __stub: 1 };

    if (filesSnap.length){
      stub.files = filesSnap.map(f => ({
        kind: f.kind,
        dataURL: "",
        previewURL: String(f.previewURL || ""),
        fileName: f.fileName || null,
        name: f.name || "",
        displayName: f.displayName || "",
        isVoiceMessage: !!f.isVoiceMessage,
        voiceTrimStartSec: Math.max(0, Number(f.voiceTrimStartSec) || 0),
        mimeType: f.mimeType || f.type || "",
        size: f.size || 0,
        uploadPending: 1,
        __loading: 1
      }));
    }

    if (gifsSnap.length){
      stub.gifs = gifsSnap.map(g => ({
        kind: "gif",
        dataURL: "",
        previewURL: String(g.previewURL || g.dataURL || g.tenorUrl || ""),
        fileName: g.fileName || null,
        name: g.name || "",
        size: g.size || 0,
        source: "tenor",
        tenorId: g.tenorId || null,
        tenorUrl: g.tenorUrl || null,
        dataChunkCount: g.fileObject instanceof Blob ? countDataURLChunksForBlob(g.fileObject) : countChunkedPartsForValue(g.dataURL),
        uploadPending: 1,
        __loading: 1
      }));
    }

    renderedMsgKeys.add(msgKey);
    appendMessageRow(stub);
    if (shouldPinAfterSend) forceScrollToBottomFor(1400, { reason:"send-stub" });
  }

  enqueueSendTask(async () => {
    let sent = false;
    const k = String(newRef.key || "");
    const hasUpload = filesSnap.length || gifsSnap.length;

    const removeLocalMessage = async () => {
      try{ await newRef.remove(); }catch{}
      if (k){
        try{ msgElByKey.get(k)?.remove(); }catch{}
        try{ msgElByKey.delete(k); }catch{}
        try{ msgDataByKey.delete(k); }catch{}
        try{ renderedMsgKeys.delete(k); }catch{}
      }
    };

    const attachmentUploadScope = hasUpload ? createFirebaseUploadScope({
      type:"chat-message",
      place:`room:${roomId}`,
      disconnectRefs:[newRef],
      cleanup: removeLocalMessage
    }) : null;
    
    try{
      if (attachmentUploadScope) await armFirebaseUploadDisconnect(attachmentUploadScope);

      await setRefWithRetry(newRef, msg, RTDB_CHUNK_UPLOAD_RETRIES, attachmentUploadScope?.signal || null);

      sent = true;

      if (k){
        const prev = msgDataByKey.get(k) || null;
        const localCommitted = mergeMessageMediaForDisplay(
          normalizeMessageMedia({
            ...msg,
            _key: k,
            createdAt: Number(prev?.createdAt) || Date.now(),
            attachmentsSyncedAt: hasUpload ? 0 : Date.now()
          }),
          prev
        );
        replaceMessageRowByKey(localCommitted);
        if (shouldPinAfterSend) forceScrollToBottomFor(1200, { reason:"send-commit" });
      }

      if (hasUpload){
        Promise.resolve().then(async () => {
          try{
            await writeMessageAttachmentsToRef(newRef, filesSnap, gifsSnap, {
              signal: attachmentUploadScope.signal,
              roomId,
              msgKey: k,
              onProgress: ({ group, index, progress }) => {
                const liveMsg = msgDataByKey.get(k);
                const list = group === "gifs" ? liveMsg?.gifs : liveMsg?.files;
                if (!Array.isArray(list) || !list[index]) return;
                list[index] = { ...list[index], uploadProgress: progress, uploadPending: progress >= 100 ? null : 1 };
                replaceMessageRowByKey({ ...liveMsg, [group]: list });
              }
            });

            await finishFirebaseUploadScope(attachmentUploadScope);

            const committedSnap = await newRef.once("value");
            const committedRaw = committedSnap.val();
            if (!committedRaw) return;

            const committedMsg = mergeMessageMediaForDisplay(
              normalizeMessageMedia({ _key:k, ...committedRaw }),
              msgDataByKey.get(k) || null
            );
            replaceMessageRowByKey(committedMsg);
            if (messageHasPendingChunkedMedia(committedMsg)){
              scheduleMessageMediaRefresh(roomId, k, 120);
            }
          }catch(e){
            await cleanupFirebaseUploadScope(attachmentUploadScope, e?.message || "chat upload failed");
            if (isUploadAbortError(e)) return;
            console.error("attachment upload failed:", e);
            showToast({
              title:"Attachment sync incomplete",
              body:"The message was removed because one or more attachments could not finish syncing.",
              duration: 3200
            });
          }
        });
      }
    }catch(e){
      console.error("send message failed:", e);
      if (attachmentUploadScope) await cleanupFirebaseUploadScope(attachmentUploadScope, e?.message || "send failed");
      else await removeLocalMessage();

      const canRestore = (() => {
        const curText = String(($("msg-input")?.value || "")).trim();
        const curHasAtt = getTotalPendingAttachmentCount() > 0;
        const curHasReply = !!(replyState && replyState.key);
        return !curText && !curHasAtt && !curHasReply;
      })();

      if (canRestore){
        try{ $("msg-input").value = raw; }catch{}
        try{ pendingFiles = filesSnap.map(f => ({ ...f })); }catch{}
        try{ pendingGifs  = gifsSnap.map(g => ({ ...g })); }catch{}
        try{ if (getTotalPendingAttachmentCount() > 0) renderFilesBar(); }catch{}
        try{ if (replySnap?.key) setReplyState(replySnap); }catch{}
        try{ syncChatOverlayMetrics(); }catch{}
      }

      showToast({ title:"Send failed", body:"Check console / rules.", duration: 2600 });
      return;
    }

    if (!sent) return;

    Promise.resolve().then(async () => {
      try{ await maybeSendPingsFromText({ roomId, text, msgKey: k }); }catch{}
      try{ await updateRoomLastMessage(roomId, lastPreview || ""); }catch{}
      try{ scheduleLastSeenBump(roomId, { immediate:true }); }catch{}
    });
  });
}

$("btn-upload").addEventListener("click", () => {
  const placeNow = localStorage.getItem(LS.PLACE) || "home";

  if (placeNow === "slideshow"){
    if (!slideshowSelectedId){
      showToast({ title:"Select a slide", body:"Pick a slide first.", duration: 2200 });
      return;
    }
    slideshowFilePickMode = "object";
    slideshowDividerInsertMode = false;
    slideshowTitleInsertMode = false;
    try{
      const fi = $("file-input");
      if (fi){
        fi.accept = "image/*,image/gif,video/*,audio/*";
        fi.click();
      }
    }catch{}
    return;
  }

  if (!canChat()){
    showToast({ title:"Pick a room", body:"Create or join a room first.", duration: 2200 });
    return;
  }
  $("file-input").click();
});

$("file-input").addEventListener("change", async () => {
  const placeNow = localStorage.getItem(LS.PLACE) || "home";
  const picked = Array.from($("file-input").files || []);
  $("file-input").value = "";
  if (!picked.length) return;

  if (placeNow === "slideshow"){
    if (!slideshowSelectedId){
      showToast({ title:"Select a slide", body:"Pick a slide first.", duration: 2200 });
      return;
    }

    // Slideshows support only images/GIFs/videos/audio and insert them onto the slide
    const allow = picked.filter(f => {
      const kind = chatFileKind(f);
      return kind === "image" || kind === "video" || kind === "audio";
    });

    if (!allow.length){
      showToast({ title:"Not supported", body:"Slideshows only support images/GIFs/videos/audio.", duration: 2400 });
      return;
    }

    if (slideshowFilePickMode === "bg"){
      slideshowFilePickMode = "object";
      const f = allow[0];
      let previewURL = "";
      try{ previewURL = URL.createObjectURL(f); }catch{ previewURL = ""; }
      try{
        await slideshowSetBackground({ type:"image", src:"", previewURL, fileObject:f });
      }catch{
        if (previewURL.startsWith("blob:")) try{ URL.revokeObjectURL(previewURL); }catch{}
        showToast({ title:"Upload failed", body:"Couldn’t upload that file.", duration: 2400 });
      }
      return;
    }

    await slideshowAddMediaFiles(allow);
    return;
  }

  // Room uploads (attachments)
  if (!canChat()){
    showToast({ title:"Pick a room", body:"Create or join a room first.", duration: 2200 });
    return;
  }

  initOverlaysUI();

  const maxTotal = 3;
  const currentStandardFiles = countPendingStandardFiles();
  const space = maxTotal - currentStandardFiles;
  if (space <= 0){
    showToast({ title:"Max files", body:"You can attach up to 3 regular files at a time.", duration: 2400 });
    return;
  }

  const use = picked.slice(0, space);
  for (const file of use){
    const ok = await addPendingFile(file);
    if (!ok) break;
  }
});

/* -------------------- Media viewer -------------------- */
// Video UI stored in Realtime Database (no Firebase Storage).
const VIDEO_UI_DEFAULTS = {
  stepBackSec: 5,
  stepFwdSec: 5,
  speeds: [0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2],
  maxCustomSpeed: 10,
  mediaZoom: {
    step: 0.5,
    wheelStep: 0.5,
    maxScale: 20,
    doubleTapScale: 2.5
  }
};

let videoUiConfigCache = null;
let videoUiConfigPromise = null;

async function getVideoUiConfig(){
  if (videoUiConfigCache) return videoUiConfigCache;
  if (videoUiConfigPromise) return videoUiConfigPromise;

  videoUiConfigPromise = (async ()=>{
    try{
      const snap = await db.ref("ui/videoPlayer").once("value");
      const raw = snap.val();

      if (!raw){
        try{ await db.ref("ui/videoPlayer").set(VIDEO_UI_DEFAULTS); }catch{}
      }

      const cfg = {
        ...VIDEO_UI_DEFAULTS,
        ...(raw || {}),
        mediaZoom: {
          ...VIDEO_UI_DEFAULTS.mediaZoom,
          ...((raw && raw.mediaZoom) || {})
        }
      };

      cfg.stepBackSec = Math.round(clampNum(cfg.stepBackSec, 1, 30, VIDEO_UI_DEFAULTS.stepBackSec));
      cfg.stepFwdSec = Math.round(clampNum(cfg.stepFwdSec, 1, 30, VIDEO_UI_DEFAULTS.stepFwdSec));
      cfg.maxCustomSpeed = clampNum(cfg.maxCustomSpeed, 2, 10, VIDEO_UI_DEFAULTS.maxCustomSpeed);

      const speeds = Array.isArray(cfg.speeds) ? cfg.speeds : VIDEO_UI_DEFAULTS.speeds;
      cfg.speeds = Array.from(new Set(
        speeds.map((s) => clampNum(s, 0.05, cfg.maxCustomSpeed, 1))
      )).sort((a, b) => a - b);

      if (!cfg.speeds.some((s) => Math.abs(s - 1) < 1e-9)) cfg.speeds.push(1);
      cfg.speeds.sort((a, b) => a - b);

      cfg.mediaZoom.step = clampNum(Math.max(Number(cfg.mediaZoom.step) || 0, VIDEO_UI_DEFAULTS.mediaZoom.step), 0.05, 2, VIDEO_UI_DEFAULTS.mediaZoom.step);
      cfg.mediaZoom.wheelStep = clampNum(Math.max(Number(cfg.mediaZoom.wheelStep) || 0, VIDEO_UI_DEFAULTS.mediaZoom.wheelStep), 0.02, 1, VIDEO_UI_DEFAULTS.mediaZoom.wheelStep);
      cfg.mediaZoom.maxScale = clampNum(Math.max(Number(cfg.mediaZoom.maxScale) || 0, VIDEO_UI_DEFAULTS.mediaZoom.maxScale), 1.25, 24, VIDEO_UI_DEFAULTS.mediaZoom.maxScale);
      cfg.mediaZoom.doubleTapScale = clampNum(
        cfg.mediaZoom.doubleTapScale,
        1.25,
        cfg.mediaZoom.maxScale,
        VIDEO_UI_DEFAULTS.mediaZoom.doubleTapScale
      );

      videoUiConfigCache = cfg;
      return cfg;
    }catch{
      videoUiConfigCache = {
        ...VIDEO_UI_DEFAULTS,
        mediaZoom: { ...VIDEO_UI_DEFAULTS.mediaZoom }
      };
      return videoUiConfigCache;
    }finally{
      videoUiConfigPromise = null;
    }
  })();

  return videoUiConfigPromise;
}

async function videoKeyFor(fileName, src){
  // Per-video settings key: stable per file without hashing an entire huge data URL.
  const srcText = String(src || "");
  const sample = srcText.length > 4096
    ? `${srcText.slice(0, 2048)}::${srcText.slice(-2048)}::${srcText.length}`
    : srcText;
  const base = `${String(fileName || "")}::${sample}`;
  try{ return await sha256Hex(base); }catch{ return fnv1aHex(base); }
}

async function getVideoPrefs(roomId, videoKey){
  const rid = sanitizeRoomCode(roomId || currentRoomId);
  if (!currentUser?.code || !rid || !videoKey) return {};
  try{
    const snap = await db.ref(`users/${currentUser.code}/prefs/videoPlayerByRoom/${rid}/${videoKey}`).once("value");
    return snap.val() || {};
  }catch{
    return {};
  }
}

// Debounced writes per-room+per-video so rapid UI actions don't drop.
const videoPrefsPendingByKey = new Map();
const videoPrefsTimerByKey = new Map();

async function saveVideoPrefs(roomId, videoKey, patch){
  const rid = sanitizeRoomCode(roomId || currentRoomId);
  if (!currentUser?.code || !rid || !videoKey) return;

  const p = (patch && typeof patch === "object") ? patch : {};
  const mapKey = `${rid}::${videoKey}`;

  const pending = { ...(videoPrefsPendingByKey.get(mapKey) || {}), ...p };
  videoPrefsPendingByKey.set(mapKey, pending);

  const prev = videoPrefsTimerByKey.get(mapKey);
  if (prev) clearTimeout(prev);

  const t = setTimeout(async ()=>{
    const toWrite = videoPrefsPendingByKey.get(mapKey) || {};
    videoPrefsPendingByKey.delete(mapKey);
    videoPrefsTimerByKey.delete(mapKey);
    try{
      await db.ref(`users/${currentUser.code}/prefs/videoPlayerByRoom/${rid}/${videoKey}`).update(toWrite);
    }catch{}
  }, 150);

  videoPrefsTimerByKey.set(mapKey, t);
}

function fmtTime(sec){
  const s = Math.max(0, Number(sec) || 0);
  const whole = Math.floor(s);
  const m = Math.floor(whole / 60);
  const r = whole % 60;
  return `${m}:${String(r).padStart(2,"0")}`;
}

function svgIcon(name){
  // Minimal custom icons (no external assets).
  if (name === "play") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M9 7v10l8-5-8-5Z" fill="currentColor"/></svg>`;
  if (name === "pause") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M7 6h3v12H7V6Zm7 0h3v12h-3V6Z" fill="currentColor"/></svg>`;
  if (name === "back5") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M11 5 5 9l6 4V5Z" fill="currentColor"/><path d="M20 7v10h-2V7h2Z" fill="currentColor"/><path d="M9 19a8 8 0 1 1 8-8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  if (name === "fwd5") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M13 5v8l6-4-6-4Z" fill="currentColor"/><path d="M4 7v10h2V7H4Z" fill="currentColor"/><path d="M15 19a8 8 0 1 0-8-8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  if (name === "loop") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M7 7h9a3 3 0 0 1 3 3v1" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M17 17H8a3 3 0 0 1-3-3v-1" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M20 9 18 11 16 9" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><path d="M4 15l2-2 2 2" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
  if (name === "vol") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M4 10v4h3l5 4V6L7 10H4Z" fill="currentColor"/><path d="M16 9a4 4 0 0 1 0 6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M18.5 6.5a8 8 0 0 1 0 11" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  if (name === "mute") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M4 10v4h3l5 4V6L7 10H4Z" fill="currentColor"/><path d="M16 9l5 6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M21 9l-5 6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  if (name === "menu") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M5 12h14" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M5 6h14" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M5 18h14" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  if (name === "full") return `<svg viewBox="0 0 24 24" width="18" height="18" fill="none"><path d="M8 3H3v5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M16 3h5v5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M8 21H3v-5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M16 21h5v-5" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>`;
  return "";
}

const videoPlayerTeardowns = new Map();

function initVideoPlayer(root, { fileName=null, videoKey=null, roomId=null } = {}){
  const host = (root && root.classList && root.classList.contains("vpu")) ? root : root.querySelector(".vpu");
  if (!host) return () => {};

  const vid = host.querySelector("video");
  const timeEl = host.querySelector(".vpu-time");
  const seek = host.querySelector(".vpu-seek");
  const btnPlay = host.querySelector(".vpu-play");
  const btnBack = host.querySelector(".vpu-back");
  const btnFwd = host.querySelector(".vpu-fwd");
  const btnLoop = host.querySelector(".vpu-loop");
  const btnMenu = host.querySelector(".vpu-menu");
  const btnFull = host.querySelector(".vpu-full");
  const pop = host.querySelector(".vpu-pop");
  const speedWrap = host.querySelector(".vpu-speedwrap");
  const speedCustom = host.querySelector(".vpu-speedcustom");
  const volBtn = host.querySelector(".vpu-volbtn");
  const volRange = host.querySelector(".vpu-volrange");
  const volPct = host.querySelector(".vpu-volpct");

  const _vk = videoKey ? String(videoKey) : null;
  const _rid = sanitizeRoomCode(roomId || currentRoomId);
  const savePrefs = (patch)=>{ try{ if (_vk && _rid) saveVideoPrefs(_rid, _vk, patch); }catch{} };

  let destroyed = false;
  let lastVol = 1;

  // WebAudio volume boost (lets us go past HTMLMediaElement's 1.0 limit)
  let audioCtx = null;
  let gainNode = null;
  let mediaSrcNode = null;

  // Track the user's intended volume (0..2). Don't rely on vid.volume for >1.
  let uiVol = 1;

  function ensureAudioBoost(){
    if (gainNode || mediaSrcNode) return;
    const Ctx = window.AudioContext || window.webkitAudioContext;
    if (!Ctx) return;

    try{
      audioCtx = new Ctx();
      mediaSrcNode = audioCtx.createMediaElementSource(vid);
      gainNode = audioCtx.createGain();
      mediaSrcNode.connect(gainNode);
      gainNode.connect(audioCtx.destination);
    }catch{
      // If this fails (rare), fall back to native volume only.
      audioCtx = null;
      gainNode = null;
      mediaSrcNode = null;
    }
  }

  function applyBoostedVolume(vRaw){
    const v = clampNum(vRaw, 0, 2, 1);
    uiVol = v;

    // Always try to enable boost so 200% works when supported.
    ensureAudioBoost();

    if (gainNode){
      try{ gainNode.gain.value = v; }catch{}
      // Keep native volume pinned to 1 so gain controls the full range.
      try{ vid.volume = 1; }catch{}
      // Resume context on interaction (best-effort; may remain suspended until a gesture)
      try{ if (audioCtx && audioCtx.state === "suspended" && !vid.muted && v > 0) audioCtx.resume(); }catch{}
      return;
    }

    // Fallback: native volume only (0..1)
    try{ vid.volume = Math.min(1, v); }catch{}
  }

  function setPlayIcon(){
    btnPlay.innerHTML = vid.paused ? svgIcon("play") : svgIcon("pause");
  }

  function setLoopUI(){
    const on = !!vid.loop;
    btnLoop.setAttribute("aria-pressed", on ? "true" : "false");
    host.dataset.loop = on ? "1" : "0";
  }

  function setVolumeUI(){
    const v = clampNum(vid.muted ? 0 : uiVol, 0, 2, 1);
    volRange.value = String(v);
    volPct.textContent = `${Math.round(v * 100)}%`;
    volBtn.innerHTML = (v === 0) ? svgIcon("mute") : svgIcon("vol");
  }

  function syncTimeUI(){
    const dur = Number.isFinite(vid.duration) ? vid.duration : 0;
    const cur = Number.isFinite(vid.currentTime) ? vid.currentTime : 0;
    timeEl.textContent = `${fmtTime(cur)} / ${fmtTime(dur)}`;
    seek.max = String(Math.max(0, dur || 0));
    seek.value = String(Math.min(dur || 0, Math.max(0, cur || 0)));
  }

  function closePop(){
    pop.hidden = true;
    host.dataset.menu = "0";
    try{ btnMenu.setAttribute("aria-pressed","false"); }catch{}
  }

  function openPop(){
    pop.hidden = false;
    host.dataset.menu = "1";
    try{ btnMenu.setAttribute("aria-pressed","true"); }catch{}
  }

  function highlightSpeed(){
    const r = Number(vid.playbackRate) || 1;
    const btns = speedWrap.querySelectorAll("button[data-rate]");
    btns.forEach(b => {
      const v = Number(b.dataset.rate);
      b.dataset.active = (Math.abs(v - r) < 1e-9) ? "1" : "0";
    });
  }

  // hard-disable default browser/Google video context options
  vid.controls = false;
  vid.setAttribute("controlslist", "nodownload noplaybackrate noremoteplayback");
  vid.setAttribute("disablepictureinpicture", "");
  try{ vid.disablePictureInPicture = true; }catch{}
  vid.addEventListener("contextmenu", (e)=>e.preventDefault());
  vid.addEventListener("dragstart", (e)=>e.preventDefault());
  vid.playsInline = true;
  
  // Eager-load to reduce “invisible video” cases (height=0 until metadata) and speed up start.
  try{ vid.preload = "auto"; }catch{}
  try{ vid.setAttribute("preload","auto"); }catch{}
  try{ vid.load(); }catch{}

  // Apply saved settings BEFORE first UI paint (so toggles render correctly on refresh)
  try{
    const il = host.dataset.initialLoop;
    if (il != null) vid.loop = (il === "1" || il === "true");
  }catch{}

  try{
    const im = host.dataset.initialMuted;
    if (im != null) vid.muted = (im === "1" || im === "true");
  }catch{}

  try{
    const iv = Number(host.dataset.initialVolume);
    if (Number.isFinite(iv)){
      const v = clampNum(iv, 0, 2, 1);
      applyBoostedVolume(v);
      if (v > 0) lastVol = v;
    }
  }catch{}

  try{
    const ir = Number(host.dataset.initialRate);
    if (Number.isFinite(ir) && ir > 0){
      vid.playbackRate = ir;
    }
  }catch{}

  try{
    const cr = host.dataset.initialCustomRate;
    if (cr != null){
      const v = String(cr);
      if (speedCustom) speedCustom.value = v;
    }
  }catch{}

  // Initial UI state (now reflects saved settings)
  closePop();        // ensures menu is visually OFF on load
  setPlayIcon();
  setLoopUI();
  setVolumeUI();
  syncTimeUI();
  highlightSpeed();

  const off = [];
  const on = (el, ev, fn, opts) => { el.addEventListener(ev, fn, opts); off.push(()=>el.removeEventListener(ev, fn, opts)); };

  // Only recover once, and only for genuinely broken initial loads.
  let vpuReloaded = false;
  const canSafelyReloadSource = () => {
    const hasDuration = Number.isFinite(vid.duration) && vid.duration > 0;
    return !hasDuration && vid.readyState < HTMLMediaElement.HAVE_METADATA;
  };
  const forceReload = () => {
    if (vpuReloaded || !canSafelyReloadSource()) return;
    vpuReloaded = true;
    try{
      const src = vid.getAttribute("src") || vid.src || "";
      if (!src) return;
      try{ vid.pause(); }catch{}
      vid.src = src;
      try{ vid.load(); }catch{}
    }catch{}
  };

  let isScrubbing = false;
  let pendingSeekTime = null;

  const paintSeekUI = (nextTime) => {
    const dur = Number.isFinite(vid.duration) ? vid.duration : 0;
    const clamped = Math.max(0, Math.min(dur || Number.MAX_SAFE_INTEGER, Number(nextTime) || 0));
    if (!Number.isFinite(clamped)) return null;
    try{ seek.value = String(clamped); }catch{}
    try{ timeEl.textContent = `${fmtTime(clamped)} / ${fmtTime(dur)}`; }catch{}
    return clamped;
  };

  const seekVideoInstant = (nextTime) => {
    const clamped = paintSeekUI(nextTime);
    if (clamped == null) return;

    try{
      if (Math.abs((Number(vid.currentTime) || 0) - clamped) > 0.01){
        if (typeof vid.fastSeek === "function") vid.fastSeek(clamped);
        else vid.currentTime = clamped;
      }
    }catch{
      try{ vid.currentTime = clamped; }catch{}
    }

    if (!isScrubbing) requestAnimationFrame(syncTimeUI);
  };

  const commitPendingSeek = () => {
    if (pendingSeekTime == null) return;
    const t = pendingSeekTime;
    pendingSeekTime = null;
    seekVideoInstant(t);
  };

  on(vid, "error", forceReload);
  on(vid, "stalled", () => {
    if (canSafelyReloadSource()) forceReload();
  });

  on(btnPlay, "click", ()=>{
    if (vid.paused) vid.play().catch(()=>{});
    else vid.pause();
  });

  // Clicking the video toggles play/pause (CHAT only). In slideshows, clicking selects/moves instead.
  if (!host.classList.contains("vpu-slideshow")){
    on(vid, "click", (e)=>{
      e.preventDefault();
      e.stopPropagation();
      if (vid.paused) vid.play().catch(()=>{});
      else vid.pause();
    });
  } else {
    // Improve drag/move perf on slideshow canvas (video never consumes pointer events).
    try{ vid.style.pointerEvents = "none"; }catch{}
  }

  on(btnBack, "click", ()=>{
    const step = Number(host.dataset.stepBack) || 5;
    isScrubbing = false;
    pendingSeekTime = null;
    seekVideoInstant((vid.currentTime || 0) - step);
  });

  on(btnFwd, "click", ()=>{
    const step = Number(host.dataset.stepFwd) || 5;
    isScrubbing = false;
    pendingSeekTime = null;
    seekVideoInstant((vid.currentTime || 0) + step);
  });

  on(btnLoop, "click", ()=>{
    vid.loop = !vid.loop;
    setLoopUI();
  });

  on(seek, "pointerdown", ()=>{
    isScrubbing = true;
    pendingSeekTime = Number(seek.value);
  });

  on(seek, "input", ()=>{
    const t = Number(seek.value);
    if (!Number.isFinite(t)) return;
    pendingSeekTime = t;
    paintSeekUI(t);
    if (!isScrubbing) commitPendingSeek();
  });

  on(seek, "change", ()=>{
    isScrubbing = false;
    commitPendingSeek();
  });

  on(seek, "pointerup", ()=>{
    isScrubbing = false;
    commitPendingSeek();
  });

  on(seek, "pointercancel", ()=>{
    isScrubbing = false;
    commitPendingSeek();
  });

  on(vid, "timeupdate", rafThrottle(() => {
    if (!isScrubbing) syncTimeUI();
  }));
  on(vid, "seeking", () => {
    if (!isScrubbing) syncTimeUI();
  });
  on(vid, "seeked", () => {
    if (!isScrubbing) syncTimeUI();
  });
  on(vid, "durationchange", syncTimeUI);
  on(vid, "loadedmetadata", ()=>{
    syncTimeUI();
    // Re-assert desired playback rate after metadata loads (some browsers reset it)
    const want = Number(host.dataset.initialRate);
    if (Number.isFinite(want) && want > 0){
      try{ vid.playbackRate = want; }catch{}
      requestAnimationFrame(()=>{ try{ vid.playbackRate = want; }catch{} });
      highlightSpeed();
    }
  });
  on(vid, "play", setPlayIcon);
  on(vid, "pause", setPlayIcon);
  on(vid, "volumechange", rafThrottle(setVolumeUI));
  on(vid, "ratechange", highlightSpeed);

  on(volRange, "input", ()=>{
    const v = clampNum(volRange.value, 0, 2, 1);
    vid.muted = false;
    applyBoostedVolume(v);
    if (v > 0) lastVol = v;
    savePrefs({ volume: v, muted: false });
    setVolumeUI(); // WebAudio gain changes don't always trigger `volumechange`
  });

  on(volBtn, "click", ()=>{
    if (vid.muted || vid.volume === 0){
      vid.muted = false;
      vid.volume = lastVol || 1;
      savePrefs({ muted:false, volume: vid.volume });
    } else {
      vid.muted = true;
      savePrefs({ muted:true });
    }
    setVolumeUI();
  });

  on(btnMenu, "click", (e)=>{
    e.stopPropagation();
    if (!pop.hidden) closePop();
    else openPop();
  });

  on(document, "click", (e)=>{
    if (pop.hidden) return;
    if (!host.contains(e.target)) closePop();
  });

  on(btnFull, "click", async ()=>{
    try{
      if (document.fullscreenElement){
        await document.exitFullscreen();
      } else {
        // Fullscreen ONLY the video frame (controls remain outside fullscreen)
        await vid.requestFullscreen?.();
      }
    }catch{}
  });

  // Speed controls (preset buttons + custom input)
  function applyRate(r, { custom=false } = {}){
    const max = Number(host.dataset.maxCustomSpeed) || 10;
    const want = clampNum(r, 0.05, max, 1);

    // Save desired rate on the host so loadedmetadata can re-assert it.
    host.dataset.initialRate = String(want);

    try{ vid.playbackRate = want; }catch{}
    // Re-assert next frame (fixes occasional “doesn’t stick”)
    requestAnimationFrame(()=>{ try{ vid.playbackRate = want; }catch{} });

    highlightSpeed();

    if (!custom){
      try{ speedCustom.value = ""; }catch{}
      savePrefs({ playbackRate: want, customRate: null });
    } else {
      savePrefs({ playbackRate: want, customRate: want });
    }
  }

  on(speedWrap, "click", (e)=>{
    const b = e.target.closest("button[data-rate]");
    if (!b) return;
    const r = Number(b.dataset.rate);
    if (!Number.isFinite(r)) return;
    applyRate(r, { custom:false });
  });

  on(speedCustom, "change", ()=>{
    applyRate(speedCustom.value, { custom:true });
  });

  // Optional: show file name in the menu header.
  if (fileName){
    const title = host.querySelector(".vpu-pop-title");
    if (title) title.textContent = String(fileName);
  }

  // Return teardown
  return () => {
    if (destroyed) return;
    destroyed = true;
    try{ closePop(); }catch{}
    try{ vid.pause(); }catch{}
    off.reverse().forEach(fn => { try{ fn(); }catch{} });

    // Cleanup WebAudio boost (if created)
    try{ vid.removeAttribute("src"); }catch{}
    try{ vid.load?.(); }catch{}
    try{ if (mediaSrcNode) mediaSrcNode.disconnect(); }catch{}
    try{ if (gainNode) gainNode.disconnect(); }catch{}
    try{ if (audioCtx && audioCtx.state !== "closed") audioCtx.close(); }catch{}
    mediaSrcNode = null;
    gainNode = null;
    audioCtx = null;
  };
}

const mediaModalSrcCache = new Map();
let mediaModalSrcCacheBound = false;

function cleanupMediaModalSrcCache(){
  for (const entry of mediaModalSrcCache.values()){
    try{
      if (entry?.url && String(entry.url).startsWith("blob:")) URL.revokeObjectURL(entry.url);
    }catch{}
  }
  mediaModalSrcCache.clear();
}

function bindMediaModalSrcCacheCleanup(){
  if (mediaModalSrcCacheBound) return;
  mediaModalSrcCacheBound = true;
  window.addEventListener("pagehide", cleanupMediaModalSrcCache);
  window.addEventListener("beforeunload", cleanupMediaModalSrcCache);
}

async function getFastMediaModalSrc(dataURL, mimeType = ""){
  const src = String(dataURL || "").trim();
  if (!src) return "";
  if (!/^data:/i.test(src)) return src;

  bindMediaModalSrcCacheCleanup();

  const hit = mediaModalSrcCache.get(src);
  if (hit?.url) return hit.url;
  if (hit?.promise) return hit.promise;

  const promise = (async () => {
    try{
      const res = await fetch(src);
      const rawBlob = await res.blob();
      const type = String(mimeType || rawBlob.type || "").trim();
      const blob = type && rawBlob.type !== type
        ? rawBlob.slice(0, rawBlob.size, type)
        : rawBlob;
      const url = URL.createObjectURL(blob);
      mediaModalSrcCache.set(src, { url, ts:Date.now() });
      return url;
    }catch{
      mediaModalSrcCache.delete(src);
      return src;
    }
  })();

  mediaModalSrcCache.set(src, { promise, ts:Date.now() });
  return promise;
}

function openMediaModal(kind, dataURL, { fileName=null, mimeType="" } = {}){
  const src = String(dataURL || "").trim();
  if (!src) return;

  const modalTitle = fileName ? String(fileName) : "Media";
  const mountId = `media_mount_${Math.random().toString(36).slice(2, 9)}`;
  let mediaPlayerId = "";
  let mediaZoomTeardown = null;

  function initMediaZoomViewer(root, cfg = {}){
    if (!root) return () => {};
    const viewport = root.querySelector(".media-zoom-viewport");
    const target = root.querySelector(".media-zoom-target");
    const btnIn = root.querySelector('[data-media-zoom="in"]');
    const btnOut = root.querySelector('[data-media-zoom="out"]');
    const btnReset = root.querySelector('[data-media-zoom="reset"]');
    const readout = root.querySelector('[data-media-zoom="percent"]');
    if (!viewport || !target) return () => {};

    const maxScale = clampNum(Math.max(Number(cfg.maxScale) || 0, 20), 1.25, 24, 20);
    const step = clampNum(Math.max(Number(cfg.step) || 0, 0.5), 0.05, 2, 0.5);
    const wheelStep = clampNum(Math.max(Number(cfg.wheelStep) || 0, 0.5), 0.02, 1, 0.5);
    const dblScale = clampNum(cfg.doubleTapScale, 1.25, maxScale, 2.5);

    let scale = 1;
    let panX = 0;
    let panY = 0;
    let dragging = false;
    let dragStartX = 0;
    let dragStartY = 0;
    let dragPanStartX = 0;
    let dragPanStartY = 0;
    let lastTapAt = 0;
    let pinchDistance = 0;
    let pinchStartScale = 1;
    let pinchCenter = null;
    let pointerDownX = 0;
    let pointerDownY = 0;
    let clickCanceledByDrag = false;
    const clickDragThreshold = 6;

    const pointers = new Map();
    const off = [];

    function getLimits(nextScale = scale){
      const rect = viewport.getBoundingClientRect();
      const baseW = target.clientWidth || rect.width || 0;
      const baseH = target.clientHeight || rect.height || 0;
      const extraX = Math.max(0, ((baseW * nextScale) - rect.width) / 2);
      const extraY = Math.max(0, ((baseH * nextScale) - rect.height) / 2);
      return { x: extraX, y: extraY };
    }

    function clampPan(nextX, nextY, nextScale = scale){
      const lim = getLimits(nextScale);
      return {
        x: Math.min(lim.x, Math.max(-lim.x, nextX)),
        y: Math.min(lim.y, Math.max(-lim.y, nextY))
      };
    }

    function updateReadout(){
      if (readout) readout.textContent = `${Math.round(scale * 100)}%`;
      if (btnReset) btnReset.textContent = "100%";
    }

    function apply(){
      const clamped = (scale <= 1)
        ? { x:0, y:0 }
        : clampPan(panX, panY, scale);

      panX = clamped.x;
      panY = clamped.y;

      target.style.transform = `translate(${panX}px, ${panY}px) scale(${scale})`;
      viewport.classList.toggle("is-zoomed", scale > 1.001);
      viewport.classList.toggle("is-dragging", dragging && scale > 1.001);
      viewport.setAttribute("aria-label", scale > 1.001 ? "Zoomed media viewer. Drag to pan." : "Media viewer");
      updateReadout();
    }

    function setScale(nextScale, anchorClientX = null, anchorClientY = null){
      const prevScale = scale;
      const clampedScale = Math.min(maxScale, Math.max(1, Number(nextScale) || 1));
      if (Math.abs(clampedScale - prevScale) < 0.0001) return;

      if (anchorClientX != null && anchorClientY != null){
        const rect = viewport.getBoundingClientRect();
        const offsetX = anchorClientX - rect.left - (rect.width / 2);
        const offsetY = anchorClientY - rect.top - (rect.height / 2);
        const contentX = (offsetX - panX) / prevScale;
        const contentY = (offsetY - panY) / prevScale;
        scale = clampedScale;
        panX = offsetX - (contentX * scale);
        panY = offsetY - (contentY * scale);
      } else {
        scale = clampedScale;
      }

      if (scale <= 1){
        panX = 0;
        panY = 0;
      }

      apply();
    }

    function zoomBy(delta, anchorClientX = null, anchorClientY = null){
      setScale(scale + delta, anchorClientX, anchorClientY);
    }

    function resetZoom(){
      scale = 1;
      panX = 0;
      panY = 0;
      dragging = false;
      pinchDistance = 0;
      pinchCenter = null;
      apply();
    }

    function beginDrag(clientX, clientY){
      if (scale <= 1.001) return;
      dragging = true;
      dragStartX = clientX;
      dragStartY = clientY;
      dragPanStartX = panX;
      dragPanStartY = panY;
      apply();
    }

    function moveDrag(clientX, clientY){
      if (!dragging || scale <= 1.001) return;
      panX = dragPanStartX + (clientX - dragStartX);
      panY = dragPanStartY + (clientY - dragStartY);
      apply();
    }

    function endDrag(){
      dragging = false;
      apply();
    }

    function getPointerCenter(){
      const pts = Array.from(pointers.values());
      if (pts.length < 2) return null;
      return {
        x: (pts[0].x + pts[1].x) / 2,
        y: (pts[0].y + pts[1].y) / 2
      };
    }

    function getPointerDistance(){
      const pts = Array.from(pointers.values());
      if (pts.length < 2) return 0;
      return Math.hypot(pts[0].x - pts[1].x, pts[0].y - pts[1].y);
    }

    function onPointerDown(e){
      if (e.button === 1){
        e.preventDefault();
        return;
      }
      if (e.button != null && e.button !== 0 && e.pointerType !== "touch") return;
      pointers.set(e.pointerId, { x:e.clientX, y:e.clientY });

      if (target.tagName === "VIDEO"){
        try{ viewport.focus({ preventScroll:true }); }catch{ try{ viewport.focus(); }catch{} }
      }

      if (pointers.size === 2){
        clickCanceledByDrag = true;
        pinchDistance = getPointerDistance();
        pinchStartScale = scale;
        pinchCenter = getPointerCenter();
        dragging = false;
        apply();
      } else {
        pointerDownX = e.clientX;
        pointerDownY = e.clientY;
        clickCanceledByDrag = false;
        if (scale > 1.001) beginDrag(e.clientX, e.clientY);
      }

      try{ viewport.setPointerCapture(e.pointerId); }catch{}
      e.preventDefault();
    }

    function onPointerMove(e){
      if (!pointers.has(e.pointerId)) return;
      pointers.set(e.pointerId, { x:e.clientX, y:e.clientY });

      if (pointers.size >= 2){
        clickCanceledByDrag = true;
        root.dataset.mediaSuppressCloseUntil = String(Date.now() + 350);
        const dist = getPointerDistance();
        const center = getPointerCenter();
        if (pinchDistance > 0 && dist > 0 && center){
          const ratio = dist / pinchDistance;
          setScale(pinchStartScale * ratio, center.x, center.y);
        }
        return;
      }

      if (!clickCanceledByDrag){
        const moved = Math.hypot(e.clientX - pointerDownX, e.clientY - pointerDownY);
        if (moved > clickDragThreshold){
          clickCanceledByDrag = true;
          root.dataset.mediaSuppressCloseUntil = String(Date.now() + 350);
        }
      }

      moveDrag(e.clientX, e.clientY);
    }

    function clearPointer(e){
      pointers.delete(e.pointerId);
      if (pointers.size < 2){
        pinchDistance = 0;
        pinchCenter = null;
      }
      if (!pointers.size) endDrag();
    }

    function onWheel(e){
      const rect = viewport.getBoundingClientRect();
      const ax = e.clientX || (rect.left + rect.width / 2);
      const ay = e.clientY || (rect.top + rect.height / 2);

      e.preventDefault();

      const dir = e.deltaY < 0 ? 1 : -1;
      zoomBy(dir * wheelStep, ax, ay);
    }
    
    function onAuxClick(e){
      if (e.button !== 1) return;
      e.preventDefault();
      if (scale > 1.001) resetZoom();
      else setScale(dblScale, e.clientX, e.clientY);
    }

    function onTouchEnd(){
      lastTapAt = Date.now();
    }

    function onKeyDown(e){
      if ((e.key === " " || e.key === "Spacebar" || e.code === "Space") && target.tagName === "VIDEO"){
        e.preventDefault();
        const video = target;
        if (video.paused) video.play().catch(()=>{});
        else video.pause();
      } else if (e.key === "+" || e.key === "="){
        e.preventDefault();
        zoomBy(step);
      } else if (e.key === "-" || e.key === "_"){
        e.preventDefault();
        zoomBy(-step);
      } else if (e.key === "0"){
        e.preventDefault();
        resetZoom();
      } else if (scale > 1.001 && ["ArrowUp","ArrowDown","ArrowLeft","ArrowRight"].includes(e.key)){
        e.preventDefault();
        const delta = 40;
        if (e.key === "ArrowUp") panY += delta;
        if (e.key === "ArrowDown") panY -= delta;
        if (e.key === "ArrowLeft") panX += delta;
        if (e.key === "ArrowRight") panX -= delta;
        apply();
      }
    }

    function onClick(e){
      if (target.tagName !== "VIDEO") return;
      if (clickCanceledByDrag){
        clickCanceledByDrag = false;
        return;
      }
      e.preventDefault();
      const video = target;
      if (video.paused) video.play().catch(()=>{});
      else video.pause();
    }

    if (btnIn) btnIn.addEventListener("click", () => zoomBy(step));
    if (btnOut) btnOut.addEventListener("click", () => zoomBy(-step));
    if (btnReset) btnReset.addEventListener("click", resetZoom);

    viewport.addEventListener("pointerdown", onPointerDown);
    viewport.addEventListener("pointermove", onPointerMove);
    viewport.addEventListener("pointerup", clearPointer);
    viewport.addEventListener("pointercancel", clearPointer);
    viewport.addEventListener("click", onClick);
    viewport.addEventListener("wheel", onWheel, { passive:false });
    viewport.addEventListener("auxclick", onAuxClick);
    viewport.addEventListener("touchend", onTouchEnd, { passive:true });
    viewport.addEventListener("keydown", onKeyDown);
    window.addEventListener("resize", apply);

    off.push(() => viewport.removeEventListener("pointerdown", onPointerDown));
    off.push(() => viewport.removeEventListener("pointermove", onPointerMove));
    off.push(() => viewport.removeEventListener("pointerup", clearPointer));
    off.push(() => viewport.removeEventListener("pointercancel", clearPointer));
    off.push(() => viewport.removeEventListener("click", onClick));
    off.push(() => viewport.removeEventListener("wheel", onWheel));
    off.push(() => viewport.removeEventListener("auxclick", onAuxClick));
    off.push(() => viewport.removeEventListener("touchend", onTouchEnd));
    off.push(() => viewport.removeEventListener("keydown", onKeyDown));
    off.push(() => window.removeEventListener("resize", apply));

    if (target.tagName === "IMG"){
      target.addEventListener("load", apply, { once:true });
    } else if (target.tagName === "VIDEO"){
      target.addEventListener("loadedmetadata", apply, { once:true });
      target.addEventListener("loadeddata", apply, { once:true });
    }

    resetZoom();
    return () => {
      pointers.clear();
      endDrag();
      resetZoom();
      off.reverse().forEach(fn => { try{ fn(); }catch{} });
    };
  }

  openModal({
    title: modalTitle,
    size: "media",
    bodyHTML: `
      <div class="media-viewer${kind === "video" ? " media-viewer-video" : ""}" id="${mountId}">
        <div class="media-modal-loading">Loading preview...</div>
      </div>
    `,
    onBeforeClose: () => {
      try{
        if (typeof mediaZoomTeardown === "function") mediaZoomTeardown();
      }catch{}
      mediaZoomTeardown = null;

      if (!mediaPlayerId) return;
      try{
        const tdNow = videoPlayerTeardowns.get(mediaPlayerId);
        if (tdNow){
          tdNow();
          videoPlayerTeardowns.delete(mediaPlayerId);
        }
      }catch{}
    }
  });

  (async ()=>{
    const mount = document.getElementById(mountId);
    if (!mount) return;

    const fastSrc = await getFastMediaModalSrc(src, mimeType);
    if (!mount.isConnected) return;

    const cfg = await getVideoUiConfig();
    const zoomCfg = cfg.mediaZoom || {};

    if (kind !== "video"){
      mount.innerHTML = `
        <div class="media-zoom-shell media-zoom-shell-image">
          <div class="media-zoom-controls" aria-label="Image zoom controls">
            <button class="media-zoom-btn" type="button" data-media-zoom="out" aria-label="Zoom out">−</button>
            <button class="media-zoom-btn" type="button" data-media-zoom="reset" aria-label="Reset zoom">100%</button>
            <button class="media-zoom-btn" type="button" data-media-zoom="in" aria-label="Zoom in">+</button>
            <div class="media-zoom-readout" data-media-zoom="percent">100%</div>
          </div>
          <div class="media-zoom-viewport" tabindex="0" aria-label="Zoomable image viewer">
            <div class="media-zoom-surface">
              <img class="media-img media-zoom-target" src="${escapeHtml(fastSrc)}" alt="Media" draggable="false" />
            </div>
          </div>
        </div>
      `;
      const imageShell = mount.querySelector(".media-zoom-shell");
      imageShell?.addEventListener("click", (e) => {
        if (e.target.closest(".media-zoom-controls")) return;

        const target = imageShell.querySelector(".media-zoom-target");
        if (target){
          const r = target.getBoundingClientRect();
          const clickedInsideTarget =
            e.clientX >= r.left &&
            e.clientX <= r.right &&
            e.clientY >= r.top &&
            e.clientY <= r.bottom;

          if (clickedInsideTarget) return;
        }

        const suppressCloseUntil = Number(imageShell.dataset.mediaSuppressCloseUntil || 0);
        if (Date.now() < suppressCloseUntil) return;
        closeModal();
      });
      mediaZoomTeardown = initMediaZoomViewer(imageShell, zoomCfg);
      return;
    }

    const id = `vpu_${Math.random().toString(36).slice(2, 9)}`;
    mediaPlayerId = id;

    mount.innerHTML = `
      <div class="vpu" id="${id}" data-step-back="5" data-step-fwd="5" data-max-custom-speed="10" data-menu="0" data-loop="0">
        <div class="vpu-stage">
          <div class="media-zoom-shell media-zoom-shell-video">
            <div class="media-zoom-controls media-zoom-controls-video" aria-label="Video zoom controls">
              <button class="media-zoom-btn" type="button" data-media-zoom="out" aria-label="Zoom out">−</button>
              <button class="media-zoom-btn" type="button" data-media-zoom="reset" aria-label="Reset zoom">100%</button>
              <button class="media-zoom-btn" type="button" data-media-zoom="in" aria-label="Zoom in">+</button>
              <div class="media-zoom-readout" data-media-zoom="percent">100%</div>
            </div>
            <div class="media-zoom-viewport" tabindex="0" aria-label="Zoomable video viewer">
              <div class="media-zoom-surface">
                <video class="vpu-video media-zoom-target" preload="auto" playsinline>${videoSourceMarkup(fastSrc, mimeType)}</video>
              </div>
            </div>
          </div>
        </div>

        <div class="vpu-controls">
          <div class="vpu-row vpu-row1">
            <div class="vpu-time">0:00 / 0:00</div>
            <input class="vpu-seek" type="range" min="0" max="0" value="0" step="0.01" />
          </div>

          <div class="vpu-row vpu-row2">
            <div class="vpu-left">
              <button class="vpu-btn vpu-play" type="button" aria-label="Play/Pause">${svgIcon("play")}</button>
              <button class="vpu-btn vpu-back" type="button" aria-label="Back 5 seconds">${svgIcon("back5")}</button>
              <button class="vpu-btn vpu-fwd" type="button" aria-label="Forward 5 seconds">${svgIcon("fwd5")}</button>
            </div>

            <div class="vpu-mid">
              <button class="vpu-btn vpu-volbtn" type="button" aria-label="Mute/Unmute">${svgIcon("vol")}</button>
              <input class="vpu-volrange" type="range" min="0" max="2" value="1" step="0.05" />
              <div class="vpu-volpct">100%</div>
            </div>

            <div class="vpu-right">
              <button class="vpu-btn vpu-loop" type="button" aria-label="Loop video" aria-pressed="false">${svgIcon("loop")}</button>
              <button class="vpu-btn vpu-menu" type="button" aria-label="More">${svgIcon("menu")}</button>
              <button class="vpu-btn vpu-full" type="button" aria-label="Fullscreen">${svgIcon("full")}</button>
            </div>
          </div>

          <div class="vpu-pop" hidden>
            <div class="vpu-pop-head">
              <div class="vpu-pop-title">Playback speed</div>
              <div class="vpu-pop-sub">Choose a preset, or set a custom speed.</div>
            </div>
            <div class="vpu-speedwrap"></div>
            <div class="vpu-custom">
              <label class="vpu-custom-label" for="${id}_custom">Custom (up to 10×)</label>
              <input id="${id}_custom" class="vpu-speedcustom" type="number" min="0.05" max="10" step="0.05" placeholder="e.g. 3" />
            </div>
          </div>
        </div>
      </div>
    `;

    const videoKey = await videoKeyFor(fileName || "video.mp4", src);
    const prefs = await getVideoPrefs(currentRoomId, videoKey);

    const host = document.getElementById(id);
    if (!host) return;

    host.dataset.stepBack = String(cfg.stepBackSec);
    host.dataset.stepFwd = String(cfg.stepFwdSec);
    host.dataset.maxCustomSpeed = String(cfg.maxCustomSpeed);

    const wrap = host.querySelector(".vpu-speedwrap");
    if (wrap){
      wrap.innerHTML = cfg.speeds.map(r => {
        const label = (Math.abs(r - 1) < 1e-9) ? "1 (Normal)" : String(r);
        return `<button type="button" class="vpu-rate" data-rate="${r}">${label}</button>`;
      }).join("");
    }

    const speedCustom = host.querySelector(".vpu-speedcustom");
    if (speedCustom){
      speedCustom.max = String(cfg.maxCustomSpeed);
      const lbl = host.querySelector(".vpu-custom-label");
      if (lbl) lbl.textContent = `Custom (up to ${cfg.maxCustomSpeed}×)`;
    }

    if (typeof prefs.muted === "boolean") host.dataset.initialMuted = prefs.muted ? "1" : "0";

    const vol = clampNum(prefs.volume, 0, 2, null);
    if (vol != null) host.dataset.initialVolume = String(vol);

    const rate = clampNum(prefs.playbackRate, 0.05, cfg.maxCustomSpeed, null);
    if (rate != null) host.dataset.initialRate = String(rate);

    const cr = clampNum(prefs.customRate, 0.05, cfg.maxCustomSpeed, null);
    if (cr != null) host.dataset.initialCustomRate = String(cr);
    else delete host.dataset.initialCustomRate;

    const td = initVideoPlayer(host, { fileName, videoKey, roomId: currentRoomId });
    videoPlayerTeardowns.set(id, td);

    mediaZoomTeardown = initMediaZoomViewer(host.querySelector(".media-zoom-shell"), zoomCfg);
  })();
}

async function downloadHtmlViaObjectURL(dataURL, fileName){
  let fn = String(fileName || "experience.html").trim();
  if (!/\.html?$/i.test(fn)) fn += ".html";

  let url = "";
  try{
    const resp = await fetch(dataURL);
    const b = await resp.blob();
    const blob = b.type ? b : b.slice(0, b.size, "text/html");
    url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = fn;
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    a.remove();
  }catch(e){
    console.error("download html failed:", e);
    showToast({ title:"Download failed", body:"Could not download that HTML file.", duration: 2200 });
  }finally{
    if (url) setTimeout(() => URL.revokeObjectURL(url), 1000);
  }
}

async function downloadFileViaObjectURL(dataURL, fileName){
  let fn = String(fileName || "file").trim();
  if (!fn) fn = "file";

  let url = "";
  try{
    const resp = await fetch(dataURL);
    const b = await resp.blob();
    const blob = b.type ? b : b.slice(0, b.size, "application/octet-stream");
    url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = fn;
    a.style.display = "none";
    document.body.appendChild(a);
    a.click();
    a.remove();
  }catch(e){
    console.error("download file failed:", e);
    showToast({ title:"Download failed", body:"Could not download that file.", duration: 2200 });
  }finally{
    if (url) setTimeout(() => URL.revokeObjectURL(url), 1000);
  }
}

async function updateMyDisplayName(displayName){
  if (!currentUser) return false;

  const cleaned = sanitizeUsername(displayName);
  if (!cleaned) return false;

  const nextLower = cleaned.toLowerCase();
  const currentLower = String(currentUser.displayNameLower || currentUser.displayName || currentUser.username || "").toLowerCase();
  const oldDisplayName = String(currentUser.displayName || currentUser.username || "").trim();

  if (nextLower === currentLower){
    if (cleaned !== currentUser.displayName){
      try{
        await db.ref(`users/${currentUser.code}`).update({
          displayName: cleaned,
          displayNameLower: nextLower
        });
      }catch(e){
        showToast({ title:"Update failed", body:"Could not save display name.", duration: 2600 });
        return false;
      }
      currentUser.displayName = cleaned;
      currentUser.displayNameLower = nextLower;
    }
  } else {
    let claim;
    try{
      if (oldDisplayName && oldDisplayName.toLowerCase() !== nextLower){
        await releaseDisplayName(oldDisplayName, currentUser.code);
      }
      claim = await claimDisplayName(cleaned, currentUser.code);
    }catch(e){
      showToast({ title:"Update failed", body:"Could not check display name availability.", duration: 2600 });
      return false;
    }

    if (!claim?.ok){
      showToast({ title:"Display name taken", body:"That display name is already in use.", duration: 2600 });
      return false;
    }

    const patch = {
      displayName: claim.cleaned,
      displayNameLower: claim.displayNameLower
    };

    try{
      await db.ref(`users/${currentUser.code}`).update(patch);
    }catch(e){
      try{ await releaseDisplayName(claim.cleaned, currentUser.code); }catch{}
      showToast({ title:"Update failed", body:"Could not save display name.", duration: 2600 });
      return false;
    }

    currentUser.displayName = patch.displayName;
    currentUser.displayNameLower = patch.displayNameLower;
  }

  const selfCode = String(currentUser.code || "");
  if (selfCode){
    liveUserCache.set(selfCode, {
      ...(liveUserCache.get(selfCode) || {}),
      code: selfCode,
      username: currentUser.username || "User",
      usernameLower: String(currentUser.usernameLower || currentUser.username || "user").toLowerCase(),
      displayName: currentUser.displayName,
      displayNameLower: currentUser.displayNameLower,
      bio: String(currentUser.bio || "").slice(0, 400),
      photoDataURL: currentUser.photoDataURL || defaultStickmanDataURL(),
      photoTransform: currentUser.photoTransform || null,
      bannerDataURL: String(currentUser.bannerDataURL || ""),
      bannerTransform: normalizeTransformToRel(currentUser.bannerTransform, 340)
    });

    document.querySelectorAll(`[data-display-name-usercode="${selfCode}"]`)
      .forEach(el => { el.textContent = currentUser.displayName; });

    document.querySelectorAll(`.reply-preview-label[data-reply-usercode="${selfCode}"]`)
      .forEach(el => {
        const selfReply = el.dataset.replySelf === "1";
        el.textContent = selfReply ? "Replied to themselves" : `Replied to ${currentUser.displayName}'s message`;
      });

    if (replyState && String(replyState.userCode || "") === selfCode){
      replyState.displayName = currentUser.displayName;
      updateReplyBarPreview();
    }

    refreshMentionFormattingForRenderedMessages();
  }

  writeCurrentUserBootstrapCache();
  setMeHeader();

  return true;
}

async function updateMyProfilePicture(photoDataURL, photoTransform){
  if (!currentUser) return;

  const patch = {
    photoDataURL: photoDataURL || defaultStickmanDataURL(),
    photoTransform: normalizeTransformToRel(photoTransform, 84)
  };

  try{
    await db.ref(`users/${currentUser.code}`).update(patch);
  }catch(e){
    showToast({ title:"Update failed", body:"Could not save profile picture.", duration: 2600 });
    return;
  }

  currentUser.photoDataURL = patch.photoDataURL;
  currentUser.photoTransform = patch.photoTransform;

  const selfCode = String(currentUser.code || "");
  if (selfCode){
    liveUserCache.set(selfCode, {
      ...(liveUserCache.get(selfCode) || {}),
      code: selfCode,
      username: currentUser.username || "User",
      usernameLower: String(currentUser.usernameLower || currentUser.username || "user").toLowerCase(),
      displayName: currentUser.displayName || currentUser.username || "User",
      displayNameLower: String(currentUser.displayNameLower || currentUser.displayName || currentUser.username || "user").toLowerCase(),
      bio: String(currentUser.bio || "").slice(0, 400),
      photoDataURL: patch.photoDataURL,
      photoTransform: patch.photoTransform,
      bannerDataURL: String(currentUser.bannerDataURL || ""),
      bannerTransform: normalizeTransformToRel(currentUser.bannerTransform, 340),
      htmlActivity: getUserHtmlActivity(currentUser)
    });
  }

  writeCurrentUserBootstrapCache();
  setMeHeader();
  refreshRenderedAvatarForUser(liveUserCache.get(selfCode) || currentUser);

  try{ renderOnlineIndicator(); }catch{}
  try{ renderSlideshowThumbLocations(); }catch{}
  try{ renderSlideshowRemoteSelections(); }catch{}
  try{ renderCallMenu(); }catch{}
  if (pingBarEl && !pingBarEl.hidden){
    try{ renderPingList(); }catch{}
  }
  if (userProfileOpen && userProfilePinnedCode === selfCode){
    refreshOpenUserProfileCard();
  }
}

