function stopCameraModalStream(){
  if (!window.__cameraModalStream) return;
  try{
    window.__cameraModalStream.getTracks().forEach((track) => track.stop());
  }catch{}
  window.__cameraModalStream = null;
}

function downloadNotepadFile(filename, content, mime){
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function openNotepadModal(){
  openModal({
    title: "Notepad",
    bodyHTML: `
      <div style="display:grid; gap:12px;">
        <div style="display:grid; gap:8px; grid-template-columns:minmax(0,1fr) auto auto auto auto; align-items:center;">
          <input class="input mono-input" id="notepad-filename" maxlength="80" spellcheck="false" placeholder="file.txt" />
          <button class="btn tiny" id="btn-notepad-new" type="button">New</button>
          <button class="btn tiny" id="btn-notepad-open" type="button">Open</button>
          <button class="btn tiny" id="btn-notepad-copy" type="button">Copy</button>
          <button class="btn tiny" id="btn-notepad-download" type="button">Download</button>
        </div>
        <input id="notepad-file-input" type="file" accept=".txt,.html,.htm,text/plain,text/html" hidden />
        <div id="notepad-editor-wrap" style="position:relative; min-height:420px;"><div id="notepad-search-overlay" aria-hidden="true" style="position:absolute; inset:0; min-height:420px; overflow:hidden; white-space:pre-wrap; overflow-wrap:break-word; word-break:break-word; color:transparent; background:transparent; pointer-events:none; box-sizing:border-box; z-index:0;"></div><textarea class="input mono-input" id="notepad-editor" spellcheck="false" placeholder="Start typing..." style="position:relative; z-index:1; min-height:420px; resize:vertical; line-height:1.45; letter-spacing:0; background:transparent;"></textarea></div>      </div>
    `,
  });

  const titleEl = $("modal-title");
  if (titleEl){
    titleEl.innerHTML = `
      <div class="html-library-titlebar">
        <span class="html-library-title-text">Notepad</span>
        <input
          class="html-library-search-input"
          id="notepad-search-input"
          type="search"
          placeholder="Search"
          autocomplete="off"
          spellcheck="false"
          aria-label="Search notepad text"
        />
      </div>
    `;
  }

  const filenameEl = $("notepad-filename");
  const editorEl = $("notepad-editor");
  const overlayEl = $("notepad-search-overlay");
  const fileInputEl = $("notepad-file-input");
  const searchEl = $("notepad-search-input");

  let notepadSearchMatches = [];
  let notepadSearchIndex = -1;

  const collectNotepadSearchMatches = (needle) => {
    const text = String(editorEl?.value || "");
    const query = String(needle || "");
    const matches = [];
    if (!query) return matches;

    const lowerText = text.toLowerCase();
    const lowerQuery = query.toLowerCase();
    let start = 0;

    while (start <= lowerText.length){
      const idx = lowerText.indexOf(lowerQuery, start);
      if (idx === -1) break;
      matches.push(idx);
      start = idx + Math.max(1, lowerQuery.length);
    }

    return matches;
  };

  const syncNotepadSearchOverlay = () => {
    if (!editorEl || !overlayEl) return;
    const cs = window.getComputedStyle(editorEl);
    overlayEl.scrollTop = editorEl.scrollTop;
    overlayEl.style.height = `${editorEl.offsetHeight}px`;
    overlayEl.style.padding = cs.padding;
    overlayEl.style.borderWidth = cs.borderWidth;
    overlayEl.style.borderStyle = cs.borderStyle;
    overlayEl.style.borderColor = "transparent";
    overlayEl.style.borderRadius = cs.borderRadius;
    overlayEl.style.font = cs.font;
    overlayEl.style.lineHeight = cs.lineHeight;
    overlayEl.style.letterSpacing = cs.letterSpacing;
    overlayEl.style.tabSize = cs.tabSize;
    overlayEl.style.textIndent = cs.textIndent;
    overlayEl.style.textTransform = cs.textTransform;
    overlayEl.style.textRendering = cs.textRendering;
  };

  const renderNotepadSearchOverlay = () => {
    if (!editorEl || !overlayEl) return;

    const text = String(editorEl.value || "");
    const query = String(searchEl?.value || "").trim();

    if (!query){
      overlayEl.innerHTML = "";
      syncNotepadSearchOverlay();
      return;
    }

    const matches = collectNotepadSearchMatches(query);
    if (!matches.length){
      overlayEl.innerHTML = escapeHtml(text);
      syncNotepadSearchOverlay();
      return;
    }

    const activeIndex = notepadSearchIndex >= 0 ? (((notepadSearchIndex % matches.length) + matches.length) % matches.length) : -1;
    let cursor = 0;
    let html = "";

    matches.forEach((start, idx) => {
      const end = start + query.length;
      html += escapeHtml(text.slice(cursor, start));
      html += idx === activeIndex
        ? `<mark style="display:inline; background:rgba(59,130,246,.55); color:transparent; padding:0; margin:0; border-radius:0; line-height:inherit; font:inherit; letter-spacing:inherit; vertical-align:baseline;">${escapeHtml(text.slice(start, end))}</mark>`
        : `<mark style="display:inline; background:rgba(59,130,246,.28); color:transparent; padding:0; margin:0; border-radius:0; line-height:inherit; font:inherit; letter-spacing:inherit; vertical-align:baseline;">${escapeHtml(text.slice(start, end))}</mark>`;      cursor = end;
    });

    html += escapeHtml(text.slice(cursor));
    overlayEl.innerHTML = html;
    syncNotepadSearchOverlay();
  };

  const focusNotepadMatchAt = (index, { keepSearchFocus = false } = {}) => {
    if (!editorEl || !notepadSearchMatches.length) return;
    const normalized = ((index % notepadSearchMatches.length) + notepadSearchMatches.length) % notepadSearchMatches.length;
    notepadSearchIndex = normalized;

    const query = String(searchEl?.value || "");
    const start = notepadSearchMatches[normalized];
    const end = start + query.length;

    if (!keepSearchFocus){
      editorEl.focus();
      editorEl.setSelectionRange(start, end);
    }

    const textBefore = editorEl.value.slice(0, start);
    const lineHeight = parseFloat(window.getComputedStyle(editorEl).lineHeight) || 23;
    const lineCountBefore = (textBefore.match(/\n/g) || []).length;
    editorEl.scrollTop = Math.max(0, (lineCountBefore - 2) * lineHeight);
    renderNotepadSearchOverlay();
  };

  const runNotepadSearch = (direction = 1, resetCycle = false) => {
    const query = String(searchEl?.value || "").trim();
    notepadSearchMatches = collectNotepadSearchMatches(query);

    if (!query){
      notepadSearchIndex = -1;
      renderNotepadSearchOverlay();
      return;
    }

    if (!notepadSearchMatches.length){
      notepadSearchIndex = -1;
      renderNotepadSearchOverlay();
      showToast({ title:"No matches", body:`No results for "${query}".`, duration: 1600 });
      return;
    }

    if (resetCycle || notepadSearchIndex === -1){
      notepadSearchIndex = direction < 0 ? notepadSearchMatches.length - 1 : 0;
    } else {
      notepadSearchIndex += direction;
    }

    focusNotepadMatchAt(notepadSearchIndex, { keepSearchFocus: document.activeElement === searchEl });
  };

  $("btn-notepad-new")?.addEventListener("click", () => {
    if (editorEl) editorEl.value = "";
    if (filenameEl) filenameEl.value = "";
    if (fileInputEl) fileInputEl.value = "";
    if (searchEl) searchEl.value = "";
    notepadSearchMatches = [];
    notepadSearchIndex = -1;
    editorEl?.focus();
  });
  $("btn-notepad-open")?.addEventListener("click", () => fileInputEl?.click());

  fileInputEl?.addEventListener("change", async () => {
    const file = fileInputEl.files && fileInputEl.files[0];
    if (!file) return;
    try{
      const text = await file.text();
      if (editorEl) editorEl.value = text;
      if (filenameEl) filenameEl.value = file.name || "";
      notepadSearchMatches = [];
      notepadSearchIndex = -1;
    }catch{
      showToast({ title:"Open failed", body:"That file could not be opened.", duration: 2600 });
    }
    fileInputEl.value = "";
  });

  $("btn-notepad-copy")?.addEventListener("click", async () => {
    try{
      await copyTextToClipboard(editorEl?.value || "");
      showToast({ title:"Copied", body:"The full note was copied.", duration: 1800 });
    }catch{
      showToast({ title:"Copy failed", body:"Could not copy that note.", duration: 2200 });
    }
  });

  $("btn-notepad-download")?.addEventListener("click", () => {
    const rawName = String(filenameEl?.value || "").trim();
    const safeName = rawName.replace(/[\\/:*?"<>|]+/g, "_");

    if (!safeName){
      showToast({ title:"File name required", body:"Enter a file name with an extension, like file.txt.", duration: 2600 });
      return;
    }

    if (!/.+\.[A-Za-z0-9]{1,16}$/.test(safeName)){
      showToast({ title:"File type required", body:"Include the file type in the name, like file.txt or file.html.", duration: 2600 });
      return;
    }

    const ext = safeName.split(".").pop().toLowerCase();
    const mime = /^(html|htm)$/.test(ext)
      ? "text/html;charset=utf-8"
      : "text/plain;charset=utf-8";

    downloadNotepadFile(safeName, editorEl?.value || "", mime);
  });

  searchEl?.addEventListener("input", () => {
    notepadSearchMatches = [];
    notepadSearchIndex = -1;
    const query = String(searchEl.value || "").trim();
    if (!query){
      renderNotepadSearchOverlay();
      return;
    }
    runNotepadSearch(1, true);
  });

  searchEl?.addEventListener("keydown", (e) => {
    if (e.key === "Enter"){
      e.preventDefault();
      runNotepadSearch(e.shiftKey ? -1 : 1, false);
      return;
    }
    if (e.key === "Escape"){
      e.preventDefault();
      searchEl.value = "";
      notepadSearchMatches = [];
      notepadSearchIndex = -1;
      renderNotepadSearchOverlay();
      editorEl?.focus();
    }
  });

  editorEl?.addEventListener("input", () => {
    notepadSearchMatches = collectNotepadSearchMatches(String(searchEl?.value || "").trim());
    if (notepadSearchIndex >= notepadSearchMatches.length) notepadSearchIndex = notepadSearchMatches.length ? 0 : -1;
    renderNotepadSearchOverlay();
  });

  editorEl?.addEventListener("scroll", syncNotepadSearchOverlay);
  editorEl?.addEventListener("mouseup", syncNotepadSearchOverlay);

  editorEl?.addEventListener("keydown", (e) => {
    if ((e.ctrlKey || e.metaKey) && String(e.key).toLowerCase() === "f"){
      e.preventDefault();
      searchEl?.focus();
      searchEl?.select();
      return;
    }
    if (e.key === "F3"){
      e.preventDefault();
      runNotepadSearch(e.shiftKey ? -1 : 1, false);
    }
  });
}

async function openCameraModal(){
  stopCameraModalStream();

  openModal({
    title: "Camera",
    bodyHTML: `
      <div style="display:grid; gap:12px;">
        <div style="display:flex; gap:10px; flex-wrap:wrap;">
          <button class="btn primary" id="btn-camera-request" type="button">Allow Camera</button>
        </div>
        <div class="muted small" id="camera-permission-status">Camera idle</div>
        <video id="camera-preview" autoplay playsinline muted hidden style="width:100%; border-radius:16px; border:1px solid rgba(255,255,255,.12); background:#000;"></video>
      </div>
    `,
    onBeforeClose: stopCameraModalStream
  });

  const statusEl = $("camera-permission-status");
  const videoEl = $("camera-preview");

  $("btn-camera-request")?.addEventListener("click", async () => {
    if (!navigator.mediaDevices?.getUserMedia){
      if (statusEl) statusEl.textContent = "Camera access is not supported in this browser.";
      return;
    }

    if (statusEl) statusEl.textContent = "Requesting camera permission...";

    try{
      const stream = await navigator.mediaDevices.getUserMedia({ video:true, audio:false });
      window.__cameraModalStream = stream;
      if (videoEl){
        videoEl.srcObject = stream;
        videoEl.hidden = false;
      }
      if (statusEl) statusEl.textContent = "Camera permission granted.";
    }catch(err){
      if (statusEl) statusEl.textContent = (err && err.name === "NotAllowedError")
        ? "Camera permission was denied."
        : "Camera could not be started.";
    }
  });
}

